    fn init_auth_matcher_context(
        &mut self,
        matcher_program: Pubkey,
        maker_owner: &Keypair,
        maker_account: Pubkey,
    ) -> (Pubkey, Pubkey, u64) {
        let ctx = Pubkey::new_unique();
        let delegate = matcher_delegate_key(
            &self.program_id,
            &self.market,
            &maker_account,
            &maker_owner.pubkey(),
            &matcher_program,
            &ctx,
        );
        let cu = self
            .try_init_auth_matcher_context_with_delegate(
                matcher_program,
                maker_owner,
                maker_account,
                ctx,
                delegate,
            )
            .expect("init auth matcher context");
        self.set_matcher_config(
            matcher_program,
            maker_owner,
            maker_account,
            ctx,
            delegate,
            1,
        );
        (ctx, delegate, cu)
    }

    fn init_auth_matcher_context_via_system_create(
        &mut self,
        matcher_program: Pubkey,
        maker_owner: &Keypair,
        maker_account: Pubkey,
    ) -> (Pubkey, Pubkey, u64) {
        self.ensure_signer_account(maker_owner.pubkey());
        let ctx = Keypair::new();
        let create_cu = send_raw_tx(
            &mut self.svm,
            &self.payer,
            system_instruction::create_account(
                &self.payer.pubkey(),
                &ctx.pubkey(),
                1_000_000_000,
                MATCHER_CONTEXT_LEN as u64,
                &matcher_program,
            ),
            &[&ctx],
        )
        .expect("system-create matcher context");
        let delegate = matcher_delegate_key(
            &self.program_id,
            &self.market,
            &maker_account,
            &maker_owner.pubkey(),
            &matcher_program,
            &ctx.pubkey(),
        );
        let init_cu = send_raw_tx(
            &mut self.svm,
            &self.payer,
            Instruction {
                program_id: matcher_program,
                accounts: vec![
                    AccountMeta::new_readonly(maker_owner.pubkey(), true),
                    AccountMeta::new_readonly(delegate, false),
                    AccountMeta::new(ctx.pubkey(), false),
                    AccountMeta::new_readonly(self.program_id, false),
                    AccountMeta::new_readonly(self.market, false),
                    AccountMeta::new_readonly(maker_account, false),
                ],
                data: vec![2],
            },
            &[maker_owner],
        )
        .expect("auth matcher init after system create");
        self.set_matcher_config(
            matcher_program,
            maker_owner,
            maker_account,
            ctx.pubkey(),
            delegate,
            1,
        );
        (ctx.pubkey(), delegate, create_cu + init_cu)
    }

    fn set_matcher_config(
        &mut self,
        matcher_program: Pubkey,
        maker_owner: &Keypair,
        maker_account: Pubkey,
        matcher_context: Pubkey,
        matcher_delegate: Pubkey,
        enabled: u8,
    ) -> Pubkey {
        self.try_set_matcher_config(
            matcher_program,
            maker_owner,
            maker_account,
            matcher_context,
            matcher_delegate,
            enabled,
        )
        .expect("set matcher config")
    }

    fn try_set_matcher_config(
        &mut self,
        matcher_program: Pubkey,
        maker_owner: &Keypair,
        maker_account: Pubkey,
        matcher_context: Pubkey,
        matcher_delegate: Pubkey,
        enabled: u8,
    ) -> Result<Pubkey, String> {
        self.svm.expire_blockhash();
        let mut accounts = vec![
            AccountMeta::new(maker_owner.pubkey(), true),
            AccountMeta::new_readonly(self.market, false),
            AccountMeta::new(maker_account, false),
        ];
        if enabled != 0 {
            accounts.extend([
                AccountMeta::new_readonly(matcher_program, false),
                AccountMeta::new_readonly(matcher_context, false),
                AccountMeta::new_readonly(matcher_delegate, false),
            ]);
        }
        self.send(
            ProgInstruction::SetMatcherConfig { enabled },
            accounts,
            &[maker_owner],
        )?;
        Ok(matcher_delegate)
    }

