#[test]
fn v16_bpf_perps_positive_smoke_cross_margin_pnl_convert_close_and_withdraw() {
    const INITIAL_PRICE: u64 = 100;
    const ASSET0_MARK: u64 = 105;
    const ASSET1_MARK: u64 = 100;
    const DEPOSIT: u128 = 2_000_000;
    const EXPECTED_PNL: i128 = 5;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_for_asset_as_admin(0, 1, INITIAL_PRICE);
    env.configure_auth_mark_for_asset_as_admin(1, 1, INITIAL_PRICE);

    let cross_owner = Keypair::new();
    let counterparty_owner = Keypair::new();
    let cross_account = env.create_portfolio(&cross_owner);
    let counterparty_account = env.create_portfolio(&counterparty_owner);
    env.deposit(&cross_owner, cross_account, DEPOSIT);
    env.deposit(&counterparty_owner, counterparty_account, DEPOSIT);

    let open_asset0_cu = env.trade_asset_with_cu(
        0,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        POS_SCALE as i128,
        INITIAL_PRICE,
        0,
    );
    assert_cu_within("perps smoke open asset[0]", open_asset0_cu, TRADE_CU_LIMIT);
    let open_asset1_cu = env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        -(POS_SCALE as i128),
        INITIAL_PRICE,
        0,
    );
    assert_cu_within("perps smoke open asset[1]", open_asset1_cu, TRADE_CU_LIMIT);

    let cross_open = env.portfolio_state(cross_account);
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&cross_open)),
        2
    );
    assert_eq!(
        active_leg_for_asset(&cross_open, 0).basis_pos_q,
        POS_SCALE as i128
    );
    assert_eq!(
        active_leg_for_asset(&cross_open, 1).basis_pos_q,
        -(POS_SCALE as i128)
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(0, 2, ASSET0_MARK);
    env.push_auth_mark_for_asset_as_admin(1, 2, ASSET1_MARK);

    for (portfolio, asset_index, label) in [
        (
            counterparty_account,
            0,
            "counterparty asset[0] loss refresh",
        ),
        (cross_account, 0, "cross account asset[0] gain refresh"),
        (
            counterparty_account,
            1,
            "counterparty asset[1] loss refresh",
        ),
        (cross_account, 1, "cross account asset[1] gain refresh"),
    ] {
        let cu = env.crank(
            portfolio,
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(asset_index),
            },
        );
        assert_cu_within(label, cu, CRANK_CU_LIMIT);
    }

    let cross_after_refresh = env.portfolio_state(cross_account);
    let counterparty_after_refresh = env.portfolio_state(counterparty_account);
    assert_eq!(
        cross_after_refresh.pnl.get(),
        EXPECTED_PNL,
        "cross-margin account should realize +5 while carrying two active legs"
    );
    assert_eq!(counterparty_after_refresh.pnl.get(), 0);
    assert_eq!(
        counterparty_after_refresh.capital.get(),
        DEPOSIT - EXPECTED_PNL as u128
    );

    let close_asset0_cu = env.trade_asset_with_cu(
        0,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        -(POS_SCALE as i128),
        ASSET0_MARK,
        0,
    );
    assert_cu_within(
        "perps smoke close asset[0]",
        close_asset0_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );
    let close_asset1_cu = env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        POS_SCALE as i128,
        ASSET1_MARK,
        0,
    );
    assert_cu_within(
        "perps smoke close asset[1]",
        close_asset1_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let cross_flat = env.portfolio_state(cross_account);
    let counterparty_flat = env.portfolio_state(counterparty_account);
    assert!(percolator::active_bitmap_is_empty(active_bitmap(
        &cross_flat
    )));
    assert!(percolator::active_bitmap_is_empty(active_bitmap(
        &counterparty_flat
    )));
    assert_eq!(cross_flat.pnl.get(), EXPECTED_PNL);
    assert_eq!(cross_flat.capital.get(), DEPOSIT);
    assert_eq!(
        counterparty_flat.capital.get(),
        DEPOSIT - EXPECTED_PNL as u128
    );

    let convert_cu =
        env.convert_released_pnl_with_cu(&cross_owner, cross_account, EXPECTED_PNL as u128);
    assert_cu_within(
        "perps smoke convert released pnl",
        convert_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );
    let cross_after_convert = env.portfolio_state(cross_account);
    assert_eq!(cross_after_convert.pnl.get(), 0);
    assert_eq!(
        cross_after_convert.capital.get(),
        DEPOSIT + EXPECTED_PNL as u128
    );

    let cross_dest = env.withdraw(
        &cross_owner,
        cross_account,
        cross_after_convert.capital.get(),
    );
    let counterparty_dest = env.withdraw(
        &counterparty_owner,
        counterparty_account,
        counterparty_flat.capital.get(),
    );
    assert_eq!(
        env.token_amount(cross_dest) as u128,
        DEPOSIT + EXPECTED_PNL as u128
    );
    assert_eq!(
        env.token_amount(counterparty_dest) as u128,
        DEPOSIT - EXPECTED_PNL as u128
    );
    assert_eq!(env.token_amount(env.vault), 0);
    let (_, group) = env.market_state();
    assert_eq!(group.vault, 0);
    assert_eq!(group.c_tot, 0);
    assert_eq!(group.insurance, 0);
}

#[test]
fn v16_bpf_cross_margin_positive_pnl_allows_trading_negative_leg_before_convert() {
    const INITIAL_PRICE: u64 = 100;
    const ASSET0_MARK: u64 = 105;
    const ASSET1_MARK: u64 = 95;
    const ASSET0_SIZE_Q: i128 = 20 * POS_SCALE as i128;
    const ASSET1_SIZE_Q: i128 = 10 * POS_SCALE as i128;
    const DEPOSIT: u128 = 320;
    const EXPECTED_POSITIVE_PNL: i128 = 100;
    const EXPECTED_NET_PNL_AFTER_NEGATIVE_CLOSE: i128 = 50;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_for_asset_as_admin(0, 1, INITIAL_PRICE);
    env.configure_auth_mark_for_asset_as_admin(1, 1, INITIAL_PRICE);

    let cross_owner = Keypair::new();
    let counterparty_owner = Keypair::new();
    let cross_account = env.create_portfolio(&cross_owner);
    let counterparty_account = env.create_portfolio(&counterparty_owner);
    env.deposit(&cross_owner, cross_account, DEPOSIT);
    env.deposit(&counterparty_owner, counterparty_account, 1_000);

    env.trade_asset_with_cu(
        0,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        ASSET0_SIZE_Q,
        INITIAL_PRICE,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        ASSET1_SIZE_Q,
        INITIAL_PRICE,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(0, 2, ASSET0_MARK);
    env.push_auth_mark_for_asset_as_admin(1, 2, ASSET1_MARK);

    for (portfolio, asset_index, label) in [
        (
            counterparty_account,
            0,
            "counterparty asset[0] loss refresh",
        ),
        (cross_account, 0, "cross account asset[0] gain refresh"),
        (
            counterparty_account,
            1,
            "counterparty asset[1] gain refresh",
        ),
    ] {
        let cu = env.crank(
            portfolio,
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(asset_index),
            },
        );
        assert_cu_within(label, cu, CRANK_CU_LIMIT);
    }
    let (_, moved_group) = env.market_state();
    assert_eq!(moved_group.assets[0].effective_price, ASSET0_MARK);
    assert_eq!(moved_group.assets[1].effective_price, ASSET1_MARK);

    let cross_before_close = env.portfolio_state(cross_account);
    assert_eq!(cross_before_close.pnl.get(), EXPECTED_POSITIVE_PNL);
    assert_eq!(cross_before_close.capital.get(), DEPOSIT);
    assert_eq!(
        active_leg_for_asset(&cross_before_close, 1).basis_pos_q,
        ASSET1_SIZE_Q,
        "asset[1] is a long leg with negative mark-to-market at the moved price"
    );

    let close_negative_leg_cu = env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        -ASSET1_SIZE_Q,
        ASSET1_MARK,
        0,
    );
    assert_cu_within(
        "cross-margin close negative leg before pnl convert",
        close_negative_leg_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let cross_after_close = env.portfolio_state(cross_account);
    assert!(
        has_active_leg_for_asset(&cross_after_close, 0),
        "positive-PnL leg should remain open"
    );
    assert!(
        !has_active_leg_for_asset(&cross_after_close, 1),
        "negative-PnL leg should close without converting positive PnL first"
    );
    assert_eq!(cross_after_close.capital.get(), DEPOSIT);
    assert_eq!(
        cross_after_close.pnl.get(),
        EXPECTED_NET_PNL_AFTER_NEGATIVE_CLOSE,
        "asset[1] loss should net against the existing source-backed positive PnL"
    );
}

#[derive(Clone, Copy, Debug)]
enum SourceCreditWatermarkTradePath {
    NoCpi,
    Cpi,
}

#[derive(Clone, Copy, Debug)]
enum SourceCreditWatermarkDirection {
    PositiveSize,
    NegativeSize,
}

#[allow(clippy::too_many_arguments)]
fn try_source_credit_watermark_trade(
    env: &mut V16CuEnv,
    path: SourceCreditWatermarkTradePath,
    matcher_accounts: Option<(Pubkey, Pubkey, Pubkey)>,
    owner_a: &Keypair,
    account_a: Pubkey,
    owner_b: &Keypair,
    account_b: Pubkey,
    asset_index: u16,
    size_q: i128,
    exec_price: u64,
    fee_bps: u64,
) -> Result<u64, String> {
    match path {
        SourceCreditWatermarkTradePath::NoCpi => env.try_trade_asset_with_cu(
            asset_index,
            owner_a,
            account_a,
            owner_b,
            account_b,
            size_q,
            exec_price,
            fee_bps,
        ),
        SourceCreditWatermarkTradePath::Cpi => {
            let (matcher_program, matcher_ctx, matcher_delegate) =
                matcher_accounts.expect("matcher accounts");
            env.try_trade_cpi_with_cu_on_asset(
                owner_a,
                account_a,
                owner_b,
                account_b,
                matcher_program,
                matcher_ctx,
                matcher_delegate,
                asset_index,
                size_q,
                fee_bps,
            )
        }
    }
}

fn run_source_credit_watermark_trade_case(
    path: SourceCreditWatermarkTradePath,
    direction: SourceCreditWatermarkDirection,
) {
    const INITIAL_PRICE: u64 = 100;
    const ASSET0_SIZE_Q: i128 = 20 * POS_SCALE as i128;
    const ASSET1_SIZE_Q: i128 = 10 * POS_SCALE as i128;
    const SAFE_INCREASE_Q: i128 = POS_SCALE as i128;
    const DEPOSIT: u128 = 313;
    const EXPECTED_POSITIVE_PNL: i128 = 100;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    let matcher_program = match path {
        SourceCreditWatermarkTradePath::NoCpi => None,
        SourceCreditWatermarkTradePath::Cpi => {
            let matcher_program = Pubkey::new_unique();
            let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
            env.svm.add_program(matcher_program, &matcher_bytes);
            Some(matcher_program)
        }
    };
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_for_asset_as_admin(0, 1, INITIAL_PRICE);
    env.configure_auth_mark_for_asset_as_admin(1, 1, INITIAL_PRICE);

    let cross_owner = Keypair::new();
    let counterparty_owner = Keypair::new();
    let cross_account = env.create_portfolio(&cross_owner);
    let counterparty_account = env.create_portfolio(&counterparty_owner);
    env.deposit(&cross_owner, cross_account, DEPOSIT);
    env.deposit(&counterparty_owner, counterparty_account, 1_000);
    let matcher_accounts = matcher_program.map(|program| {
        let (ctx, delegate, _) =
            env.init_matcher_context_authorized(program, &counterparty_owner, counterparty_account);
        (program, ctx, delegate)
    });

    let (winning_domain, asset0_mark, asset1_mark, side_sign) = match direction {
        SourceCreditWatermarkDirection::PositiveSize => (1usize, 105, 95, 1i128),
        SourceCreditWatermarkDirection::NegativeSize => (0usize, 95, 105, -1i128),
    };
    env.top_up_backing_bucket(winning_domain as u16, 150, 10);

    env.trade_asset_with_cu(
        0,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        side_sign * ASSET0_SIZE_Q,
        INITIAL_PRICE,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        side_sign * ASSET1_SIZE_Q,
        INITIAL_PRICE,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(0, 2, asset0_mark);
    env.push_auth_mark_for_asset_as_admin(1, 2, asset1_mark);
    for (portfolio, asset_index) in [
        (counterparty_account, 0),
        (cross_account, 0),
        (counterparty_account, 1),
    ] {
        env.crank(
            portfolio,
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(asset_index),
            },
        );
    }
    let forced_capital = match direction {
        SourceCreditWatermarkDirection::PositiveSize => 260,
        SourceCreditWatermarkDirection::NegativeSize => 100,
    };
    env.force_portfolio_capital_for_benchmark(cross_account, forced_capital);

    let cross_before = env.portfolio_state(cross_account);
    assert_eq!(
        cross_before.pnl.get(),
        EXPECTED_POSITIVE_PNL,
        "{path:?} {direction:?} setup must create source-backed positive PnL"
    );
    let (_, before_withdraw_group) = env.market_state();
    assert_eq!(
        before_withdraw_group.source_credit[winning_domain].positive_claim_bound_num,
        EXPECTED_POSITIVE_PNL as u128 * BOUND_SCALE
    );
    let surplus_backing = before_withdraw_group.source_credit[winning_domain]
        .fresh_reserved_backing_num
        .checked_sub(before_withdraw_group.source_credit[winning_domain].positive_claim_bound_num)
        .unwrap()
        / BOUND_SCALE;
    assert!(
        surplus_backing > 0,
        "{path:?} {direction:?} setup must leave withdrawable surplus backing"
    );

    let watermark_withdraw_dest = env.token_account(env.admin.pubkey(), 0);
    env.withdraw_backing_bucket_to_admin_token_with_cu(
        watermark_withdraw_dest,
        winning_domain as u16,
        surplus_backing,
    );
    let (_, exact_watermark_group) = env.market_state();
    assert_eq!(
        exact_watermark_group.source_credit[winning_domain].fresh_reserved_backing_num,
        exact_watermark_group.source_credit[winning_domain].positive_claim_bound_num,
        "{path:?} {direction:?} setup must leave no surplus source-credit backing"
    );

    let before_market = env.svm.get_account(&env.market).unwrap();
    let before_cross = env.svm.get_account(&cross_account).unwrap();
    let before_counterparty = env.svm.get_account(&counterparty_account).unwrap();
    let over_watermark = try_source_credit_watermark_trade(
        &mut env,
        path,
        matcher_accounts,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        1,
        side_sign * SAFE_INCREASE_Q,
        asset1_mark,
        0,
    );
    assert!(
        over_watermark.is_err(),
        "{path:?} {direction:?} risk increase must reject at the exact source-credit watermark"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_market.data
    );
    assert_eq!(
        env.svm.get_account(&cross_account).unwrap().data,
        before_cross.data
    );
    assert_eq!(
        env.svm.get_account(&counterparty_account).unwrap().data,
        before_counterparty.data
    );

    env.top_up_backing_bucket(winning_domain as u16, 5_000, 10);
    let second_pass_deposit = match direction {
        SourceCreditWatermarkDirection::PositiveSize => 50,
        SourceCreditWatermarkDirection::NegativeSize => 200,
    };
    env.deposit(&cross_owner, cross_account, second_pass_deposit);
    env.deposit(
        &counterparty_owner,
        counterparty_account,
        second_pass_deposit,
    );
    env.svm.warp_to_slot(3);
    let inside_watermark = try_source_credit_watermark_trade(
        &mut env,
        path,
        matcher_accounts,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        1,
        side_sign * SAFE_INCREASE_Q,
        asset1_mark,
        1,
    );
    assert!(
        inside_watermark.is_ok(),
        "{path:?} {direction:?} risk increase inside the source-credit watermark failed: {inside_watermark:?}"
    );

    let (_, after_group) = env.market_state();
    let cross_after = env.portfolio_state(cross_account);
    assert_eq!(
        after_group.source_credit[winning_domain].credit_rate_num,
        percolator::CREDIT_RATE_SCALE,
        "{path:?} {direction:?} must not dilute live positive claims"
    );
    assert!(
        state::portfolio_source_domain(&cross_after, winning_domain)
            .source_lien_effective_reserved
            .get()
            > 0,
        "{path:?} {direction:?} must reserve source credit once surplus backing exists"
    );
}

#[test]
fn v16_bpf_trade_paths_respect_source_credit_watermark_permutations() {
    for path in [
        SourceCreditWatermarkTradePath::NoCpi,
        SourceCreditWatermarkTradePath::Cpi,
    ] {
        for direction in [
            SourceCreditWatermarkDirection::PositiveSize,
            SourceCreditWatermarkDirection::NegativeSize,
        ] {
            run_source_credit_watermark_trade_case(path, direction);
        }
    }
}

#[test]
fn v16_bpf_cross_margin_positive_pnl_allows_backed_risk_increase_on_negative_leg() {
    const INITIAL_PRICE: u64 = 100;
    const ASSET0_MARK: u64 = 105;
    const ASSET1_MARK: u64 = 95;
    const ASSET0_SIZE_Q: i128 = 20 * POS_SCALE as i128;
    const ASSET1_SIZE_Q: i128 = 10 * POS_SCALE as i128;
    const SAFE_INCREASE_Q: i128 = POS_SCALE as i128;
    const TOO_LARGE_INCREASE_Q: i128 = 30 * POS_SCALE as i128;
    const DEPOSIT: u128 = 313;
    const EXPECTED_POSITIVE_PNL: i128 = 100;
    const EXPECTED_NET_PNL_AFTER_REFRESH: i128 = 50;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_for_asset_as_admin(0, 1, INITIAL_PRICE);
    env.configure_auth_mark_for_asset_as_admin(1, 1, INITIAL_PRICE);

    let cross_owner = Keypair::new();
    let counterparty_owner = Keypair::new();
    let cross_account = env.create_portfolio(&cross_owner);
    let counterparty_account = env.create_portfolio(&counterparty_owner);
    env.deposit(&cross_owner, cross_account, DEPOSIT);
    env.deposit(&counterparty_owner, counterparty_account, 1_000);
    env.top_up_backing_bucket(1, 150, 10);

    env.trade_asset_with_cu(
        0,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        ASSET0_SIZE_Q,
        INITIAL_PRICE,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        ASSET1_SIZE_Q,
        INITIAL_PRICE,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(0, 2, ASSET0_MARK);
    env.push_auth_mark_for_asset_as_admin(1, 2, ASSET1_MARK);
    for (portfolio, asset_index) in [
        (counterparty_account, 0),
        (cross_account, 0),
        (counterparty_account, 1),
    ] {
        env.crank(
            portfolio,
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(asset_index),
            },
        );
    }

    let cross_before = env.portfolio_state(cross_account);
    assert_eq!(cross_before.pnl.get(), EXPECTED_POSITIVE_PNL);
    assert_eq!(cross_before.capital.get(), DEPOSIT);
    assert_eq!(
        active_leg_for_asset(&cross_before, 1).basis_pos_q,
        ASSET1_SIZE_Q,
        "asset[1] is a losing long leg before the risk-increasing trade"
    );
    let (_, before_watermark_group) = env.market_state();
    let fresh_reserved_before_withdraw =
        before_watermark_group.source_credit[1].fresh_reserved_backing_num;
    let positive_claim_before_withdraw =
        before_watermark_group.source_credit[1].positive_claim_bound_num;

    let watermark_withdraw_dest = env.token_account(env.admin.pubkey(), 0);
    let withdraw_cu =
        env.withdraw_backing_bucket_to_admin_token_with_cu(watermark_withdraw_dest, 1, 50);
    assert_cu_within(
        "WithdrawBackingBucket live watermark",
        withdraw_cu,
        CUSTODY_CU_LIMIT,
    );
    let (_, watermarked_group) = env.market_state();
    assert_eq!(
        watermarked_group.source_credit[1].fresh_reserved_backing_num,
        fresh_reserved_before_withdraw - 50 * BOUND_SCALE,
        "admin withdrawal lowers the future encumbrance watermark"
    );
    assert!(
        watermarked_group.source_credit[1].fresh_reserved_backing_num
            >= positive_claim_before_withdraw,
        "the lowered watermark must still cover live positive-claim demand"
    );
    assert_eq!(
        watermarked_group.source_credit[1].credit_rate_num,
        percolator::CREDIT_RATE_SCALE,
        "lowering the watermark must not dilute already-live positive claims"
    );

    let before_market = env.svm.get_account(&env.market).unwrap();
    let before_cross = env.svm.get_account(&cross_account).unwrap();
    let before_counterparty = env.svm.get_account(&counterparty_account).unwrap();
    let too_large = env.try_trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        TOO_LARGE_INCREASE_Q,
        ASSET1_MARK,
        0,
    );
    assert!(
        too_large.is_err(),
        "risk increase must stay capped by realizable source-backed positive PnL"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_market.data
    );
    assert_eq!(
        env.svm.get_account(&cross_account).unwrap().data,
        before_cross.data
    );
    assert_eq!(
        env.svm.get_account(&counterparty_account).unwrap().data,
        before_counterparty.data
    );

    let increase_cu = env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        SAFE_INCREASE_Q,
        ASSET1_MARK,
        0,
    );
    assert_cu_within(
        "cross-margin increase negative leg with backed positive pnl",
        increase_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let cross_after = env.portfolio_state(cross_account);
    assert_eq!(
        active_leg_for_asset(&cross_after, 1).basis_pos_q,
        ASSET1_SIZE_Q + SAFE_INCREASE_Q
    );
    assert_eq!(cross_after.capital.get(), DEPOSIT);
    assert_eq!(cross_after.pnl.get(), EXPECTED_NET_PNL_AFTER_REFRESH);
    assert!(
        cross_after.capital.get() < health_cert(&cross_after).certified_initial_req,
        "without positive PnL credit this risk increase would fail initial margin"
    );
    assert!(
        health_cert(&cross_after).certified_equity as u128
            >= health_cert(&cross_after).certified_initial_req
    );
    let source_lien_effective_reserved: u128 = cross_after
        .source_domains
        .iter()
        .map(|slot| slot.source_lien_effective_reserved.get())
        .sum();
    assert!(
        source_lien_effective_reserved > 0,
        "risk-increasing trade must reserve backed source-credit support for IM"
    );
    assert!(
        cross_after
            .source_domains
            .iter()
            .any(|slot| slot.source_lien_counterparty_backing_num.get() != 0)
            || cross_after
                .source_domains
                .iter()
                .any(|slot| slot.source_lien_insurance_backing_num.get() != 0),
        "source-credit IM lien must be backed by counterparty backing or reserved insurance"
    );

    let (_, after_increase_group) = env.market_state();
    let after_increase_source = after_increase_group.source_credit[1];
    let after_increase_bucket = after_increase_group.source_backing_buckets[1];
    let insurance_encumbered_num = after_increase_source
        .valid_liened_insurance_num
        .checked_add(after_increase_source.impaired_liened_insurance_num)
        .unwrap();
    let available_backing_num = after_increase_source
        .fresh_reserved_backing_num
        .checked_sub(after_increase_source.valid_liened_backing_num)
        .unwrap()
        .checked_add(
            after_increase_source
                .insurance_credit_reserved_num
                .checked_sub(insurance_encumbered_num)
                .unwrap(),
        )
        .unwrap();
    let max_lossless_withdrawable_num = after_increase_bucket
        .fresh_unliened_backing_num
        .min(available_backing_num - after_increase_source.positive_claim_bound_num);
    let over_watermark_amount = max_lossless_withdrawable_num / BOUND_SCALE + 1;
    assert!(
        over_watermark_amount > 0,
        "test must attempt a withdrawal above the live backing watermark"
    );

    let backing_withdraw_dest = env.token_account(env.admin.pubkey(), 0);
    let market_before_withdraw = env.svm.get_account(&env.market).unwrap();
    let backing_withdraw = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 1,
            amount: over_watermark_amount,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(backing_withdraw_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&env.admin],
    );
    assert!(
        backing_withdraw.is_err(),
        "withdrawal above the live backing watermark must not be allowed"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        market_before_withdraw.data
    );
}

#[test]
fn v16_bpf_permissionless_crank_computes_funding_from_internal_mark_premium() {
    const INITIAL_PRICE: u64 = 1_000_000;
    const DEPOSIT: u128 = 10_000_000;

    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: INITIAL_PRICE,
        max_price_move_bps_per_slot: 1_000,
        max_accrual_dt_slots: 1,
        max_abs_funding_e9_per_slot: 1_000,
        min_funding_lifetime_slots: 1,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(0);
    env.configure_ewma_mark_with_cu(0, INITIAL_PRICE, 1, 0);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, DEPOSIT);
    env.deposit(&short_owner, short_account, DEPOSIT);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        INITIAL_PRICE,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, INITIAL_PRICE * 2);
    env.crank(
        long_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let (cfg_after_first, group_after_first) = env.market_state();
    assert_eq!(cfg_after_first.mark_ewma_e6, 1_500_000);
    assert_eq!(group_after_first.assets[0].effective_price, 1_100_000);
    assert_eq!(
        group_after_first.funding_epoch, 0,
        "a newly pushed mark must not retroactively charge funding before its slot"
    );
    assert_eq!(group_after_first.assets[0].f_long_num, 0);
    assert_eq!(group_after_first.assets[0].f_short_num, 0);

    env.svm.warp_to_slot(2);
    let funding_cu = env.crank(
        long_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert_cu_within(
        "permissionless computed funding crank",
        funding_cu,
        CRANK_CU_LIMIT,
    );
    let (_, funded_group) = env.market_state();
    assert_eq!(funded_group.funding_epoch, 1);
    assert_eq!(funded_group.assets[0].effective_price, 1_210_000);
    assert_eq!(funded_group.assets[0].f_long_num, -(ADL_ONE as i128));
    assert_eq!(funded_group.assets[0].f_short_num, ADL_ONE as i128);
}

#[test]
fn v16_bpf_existing_funding_ledger_refreshes_and_converts_between_sides() {
    const INITIAL_PRICE: u64 = 1_000_000;
    const FUNDING_RATE_E9: i128 = 1_000;
    const DEPOSIT: u128 = 2_000_000;

    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, DEPOSIT);
    env.deposit(&short_owner, short_account, DEPOSIT);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        INITIAL_PRICE,
        0,
    );

    env.mutate_market(|_, group| {
        let out = group
            .accrue_asset_to_not_atomic(0, 1, INITIAL_PRICE, FUNDING_RATE_E9, true)
            .unwrap();
        assert!(out.funding_active);
        group.assets[0].raw_oracle_target_price = INITIAL_PRICE;
    });
    env.svm.warp_to_slot(1);
    let (_, funded_group) = env.market_state();
    assert_eq!(funded_group.funding_epoch, 1);
    assert_eq!(funded_group.assets[0].f_long_num, -(ADL_ONE as i128));
    assert_eq!(funded_group.assets[0].f_short_num, ADL_ONE as i128);

    let long_refresh_cu = env.crank(
        long_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert_cu_within(
        "funding smoke long loss refresh",
        long_refresh_cu,
        CRANK_CU_LIMIT,
    );
    let long_after = env.portfolio_state(long_account);
    assert_eq!(long_after.pnl.get(), 0);
    assert_eq!(long_after.capital.get(), DEPOSIT - 1);

    let short_refresh_cu = env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert_cu_within(
        "funding smoke short gain refresh",
        short_refresh_cu,
        CRANK_CU_LIMIT,
    );
    let short_after = env.portfolio_state(short_account);
    assert_eq!(short_after.pnl.get(), 1);
    assert_eq!(short_after.capital.get(), DEPOSIT);

    let close_cu = env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        -(POS_SCALE as i128),
        INITIAL_PRICE,
        0,
    );
    assert_cu_within(
        "funding smoke close funded position",
        close_cu,
        TRADE_CU_LIMIT,
    );
    let long_flat = env.portfolio_state(long_account);
    let short_flat = env.portfolio_state(short_account);
    assert!(percolator::active_bitmap_is_empty(active_bitmap(
        &long_flat
    )));
    assert!(percolator::active_bitmap_is_empty(active_bitmap(
        &short_flat
    )));
    assert_eq!(long_flat.capital.get(), DEPOSIT - 1);
    assert_eq!(short_flat.pnl.get(), 1);

    let convert_cu = env.convert_released_pnl_with_cu(&short_owner, short_account, 1);
    assert_cu_within(
        "funding smoke convert released pnl",
        convert_cu,
        CUSTODY_CU_LIMIT,
    );
    let short_after_convert = env.portfolio_state(short_account);
    assert_eq!(short_after_convert.pnl.get(), 0);
    assert_eq!(short_after_convert.capital.get(), DEPOSIT + 1);

    let (_, group) = env.market_state();
    assert_eq!(group.c_tot, DEPOSIT * 2);
    assert_eq!(group.vault, DEPOSIT * 2);
}

#[test]
fn v16_bpf_stale_asset_does_not_block_current_unrelated_trade() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);

    let stale_long_owner = Keypair::new();
    let stale_short_owner = Keypair::new();
    let stale_long_account = env.create_portfolio(&stale_long_owner);
    let stale_short_account = env.create_portfolio(&stale_short_owner);
    env.deposit(&stale_long_owner, stale_long_account, 1_000_000_000);
    env.deposit(&stale_short_owner, stale_short_account, 1_000_000_000);
    env.trade_asset_with_cu(
        1,
        &stale_long_owner,
        stale_long_account,
        &stale_short_owner,
        stale_short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    let cranker_owner = Keypair::new();
    let cranker_portfolio = env.create_portfolio(&cranker_owner);
    env.svm.warp_to_slot(3);

    for nonce in 0..3 {
        env.crank(
            cranker_portfolio,
            ProgInstruction::PermissionlessCrank {
                now_slot: 3 + nonce,
                close_q: 0,
                observations: crank_observations(0),
            },
        );
    }

    env.crank(
        cranker_portfolio,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(1),
        },
    );

    let (_, group) = env.market_state();
    assert_eq!(group.current_slot, 3);
    assert_eq!(group.assets[0].slot_last, 3);
    assert!(group.assets[1].slot_last < group.current_slot);
    assert!(
        group.loss_stale_active,
        "asset[1] partial catch-up must leave the market loss-stale bit set"
    );

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000_000);
    env.deposit(&short_owner, short_account, 1_000_000_000);

    let trade_cu = env.trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );
    println!("v16 TradeNoCpi current asset[0] with stale asset[1] CU: {trade_cu}");
    assert_cu_within(
        "TradeNoCpi current asset[0] with unrelated stale asset[1]",
        trade_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let (_, group_after) = env.market_state();
    assert_eq!(group_after.assets[0].slot_last, 3);
    assert!(group_after.assets[1].slot_last < group_after.current_slot);
    assert!(
        group_after.loss_stale_active,
        "unrelated trade must not hide the stale asset state"
    );

    let long = env.portfolio_state(long_account);
    let short = env.portfolio_state(short_account);
    assert!(has_active_leg_for_asset(&long, 0));
    assert!(has_active_leg_for_asset(&short, 0));
    assert!(!has_active_leg_for_asset(&long, 1));
    assert!(!has_active_leg_for_asset(&short, 1));
}

#[test]
fn v16_bpf_trade_refreshes_stale_related_portfolio_leg_on_demand() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(1, 0, 100);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000_000);
    env.deposit(&short_owner, short_account, 1_000_000_000);

    env.trade_asset_with_cu(
        1,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    let crank_long_owner = Keypair::new();
    let crank_short_owner = Keypair::new();
    let crank_long_account = env.create_portfolio(&crank_long_owner);
    let crank_short_account = env.create_portfolio(&crank_short_owner);
    env.deposit(&crank_long_owner, crank_long_account, 1_000_000_000);
    env.deposit(&crank_short_owner, crank_short_account, 1_000_000_000);
    env.trade_asset_with_cu(
        1,
        &crank_long_owner,
        crank_long_account,
        &crank_short_owner,
        crank_short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    let (_, group_before_push) = env.market_state();
    let long_before_push = env.portfolio_state(long_account);
    let short_before_push = env.portfolio_state(short_account);
    assert_eq!(
        health_cert(&long_before_push).cert_oracle_epoch,
        group_before_push.oracle_epoch
    );
    assert_eq!(
        health_cert(&short_before_push).cert_oracle_epoch,
        group_before_push.oracle_epoch
    );

    env.svm.warp_to_slot(1);
    env.push_auth_mark_for_asset_as_admin(1, 1, 105);
    env.crank(
        crank_long_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(1),
        },
    );

    let (_, group_after_push) = env.market_state();
    let long_stale = env.portfolio_state(long_account);
    let short_stale = env.portfolio_state(short_account);
    assert_eq!(group_after_push.assets[1].effective_price, 105);
    assert!(
        health_cert(&long_stale).cert_oracle_epoch < group_after_push.oracle_epoch,
        "asset[1] mark push made the participating long portfolio cert stale"
    );
    assert!(
        health_cert(&short_stale).cert_oracle_epoch < group_after_push.oracle_epoch,
        "asset[1] mark push made the participating short portfolio cert stale"
    );
    assert_ne!(
        active_leg_for_asset(&long_stale, 1).k_snap,
        group_after_push.assets[1].k_long,
        "long asset[1] leg snapshot is stale before the asset[0] trade"
    );
    assert_ne!(
        active_leg_for_asset(&short_stale, 1).k_snap,
        group_after_push.assets[1].k_short,
        "short asset[1] leg snapshot is stale before the asset[0] trade"
    );

    let trade_cu = env.trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    println!("v16 TradeNoCpi refreshes stale related leg on-demand CU: {trade_cu}");
    assert_cu_within(
        "TradeNoCpi on-demand refresh of stale related leg",
        trade_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let (_, group_after_trade) = env.market_state();
    let long_after = env.portfolio_state(long_account);
    let short_after = env.portfolio_state(short_account);
    assert_eq!(
        health_cert(&long_after).cert_oracle_epoch,
        group_after_trade.oracle_epoch,
        "trade refreshed and re-certified the long account"
    );
    assert_eq!(
        health_cert(&short_after).cert_oracle_epoch,
        group_after_trade.oracle_epoch,
        "trade refreshed and re-certified the short account"
    );
    assert_eq!(
        active_leg_for_asset(&long_after, 1).k_snap,
        group_after_trade.assets[1].k_long,
        "trade settled the stale related long leg in-place"
    );
    assert_eq!(
        active_leg_for_asset(&short_after, 1).k_snap,
        group_after_trade.assets[1].k_short,
        "trade settled the stale related short leg in-place"
    );
    assert!(has_active_leg_for_asset(&long_after, 0));
    assert!(has_active_leg_for_asset(&short_after, 0));
    assert!(has_active_leg_for_asset(&long_after, 1));
    assert!(has_active_leg_for_asset(&short_after, 1));
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&long_after)),
        2
    );
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&short_after)),
        2
    );
}

#[test]
fn v16_bpf_tradecpi_refreshes_stale_traded_portfolio_leg_on_demand() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(1, 0, 100);
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(auth_matcher_program_path()).expect("read auth matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);

    let taker_owner = Keypair::new();
    let lp_owner = Keypair::new();
    let taker_account = env.create_portfolio(&taker_owner);
    let lp_account = env.create_portfolio(&lp_owner);
    env.deposit(&taker_owner, taker_account, 1_000_000_000);
    env.deposit(&lp_owner, lp_account, 1_000_000_000);
    let (ctx, delegate, _) = env.init_auth_matcher_context(matcher_program, &lp_owner, lp_account);

    let initial_size = (10 * POS_SCALE) as i128;
    env.trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker_account,
        &lp_owner,
        lp_account,
        matcher_program,
        ctx,
        delegate,
        1,
        initial_size,
        100,
    );

    let crank_long_owner = Keypair::new();
    let crank_short_owner = Keypair::new();
    let crank_long_account = env.create_portfolio(&crank_long_owner);
    let crank_short_account = env.create_portfolio(&crank_short_owner);
    env.deposit(&crank_long_owner, crank_long_account, 1_000_000_000);
    env.deposit(&crank_short_owner, crank_short_account, 1_000_000_000);
    env.trade_asset_with_cu(
        1,
        &crank_long_owner,
        crank_long_account,
        &crank_short_owner,
        crank_short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_auth_mark_for_asset_as_admin(1, 1, 105);
    env.crank(
        crank_long_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(1),
        },
    );

    let (_, group_after_mark) = env.market_state();
    let taker_stale = env.portfolio_state(taker_account);
    let lp_stale = env.portfolio_state(lp_account);
    assert_eq!(group_after_mark.assets[1].effective_price, 105);
    assert_eq!(
        group_after_mark.assets[1].slot_last, 1,
        "test setup must make the traded market asset fresh"
    );
    assert!(
        health_cert(&taker_stale).cert_oracle_epoch < group_after_mark.oracle_epoch,
        "mark crank made the taker's traded asset leg stale"
    );
    assert!(
        health_cert(&lp_stale).cert_oracle_epoch < group_after_mark.oracle_epoch,
        "mark crank made the LP's traded asset leg stale"
    );
    assert_ne!(
        active_leg_for_asset(&taker_stale, 1).k_snap,
        group_after_mark.assets[1].k_long,
        "taker traded leg snapshot is stale before TradeCpi"
    );
    assert_ne!(
        active_leg_for_asset(&lp_stale, 1).k_snap,
        group_after_mark.assets[1].k_short,
        "LP traded leg snapshot is stale before TradeCpi"
    );

    let trade_cu = env.trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker_account,
        &lp_owner,
        lp_account,
        matcher_program,
        ctx,
        delegate,
        1,
        POS_SCALE as i128,
        100,
    );
    println!("v16 TradeCpi refreshes stale traded leg on-demand CU: {trade_cu}");
    assert_cu_within(
        "TradeCpi on-demand refresh of stale traded leg",
        trade_cu,
        MULTI_ASSET_OPEN_TRADE_CU_LIMIT,
    );

    let (_, group_after_trade) = env.market_state();
    let taker_after = env.portfolio_state(taker_account);
    let lp_after = env.portfolio_state(lp_account);
    assert_eq!(
        health_cert(&taker_after).cert_oracle_epoch,
        group_after_trade.oracle_epoch,
        "TradeCpi refreshed and re-certified the taker"
    );
    assert_eq!(
        health_cert(&lp_after).cert_oracle_epoch,
        group_after_trade.oracle_epoch,
        "TradeCpi refreshed and re-certified the LP"
    );
    assert_eq!(
        active_leg_for_asset(&taker_after, 1).k_snap,
        group_after_trade.assets[1].k_long,
        "TradeCpi settled the stale traded taker leg"
    );
    assert_eq!(
        active_leg_for_asset(&lp_after, 1).k_snap,
        group_after_trade.assets[1].k_short,
        "TradeCpi settled the stale traded LP leg"
    );
    assert_eq!(
        active_leg_for_asset(&taker_after, 1).basis_pos_q,
        initial_size + POS_SCALE as i128,
        "TradeCpi increased the stale traded taker leg"
    );
    assert_eq!(
        active_leg_for_asset(&lp_after, 1).basis_pos_q,
        -(initial_size + POS_SCALE as i128),
        "TradeCpi increased the opposite stale traded LP leg"
    );
}

#[test]
fn v16_bpf_sync_maintenance_fee_with_cranker_share_is_bounded() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 58,
    );
    let payer_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let payer_portfolio = env.create_portfolio(&payer_owner);
    let cranker_portfolio = env.create_portfolio(&cranker_owner);
    env.deposit(&payer_owner, payer_portfolio, 100_000_000);
    env.update_maintenance_fee_policy_with_cu(4_000);

    env.svm.warp_to_slot(10);
    let sync_cu = env.sync_maintenance_fee_with_cu(payer_portfolio, Some(cranker_portfolio), 10);
    println!("v16 SyncMaintenanceFee 3-account cranker-share CU: {sync_cu}");
    assert!(
        sync_cu <= CUSTODY_CU_LIMIT,
        "3-account SyncMaintenanceFee CU {} exceeded limit {}",
        sync_cu,
        CUSTODY_CU_LIMIT
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let payer_data = env.svm.get_account(&payer_portfolio).unwrap().data;
    let cranker_data = env.svm.get_account(&cranker_portfolio).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let payer = state::read_portfolio(&payer_data).unwrap();
    let cranker = state::read_portfolio(&cranker_data).unwrap();
    assert_eq!(payer.last_fee_slot.get(), 10);
    assert_eq!(payer.capital.get(), 100_000_000 - 580);
    assert_eq!(cranker.capital.get(), 232);
    assert_eq!(group.insurance, 348);
    assert_domain_budget_remaining_total_consistent(&group, "maintenance fee with cranker share");
}

#[test]
fn v16_attack_sync_maintenance_bad_cranker_rolls_back_fee() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 58,
    );
    let payer_owner = Keypair::new();
    let payer_portfolio = env.create_portfolio(&payer_owner);
    env.deposit(&payer_owner, payer_portfolio, 100_000_000);
    env.update_maintenance_fee_policy_with_cu(4_000);

    let bad_cranker_portfolio = env.program_account(env.portfolio_account_len);
    let payer_before = env.svm.get_account(&payer_portfolio).unwrap().data;
    let market_before = env.svm.get_account(&env.market).unwrap().data;
    let bad_cranker_before = env.svm.get_account(&bad_cranker_portfolio).unwrap().data;

    env.svm.warp_to_slot(10);
    env.svm.expire_blockhash();
    let err = env
        .try_sync_maintenance_fee_with_cu(payer_portfolio, Some(bad_cranker_portfolio), 10)
        .expect_err("malformed cranker reward account must reject");
    assert!(
        err.contains("TransactionError") || err.contains("InstructionError"),
        "unexpected maintenance bad-cranker error: {err}"
    );

    assert_eq!(
        env.svm.get_account(&payer_portfolio).unwrap().data,
        payer_before,
        "failed cranker maintenance sync must not charge the payer"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        market_before,
        "failed cranker maintenance sync must not credit insurance or mutate market accounting"
    );
    assert_eq!(
        env.svm.get_account(&bad_cranker_portfolio).unwrap().data,
        bad_cranker_before,
        "failed cranker maintenance sync must not mutate the malformed reward account"
    );

    let cranker_owner = Keypair::new();
    let cranker_portfolio = env.create_portfolio(&cranker_owner);
    env.svm.expire_blockhash();
    env.sync_maintenance_fee_with_cu(payer_portfolio, Some(cranker_portfolio), 10);
    assert_eq!(env.portfolio_state(payer_portfolio).last_fee_slot.get(), 10);
    assert!(
        env.portfolio_state(cranker_portfolio).capital.get() > 0,
        "valid cranker reward path should still pay the cranker share"
    );
}

#[test]
fn v16_attack_sync_maintenance_rejects_cross_market_cranker_reward() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 58,
    );
    let payer_owner = Keypair::new();
    let payer_portfolio = env.create_portfolio(&payer_owner);
    env.deposit(&payer_owner, payer_portfolio, 100_000_000);
    env.update_maintenance_fee_policy_with_cu(4_000);

    let market_b = Pubkey::new_unique();
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&env.admin],
    )
    .expect("init market B");

    let foreign_cranker_owner = Keypair::new();
    env.ensure_signer_account(foreign_cranker_owner.pubkey());
    let foreign_cranker_portfolio = Pubkey::new_unique();
    env.svm
        .set_account(
            foreign_cranker_portfolio,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; env.portfolio_account_len],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(foreign_cranker_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(foreign_cranker_portfolio, false),
        ],
        &[&foreign_cranker_owner],
    )
    .expect("init foreign cranker portfolio on market B");

    let payer_before = env.svm.get_account(&payer_portfolio).unwrap().data;
    let market_a_before = env.svm.get_account(&env.market).unwrap().data;
    let market_b_before = env.svm.get_account(&market_b).unwrap().data;
    let foreign_before = env
        .svm
        .get_account(&foreign_cranker_portfolio)
        .unwrap()
        .data;

    env.svm.warp_to_slot(10);
    env.svm.expire_blockhash();
    let rejected = env
        .try_sync_maintenance_fee_with_cu(payer_portfolio, Some(foreign_cranker_portfolio), 10)
        .expect_err("foreign-market cranker reward account must reject");
    assert!(
        rejected.contains("TransactionError") || rejected.contains("InstructionError"),
        "unexpected cross-market cranker rejection: {rejected}"
    );
    assert_eq!(
        env.svm.get_account(&payer_portfolio).unwrap().data,
        payer_before,
        "cross-market reward rejection must not charge the payer"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        market_a_before,
        "cross-market reward rejection must not mutate market A"
    );
    assert_eq!(
        env.svm.get_account(&market_b).unwrap().data,
        market_b_before,
        "cross-market reward rejection must not mutate market B"
    );
    assert_eq!(
        env.svm
            .get_account(&foreign_cranker_portfolio)
            .unwrap()
            .data,
        foreign_before,
        "cross-market reward rejection must not credit the foreign portfolio"
    );

    let local_cranker_owner = Keypair::new();
    let local_cranker_portfolio = env.create_portfolio(&local_cranker_owner);
    env.svm.expire_blockhash();
    env.sync_maintenance_fee_with_cu(payer_portfolio, Some(local_cranker_portfolio), 10);
    assert_eq!(env.portfolio_state(payer_portfolio).last_fee_slot.get(), 10);
    assert!(
        env.portfolio_state(local_cranker_portfolio).capital.get() > 0,
        "same-market cranker still receives the reward"
    );
}

// Regression for #113 — permissionless cross-asset maintenance-fee siphon (FIXED).
// credit_maintenance_fee_to_active_market_budgets_view (v16_program 5298) previously split every
// maintenance fee equally across all ACTIVE assets' insurance domains with no positions/activity
// requirement, so a non-admin could append a do-nothing asset (itself as insurance_operator) and
// capture 1/N of every honest trader's maintenance fee, then withdraw it via WithdrawInsuranceAsset.
// The fix credits the account-level maintenance fee solely to asset-0 (the canonical base insurance,
// not permissionlessly creatable), so a parasitic zero-activity asset earns ZERO. This guards the fix.
#[test]
fn v16_attack_bug113_maintenance_fee_siphon_to_parasitic_asset() {
    // capacity 1 (asset-1 is appended at index == configured_slots, growing to 2), maintenance fee 58/slot.
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 58,
    );
    env.update_market_init_fee_policy_with_cu(1); // permissionless create enabled (nonzero fee)

    // Honest depositor H on the real market (asset 0).
    let h_owner = Keypair::new();
    let h = env.create_portfolio(&h_owner);
    env.deposit(&h_owner, h, 100_000_000);

    // Attacker permissionlessly appends a do-nothing asset 1 with ITSELF as insurance_operator.
    let attacker = Keypair::new();
    env.ensure_signer_account(attacker.pubkey());
    env.svm.warp_to_slot(1);
    env.activate_permissionless_asset_with_fee(
        &attacker,
        1,
        1,
        100,
        attacker.pubkey(),
        attacker.pubkey(),
        attacker.pubkey(),
        attacker.pubkey(),
        1,
    );
    let (_, g_pre) = env.market_state();
    assert_eq!(
        g_pre.assets[1].lifecycle,
        AssetLifecycleV16::Active,
        "parasite asset-1 active"
    );
    // asset-1 domains (2 = long, 3 = short) start empty: it has no positions and was never funded.
    assert_eq!(g_pre.insurance_domain_budget[2], 0);
    assert_eq!(g_pre.insurance_domain_budget[3], 0);

    // Charge H's maintenance fee (58 * 10 slots = 580).
    env.svm.warp_to_slot(10);
    let h_cap_before = env.portfolio_state(h).capital.get();
    env.svm.expire_blockhash();
    env.sync_maintenance_fee_with_cu(h, None, 10);
    let fee_paid = h_cap_before - env.portfolio_state(h).capital.get();
    assert!(
        fee_paid > 0,
        "H actually paid a maintenance fee (non-vacuous)"
    );

    // SECURITY PROPERTY: the parasitic zero-activity asset-1 must have captured NOTHING of H's fee.
    let (_, g) = env.market_state();
    let parasite_share = g.insurance_domain_budget[2] + g.insurance_domain_budget[3];
    assert_eq!(
        parasite_share, 0,
        "BUG #113: parasitic asset-1 captured {parasite_share} of H's {fee_paid} maintenance fee"
    );

    // Positive side of the fix: the whole retained fee (no cranker here) landed in ASSET-0's insurance
    // domains (0 = long, 1 = short), and the domain-budget aggregate stays consistent with group.insurance
    // (a desync here would be a "weird state" — engine fee charge + wrapper credit double-counting).
    let asset0_before = g_pre.insurance_domain_budget[0] + g_pre.insurance_domain_budget[1];
    let asset0_after = g.insurance_domain_budget[0] + g.insurance_domain_budget[1];
    assert_eq!(
        asset0_after - asset0_before,
        fee_paid,
        "the full retained maintenance fee must land in asset-0 insurance"
    );
    assert_domain_budget_remaining_total_consistent(
        &g,
        "after #113-fix maintenance fee to asset-0",
    );

    // And the attacker must not be able to withdraw any of it as that asset's insurance_operator.
    env.svm.expire_blockhash();
    let siphon = env.try_withdraw_insurance_asset_with_authority(&attacker, 1, 1);
    assert!(
        siphon.is_err(),
        "BUG #113: attacker siphoned honest maintenance fees via WithdrawInsuranceAsset(asset 1)"
    );
}

#[test]
fn v16_bpf_underfunded_flat_sync_sweeps_remaining_capital_once() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 40,
    );
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_portfolio = env.create_portfolio(&long_owner);
    let short_portfolio = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_portfolio, 1);
    env.deposit(&short_owner, short_portfolio, 10_000);

    env.svm.warp_to_slot(10);
    let market_lamports_before_close = env.svm.get_account(&env.market).unwrap().lamports;
    let long_lamports_before_close = env.svm.get_account(&long_portfolio).unwrap().lamports;
    env.sync_maintenance_fee_with_cu(long_portfolio, None, 10);
    let (_, group_after_flat_sync) = env.market_state();
    assert_eq!(
        group_after_flat_sync.insurance, 1,
        "underfunded flat sync sweeps the remaining capital into insurance"
    );
    assert_eq!(group_after_flat_sync.materialized_portfolio_count, 1);
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().lamports,
        market_lamports_before_close + long_lamports_before_close,
        "dust-closed portfolio rent should move into the market slab"
    );
    if let Some(closed_long_account) = env.svm.get_account(&long_portfolio) {
        assert_eq!(closed_long_account.lamports, 0);
        assert!(
            closed_long_account.data.is_empty()
                || !state::is_initialized(&closed_long_account.data)
        );
    }

    let fresh_long_portfolio = env.create_portfolio(&long_owner);
    env.deposit(&long_owner, fresh_long_portfolio, 1_000);
    env.trade_with_cu(
        &long_owner,
        fresh_long_portfolio,
        &short_owner,
        short_portfolio,
        POS_SCALE as i128,
        100,
        0,
    );
    env.crank(
        fresh_long_portfolio,
        ProgInstruction::PermissionlessCrank {
            now_slot: 10,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let (_, before_nonflat_sync) = env.market_state();
    assert_eq!(before_nonflat_sync.assets[0].slot_last, 1);
    let insurance_before_nonflat_sync = before_nonflat_sync.insurance;

    let fresh_long_lamports_before_sync =
        env.svm.get_account(&fresh_long_portfolio).unwrap().lamports;
    env.sync_maintenance_fee_with_cu(fresh_long_portfolio, None, 11);
    let (_, group_after_nonflat_sync) = env.market_state();
    let long_after_nonflat_sync = env.portfolio_state(fresh_long_portfolio);
    assert_eq!(long_after_nonflat_sync.capital.get(), 1_000);
    assert_eq!(long_after_nonflat_sync.last_fee_slot.get(), 10);
    assert_eq!(
        env.svm
            .get_account(&fresh_long_portfolio)
            .expect("non-flat portfolio should remain allocated")
            .lamports,
        fresh_long_lamports_before_sync
    );
    assert_eq!(
        group_after_nonflat_sync.insurance, insurance_before_nonflat_sync,
        "later deposits are not charged for an already-swept empty interval"
    );
}

// LoF/DoS sweep: permissionless SyncMaintenanceFee can drain a dust portfolio to zero and then
// dematerialize it via the shared rent-sweep helper. A late rent overflow must roll back the fee
// charge, market insurance credit, materialized-count decrement, and portfolio close.
#[test]
fn v16_attack_sync_maintenance_late_lamport_overflow_rolls_back_fee_close() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 40,
    );
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1);
    env.svm.warp_to_slot(10);

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    assert_eq!(
        env.portfolio_state(portfolio).capital.get(),
        1,
        "dust portfolio has one atom before maintenance sync"
    );
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "dust portfolio is materialized before maintenance sync"
    );

    let mut saturated_market = market_before.clone();
    saturated_market.lamports = u64::MAX;
    env.svm
        .set_account(env.market, saturated_market.clone())
        .unwrap();
    let saturated_before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.try_sync_maintenance_fee_with_cu(portfolio, None, 10);
    assert!(
        rejected.is_err(),
        "SyncMaintenanceFee must reject when the dust-close rent sweep overflows"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        saturated_before,
        "overflow rejection must roll back market fee credit and materialized count"
    );
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "overflow rejection must not dematerialize the dust portfolio"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "overflow rejection must not debit or close the dust portfolio"
    );

    env.svm.set_account(env.market, market_before).unwrap();
    env.svm.expire_blockhash();
    let ok_cu = env.sync_maintenance_fee_with_cu(portfolio, None, 10);
    assert_cu_within(
        "SyncMaintenanceFee late-lamport-overflow retry",
        ok_cu,
        CUSTODY_CU_LIMIT,
    );
    let (_, group_after) = env.market_state();
    assert_eq!(group_after.insurance, 1);
    assert_eq!(group_after.materialized_portfolio_count, 0);
    let closed = env.svm.get_account(&portfolio).unwrap();
    assert_eq!(closed.lamports, 0);
    assert!(closed.data.is_empty() || !state::is_initialized(&closed.data));
}

#[test]
fn v16_attack_underfunded_sync_with_cranker_reward_still_closes_payer() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 40,
    );
    env.update_maintenance_fee_policy_with_cu(5_000);
    let payer_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let payer_portfolio = env.create_portfolio(&payer_owner);
    let cranker_portfolio = env.create_portfolio(&cranker_owner);
    env.deposit(&payer_owner, payer_portfolio, 3);

    env.svm.warp_to_slot(10);
    let market_lamports_before_close = env.svm.get_account(&env.market).unwrap().lamports;
    let payer_lamports_before_close = env.svm.get_account(&payer_portfolio).unwrap().lamports;
    let cranker_cap_before = env.portfolio_state(cranker_portfolio).capital.get();
    let sync_cu = env.sync_maintenance_fee_with_cu(payer_portfolio, Some(cranker_portfolio), 10);
    println!("v16 underfunded SyncMaintenanceFee with cranker reward CU: {sync_cu}");
    assert_cu_within(
        "underfunded SyncMaintenanceFee with cranker reward",
        sync_cu,
        CUSTODY_CU_LIMIT,
    );

    let (_, group_after_sync) = env.market_state();
    assert_eq!(
        group_after_sync.insurance, 2,
        "underfunded sync retains the non-cranker share in insurance"
    );
    assert_eq!(
        env.portfolio_state(cranker_portfolio).capital.get(),
        cranker_cap_before + 1,
        "cranker receives only the configured share of the swept dust fee"
    );
    assert_eq!(
        group_after_sync.materialized_portfolio_count, 1,
        "dust payer is still closed even when a cranker reward is paid"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().lamports,
        market_lamports_before_close + payer_lamports_before_close,
        "dust-closed payer rent moves into the market slab"
    );
    if let Some(closed_payer_account) = env.svm.get_account(&payer_portfolio) {
        assert_eq!(closed_payer_account.lamports, 0);
        assert!(
            closed_payer_account.data.is_empty()
                || !state::is_initialized(&closed_payer_account.data)
        );
    }
}

#[test]
fn v16_bpf_nonflat_fee_sync_settles_hidden_loss_before_sweeping_fee() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 100,
    );
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_portfolio = env.create_portfolio(&long_owner);
    let short_portfolio = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_portfolio, 100);
    env.deposit(&short_owner, short_portfolio, 1_000);
    env.trade_with_cu(
        &long_owner,
        long_portfolio,
        &short_owner,
        short_portfolio,
        POS_SCALE as i128,
        100,
        0,
    );

    let long_before_move = env.portfolio_state(long_portfolio);
    assert_eq!(long_before_move.capital.get(), 100);
    assert_eq!(long_before_move.pnl.get(), 0);

    env.mutate_market(|_, group| {
        group.accrue_asset_to_not_atomic(0, 1, 50, 0, true).unwrap();
        group.assets[0].raw_oracle_target_price = 50;
    });
    env.svm.warp_to_slot(1);

    let long_with_hidden_loss = env.portfolio_state(long_portfolio);
    assert_eq!(
        long_with_hidden_loss.capital.get(),
        100,
        "the price move should be hidden until the account is touched"
    );
    assert_eq!(long_with_hidden_loss.pnl.get(), 0);
    let (_, group_with_hidden_loss) = env.market_state();
    assert_eq!(group_with_hidden_loss.insurance, 0);
    assert_eq!(group_with_hidden_loss.c_tot, 1_100);

    let sync_cu = env.sync_maintenance_fee_with_cu(long_portfolio, None, 1);
    println!("v16 SyncMaintenanceFee nonflat hidden-loss CU: {sync_cu}");
    assert_cu_within(
        "SyncMaintenanceFee nonflat hidden-loss regression",
        sync_cu,
        CUSTODY_CU_LIMIT,
    );

    let long_after_sync = env.portfolio_state(long_portfolio);
    let (_, group_after_sync) = env.market_state();
    assert_eq!(long_after_sync.capital.get(), 0);
    assert_eq!(long_after_sync.pnl.get(), 0);
    assert_eq!(long_after_sync.last_fee_slot.get(), 1);
    assert_eq!(
        group_after_sync.insurance, 50,
        "only capital remaining after the hidden loss is settled can be swept as fee"
    );
    assert_eq!(group_after_sync.c_tot, 1_000);
}

#[test]
fn v16_bpf_fee_sync_rejects_reused_market_slot_stale_leg_without_mutation() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 1,
    );
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_portfolio = env.create_portfolio(&long_owner);
    let short_portfolio = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_portfolio, 1_000);
    env.deposit(&short_owner, short_portfolio, 1_000);
    env.trade_with_cu(
        &long_owner,
        long_portfolio,
        &short_owner,
        short_portfolio,
        POS_SCALE as i128,
        100,
        0,
    );

    let old_market_id = env.market_state().1.assets[0].market_id;
    env.mutate_market(|_, group| {
        group
            .accrue_asset_to_not_atomic(0, 1, 100, 0, true)
            .unwrap();
        group.assets[0].market_id = old_market_id + 1;
        group.next_market_id = group.next_market_id.max(old_market_id + 2);
    });
    env.svm.warp_to_slot(1);

    let market_before = env.svm.get_account(&env.market).unwrap().data;
    let long_before = env.svm.get_account(&long_portfolio).unwrap().data;
    let err = env
        .try_sync_maintenance_fee_with_cu(long_portfolio, None, 1)
        .expect_err("stale market id leg must fail closed");
    println!("v16 SyncMaintenanceFee stale reused-market-id rejection: {err}");

    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        market_before,
        "failed sync must not mutate the reused market slot"
    );
    assert_eq!(
        env.svm.get_account(&long_portfolio).unwrap().data,
        long_before,
        "failed sync must not mutate the stale portfolio"
    );
}

#[test]
fn v16_bpf_close_portfolio_sweeps_rent_to_market_slab() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.withdraw(&owner, portfolio, 1_000);

    let market_lamports_before_close = env.svm.get_account(&env.market).unwrap().lamports;
    let portfolio_lamports_before_close = env.svm.get_account(&portfolio).unwrap().lamports;
    let close_cu = env.close_portfolio_with_cu(&owner, portfolio);
    assert_cu_within("close portfolio rent sweep", close_cu, CUSTODY_CU_LIMIT);

    let (_, group) = env.market_state();
    assert_eq!(group.materialized_portfolio_count, 0);
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().lamports,
        market_lamports_before_close + portfolio_lamports_before_close,
        "ClosePortfolio should move closed account rent into the market slab"
    );
    if let Some(closed_account) = env.svm.get_account(&portfolio) {
        assert_eq!(closed_account.lamports, 0);
        assert!(closed_account.data.is_empty() || !state::is_initialized(&closed_account.data));
    }
}

// LoF/DoS sweep: ClosePortfolio deregisters the empty portfolio before sweeping its rent into the
// market slab. If the final lamport add overflows, SVM rollback must preserve the materialized count
// and leave the user's portfolio closeable once the slab can receive rent again.
#[test]
fn v16_attack_close_portfolio_late_lamport_overflow_rolls_back_deregister() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "fresh empty portfolio is materialized before close"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    assert!(
        portfolio_before.lamports != 0,
        "test requires rent to sweep from the portfolio"
    );

    let mut saturated_market = market_before.clone();
    saturated_market.lamports = u64::MAX;
    env.svm
        .set_account(env.market, saturated_market.clone())
        .unwrap();
    let saturated_before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::ClosePortfolio,
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
        ],
        &[&owner],
    );
    assert!(
        rejected.is_err(),
        "ClosePortfolio must reject when the final rent sweep overflows"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        saturated_before,
        "overflow rejection must roll back market lamports and materialized count"
    );
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "overflow rejection must not deregister the closeable portfolio"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "overflow rejection must not zero or drain the portfolio account"
    );

    env.svm.set_account(env.market, market_before).unwrap();
    env.svm.expire_blockhash();
    let ok_cu = env.close_portfolio_with_cu(&owner, portfolio);
    assert_cu_within(
        "ClosePortfolio late-lamport-overflow retry",
        ok_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        0,
        "same portfolio remains closeable after the overflow rejection"
    );
    let closed = env.svm.get_account(&portfolio).unwrap();
    assert_eq!(closed.lamports, 0);
    assert!(closed.data.is_empty() || !state::is_initialized(&closed.data));
}

#[test]
fn v16_attack_non_owner_cannot_close_flat_portfolio() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "portfolio is materialized before the close attempt"
    );

    env.svm.expire_blockhash();
    let bad_close = env.send(
        ProgInstruction::ClosePortfolio,
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
        ],
        &[&mallory],
    );
    assert!(
        bad_close.is_err(),
        "a non-owner must not be able to dematerialize a flat victim portfolio"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "non-owner close must not decrement counters or receive rent into the market slab"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "non-owner close must leave the victim portfolio account intact"
    );

    env.close_portfolio_with_cu(&owner, portfolio);
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        0,
        "the real owner can still close the flat portfolio"
    );
}

// security.md sweep - ClosePortfolio legacy realloc rollback (#6/#44/#48):
// ClosePortfolio grows legacy portfolio accounts before checking whether the
// signer owns the portfolio. A hostile signer must not be able to leave a
// victim's legacy account expanded/zero-filled, move rent, or decrement the
// materialized portfolio count before the owner check rejects.
#[test]
fn v16_attack_non_owner_close_rolls_back_legacy_realloc() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    let mut legacy = env.svm.get_account(&portfolio).unwrap();
    legacy.data.truncate(PORTFOLIO_ENGINE_ACCOUNT_LEN);
    env.svm.set_account(portfolio, legacy).unwrap();
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "test setup simulates a legacy initialized portfolio without the matcher tail"
    );

    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "legacy victim portfolio is materialized before the close attempt"
    );

    env.svm.expire_blockhash();
    let bad_close = env.send(
        ProgInstruction::ClosePortfolio,
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
        ],
        &[&mallory],
    );
    assert!(
        bad_close.is_err(),
        "non-owner close of a legacy victim portfolio must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected legacy close must not move rent or decrement materialized count"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "rejected legacy close rolls back the pre-auth realloc and zero-fill"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "failed close does not leave a public legacy realloc behind"
    );

    let close_cu = env.close_portfolio_with_cu(&owner, portfolio);
    assert_cu_within(
        "ClosePortfolio legacy owner retry",
        close_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        0,
        "the real owner can still close after the rejected legacy realloc attempt"
    );
}

#[test]
fn v16_attack_close_portfolio_rejects_occupied_source_domain_without_claim_bound() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    let market_id = env.market_state().1.assets[0].market_id;

    let mut portfolio_account = env.svm.get_account(&portfolio).unwrap();
    let (_, _, max_market_slots, _) = state::read_market_config_mode_and_capacity(
        &env.svm.get_account(&env.market).unwrap().data,
    )
    .unwrap();
    {
        let view = state::portfolio_view_mut_for_market_slots(
            &mut portfolio_account.data,
            max_market_slots,
        )
        .unwrap();
        view.header.source_domains[0].domain = percolator::V16PodU32::new(0);
        view.header.source_domains[0].source_claim_market_id =
            percolator::V16PodU64::new(market_id);
        view.header.source_domains[0].source_lien_capital_at_risk_fee_revenue =
            percolator::V16PodU128::new(7);
        assert_eq!(
            view.header.source_domains[0].source_claim_bound_num.get(),
            0,
            "test precondition: old wrapper close check only inspected claim bound"
        );
    }
    env.svm.set_account(portfolio, portfolio_account).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    assert_eq!(env.market_state().1.materialized_portfolio_count, 1);

    env.svm.expire_blockhash();
    let close = env.send(
        ProgInstruction::ClosePortfolio,
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
        ],
        &[&owner],
    );
    assert!(
        close.is_err(),
        "ClosePortfolio must use engine dematerialization emptiness, not wrapper-local claim-bound checks"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected close must not decrement materialized_portfolio_count or collect rent"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "rejected close must leave the occupied source-domain state intact"
    );
}

#[test]
fn v16_bpf_tradecpi_executes_through_external_matcher_and_is_bounded() {
    let mut env = V16CuEnv::new();
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);

    let taker_owner = Keypair::new();
    let maker_owner = Keypair::new();
    let taker_account = env.create_portfolio(&taker_owner);
    let maker_account = env.create_portfolio(&maker_owner);
    env.deposit(&taker_owner, taker_account, 1_000_000);
    env.deposit(&maker_owner, maker_account, 1_000_000);

    let (matcher_ctx, matcher_delegate, init_matcher_cu) =
        env.init_matcher_context_authorized(matcher_program, &maker_owner, maker_account);
    let trade_cpi_cu = env.trade_cpi_with_cu(
        &taker_owner,
        taker_account,
        &maker_owner,
        maker_account,
        matcher_program,
        matcher_ctx,
        matcher_delegate,
        (10 * POS_SCALE) as i128,
        100,
    );
    println!("v16 matcher init CU: {init_matcher_cu}, TradeCpi BPF CU: {trade_cpi_cu}");
    assert!(
        trade_cpi_cu <= TRADE_CU_LIMIT,
        "TradeCpi CU {} exceeded limit {}",
        trade_cpi_cu,
        TRADE_CU_LIMIT
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let taker_data = env.svm.get_account(&taker_account).unwrap().data;
    let maker_data = env.svm.get_account(&maker_account).unwrap().data;
    let matcher_data = env.svm.get_account(&matcher_ctx).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let taker = state::read_portfolio(&taker_data).unwrap();
    let maker = state::read_portfolio(&maker_data).unwrap();
    println!(
        "TradeCpi BPF taker_basis={}, maker_basis={}, insurance={}",
        taker.legs[0].basis_pos_q.get(),
        maker.legs[0].basis_pos_q.get(),
        group.insurance
    );
    assert_eq!(group.assets[0].effective_price, 100);
    assert_eq!(taker.legs[0].basis_pos_q.get(), (10 * POS_SCALE) as i128);
    assert_eq!(maker.legs[0].basis_pos_q.get(), -((10 * POS_SCALE) as i128));
    assert_eq!(
        group.insurance, 20,
        "passive matcher fills at oracle price; 100 bps charges 10 to each side"
    );
    assert_eq!(
        u32::from_le_bytes(matcher_data[0..4].try_into().unwrap()),
        MATCHER_ABI_VERSION,
        "LiteSVM matcher path must use the same ABI version as the wrapper"
    );
    assert_eq!(
        u64::from_le_bytes(matcher_data[56..64].try_into().unwrap()),
        0,
        "matcher must echo the requested asset index in the v3 return slot"
    );
    assert_eq!(group.c_tot + group.insurance, group.vault);
}

#[test]
fn v16_bpf_tradecpi_external_matcher_executes_on_added_asset() {
    let mut env = V16CuEnv::new();
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    env.activate_asset(1, 1, 100);
    env.activate_asset(2, 2, 250);

    let taker_owner = Keypair::new();
    let maker_owner = Keypair::new();
    let taker_account = env.create_portfolio(&taker_owner);
    let maker_account = env.create_portfolio(&maker_owner);
    env.deposit(&taker_owner, taker_account, 1_000_000);
    env.deposit(&maker_owner, maker_account, 1_000_000);

    let (matcher_ctx, matcher_delegate, _) =
        env.init_matcher_context_authorized(matcher_program, &maker_owner, maker_account);
    let trade_cpi_cu = env.trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker_account,
        &maker_owner,
        maker_account,
        matcher_program,
        matcher_ctx,
        matcher_delegate,
        2,
        (10 * POS_SCALE) as i128,
        100,
    );
    println!("v16 TradeCpi BPF nonzero-asset CU: {trade_cpi_cu}");
    assert!(
        trade_cpi_cu <= TRADE_CU_LIMIT,
        "TradeCpi nonzero-asset CU {} exceeded limit {}",
        trade_cpi_cu,
        TRADE_CU_LIMIT
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let taker_data = env.svm.get_account(&taker_account).unwrap().data;
    let maker_data = env.svm.get_account(&maker_account).unwrap().data;
    let matcher_data = env.svm.get_account(&matcher_ctx).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let taker = state::read_portfolio(&taker_data).unwrap();
    let maker = state::read_portfolio(&maker_data).unwrap();

    assert_eq!(group.assets[0].oi_eff_long_q, 0);
    assert_eq!(group.assets[0].oi_eff_short_q, 0);
    assert_eq!(group.assets[2].effective_price, 250);
    assert_eq!(group.assets[2].oi_eff_long_q, 10 * POS_SCALE);
    assert_eq!(group.assets[2].oi_eff_short_q, 10 * POS_SCALE);
    assert_eq!(active_bitmap(&taker), active_bitmap_with(&[0]));
    assert_eq!(active_bitmap(&maker), active_bitmap_with(&[0]));
    assert_eq!(
        active_leg_for_asset(&taker, 2).basis_pos_q,
        (10 * POS_SCALE) as i128
    );
    assert_eq!(
        active_leg_for_asset(&maker, 2).basis_pos_q,
        -((10 * POS_SCALE) as i128)
    );
    assert_eq!(
        group.insurance, 50,
        "passive matcher fills asset 2 at 250; notional=2500 and 100 bps charges 25 to each side"
    );
    assert_eq!(
        u64::from_le_bytes(matcher_data[56..64].try_into().unwrap()),
        2,
        "external matcher must echo the requested nonzero asset index"
    );
    assert_eq!(group.c_tot + group.insurance, group.vault);
}

#[test]
fn v16_bpf_permissionless_liquidation_is_bounded() {
    let mut env = V16CuEnv::new();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 250);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, 300);
    let liquidation_cu = env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    println!("v16 liquidation crank CU: {liquidation_cu}");
    assert!(
        liquidation_cu <= CRANK_CU_LIMIT,
        "liquidation CU {} exceeded limit {}",
        liquidation_cu,
        CRANK_CU_LIMIT
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let short_data = env.svm.get_account(&short_account).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let short = state::read_portfolio(&short_data).unwrap();
    assert_eq!(group.slot_last, 1);
    assert_eq!(group.assets[0].effective_price, 200);
    assert!(percolator::active_bitmap_is_empty(active_bitmap(&short)));
}

#[test]
fn v16_attack_zero_work_liquidation_does_not_report_successful_noop() {
    let mut env = V16CuEnv::new();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 250);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, 300);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert!(
        health_cert(&env.portfolio_state(short_account)).certified_liq_deficit != 0,
        "first crank should refresh the short into a fresh liquidatable state"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let short_before = env.svm.get_account(&short_account).unwrap();
    env.svm.expire_blockhash();
    let zero_work = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
        ],
        &[],
    );
    assert!(
        zero_work.is_err(),
        "liquidation selected with zero close_q must reject, not report a successful no-op"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "zero-work liquidation rejection must not mutate market state"
    );
    assert_eq!(
        env.svm.get_account(&short_account).unwrap(),
        short_before,
        "zero-work liquidation rejection must not mutate the liquidatable portfolio"
    );

    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    assert!(percolator::active_bitmap_is_empty(active_bitmap(
        &env.portfolio_state(short_account)
    )));
}

#[test]
fn v16_bpf_tradenocpi_rejects_off_mark_recycle_when_deficit_cannot_settle() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, 100);

    let extractor_owner = Keypair::new();
    let probe_owner = Keypair::new();
    let extractor = env.create_portfolio(&extractor_owner);
    let probe = env.create_portfolio(&probe_owner);
    env.deposit(&extractor_owner, extractor, 10_000);
    env.deposit(&probe_owner, probe, 1_000);
    env.trade_with_cu(
        &extractor_owner,
        extractor,
        &probe_owner,
        probe,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, 300);
    env.crank(
        probe,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    env.svm.warp_to_slot(3);
    env.crank(
        probe,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let before_market = env.svm.get_account(&env.market).unwrap();
    let before_extractor = env.svm.get_account(&extractor).unwrap();
    let before_probe = env.svm.get_account(&probe).unwrap();
    let (_, before_group) = state::read_market(&before_market.data).unwrap();
    assert_eq!(before_group.insurance, 1_000_000);
    let before_probe_state = state::read_portfolio(&before_probe.data).unwrap();
    assert!(
        health_cert(&before_probe_state).certified_liq_deficit != 0,
        "probe must be liquidatable before the attempted recycling trade"
    );

    let close = env.try_trade_asset_with_cu(
        0,
        &extractor_owner,
        extractor,
        &probe_owner,
        probe,
        -((10 * POS_SCALE) as i128),
        500,
        0,
    );
    assert!(
        close.is_err(),
        "liquidatable probe must not recycle an unsettled deficit through an off-mark close"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_market.data
    );
    assert_eq!(
        env.svm.get_account(&extractor).unwrap().data,
        before_extractor.data
    );
    assert_eq!(env.svm.get_account(&probe).unwrap().data, before_probe.data);
}

