#[test]
fn v16_bpf_tradenocpi_allows_both_counterparties_with_capitalized_losses_to_risk_reduce() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 10_000);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );
    env.force_portfolio_loss_for_security_test(long_account, 500);
    env.force_portfolio_loss_for_security_test(short_account, 500);

    let (_, before_group) = env.market_state();
    let before_long = env.portfolio_state(long_account);
    let before_short = env.portfolio_state(short_account);
    assert!(
        before_long.pnl.get() < 0
            && before_long.capital.get() > before_long.pnl.get().unsigned_abs()
    );
    assert!(
        before_short.pnl.get() < 0
            && before_short.capital.get() > before_short.pnl.get().unsigned_abs()
    );

    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        -((10 * POS_SCALE) as i128),
        100,
        0,
    );

    let (_, after_group) = env.market_state();
    let after_long = env.portfolio_state(long_account);
    let after_short = env.portfolio_state(short_account);
    assert_eq!(
        after_group.insurance, before_group.insurance,
        "capitalized losses must settle from account capital, not insurance"
    );
    assert_eq!(after_long.pnl.get(), 0);
    assert_eq!(after_short.pnl.get(), 0);
    assert!(!has_active_leg_for_asset(&after_long, 0));
    assert!(!has_active_leg_for_asset(&after_short, 0));
}

#[test]
fn v16_bpf_liquidatable_solvent_account_can_risk_reduce_without_insurance_drain() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, 100);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 3_000);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, 300);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    env.svm.warp_to_slot(3);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
    );

    let (_, before_group) = env.market_state();
    let before_short = env.portfolio_state(short_account);
    assert_eq!(before_group.insurance, 1_000_000);
    assert!(
        health_cert(&before_short).certified_liq_deficit != 0,
        "short account should be liquidatable before the safe risk reduction"
    );
    assert!(
        health_cert(&before_short).certified_equity > 0,
        "short account should still be solvent before the safe risk reduction"
    );

    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        -((10 * POS_SCALE) as i128),
        500,
        0,
    );

    let (_, after_group) = env.market_state();
    let after_long = env.portfolio_state(long_account);
    let after_short = env.portfolio_state(short_account);
    assert_eq!(
        after_group.insurance, before_group.insurance,
        "safe risk reduction must not consume or credit insurance"
    );
    assert_eq!(
        after_group.c_tot + after_group.insurance + after_group.pnl_pos_tot,
        after_group.vault
    );
    assert!(!has_active_leg_for_asset(&after_long, 0));
    assert!(!has_active_leg_for_asset(&after_short, 0));
    assert!(
        health_cert(&after_long).certified_liq_deficit == 0
            && health_cert(&after_short).certified_liq_deficit == 0,
        "both accounts must be non-liquidatable after the risk reduction"
    );
}

// Public auto-crank liveness sweep: helper-driven liquidation tests retry when close_q != 0, which can
// hide whether a current liquidatable account makes progress in one public instruction. Start from a
// solvent but under-margin account with a current health cert, then submit one bounded liquidation step
// without observations. The instruction must execute and close no more than the keeper's work budget.
#[test]
fn v16_attack_auto_crank_current_solvent_partial_liquidation_makes_progress() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, 100);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 3_000);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, 300);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    env.svm.warp_to_slot(3);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
    );

    let before_group = env.market_state().1;
    let before_short = env.portfolio_state(short_account);
    let before_cert = health_cert(&before_short);
    assert!(
        before_cert.certified_liq_deficit != 0 && before_cert.certified_equity > 0,
        "setup must be solvent but liquidatable before partial liquidation: {before_cert:?}"
    );
    let oi_pre = before_group.assets[0].oi_eff_short_q;

    env.svm.expire_blockhash();
    let partial = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: POS_SCALE,
            observations: vec![],
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
        ],
        &[],
    );
    assert!(
        partial.is_ok(),
        "current solvent liquidation must not require observations to make progress: {partial:?}"
    );

    let after_group = env.market_state().1;
    let after_short = env.portfolio_state(short_account);
    let closed = oi_pre.saturating_sub(after_group.assets[0].oi_eff_short_q);
    assert!(closed > 0, "partial liquidation must reduce open interest");
    assert!(
        closed <= POS_SCALE,
        "partial liquidation closed at most close_q: closed={closed}"
    );
    assert!(
        has_active_leg_for_asset(&after_short, 0),
        "partial close should leave the remaining position active"
    );
    assert_eq!(
        after_group.vault, before_group.vault,
        "liquidation fee is internal accounting, not a vault mint"
    );
    assert_eq!(after_group.vault as u64, env.token_amount(env.vault));
    assert!(after_group.vault >= after_group.c_tot + after_group.insurance);
}

#[test]
fn v16_attack_stale_resolve_matured_no_observation_liquidation_rejects() {
    let mut env = V16CuEnv::new();
    env.configure_permissionless_resolve_with_cu(5, 5);
    env.top_up_insurance(1_000_000);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, 100);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 3_000);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, 300);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    env.svm.warp_to_slot(3);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert!(
        health_cert(&env.portfolio_state(short_account)).certified_liq_deficit != 0,
        "setup must be liquidatable before stale-window probe"
    );

    env.svm.warp_to_slot(40);
    let before_market = env.svm.get_account(&env.market).unwrap();
    let before_short = env.svm.get_account(&short_account).unwrap();
    env.svm.expire_blockhash();
    let result = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 40,
            close_q: POS_SCALE,
            observations: vec![],
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
        ],
        &[],
    );
    let err = result
        .expect_err("stale-window no-observation liquidation must reject before live mutation");
    assert!(
        err.contains("Custom(27)") || err.contains("custom program error: 0x1b"),
        "stale-window no-observation liquidation should fail as OracleStale, got: {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before_market,
        "rejected stale-window liquidation leaves market state unchanged"
    );
    assert_eq!(
        env.svm.get_account(&short_account).unwrap(),
        before_short,
        "rejected stale-window liquidation leaves target portfolio unchanged"
    );

    env.svm.expire_blockhash();
    let resolve = env.send(
        ProgInstruction::ResolveStalePermissionless { now_slot: 0 },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        resolve.is_ok(),
        "permissionless stale resolve remains available after rejected liquidation: {resolve:?}"
    );
    assert_eq!(env.market_state().1.mode, MarketModeV16::Resolved);
}

#[test]
fn v16_attack_stale_resolve_matured_b_stale_cleanup_still_progresses() {
    let mut env = V16CuEnv::new();
    env.configure_permissionless_resolve_with_cu(5, 5);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 10_000);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    env.mark_b_stale_gap(long_account, 0, 1);
    assert!(
        env.portfolio_state(long_account).b_stale_state != 0,
        "setup must leave a B-stale account that blocks final cleanup"
    );

    env.svm.warp_to_slot(40);
    env.svm.expire_blockhash();
    let settle = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 40,
            close_q: 0,
            observations: vec![],
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(long_account, false),
        ],
        &[],
    );
    assert!(
        settle.is_ok(),
        "stale boundary must still allow B-stale cleanup required for resolution: {settle:?}"
    );
    assert_eq!(
        env.portfolio_state(long_account).b_stale_state,
        0,
        "B-stale cleanup clears the account blocker"
    );

    env.svm.expire_blockhash();
    let resolve = env.send(
        ProgInstruction::ResolveStalePermissionless { now_slot: 0 },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        resolve.is_ok(),
        "permissionless stale resolve remains available after B cleanup: {resolve:?}"
    );
    assert_eq!(env.market_state().1.mode, MarketModeV16::Resolved);
}

// Public auto-crank ordering sweep: a stale budgeted liquidation tx may land after
// the account's selected step has changed to a committed-state refresh. In that
// case the tx may make refresh progress and apply a valid unrelated oracle update,
// but it must not liquidate or pay a cranker reward for work it did not perform.
#[test]
fn v16_attack_budgeted_out_of_order_crank_refreshes_without_unearned_reward() {
    const MARK: u64 = 1_000_000;
    const OPEN_SLOT: u64 = 1;
    const OBS_SLOT: u64 = 2;

    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.activate_asset(1, OPEN_SLOT, MARK);

    set_test_clock(&mut env, OPEN_SLOT, 100);
    let feed0 = [0x37u8; 32];
    let initial0 = env.set_pyth_price_with_conf(&feed0, MARK as i64, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed0, [0u8; 32], [0u8; 32]],
        &[initial0],
        OPEN_SLOT,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure unrelated asset-0 hybrid oracle");
    env.configure_auth_mark_for_asset_as_admin(1, OPEN_SLOT, MARK);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let long = env.create_portfolio(&long_owner);
    let short = env.create_portfolio(&short_owner);
    let cranker = env.create_portfolio(&cranker_owner);
    env.deposit(&long_owner, long, 100_000_000);
    env.deposit(&short_owner, short, 100_000_000);
    env.deposit(&cranker_owner, cranker, 1_000);
    env.trade_asset_with_cu(
        1,
        &long_owner,
        long,
        &short_owner,
        short,
        POS_SCALE as i128,
        MARK,
        0,
    );

    set_test_clock(&mut env, OBS_SLOT, 101);
    env.push_auth_mark_for_asset_as_admin(1, OBS_SLOT, MARK + 10_000);
    env.crank(
        long,
        ProgInstruction::PermissionlessCrank {
            now_slot: OBS_SLOT,
            close_q: 0,
            observations: crank_observations(1),
        },
    );
    let (_, group_after_asset1) = env.market_state();
    assert!(
        health_cert(&env.portfolio_state(short)).cert_oracle_epoch
            < group_after_asset1.oracle_epoch,
        "setup must leave the target account stale on its active asset"
    );

    let fresh0 = env.set_pyth_price_with_conf(&feed0, (MARK + 10_000) as i64, -6, 0, 101);
    let (_, group_before) = env.market_state();
    let short_before = env.portfolio_state(short);
    let short_oi_before = group_before.assets[1].oi_eff_short_q;
    let cranker_before = env.svm.get_account(&cranker).unwrap();

    env.svm.expire_blockhash();
    let refreshed = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: OBS_SLOT,
            close_q: POS_SCALE,
            observations: crank_observations_with_accounts(0, 1),
        },
        vec![
            AccountMeta::new(cranker_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short, false),
            AccountMeta::new_readonly(fresh0, false),
            AccountMeta::new(cranker, false),
        ],
        &[&cranker_owner],
    );
    assert!(
        refreshed.is_ok(),
        "budgeted stale tx may still refresh from committed state: {refreshed:?}"
    );
    let (_, group_after) = env.market_state();
    let short_after = env.portfolio_state(short);
    assert!(
        health_cert(&short_after).cert_oracle_epoch >= group_after.oracle_epoch,
        "stale target account becomes current"
    );
    assert_eq!(
        group_after.assets[1].oi_eff_short_q, short_oi_before,
        "out-of-order refresh must not liquidate the target position"
    );
    assert_eq!(
        active_leg_for_asset(&short_after, 1).basis_pos_q,
        active_leg_for_asset(&short_before, 1).basis_pos_q,
        "target leg size is unchanged by refresh-only progress"
    );
    assert_eq!(
        env.svm.get_account(&cranker).unwrap(),
        cranker_before,
        "refresh-only progress must not credit or rewrite the reward account"
    );
}

#[test]
fn v16_attack_auto_crank_refresh_not_blocked_by_unneeded_first_asset_oracle() {
    const MARK: u64 = 1_000_000;
    const OPEN_SLOT: u64 = 1;
    const REFRESH_SLOT: u64 = 2;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    set_test_clock(&mut env, OPEN_SLOT, 100);

    let stale_feed0 = [0x52u8; 32];
    let initial0 = env.set_pyth_price_with_conf(&stale_feed0, MARK as i64, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [stale_feed0, [0u8; 32], [0u8; 32]],
        &[initial0],
        OPEN_SLOT,
        100,
        0,
        0,
        1_000,
        0,
    )
    .expect("configure asset-0 hybrid oracle");
    env.configure_auth_mark_for_asset_as_admin(1, OPEN_SLOT, MARK);

    let owner_a = Keypair::new();
    let owner_b = Keypair::new();
    let account_a = env.create_portfolio(&owner_a);
    let account_b = env.create_portfolio(&owner_b);
    env.deposit(&owner_a, account_a, 10_000_000);
    env.deposit(&owner_b, account_b, 10_000_000);
    env.trade_asset_with_cu(
        0,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        POS_SCALE as i128,
        MARK,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        POS_SCALE as i128,
        MARK,
        0,
    );
    let a_before_update = env.portfolio_state(account_a);
    assert!(
        health_cert(&a_before_update).valid,
        "setup starts from a current multi-asset account"
    );
    assert_eq!(
        active_leg_for_asset(&a_before_update, 0).asset_index,
        0,
        "asset 0 is active"
    );
    assert_eq!(
        active_leg_for_asset(&a_before_update, 1).asset_index,
        1,
        "asset 1 is active"
    );

    set_test_clock(&mut env, REFRESH_SLOT, 200);
    env.push_auth_mark_for_asset_as_admin(1, REFRESH_SLOT, MARK + 10_000);
    env.crank(
        account_b,
        ProgInstruction::PermissionlessCrank {
            now_slot: REFRESH_SLOT,
            close_q: 0,
            observations: crank_observations(1),
        },
    );
    let (_, group_after_asset1) = env.market_state();
    assert!(
        health_cert(&env.portfolio_state(account_a)).cert_oracle_epoch
            < group_after_asset1.oracle_epoch,
        "asset-1 progress makes account A stale"
    );

    env.svm.expire_blockhash();
    let stale_asset0_attempt = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: REFRESH_SLOT,
            close_q: 0,
            observations: crank_observations_with_accounts(0, 1),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(account_a, false),
            AccountMeta::new_readonly(initial0, false),
        ],
        &[],
    );
    assert!(
        stale_asset0_attempt.is_err(),
        "asset-0 oracle is stale; the refresh must not depend on it"
    );

    env.svm.expire_blockhash();
    let refresh = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: REFRESH_SLOT,
            close_q: 0,
            observations: vec![],
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(account_a, false),
        ],
        &[],
    );
    assert!(
        refresh.is_ok(),
        "account refresh should use already-current market state, not require an unneeded first-asset oracle: {refresh:?}"
    );
    assert!(
        health_cert(&env.portfolio_state(account_a)).cert_oracle_epoch
            >= env.market_state().1.oracle_epoch,
        "refresh makes the stale account current"
    );
}

// LoF/DoS sweep: committed-state refresh is valid only when the selected
// engine asset has no pending wrapper-side mark. If a public keeper can omit
// the selected asset observation while another asset made the account stale,
// the engine fallback would accrue the selected asset at its old committed
// price and consume the slot, making the pending mark impossible to apply in
// that slot. That lets out-of-order keepers starve mark/funding progress by
// repeatedly landing no-observation refreshes first.
#[test]
fn v16_attack_pending_selected_mark_requires_observation() {
    const MARK: u64 = 1_000_000;
    const NEXT_MARK0: u64 = 1_100_000;
    const NEXT_MARK1: u64 = 1_010_000;
    const OPEN_SLOT: u64 = 1;
    const CRANK_SLOT: u64 = 2;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_for_asset_as_admin(0, OPEN_SLOT, MARK);
    env.configure_auth_mark_for_asset_as_admin(1, OPEN_SLOT, MARK);

    let owner_a = Keypair::new();
    let owner_b = Keypair::new();
    let asset1_owner = Keypair::new();
    let asset1_counter_owner = Keypair::new();
    let account_a = env.create_portfolio(&owner_a);
    let account_b = env.create_portfolio(&owner_b);
    let asset1_account = env.create_portfolio(&asset1_owner);
    let asset1_counter = env.create_portfolio(&asset1_counter_owner);
    env.deposit(&owner_a, account_a, 100_000_000);
    env.deposit(&owner_b, account_b, 100_000_000);
    env.deposit(&asset1_owner, asset1_account, 100_000_000);
    env.deposit(&asset1_counter_owner, asset1_counter, 100_000_000);
    env.trade_asset_with_cu(
        0,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        POS_SCALE as i128,
        MARK,
        0,
    );
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(
        1,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        POS_SCALE as i128,
        MARK,
        0,
    );
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(
        1,
        &asset1_owner,
        asset1_account,
        &asset1_counter_owner,
        asset1_counter,
        POS_SCALE as i128,
        MARK,
        0,
    );
    let account_before_mark = env.portfolio_state(account_a);
    assert_eq!(
        leg(&account_before_mark, 0).asset_index,
        0,
        "asset 0 must occupy the first active slot for this selected-asset probe"
    );
    assert_eq!(
        active_leg_for_asset(&account_before_mark, 0).asset_index,
        0,
        "asset 0 is the engine-selected first active leg"
    );
    assert_eq!(active_leg_for_asset(&account_before_mark, 1).asset_index, 1);

    env.svm.warp_to_slot(CRANK_SLOT);
    env.push_auth_mark_for_asset_as_admin(0, CRANK_SLOT, NEXT_MARK0);
    let profile0 =
        state::read_asset_oracle_profile(&env.svm.get_account(&env.market).unwrap().data, 0)
            .unwrap();
    let (_, pending_group) = env.market_state();
    assert_eq!(profile0.mark_ewma_e6, NEXT_MARK0);
    assert_eq!(profile0.mark_ewma_last_slot, CRANK_SLOT);
    assert_eq!(
        pending_group.assets[0].effective_price, MARK,
        "PushAuthMark only stages the selected asset mark"
    );
    assert!(
        pending_group.assets[0].slot_last < CRANK_SLOT,
        "selected asset has a pending slot to consume"
    );

    env.push_auth_mark_for_asset_as_admin(1, CRANK_SLOT, NEXT_MARK1);
    env.crank(
        asset1_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: CRANK_SLOT,
            close_q: 0,
            observations: crank_observations(1),
        },
    );
    let (_, stale_group) = env.market_state();
    assert_eq!(stale_group.assets[1].effective_price, NEXT_MARK1);
    assert_eq!(
        stale_group.assets[0].effective_price, MARK,
        "selected asset mark is still pending after unrelated asset progress"
    );
    assert!(
        health_cert(&env.portfolio_state(account_a)).cert_oracle_epoch < stale_group.oracle_epoch,
        "unrelated asset progress makes the target account stale"
    );
    let market_before = env.svm.get_account(&env.market).unwrap();
    let account_before = env.svm.get_account(&account_a).unwrap();
    env.svm.expire_blockhash();
    let missing_selected_observation = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: CRANK_SLOT,
            close_q: 0,
            observations: vec![],
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(account_a, false),
        ],
        &[],
    );
    assert!(
        missing_selected_observation.is_err(),
        "selected asset has a pending mark, so no-observation refresh must not consume its slot"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected missing-observation refresh must not advance the selected asset at the old price"
    );
    assert_eq!(
        env.svm.get_account(&account_a).unwrap(),
        account_before,
        "rejected missing-observation refresh must not certify the target against a pending mark"
    );

    env.svm.expire_blockhash();
    let observed = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: CRANK_SLOT,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(account_a, false),
        ],
        &[],
    );
    assert!(
        observed.is_ok(),
        "supplying the selected asset observation must remain live: {observed:?}"
    );
    let (_, observed_group) = env.market_state();
    assert_eq!(
        observed_group.assets[0].effective_price, NEXT_MARK0,
        "selected asset observation applies the pending mark"
    );
}

#[test]
fn v16_bpf_no_cranker_liquidation_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 250);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, 300);
    env.mutate_market(|_, group| {
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
    });
    let before_market = env.svm.get_account(&env.market).unwrap().data;
    let before_short = env.svm.get_account(&short_account).unwrap().data;

    let result = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
        ],
        &[],
    );

    assert!(
        result.is_err(),
        "no-cranker liquidation must reject instead of persisting an invalid market shape"
    );
    let after_market = env.svm.get_account(&env.market).unwrap().data;
    let after_short = env.svm.get_account(&short_account).unwrap().data;
    assert_eq!(
        after_market, before_market,
        "failed no-cranker liquidation must roll back market data"
    );
    assert_eq!(
        after_short, before_short,
        "failed no-cranker liquidation must roll back portfolio data"
    );
}

// Non-liquidation PermissionlessCrank updates oracle/profile state before entering the engine and,
// unlike the liquidation branch, does not perform an explicit wrapper-side final shape check. This
// pins the engine-error propagation boundary for Refresh: if the engine rejects a bad final market
// shape, the full instruction must roll back the pre-engine wrapper writes too.
#[test]
fn v16_attack_refresh_crank_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 1_000_000);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, 101);
    env.mutate_market(|_, group| {
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
    });
    let before_market = env.svm.get_account(&env.market).unwrap().data;
    let before_long = env.svm.get_account(&long_account).unwrap().data;

    let result = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(long_account, false),
        ],
        &[],
    );

    assert!(
        result.is_err(),
        "refresh crank must reject instead of persisting an invalid market shape"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_market,
        "failed refresh crank must roll back market data"
    );
    assert_eq!(
        env.svm.get_account(&long_account).unwrap().data,
        before_long,
        "failed refresh crank must roll back portfolio data"
    );
}

// The SettleB crank returns from the engine before the normal accrual tail and has no cranker reward
// branch, so it is a separate rollback boundary from Refresh and Liquidate. A bad final market shape
// must not let a public B-settlement mutate the target account.
#[test]
fn v16_attack_settle_b_crank_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        public_b_chunk_atoms: 1,
        ..V16CuMarketParams::default()
    });
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 1_000_000);
    env.trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    env.mark_b_stale_gap(long_account, 0, 3);
    assert!(
        active_leg_for_asset(&env.portfolio_state(long_account), 0).b_stale,
        "test setup must create a non-vacuous B-stale settlement target"
    );
    env.mutate_market(|_, group| {
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
    });
    let before_market = env.svm.get_account(&env.market).unwrap().data;
    let before_long = env.svm.get_account(&long_account).unwrap().data;

    env.svm.warp_to_slot(1);
    env.svm.expire_blockhash();
    let result = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(long_account, false),
        ],
        &[],
    );
    assert!(result.is_err(), "SettleB must reject invalid market shape");
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_market,
        "failed SettleB must roll back market data"
    );
    assert_eq!(
        env.svm.get_account(&long_account).unwrap().data,
        before_long,
        "failed SettleB must roll back portfolio data"
    );
}

// Terminal top-up is a separate public value path from CloseResolved. Keep its invalid-shape
// rollback boundary pinned so a pending receipt cannot pay through a bad market final state.
#[test]
fn v16_attack_claim_resolved_topup_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    {
        let mut market_account = env.svm.get_account(&env.market).expect("market account");
        let mut portfolio_account = env.svm.get_account(&portfolio).expect("portfolio account");
        let (cfg, mut group) = state::read_market(&market_account.data).unwrap();
        let mut account = state::read_portfolio(&portfolio_account.data).unwrap();
        group.mode = MarketModeV16::Resolved;
        group.resolved_slot = 1;
        group.current_slot = 1;
        group.vault = 60;
        group.payout_snapshot_captured = true;
        group.payout_snapshot = 100;
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
        group.resolved_payout_ledger = ResolvedPayoutLedgerV16 {
            snapshot_residual: 100,
            terminal_claim_exact_receipts_num: 100 * BOUND_SCALE,
            terminal_claim_bound_unreceipted_num: 0,
            current_payout_rate_num: 100 * BOUND_SCALE,
            current_payout_rate_den: 100 * BOUND_SCALE,
            snapshot_slot: 1,
            payout_halted: false,
            finalized: false,
        };
        account.resolved_payout_receipt =
            percolator::ResolvedPayoutReceiptV16Account::from_runtime(&ResolvedPayoutReceiptV16 {
                present: true,
                prior_bound_contribution_num: 100 * BOUND_SCALE,
                live_released_face_at_receipt: 0,
                terminal_positive_claim_face: 100,
                paid_effective: 40,
                finalized: false,
            });
        state::write_market(&mut market_account.data, &cfg, &group).unwrap();
        state::write_portfolio(&mut portfolio_account.data, &account).unwrap();
        env.svm.set_account(env.market, market_account).unwrap();
        env.svm.set_account(portfolio, portfolio_account).unwrap();
    }
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 60);
    let dest = env.token_account_for_mint(env.mint, owner.pubkey(), 0);
    let before_market = env.svm.get_account(&env.market).unwrap();
    let before_portfolio = env.svm.get_account(&portfolio).unwrap();
    let before_vault = env.svm.get_account(&env.vault).unwrap();
    let before_dest = env.svm.get_account(&dest).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::ClaimResolvedPayoutTopup,
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "ClaimResolvedPayoutTopup must reject invalid final market shape"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before_market,
        "failed top-up must roll back market data"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        before_portfolio,
        "failed top-up must leave the receipt claimable"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        before_vault,
        "failed top-up must not debit the vault"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        before_dest,
        "failed top-up must not pay the destination"
    );
}

// Stale resolve is an unsigned terminal transition. It must not resolve the market through a bad
// final shape and strand users in a malformed wind-down state.
#[test]
fn v16_attack_resolve_stale_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new();
    env.configure_permissionless_resolve_with_cu(5, 5);
    env.configure_auth_mark_with_cu(0, 100);
    env.svm.warp_to_slot(3);
    env.push_auth_mark_with_cu(3, 100);
    env.svm.warp_to_slot(40);
    env.mutate_market(|_, group| {
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
    });
    let before_market = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::ResolveStalePermissionless { now_slot: 0 },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        rejected.is_err(),
        "ResolveStalePermissionless must reject invalid final market shape"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before_market,
        "failed stale resolve must roll back market data"
    );
}

#[test]
fn v16_bpf_cranker_reward_liquidation_rejects_invalid_shape_without_paying_reward() {
    let mut env = V16CuEnv::new();
    env.update_liquidation_fee_policy_with_cu(10_000);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    let cranker_account = env.create_portfolio(&cranker_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 250);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, 300);
    env.mutate_market(|_, group| {
        group.config.liquidation_fee_bps = 10_000;
        group.config.liquidation_fee_cap = 1;
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1_000_000);
    });
    let before_market = env.svm.get_account(&env.market).unwrap().data;
    let before_short = env.svm.get_account(&short_account).unwrap().data;
    let before_cranker = env.svm.get_account(&cranker_account).unwrap().data;

    let result = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::PermissionlessCrank {
            now_slot: 1,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(cranker_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
            AccountMeta::new(cranker_account, false),
        ],
        &[&cranker_owner],
    );

    assert!(
        result.is_err(),
        "cranker-reward liquidation must reject instead of persisting an invalid market shape"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before_market,
        "failed cranker-reward liquidation must roll back market data"
    );
    assert_eq!(
        env.svm.get_account(&short_account).unwrap().data,
        before_short,
        "failed cranker-reward liquidation must roll back liquidated portfolio data"
    );
    assert_eq!(
        env.svm.get_account(&cranker_account).unwrap().data,
        before_cranker,
        "failed cranker-reward liquidation must not pay the cranker portfolio"
    );
}

#[test]
fn v16_bpf_full_14_leg_refresh_crank_is_under_tx_limit() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(14, 1_000, 1_000, 500);
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 2_000);
    env.deposit(&short_owner, short_account, 100_000);
    env.seed_n_leg_position_for_benchmark(long_account, short_account, 14);
    let before_slot_last = {
        let market_data = env.svm.get_account(&env.market).unwrap().data;
        let (_, group) = state::read_market(&market_data).unwrap();
        group.assets[0].slot_last
    };

    env.svm.warp_to_slot(16);
    let refresh_cu = env.crank(
        long_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 16,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    println!("v16 full-14-leg refresh crank CU: {refresh_cu}");
    assert!(
        refresh_cu <= 900_000,
        "full-14-leg refresh CU {} exceeded limit {}",
        refresh_cu,
        900_000
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let long_data = env.svm.get_account(&long_account).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let long = state::read_portfolio(&long_data).unwrap();
    assert_eq!(group.config.max_portfolio_assets, 14);
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&long)),
        14
    );
    assert!(
        group.assets[0].slot_last > before_slot_last,
        "full-14 refresh crank must commit bounded asset progress"
    );
    assert_eq!(group.assets[0].effective_price, 95);
}

// CU/DoS sweep: the crank decoder rejects oversized observation vectors, but the exact legal
// maximum still pre-applies every observation before the engine selector runs. Pin that admitted
// max shape against a full 14-leg stale refresh so oracle-hint fanout cannot turn a live keeper
// route into a transaction-CU cliff.
#[test]
fn v16_bpf_full_14_leg_refresh_crank_with_max_observations_is_under_tx_limit() {
    const N: usize = percolator_prog::constants::WRAPPER_MAX_PORTFOLIO_ASSETS as usize;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(N as u16, 1_000, 1_000, 500);
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 2_000);
    env.deposit(&short_owner, short_account, 100_000);
    env.seed_n_leg_position_for_benchmark(long_account, short_account, N);
    let before_slot_last: Vec<u64> = {
        let market_data = env.svm.get_account(&env.market).unwrap().data;
        let (_, group) = state::read_market(&market_data).unwrap();
        (0..N)
            .map(|asset_index| group.assets[asset_index].slot_last)
            .collect()
    };
    let observations: Vec<CrankObservationHint> = (0..N)
        .map(|asset_index| CrankObservationHint {
            asset_index: asset_index as u16,
            oracle_accounts: 0,
        })
        .collect();

    env.svm.warp_to_slot(16);
    env.svm.expire_blockhash();
    let refresh_cu = env
        .send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 16,
                close_q: 0,
                observations,
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(long_account, false),
            ],
            &[],
        )
        .expect("max-observation full-leg refresh remains live");
    println!("v16 full-14-leg refresh crank with max observations CU: {refresh_cu}");
    assert!(
        refresh_cu <= 900_000,
        "full-14-leg max-observation refresh CU {} exceeded limit {}",
        refresh_cu,
        900_000
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let long_data = env.svm.get_account(&long_account).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let long = state::read_portfolio(&long_data).unwrap();
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&long)),
        N as u32
    );
    for (asset_index, before) in before_slot_last.iter().copied().enumerate() {
        assert!(
            group.assets[asset_index].slot_last > before,
            "max-observation refresh must commit asset progress for asset {asset_index}"
        );
        assert_eq!(
            group.assets[asset_index].effective_price, 95,
            "max-observation refresh applies the stale benchmark mark for asset {asset_index}"
        );
    }
}

// CU/DoS sweep: the max-observation crank above covers zero-account oracle profiles. A hostile
// keeper can also legally provide the maximum three oracle accounts for every portfolio asset. Pin
// the admitted 14x3 Pyth-tail path so oracle fanout plus a full stale portfolio cannot become a CU cliff.
#[test]
fn v16_bpf_full_14_leg_refresh_crank_with_max_three_leg_pyth_observations_is_under_tx_limit() {
    const N: usize = percolator_prog::constants::WRAPPER_MAX_PORTFOLIO_ASSETS as usize;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(N as u16, 1_000, 1_000, 500);
    set_test_clock(&mut env, 1, 100);
    for asset_index in 0..N {
        let feed_seed = 0x30u8.wrapping_add((asset_index as u8).wrapping_mul(3));
        let feeds = [
            [feed_seed; 32],
            [feed_seed.wrapping_add(1); 32],
            [feed_seed.wrapping_add(2); 32],
        ];
        let initial_oracles = [
            env.set_pyth_price(&feeds[0], 100, -6, 100),
            env.set_pyth_price(&feeds[1], 1_000_000, -6, 100),
            env.set_pyth_price(&feeds[2], 1_000_000, -6, 100),
        ];
        env.try_configure_hybrid_asset_with_conf_filter_cu(
            asset_index as u16,
            3,
            0,
            feeds,
            &initial_oracles,
            1,
            100,
            0,
            0,
            3,
            500,
        )
        .expect("configure one-leg hybrid oracle for max-observation crank");
    }

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 2_000);
    env.deposit(&short_owner, short_account, 100_000);
    env.seed_n_leg_position_for_benchmark(long_account, short_account, N);
    let before_slot_last: Vec<u64> = {
        let market_data = env.svm.get_account(&env.market).unwrap().data;
        let (_, group) = state::read_market(&market_data).unwrap();
        (0..N)
            .map(|asset_index| group.assets[asset_index].slot_last)
            .collect()
    };

    set_test_clock(&mut env, 17, 101);
    let mut observations = Vec::with_capacity(N);
    let mut oracle_tail = Vec::with_capacity(N * 3);
    for asset_index in 0..N {
        let feed_seed = 0x30u8.wrapping_add((asset_index as u8).wrapping_mul(3));
        let feeds = [
            [feed_seed; 32],
            [feed_seed.wrapping_add(1); 32],
            [feed_seed.wrapping_add(2); 32],
        ];
        observations.push(CrankObservationHint {
            asset_index: asset_index as u16,
            oracle_accounts: 3,
        });
        oracle_tail.push(env.set_pyth_price(&feeds[0], 99, -6, 101));
        oracle_tail.push(env.set_pyth_price(&feeds[1], 1_000_000, -6, 101));
        oracle_tail.push(env.set_pyth_price(&feeds[2], 1_000_000, -6, 101));
    }
    let mut accounts = vec![
        AccountMeta::new(env.payer.pubkey(), true),
        AccountMeta::new(env.market, false),
        AccountMeta::new(long_account, false),
    ];
    accounts.extend(
        oracle_tail
            .iter()
            .copied()
            .map(|key| AccountMeta::new_readonly(key, false)),
    );

    env.svm.expire_blockhash();
    let refresh_cu = env
        .send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 17,
                close_q: 0,
                observations,
            },
            accounts,
            &[],
        )
        .expect("max-three-leg-Pyth-observation full-leg refresh remains live");
    println!("v16 full-14-leg refresh crank with max three-leg Pyth observations CU: {refresh_cu}");
    const MAX_THREE_LEG_PYTH_OBSERVATION_REFRESH_CU_LIMIT: u64 = 1_250_000;
    assert!(
        refresh_cu <= MAX_THREE_LEG_PYTH_OBSERVATION_REFRESH_CU_LIMIT,
        "full-14-leg max-three-leg-Pyth-observation refresh CU {} exceeded limit {}",
        refresh_cu,
        MAX_THREE_LEG_PYTH_OBSERVATION_REFRESH_CU_LIMIT
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let long_data = env.svm.get_account(&long_account).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let long = state::read_portfolio(&long_data).unwrap();
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&long)),
        N as u32
    );
    for (asset_index, before) in before_slot_last.iter().copied().enumerate() {
        assert!(
            group.assets[asset_index].slot_last > before,
            "max-three-leg-Pyth-observation refresh must commit asset progress for asset {asset_index}"
        );
        assert_eq!(
            group.assets[asset_index].effective_price, 99,
            "max-three-leg-Pyth-observation refresh applies the fresh oracle mark for asset {asset_index}"
        );
    }
}

// LoF/DoS sweep (cron135): reward-enabled markets peel a cranker portfolio from the
// tail before parsing oracle observations. A keeper that includes both the maximum
// legal Pyth observation tail and a reward account must still get one bounded
// selector step; fresh observations make the cert stale, so the engine must refresh
// instead of paying a liquidation reward from the same call.
#[test]
fn v16_bpf_full_14_leg_max_pyth_observations_with_reward_tail_refreshes_without_reward() {
    const N: usize = percolator_prog::constants::WRAPPER_MAX_PORTFOLIO_ASSETS as usize;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(N as u16, 1_000, 1_000, 500);
    env.update_liquidation_fee_policy_with_cu(5_000);
    set_test_clock(&mut env, 1, 100);
    for asset_index in 0..N {
        let feed_seed = 0x70u8.wrapping_add((asset_index as u8).wrapping_mul(3));
        let feeds = [
            [feed_seed; 32],
            [feed_seed.wrapping_add(1); 32],
            [feed_seed.wrapping_add(2); 32],
        ];
        let initial_oracles = [
            env.set_pyth_price(&feeds[0], 100, -6, 100),
            env.set_pyth_price(&feeds[1], 1_000_000, -6, 100),
            env.set_pyth_price(&feeds[2], 1_000_000, -6, 100),
        ];
        env.try_configure_hybrid_asset_with_conf_filter_cu(
            asset_index as u16,
            3,
            0,
            feeds,
            &initial_oracles,
            1,
            100,
            0,
            0,
            3,
            500,
        )
        .expect("configure three-leg hybrid oracle for reward-tail max-observation crank");
    }

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    let cranker_account = env.create_portfolio(&cranker_owner);
    env.deposit(&long_owner, long_account, 2_000);
    env.deposit(&short_owner, short_account, 100_000);
    env.deposit(&cranker_owner, cranker_account, 1_000);
    env.seed_current_n_leg_position_for_benchmark(long_account, short_account, N);
    env.force_portfolio_capital_for_benchmark(long_account, 1_000);
    let cranker_before = env.portfolio_state(cranker_account).capital.get();
    let before_active =
        percolator::active_bitmap_count_ones(active_bitmap(&env.portfolio_state(long_account)));

    set_test_clock(&mut env, 17, 101);
    let mut observations = Vec::with_capacity(N);
    let mut accounts = vec![
        AccountMeta::new(cranker_owner.pubkey(), true),
        AccountMeta::new(env.market, false),
        AccountMeta::new(long_account, false),
    ];
    for asset_index in 0..N {
        let feed_seed = 0x70u8.wrapping_add((asset_index as u8).wrapping_mul(3));
        let feeds = [
            [feed_seed; 32],
            [feed_seed.wrapping_add(1); 32],
            [feed_seed.wrapping_add(2); 32],
        ];
        observations.push(CrankObservationHint {
            asset_index: asset_index as u16,
            oracle_accounts: 3,
        });
        accounts.push(AccountMeta::new_readonly(
            env.set_pyth_price(&feeds[0], 99, -6, 101),
            false,
        ));
        accounts.push(AccountMeta::new_readonly(
            env.set_pyth_price(&feeds[1], 1_000_000, -6, 101),
            false,
        ));
        accounts.push(AccountMeta::new_readonly(
            env.set_pyth_price(&feeds[2], 1_000_000, -6, 101),
            false,
        ));
    }
    accounts.push(AccountMeta::new(cranker_account, false));

    env.svm.expire_blockhash();
    let refresh_cu = env
        .send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 17,
                close_q: POS_SCALE,
                observations,
            },
            accounts,
            &[&cranker_owner],
        )
        .expect("reward-tail max-observation crank remains live");
    println!("v16 full-14-leg max-Pyth observations plus reward tail refresh CU: {refresh_cu}");
    const MAX_PYTH_REWARD_TAIL_REFRESH_CU_LIMIT: u64 = 1_300_000;
    assert!(
        refresh_cu <= MAX_PYTH_REWARD_TAIL_REFRESH_CU_LIMIT,
        "max-Pyth reward-tail refresh CU {} exceeded limit {}",
        refresh_cu,
        MAX_PYTH_REWARD_TAIL_REFRESH_CU_LIMIT
    );

    let after_long = env.portfolio_state(long_account);
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&after_long)),
        before_active,
        "fresh observations make the selected step refresh; liquidation waits for a later crank"
    );
    assert_eq!(
        env.portfolio_state(cranker_account).capital.get(),
        cranker_before,
        "non-liquidation auto-crank step must not pay the supplied reward portfolio"
    );
}

