#[test]
fn v16_bpf_stale_full_14_leg_tradenocpi_rejects_before_cu_cliff() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(14, 1_000, 1_000, 500);
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 20_000);
    env.deposit(&short_owner, short_account, 100_000);
    env.seed_n_leg_position_for_benchmark(long_account, short_account, 14);
    env.svm.warp_to_slot(16);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let long_before = env.svm.get_account(&long_account).unwrap();
    let short_before = env.svm.get_account(&short_account).unwrap();
    let stale_trade = env.try_trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        -(POS_SCALE as i128),
        95,
        0,
    );
    let stale_err = stale_trade.expect_err("stale active accounts must pre-crank before trading");
    assert!(
        stale_err.contains("Custom(19)") || stale_err.contains("custom program error: 0x13"),
        "stale active trade should reject as EngineStale, got: {stale_err}"
    );
    assert!(
        !stale_err.contains("exceeded CUs"),
        "stale active trade must reject before the CU cliff: {stale_err}"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&long_account).unwrap(), long_before);
    assert_eq!(env.svm.get_account(&short_account).unwrap(), short_before);

    // The successful side of the contract is covered by the adjacent
    // v16_bpf_full_14_leg_refresh_crank_is_under_tx_limit and
    // v16_bpf_current_full_14_leg_tradenocpi_is_under_tx_limit tests.
}

#[test]
fn v16_bpf_close_resolved_moves_payout_tokens_with_ledger() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);

    env.resolve();
    let dest = env.close_resolved(&owner, portfolio);
    assert_eq!(env.token_amount(dest), 1_000);
    assert_eq!(env.token_amount(env.vault), 0);

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let portfolio_data = env.svm.get_account(&portfolio).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let account = state::read_portfolio(&portfolio_data).unwrap();
    assert_eq!(group.vault, 0);
    assert_eq!(group.c_tot, 0);
    assert_eq!(account.capital.get(), 0);
}

// LoF/DoS sweep (cron135): PermissionlessCrank is the public keeper route. Once the
// market is Resolved, it must forward to the resolved-close path before trying to
// parse live-mode crank observations; otherwise stale keeper hints could block
// terminal user wind-down.
#[test]
fn v16_attack_resolved_permissionless_crank_closes_without_live_hint_parsing() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.resolve();

    let dest = env.token_account(owner.pubkey(), 0);
    env.svm.expire_blockhash();
    let cu = env
        .send(
            ProgInstruction::PermissionlessCrank {
                now_slot: u64::MAX,
                close_q: u128::MAX,
                observations: vec![CrankObservationHint {
                    asset_index: u16::MAX,
                    oracle_accounts: u8::MAX,
                }],
            },
            vec![
                AccountMeta::new_readonly(owner.pubkey(), false),
                AccountMeta::new(env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[],
        )
        .expect("resolved-mode PermissionlessCrank forwards to CloseResolved");
    assert_cu_within(
        "Resolved PermissionlessCrank CloseResolved",
        cu,
        CRANK_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(dest),
        1_000,
        "resolved crank pays the user instead of parsing hostile live hints"
    );
    assert_eq!(env.token_amount(env.vault), 0);

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let portfolio_data = env.svm.get_account(&portfolio).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let account = state::read_portfolio(&portfolio_data).unwrap();
    assert_eq!(group.vault, 0);
    assert_eq!(group.c_tot, 0);
    assert_eq!(account.capital.get(), 0);
}

// LoF/DoS sweep (cron135): the resolved PermissionlessCrank opcode is now the public keeper
// wind-down route. Its resolved-mode forwarder must not bypass the owner exit window before
// falling into CloseResolved; hostile live-mode hints are still ignored only after that auth gate.
#[test]
fn v16_attack_resolved_permissionless_crank_honors_owner_exit_window() {
    let mut env = V16CuEnv::new();
    env.configure_permissionless_resolve_with_cu(100, 5);
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.resolve();

    let dest = env.token_account(owner.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let crank_ix = ProgInstruction::PermissionlessCrank {
        now_slot: u64::MAX,
        close_q: u128::MAX,
        observations: vec![CrankObservationHint {
            asset_index: u16::MAX,
            oracle_accounts: u8::MAX,
        }],
    };

    env.svm.expire_blockhash();
    let unsigned = env.send(
        crank_ix.clone(),
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        unsigned.is_err(),
        "resolved PermissionlessCrank must not bypass the owner exit window"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "unsigned resolved crank must not mutate resolved market accounting"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "unsigned resolved crank must not burn the owner's payout state"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        dest_before,
        "unsigned resolved crank must not pay the destination"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "unsigned resolved crank must not move vault tokens"
    );

    env.svm.expire_blockhash();
    let signed = env
        .send(
            crank_ix,
            vec![
                AccountMeta::new_readonly(owner.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&owner],
        )
        .expect("owner-signed resolved PermissionlessCrank works during exit window");
    assert_cu_within(
        "Resolved PermissionlessCrank owner exit window",
        signed,
        CRANK_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(dest),
        1_000,
        "owner-signed resolved crank recovers the payout during the exit window"
    );
    assert_eq!(env.token_amount(env.vault), 0);
}

#[test]
fn v16_bpf_failed_close_resolved_transfer_rolls_back_payout_state() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.resolve();
    let dest = env.token_account(owner.pubkey(), 0);
    let mut corrupted_vault = env.svm.get_account(&env.vault).unwrap();
    corrupted_vault.owner = Pubkey::new_unique();
    env.svm.set_account(env.vault, corrupted_vault).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let result = env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );

    assert!(
        result.is_err(),
        "close-resolved must fail when the payout transfer CPI fails"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&portfolio).unwrap(), portfolio_before);
    assert_eq!(env.svm.get_account(&dest).unwrap(), dest_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    let (_, group) = env.market_state();
    let account = env.portfolio_state(portfolio);
    assert_eq!(group.vault, 1_000);
    assert_eq!(group.c_tot, 1_000);
    assert_eq!(account.capital.get(), 1_000);
    assert!(
        !resolved_receipt(&account).present,
        "failed payout must not persist a paid/finalized receipt"
    );
    assert_eq!(env.token_amount(dest), 0);
}

#[test]
fn v16_bpf_failed_claim_resolved_topup_rolls_back_receipt_and_ledger() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    {
        let mut market_account = env.svm.get_account(&env.market).expect("market account");
        let mut portfolio_account = env.svm.get_account(&portfolio).expect("portfolio account");
        let (cfg, mut group) = state::read_market(&market_account.data).unwrap();
        let mut account = state::read_portfolio(&portfolio_account.data).unwrap();
        group.mode = MarketModeV16::Resolved;
        group.resolved_slot = 1;
        group.current_slot = 1;
        group.vault = 60;
        group.payout_snapshot_captured = true;
        group.payout_snapshot = 100;
        group.resolved_payout_ledger = ResolvedPayoutLedgerV16 {
            snapshot_residual: 100,
            terminal_claim_exact_receipts_num: 100 * BOUND_SCALE,
            terminal_claim_bound_unreceipted_num: 0,
            current_payout_rate_num: 100 * BOUND_SCALE,
            current_payout_rate_den: 100 * BOUND_SCALE,
            snapshot_slot: 1,
            payout_halted: false,
            finalized: false,
        };
        account.resolved_payout_receipt =
            percolator::ResolvedPayoutReceiptV16Account::from_runtime(&ResolvedPayoutReceiptV16 {
                present: true,
                prior_bound_contribution_num: 100 * BOUND_SCALE,
                live_released_face_at_receipt: 0,
                terminal_positive_claim_face: 100,
                paid_effective: 40,
                finalized: false,
            });
        state::write_market(&mut market_account.data, &cfg, &group).unwrap();
        state::write_portfolio(&mut portfolio_account.data, &account).unwrap();
        env.svm.set_account(env.market, market_account).unwrap();
        env.svm.set_account(portfolio, portfolio_account).unwrap();
    }
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 60);
    let clean_vault = env.svm.get_account(&env.vault).unwrap();

    let dest = env.token_account_for_mint(env.mint, owner.pubkey(), 0);
    let mut corrupted_vault = clean_vault.clone();
    corrupted_vault.owner = Pubkey::new_unique();
    env.svm.set_account(env.vault, corrupted_vault).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let result = env.send(
        ProgInstruction::ClaimResolvedPayoutTopup,
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );

    assert!(
        result.is_err(),
        "resolved payout top-up must fail when post-mutation vault validation fails"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&portfolio).unwrap(), portfolio_before);
    assert_eq!(env.svm.get_account(&dest).unwrap(), dest_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    let (_, group) = env.market_state();
    let account = env.portfolio_state(portfolio);
    assert_eq!(group.vault, 60);
    assert_eq!(group.resolved_payout_ledger.snapshot_residual, 100);
    assert_eq!(
        group
            .resolved_payout_ledger
            .terminal_claim_exact_receipts_num,
        100 * BOUND_SCALE
    );
    assert_eq!(resolved_receipt(&account).paid_effective, 40);
    assert!(
        !resolved_receipt(&account).finalized,
        "failed top-up must leave the pending receipt claimable"
    );
    assert_eq!(env.token_amount(dest), 0);

    env.svm.set_account(env.vault, clean_vault).unwrap();
    env.svm.expire_blockhash();
    let cu = env.claim_resolved_payout_topup_with_cu(owner.pubkey(), portfolio, dest);
    assert_cu_within(
        "ClaimResolvedPayoutTopup rollback retry",
        cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(env.token_amount(dest), 60);
    let (_, group) = env.market_state();
    let account = env.portfolio_state(portfolio);
    assert_eq!(group.vault, 0);
    assert_eq!(resolved_receipt(&account).paid_effective, 100);
    assert!(resolved_receipt(&account).finalized);
}

#[test]
fn v16_attack_resolved_payout_short_canonical_vault_rolls_back_receipts() {
    let mut close_env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = close_env.create_portfolio(&owner);
    close_env.deposit(&owner, portfolio, 1_000);
    close_env.resolve();
    close_env.set_token_account_amount(
        close_env.vault,
        close_env.mint,
        close_env.vault_authority,
        999,
    );
    let dest = close_env.token_account(owner.pubkey(), 0);
    let market_before = close_env.svm.get_account(&close_env.market).unwrap();
    let portfolio_before = close_env.svm.get_account(&portfolio).unwrap();
    let dest_before = close_env.svm.get_account(&dest).unwrap();
    let vault_before = close_env.svm.get_account(&close_env.vault).unwrap();

    close_env.svm.expire_blockhash();
    let rejected_close = close_env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(close_env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(close_env.vault, false),
            AccountMeta::new_readonly(close_env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected_close.is_err(),
        "CloseResolved must reject when the canonical vault balance is short"
    );
    assert_eq!(
        close_env.svm.get_account(&close_env.market).unwrap(),
        market_before,
        "short-vault CloseResolved rejection rolls back market accounting"
    );
    assert_eq!(
        close_env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "short-vault CloseResolved rejection does not burn payout state"
    );
    assert_eq!(
        close_env.svm.get_account(&dest).unwrap(),
        dest_before,
        "short-vault CloseResolved rejection pays no tokens"
    );
    assert_eq!(
        close_env.svm.get_account(&close_env.vault).unwrap(),
        vault_before,
        "short-vault CloseResolved rejection leaves canonical vault unchanged"
    );
    let (_, rejected_group) = close_env.market_state();
    let rejected_portfolio = close_env.portfolio_state(portfolio);
    assert_eq!(rejected_group.vault, 1_000);
    assert_eq!(rejected_group.c_tot, 1_000);
    assert_eq!(rejected_portfolio.capital.get(), 1_000);
    assert!(!resolved_receipt(&rejected_portfolio).present);

    close_env.set_token_account_amount(
        close_env.vault,
        close_env.mint,
        close_env.vault_authority,
        1_000,
    );
    close_env.svm.expire_blockhash();
    close_env
        .send(
            ProgInstruction::CloseResolved {
                fee_rate_per_slot: 0,
            },
            vec![
                AccountMeta::new_readonly(owner.pubkey(), false),
                AccountMeta::new(close_env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(dest, false),
                AccountMeta::new(close_env.vault, false),
                AccountMeta::new_readonly(close_env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[],
        )
        .expect("CloseResolved succeeds once canonical vault liquidity matches accounting");
    assert_eq!(close_env.token_amount(dest), 1_000);
    assert_eq!(close_env.market_state().1.vault, 0);
    assert_eq!(close_env.portfolio_state(portfolio).capital.get(), 0);

    let mut topup_env = V16CuEnv::new();
    let topup_owner = Keypair::new();
    let topup_portfolio = topup_env.create_portfolio(&topup_owner);
    {
        let mut market_account = topup_env
            .svm
            .get_account(&topup_env.market)
            .expect("market account");
        let mut portfolio_account = topup_env
            .svm
            .get_account(&topup_portfolio)
            .expect("portfolio account");
        let (cfg, mut group) = state::read_market(&market_account.data).unwrap();
        let mut account = state::read_portfolio(&portfolio_account.data).unwrap();
        group.mode = MarketModeV16::Resolved;
        group.resolved_slot = 1;
        group.current_slot = 1;
        group.vault = 60;
        group.payout_snapshot_captured = true;
        group.payout_snapshot = 100;
        group.resolved_payout_ledger = ResolvedPayoutLedgerV16 {
            snapshot_residual: 100,
            terminal_claim_exact_receipts_num: 100 * BOUND_SCALE,
            terminal_claim_bound_unreceipted_num: 0,
            current_payout_rate_num: 100 * BOUND_SCALE,
            current_payout_rate_den: 100 * BOUND_SCALE,
            snapshot_slot: 1,
            payout_halted: false,
            finalized: false,
        };
        account.resolved_payout_receipt =
            percolator::ResolvedPayoutReceiptV16Account::from_runtime(&ResolvedPayoutReceiptV16 {
                present: true,
                prior_bound_contribution_num: 100 * BOUND_SCALE,
                live_released_face_at_receipt: 0,
                terminal_positive_claim_face: 100,
                paid_effective: 40,
                finalized: false,
            });
        state::write_market(&mut market_account.data, &cfg, &group).unwrap();
        state::write_portfolio(&mut portfolio_account.data, &account).unwrap();
        topup_env
            .svm
            .set_account(topup_env.market, market_account)
            .unwrap();
        topup_env
            .svm
            .set_account(topup_portfolio, portfolio_account)
            .unwrap();
    }
    topup_env.set_token_account_amount(
        topup_env.vault,
        topup_env.mint,
        topup_env.vault_authority,
        59,
    );
    let topup_dest = topup_env.token_account_for_mint(topup_env.mint, topup_owner.pubkey(), 0);
    let topup_market_before = topup_env.svm.get_account(&topup_env.market).unwrap();
    let topup_portfolio_before = topup_env.svm.get_account(&topup_portfolio).unwrap();
    let topup_dest_before = topup_env.svm.get_account(&topup_dest).unwrap();
    let topup_vault_before = topup_env.svm.get_account(&topup_env.vault).unwrap();

    topup_env.svm.expire_blockhash();
    let rejected_topup = topup_env.send(
        ProgInstruction::ClaimResolvedPayoutTopup,
        vec![
            AccountMeta::new_readonly(topup_owner.pubkey(), false),
            AccountMeta::new(topup_env.market, false),
            AccountMeta::new(topup_portfolio, false),
            AccountMeta::new(topup_dest, false),
            AccountMeta::new(topup_env.vault, false),
            AccountMeta::new_readonly(topup_env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected_topup.is_err(),
        "ClaimResolvedPayoutTopup must reject when canonical vault liquidity is short"
    );
    assert_eq!(
        topup_env.svm.get_account(&topup_env.market).unwrap(),
        topup_market_before,
        "short-vault top-up rejection rolls back payout ledger accounting"
    );
    assert_eq!(
        topup_env.svm.get_account(&topup_portfolio).unwrap(),
        topup_portfolio_before,
        "short-vault top-up rejection leaves receipt claimable"
    );
    assert_eq!(
        topup_env.svm.get_account(&topup_dest).unwrap(),
        topup_dest_before,
        "short-vault top-up rejection pays no tokens"
    );
    assert_eq!(
        topup_env.svm.get_account(&topup_env.vault).unwrap(),
        topup_vault_before,
        "short-vault top-up rejection leaves canonical vault unchanged"
    );
    let topup_group = topup_env.market_state().1;
    let topup_receipt = topup_env.portfolio_state(topup_portfolio);
    assert_eq!(topup_group.vault, 60);
    assert_eq!(topup_group.resolved_payout_ledger.snapshot_residual, 100);
    assert_eq!(resolved_receipt(&topup_receipt).paid_effective, 40);
    assert!(!resolved_receipt(&topup_receipt).finalized);

    topup_env.set_token_account_amount(
        topup_env.vault,
        topup_env.mint,
        topup_env.vault_authority,
        60,
    );
    topup_env.svm.expire_blockhash();
    topup_env
        .send(
            ProgInstruction::ClaimResolvedPayoutTopup,
            vec![
                AccountMeta::new_readonly(topup_owner.pubkey(), false),
                AccountMeta::new(topup_env.market, false),
                AccountMeta::new(topup_portfolio, false),
                AccountMeta::new(topup_dest, false),
                AccountMeta::new(topup_env.vault, false),
                AccountMeta::new_readonly(topup_env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[],
        )
        .expect(
            "ClaimResolvedPayoutTopup succeeds once canonical vault liquidity matches accounting",
        );
    assert_eq!(topup_env.token_amount(topup_dest), 60);
    assert_eq!(topup_env.market_state().1.vault, 0);
    let receipt = topup_env.portfolio_state(topup_portfolio);
    assert_eq!(resolved_receipt(&receipt).paid_effective, 100);
    assert!(resolved_receipt(&receipt).finalized);
}

#[test]
fn v16_attack_close_resolved_requires_owner_signature_during_exit_window() {
    let mut env = V16CuEnv::new();
    env.configure_permissionless_resolve_with_cu(100, 5);
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.resolve();

    let unsigned_dest = env.token_account(owner.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let dest_before = env.svm.get_account(&unsigned_dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();

    env.svm.expire_blockhash();
    let unsigned = env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(unsigned_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        unsigned.is_err(),
        "third-party CloseResolved must reject during the owner exit window"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "unsigned close inside the exit window must not mutate resolved market accounting"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "unsigned close inside the exit window must not burn the owner's payout state"
    );
    assert_eq!(
        env.svm.get_account(&unsigned_dest).unwrap(),
        dest_before,
        "unsigned close inside the exit window must not pay the destination"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "unsigned close inside the exit window must not move vault tokens"
    );

    let signed_dest = env.token_account(owner.pubkey(), 0);
    env.svm.expire_blockhash();
    let signed = env
        .send(
            ProgInstruction::CloseResolved {
                fee_rate_per_slot: 0,
            },
            vec![
                AccountMeta::new_readonly(owner.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(signed_dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&owner],
        )
        .expect("owner-signed CloseResolved works during the exit window");
    assert_cu_within(
        "owner-signed CloseResolved during exit window",
        signed,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(signed_dest),
        1_000,
        "the owner can still recover during the protected exit window"
    );
    let (_, group) = env.market_state();
    let account = env.portfolio_state(portfolio);
    assert_eq!(group.vault, 0);
    assert_eq!(group.c_tot, 0);
    assert_eq!(account.capital.get(), 0);
}

#[test]
fn v16_attack_close_resolved_after_exit_window_is_permissionless_but_not_stealable() {
    let mut env = V16CuEnv::new();
    const EXIT_DELAY: u64 = 5;
    env.configure_permissionless_resolve_with_cu(100, EXIT_DELAY);

    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.resolve();

    env.svm.warp_to_slot(EXIT_DELAY + 1);
    env.svm.expire_blockhash();

    let attacker = Keypair::new();
    let attacker_dest = env.token_account(attacker.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let attacker_dest_before = env.svm.get_account(&attacker_dest).unwrap();
    let steal = env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(attacker_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        steal.is_err(),
        "post-timeout CloseResolved is permissionless, but payout must still go to the portfolio owner"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&portfolio).unwrap(), portfolio_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    assert_eq!(
        env.svm.get_account(&attacker_dest).unwrap(),
        attacker_dest_before
    );

    let owner_dest = env.token_account(owner.pubkey(), 0);
    env.svm.expire_blockhash();
    let permissionless = env
        .send(
            ProgInstruction::CloseResolved {
                fee_rate_per_slot: 0,
            },
            vec![
                AccountMeta::new_readonly(owner.pubkey(), false),
                AccountMeta::new(env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(owner_dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[],
        )
        .expect("post-timeout CloseResolved can be cranked without owner signature");
    assert_cu_within(
        "post-timeout permissionless CloseResolved",
        permissionless,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(owner_dest),
        1_000,
        "permissionless close pays the owner-controlled destination"
    );
    assert_eq!(
        env.token_amount(attacker_dest),
        0,
        "attacker-controlled destination receives nothing"
    );
    let (_, group) = env.market_state();
    let account = env.portfolio_state(portfolio);
    assert_eq!(group.vault, 0);
    assert_eq!(group.c_tot, 0);
    assert_eq!(account.capital.get(), 0);
}

// security.md sweep - permissionless CloseResolved legacy rollback (#5/#26/#44/#48):
// After the owner exit window, CloseResolved is intentionally permissionless
// when the caller names the portfolio owner, but it mutates payout state before
// validating the destination token account. A bad destination must roll back
// both the legacy realloc and the post-engine payout mutation.
#[test]
fn v16_attack_permissionless_close_resolved_bad_dest_rolls_back_legacy_realloc() {
    let mut env = V16CuEnv::new();
    const EXIT_DELAY: u64 = 5;
    env.configure_permissionless_resolve_with_cu(100, EXIT_DELAY);

    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.resolve();
    env.svm.warp_to_slot(EXIT_DELAY + 1);

    let mut legacy = env.svm.get_account(&portfolio).unwrap();
    legacy.data.truncate(PORTFOLIO_ENGINE_ACCOUNT_LEN);
    env.svm.set_account(portfolio, legacy).unwrap();
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "test setup simulates a resolved legacy portfolio"
    );

    let attacker = Keypair::new();
    let attacker_dest = env.token_account(attacker.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let attacker_dest_before = env.svm.get_account(&attacker_dest).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(attacker_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "permissionless CloseResolved must reject an attacker-owned destination"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected legacy CloseResolved leaves resolved market accounting unchanged"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap(),
        portfolio_before,
        "rejected legacy CloseResolved rolls back realloc and payout-state mutation"
    );
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "failed CloseResolved does not leave a public legacy realloc behind"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "rejected legacy CloseResolved moves no vault custody"
    );
    assert_eq!(
        env.svm.get_account(&attacker_dest).unwrap(),
        attacker_dest_before,
        "attacker destination receives no payout"
    );

    let owner_dest = env.token_account(owner.pubkey(), 0);
    env.svm.expire_blockhash();
    let accepted = env
        .send(
            ProgInstruction::CloseResolved {
                fee_rate_per_slot: 0,
            },
            vec![
                AccountMeta::new_readonly(owner.pubkey(), false),
                AccountMeta::new(env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(owner_dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[],
        )
        .expect("permissionless CloseResolved still works for the owner destination");
    assert_cu_within(
        "permissionless legacy CloseResolved retry",
        accepted,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(env.token_amount(owner_dest), 1_000);
    assert_eq!(env.market_state().1.vault, 0);
    assert_eq!(env.portfolio_state(portfolio).capital.get(), 0);
}

// security.md sweep — CloseResolved caller-supplied fee_rate_per_slot must be IGNORED (Copenhagen
// SOL-001-class spoofed-param / SOL-023 fee-rounding-away-from-user): CloseResolved is permissionless
// after the exit window (force_close_delay_slots==0 -> always permissionless), and it carries a
// caller-supplied `fee_rate_per_slot`. handle_close_resolved (v16_program 10285) names it `_fee_rate_
// per_slot` and passes cfg.maintenance_fee_per_slot (10317) to the engine instead. If the param were
// honored, a hostile third party finalizing a victim's resolved account could pass a huge rate to
// over-charge the victim's accrued maintenance fee at terminal close, draining the payout into
// insurance (victim LOF). Every existing CloseResolved test passes fee_rate_per_slot: 0, so this
// ignore property is unpinned. With cfg maintenance_fee=0 and slots elapsed, the victim must receive
// the FULL deposit regardless of a u128::MAX spoofed rate; a regression that wired the param in would
// drain it to ~0.
#[test]
fn v16_attack_close_resolved_ignores_spoofed_fee_rate_param() {
    let mut env = V16CuEnv::new(); // default maintenance_fee_per_slot = 0, force_close_delay_slots = 0
    let victim_owner = Keypair::new();
    let victim = env.create_portfolio(&victim_owner);
    env.deposit(&victim_owner, victim, 1_000_000);
    env.resolve();
    // Advance many slots so elapsed_slots is large: a leaked spoofed rate would charge rate*elapsed.
    env.svm.warp_to_slot(10_000);

    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, victim_owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    env.svm.expire_blockhash();
    // Permissionless finalize (no signer) with a maximally-spoofed fee rate.
    env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: u128::MAX,
        },
        vec![
            AccountMeta::new_readonly(victim_owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(victim, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    )
    .expect("permissionless close-resolved with spoofed fee rate");

    assert_eq!(
        env.token_amount(dest),
        1_000_000,
        "victim must receive the FULL deposit; the caller-supplied fee_rate_per_slot must be ignored"
    );
    let (_, g) = env.market_state();
    assert_eq!(
        env.portfolio_state(victim).capital.get(),
        0,
        "account fully closed"
    );
    assert_eq!(
        g.vault,
        g.c_tot + g.insurance,
        "conservation after terminal close"
    );
}

#[test]
fn v16_attack_permissionless_close_resolved_rejects_delegated_dest() {
    let mut env = V16CuEnv::new();
    let victim_owner = Keypair::new();
    let victim = env.create_portfolio(&victim_owner);
    env.deposit(&victim_owner, victim, 1_000);
    env.resolve();

    let attacker = Keypair::new();
    let delegated_dest = Pubkey::new_unique();
    env.svm
        .set_account(
            delegated_dest,
            Account {
                lamports: 1_000_000_000,
                data: make_delegated_token_data(
                    env.mint,
                    victim_owner.pubkey(),
                    0,
                    attacker.pubkey(),
                    u64::MAX,
                ),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&victim).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let dest_before = env.svm.get_account(&delegated_dest).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(victim_owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(victim, false),
            AccountMeta::new(delegated_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "permissionless CloseResolved must reject a victim-owned destination with an active delegate"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected delegated-dest close leaves market accounting unchanged"
    );
    assert_eq!(
        env.svm.get_account(&victim).unwrap(),
        portfolio_before,
        "rejected delegated-dest close rolls back payout state"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "rejected delegated-dest close moves no vault custody"
    );
    assert_eq!(
        env.svm.get_account(&delegated_dest).unwrap(),
        dest_before,
        "delegated destination receives no payout"
    );

    let closable_dest = Pubkey::new_unique();
    env.svm
        .set_account(
            closable_dest,
            Account {
                lamports: 1_000_000_000,
                data: make_closable_token_data(
                    env.mint,
                    victim_owner.pubkey(),
                    0,
                    attacker.pubkey(),
                ),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let closable_before = env.svm.get_account(&closable_dest).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(victim_owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(victim, false),
            AccountMeta::new(closable_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "permissionless CloseResolved must reject a victim-owned destination with close authority"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&victim).unwrap(), portfolio_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    assert_eq!(
        env.svm.get_account(&closable_dest).unwrap(),
        closable_before,
        "close-authority destination receives no payout"
    );

    let clean_dest = env.token_account(victim_owner.pubkey(), 0);
    env.svm.expire_blockhash();
    env.send(
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(victim_owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(victim, false),
            AccountMeta::new(clean_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    )
    .expect("same permissionless close succeeds with a clean victim destination");
    assert_eq!(env.token_amount(clean_dest), 1_000);
    assert_eq!(env.market_state().1.vault, 0);
    assert_eq!(env.portfolio_state(victim).capital.get(), 0);
}

#[test]
fn v16_attack_claim_resolved_topup_rejects_live_market_without_mutation() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);

    let attacker = Keypair::new();
    let attacker_dest = env.token_account(attacker.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let dest_before = env.svm.get_account(&attacker_dest).unwrap();

    env.svm.expire_blockhash();
    let live_claim = env.send(
        ProgInstruction::ClaimResolvedPayoutTopup,
        vec![
            AccountMeta::new_readonly(owner.pubkey(), false),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(attacker_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        live_claim.is_err(),
        "unsigned resolved-payout top-up must reject while the market is still Live"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&portfolio).unwrap(), portfolio_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    assert_eq!(env.svm.get_account(&attacker_dest).unwrap(), dest_before);

    let (owner_dest, _) = env.withdraw_with_cu(&owner, portfolio, 1_000);
    assert_eq!(
        env.token_amount(owner_dest),
        1_000,
        "owner can still withdraw after rejected live top-up attempt"
    );
    assert_eq!(
        env.token_amount(attacker_dest),
        0,
        "attacker destination receives nothing"
    );
}

#[test]
fn v16_bpf_failed_terminal_insurance_withdraw_rolls_back_market_and_ledger() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(100);
    env.resolve();
    let ledger = env.insurance_ledger_account();
    let dest = env.token_account(env.admin.pubkey(), 0);
    let mut corrupted_vault = env.svm.get_account(&env.vault).unwrap();
    corrupted_vault.owner = Pubkey::new_unique();
    env.svm.set_account(env.vault, corrupted_vault).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let ledger_before = env.svm.get_account(&ledger).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let result = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsurance { amount: 40 },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&env.admin],
    );

    assert!(
        result.is_err(),
        "terminal insurance withdraw must fail when the transfer CPI fails"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&ledger).unwrap(), ledger_before);
    assert_eq!(env.svm.get_account(&dest).unwrap(), dest_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    let (_, group) = env.market_state();
    assert_eq!(group.insurance, 100);
    assert_eq!(group.vault, 100);
    assert_eq!(env.token_amount(dest), 0);
}

#[test]
fn v16_attack_terminal_insurance_short_canonical_vault_rolls_back_budget_and_ledger() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.top_up_insurance(100);
    env.resolve();
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 39);

    let ledger = env.insurance_ledger_account();
    let dest = env.token_account(admin.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let ledger_before = env.svm.get_account(&ledger).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsurance { amount: 40 },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "terminal WithdrawInsurance must reject when canonical vault liquidity is short"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "short canonical vault rejection rolls back terminal insurance budgets"
    );
    assert_eq!(
        env.svm.get_account(&ledger).unwrap(),
        ledger_before,
        "short canonical vault rejection rolls back optional ledger writes"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        dest_before,
        "short canonical vault rejection pays no tokens"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "short canonical vault rejection leaves the vault token account unchanged"
    );
    let (_, rejected_group) = env.market_state();
    assert_eq!(rejected_group.insurance, 100);
    assert_eq!(rejected_group.vault, 100);

    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 100);
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsurance { amount: 40 },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&admin],
    )
    .expect(
        "terminal WithdrawInsurance succeeds once canonical vault liquidity matches accounting",
    );
    assert_eq!(env.token_amount(dest), 40);
    assert_eq!(env.token_amount(env.vault), 60);
    let ledger_state =
        state::read_insurance_ledger(&env.svm.get_account(&ledger).unwrap().data).unwrap();
    assert_eq!(ledger_state.total_withdrawn_atoms, 40);
    assert_eq!(ledger_state.last_observed_insurance_atoms, 60);
    let (_, group) = env.market_state();
    assert_eq!(group.insurance, 60);
    assert_eq!(group.vault, 60);
}

#[test]
fn v16_bpf_failed_backing_withdraw_transfer_rolls_back_bucket_and_ledger() {
    let mut env = V16CuEnv::new();
    let ledger = env.backing_domain_ledger_account();
    env.top_up_backing_bucket_with_ledger_with_cu(ledger, 1, 100, 10);
    let dest = env.token_account(env.admin.pubkey(), 0);
    let mut corrupted_vault = env.svm.get_account(&env.vault).unwrap();
    corrupted_vault.owner = Pubkey::new_unique();
    env.svm.set_account(env.vault, corrupted_vault).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let ledger_before = env.svm.get_account(&ledger).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let result = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 1,
            amount: 40,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&env.admin],
    );

    assert!(
        result.is_err(),
        "backing withdraw must fail when the transfer CPI cannot debit the vault"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&ledger).unwrap(), ledger_before);
    assert_eq!(env.svm.get_account(&dest).unwrap(), dest_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    let (_, group) = env.market_state();
    assert_eq!(group.vault, 100);
    assert_eq!(
        group.source_backing_buckets[1].fresh_unliened_backing_num,
        100 * BOUND_SCALE
    );
    assert_eq!(
        group.source_credit[1].fresh_reserved_backing_num,
        100 * BOUND_SCALE
    );
    assert_eq!(env.token_amount(dest), 0);
}

#[test]
fn v16_bpf_failed_backing_earnings_withdraw_rolls_back_bucket_and_ledger() {
    let mut env = V16CuEnv::new();
    let ledger = env.backing_domain_ledger_account();
    env.top_up_backing_bucket_with_ledger_with_cu(ledger, 1, 100, 10);
    env.mutate_market(|_, group| {
        group.source_backing_buckets[1].utilization_fee_earnings = 30;
        group.vault += 30;
    });
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 130);
    env.sync_backing_domain_ledger_with_cu(ledger, 1);

    let dest = env.token_account(env.admin.pubkey(), 0);
    let mut corrupted_vault = env.svm.get_account(&env.vault).unwrap();
    corrupted_vault.owner = Pubkey::new_unique();
    env.svm.set_account(env.vault, corrupted_vault).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let ledger_before = env.svm.get_account(&ledger).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let result = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucketEarnings {
            domain: 1,
            amount: 10,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(ledger, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&env.admin],
    );

    assert!(
        result.is_err(),
        "backing earnings withdraw must fail when the transfer CPI cannot debit the vault"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&ledger).unwrap(), ledger_before);
    assert_eq!(env.svm.get_account(&dest).unwrap(), dest_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);

    let (_, group) = env.market_state();
    assert_eq!(group.vault, 130, "vault accounting rolled back");
    assert_eq!(
        group.source_backing_buckets[1].utilization_fee_earnings, 30,
        "earnings counter rolled back"
    );
    let ledger_state =
        state::read_backing_domain_ledger(&env.svm.get_account(&ledger).unwrap().data).unwrap();
    assert_eq!(
        ledger_state.last_observed_bucket_earnings_atoms, 30,
        "ledger observed earnings rolled back"
    );
    assert_eq!(
        ledger_state.total_earnings_withdrawn_atoms, 0,
        "ledger withdraw total rolled back"
    );
    assert_eq!(env.token_amount(dest), 0);
}

#[test]
fn v16_bpf_close_resolved_pays_positive_pnl_through_engine_ledger() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);
    env.top_up_backing_bucket(1, 250, 10);
    env.add_source_positive_pnl(portfolio, 1, 250);

    env.resolve();
    let dest = env.close_resolved(&owner, portfolio);
    assert_eq!(env.token_amount(dest), 1_250);
    assert_eq!(env.token_amount(env.vault), 0);

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let portfolio_data = env.svm.get_account(&portfolio).unwrap().data;
    let (_, group) = state::read_market(&market_data).unwrap();
    let account = state::read_portfolio(&portfolio_data).unwrap();
    assert_eq!(group.vault, 0);
    assert_eq!(group.c_tot, 0);
    assert_eq!(account.capital.get(), 0);
    assert_eq!(account.pnl.get(), 0);
    // Source-backed positive pnl is REALIZED into capital at resolved close (the
    // realize_source_backed_claims step) and paid out as capital — not parked as a junior payout
    // receipt against the backing it is underwritten by. The winner is fully paid (1_250 above)
    // and winds down with NO resolved receipt outstanding.
    assert!(!resolved_receipt(&account).present);
}

#[test]
fn v16_bpf_permissionless_stale_resolve_is_bounded_and_oracle_free() {
    let mut env = V16CuEnv::new();
    let configure_cu = env.configure_permissionless_resolve_with_cu(5, 1);
    let stale_resolve_cu = env.resolve_stale_permissionless_with_cu(5);
    println!(
        "v16 permissionless stale resolve CU configure={configure_cu}, resolve={stale_resolve_cu}"
    );
    assert!(
        configure_cu <= CUSTODY_CU_LIMIT,
        "configure permissionless resolve CU {} exceeded limit {}",
        configure_cu,
        CUSTODY_CU_LIMIT
    );
    assert!(
        stale_resolve_cu <= CUSTODY_CU_LIMIT,
        "permissionless stale resolve CU {} exceeded limit {}",
        stale_resolve_cu,
        CUSTODY_CU_LIMIT
    );

    let market_data = env.svm.get_account(&env.market).unwrap().data;
    let (cfg, group) = state::read_market(&market_data).unwrap();
    assert_eq!(cfg.permissionless_resolve_stale_slots, 5);
    assert_eq!(cfg.force_close_delay_slots, 1);
    assert_eq!(group.mode, percolator::MarketModeV16::Resolved);
    assert_eq!(group.resolved_slot, 5);
}

#[test]
fn v16_cu_custody_and_resolution_paths_are_bounded() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let (portfolio, init_portfolio_cu) = env.create_portfolio_with_cu(&owner);
    let (_source, deposit_cu) = env.deposit_with_cu(&owner, portfolio, 1_000);
    let (_dest, withdraw_cu) = env.withdraw_with_cu(&owner, portfolio, 400);
    let (_insurance_source, top_up_cu) = env.top_up_insurance_with_cu(250);
    env.enable_live_insurance_withdrawal();
    let (_insurance_dest, withdraw_insurance_cu) = env.withdraw_insurance_with_cu(100);
    let resolve_cu = env.resolve();
    let (_resolved_dest, close_resolved_cu) = env.close_resolved_with_cu(&owner, portfolio);

    println!(
        "v16 custody CU init_portfolio={init_portfolio_cu}, deposit={deposit_cu}, withdraw={withdraw_cu}, top_up={top_up_cu}, withdraw_insurance={withdraw_insurance_cu}, resolve={resolve_cu}, close_resolved={close_resolved_cu}"
    );
    for (name, cu) in [
        ("init_portfolio", init_portfolio_cu),
        ("deposit", deposit_cu),
        ("withdraw", withdraw_cu),
        ("top_up", top_up_cu),
        ("withdraw_insurance", withdraw_insurance_cu),
        ("resolve", resolve_cu),
        ("close_resolved", close_resolved_cu),
    ] {
        assert!(
            cu <= CUSTODY_CU_LIMIT,
            "{} CU {} exceeded limit {}",
            name,
            cu,
            CUSTODY_CU_LIMIT
        );
    }
}

