#[test]
fn v16_attack_non_base_tradecpi_rejects_before_matcher_after_base_resolve_matured() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 1_000, 1_000, 500);
    let creator = Keypair::new();
    let creator_key = creator.pubkey();
    env.update_market_init_fee_policy_with_cu(1);
    env.configure_permissionless_resolve_with_cu(5, 5);
    env.configure_auth_mark_with_cu(0, 100);

    env.svm.warp_to_slot(1);
    env.activate_permissionless_asset_with_fee(
        &creator,
        1,
        1,
        100,
        creator_key,
        creator_key,
        creator_key,
        creator_key,
        1,
    );
    env.configure_auth_mark_for_asset_with_authority(1, &creator, 1, 100);

    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let taker_portfolio = env.create_portfolio(&taker);
    let lp_portfolio = env.create_portfolio(&lp);
    env.deposit(&taker, taker_portfolio, 1_000_000);
    env.deposit(&lp, lp_portfolio, 1_000_000);

    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &lp_portfolio,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; MATCHER_CONTEXT_LEN],
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.set_matcher_config(hostile, &lp, lp_portfolio, ctx, delegate, 1);

    let accounts = |env: &V16CuEnv| {
        vec![
            AccountMeta::new(taker.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(taker_portfolio, false),
            AccountMeta::new(lp_portfolio, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(delegate, false),
        ]
    };
    let set_hostile_mode = |env: &mut V16CuEnv, mode: u8| {
        let mut data = vec![0u8; MATCHER_CONTEXT_LEN];
        data[0] = mode;
        env.svm
            .set_account(
                ctx,
                Account {
                    lamports: 1_000_000_000,
                    data,
                    owner: hostile,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
    };

    env.svm.warp_to_slot(3);
    env.push_auth_mark_with_cu(3, 100);
    env.svm.warp_to_slot(7);
    env.push_auth_mark_for_asset_with_authority(1, &creator, 7, 101);
    set_hostile_mode(&mut env, 0);
    env.svm.expire_blockhash();
    let fresh_err = env
        .send(
            ProgInstruction::TradeCpi {
                asset_index: 1,
                size_q: POS_SCALE as i128,
                fee_bps: 100,
                limit_price: 0,
            },
            accounts(&env),
            &[&taker],
        )
        .expect_err("fresh hostile non-base TradeCpi must reach matcher-return validation");
    assert!(
        fresh_err.contains("InvalidAccountData"),
        "fresh hostile non-base TradeCpi should fail from matcher validation, got {fresh_err}"
    );
    assert!(
        !fresh_err.contains("Custom(27)") && !fresh_err.contains("0x1b"),
        "fresh hostile non-base TradeCpi must not be mistaken for stale gating: {fresh_err}"
    );

    env.svm.warp_to_slot(8);
    set_hostile_mode(&mut env, 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&taker_portfolio).unwrap();
    let lp_before = env.svm.get_account(&lp_portfolio).unwrap();
    let ctx_before = env.svm.get_account(&ctx).unwrap();
    env.svm.expire_blockhash();
    let stale_err = env
        .send(
            ProgInstruction::TradeCpi {
                asset_index: 1,
                size_q: POS_SCALE as i128,
                fee_bps: 100,
                limit_price: 0,
            },
            accounts(&env),
            &[&taker],
        )
        .expect_err("base-stale non-base TradeCpi must reject before matcher CPI");
    assert!(
        stale_err.contains("Custom(27)") || stale_err.contains("0x1b"),
        "base-stale non-base TradeCpi must fail as OracleStale before matcher validation, got {stale_err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "pre-CPI stale rejection leaves market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&taker_portfolio).unwrap(),
        taker_before,
        "pre-CPI stale rejection leaves taker bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&lp_portfolio).unwrap(),
        lp_before,
        "pre-CPI stale rejection leaves LP bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&ctx).unwrap(),
        ctx_before,
        "pre-CPI stale rejection never gives the hostile matcher a writable context"
    );

    env.svm.expire_blockhash();
    let resolve = env.send(
        ProgInstruction::ResolveStalePermissionless { now_slot: 0 },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        resolve.is_ok(),
        "base resolve remains available after rejected non-base TradeCpi: {resolve:?}"
    );
    assert_eq!(env.market_state().1.mode, MarketModeV16::Resolved);
}

// security.md sweep — CloseSlab wind-down finality (#30/#48): a market may only be closed when fully
// wound down (mode==Resolved AND vault==0 && insurance==0 && c_tot==0 && no materialized portfolios).
// Closing while value/positions remain would strand funds — must reject.
#[test]
fn v16_attack_close_slab_requires_full_winddown() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    let close_slab = |env: &mut V16CuEnv| -> Result<u64, String> {
        let dest = Pubkey::new_unique();
        env.svm
            .set_account(
                dest,
                Account {
                    lamports: 1_000_000_000,
                    data: make_token_data(env.mint, env.admin.pubkey(), 0),
                    owner: spl_token::ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::CloseSlab,
            vec![
                AccountMeta::new(env.admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new(dest, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&env.admin],
        )
    };
    // 1) Live market with funds -> reject (mode != Resolved).
    assert!(
        close_slab(&mut env).is_err(),
        "CloseSlab on a Live market must reject"
    );
    assert_eq!(env.token_amount(env.vault), 1_000_000, "vault funds intact");

    // 2) Resolved market but still holding c_tot / a materialized portfolio -> reject.
    env.resolve();
    let (_, g) = env.market_state();
    assert!(
        g.c_tot != 0 || g.vault != 0,
        "market still holds value after resolve (positions not closed)"
    );
    assert!(
        close_slab(&mut env).is_err(),
        "CloseSlab while value/positions remain must reject"
    );
    assert_eq!(
        env.token_amount(env.vault),
        1_000_000,
        "vault funds still intact (not stranded)"
    );
    // the user can still recover via CloseResolved (funds not locked by the rejected CloseSlab).
    let cr = env.close_resolved(&owner, p);
    assert_eq!(
        env.token_amount(cr),
        1_000_000,
        "user recovers funds via CloseResolved"
    );
}

// security.md sweep - CloseSlab final-custody validation (#33/#44/#48): once accounting is fully
// drained, CloseSlab may still recover direct vault dust before zeroing the market slab. A wrong
// primary destination must reject before the vault is closed or the market is reclaimed.
#[test]
fn v16_attack_close_slab_bad_primary_dest_is_atomic() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.resolve();
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 7);

    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();

    let close_slab_to = |env: &mut V16CuEnv, dest: Pubkey| -> Result<u64, String> {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::CloseSlab,
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new(dest, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&admin],
        )
    };
    let assert_rejected_close_unchanged = |env: &V16CuEnv, label: &str| {
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "{label}: market slab must not be zeroed"
        );
        assert_eq!(
            env.svm.get_account(&env.vault).unwrap(),
            vault_before,
            "{label}: primary vault must not be transferred or closed"
        );
    };

    let wrong_mint = Pubkey::new_unique();
    let wrong_mint_dest = env.token_account_for_mint(wrong_mint, admin.pubkey(), 0);
    let wrong_mint_close = close_slab_to(&mut env, wrong_mint_dest);
    assert!(
        wrong_mint_close.is_err(),
        "CloseSlab must reject a wrong-mint primary destination"
    );
    assert_eq!(
        env.token_amount(wrong_mint_dest),
        0,
        "wrong-mint dest receives nothing"
    );
    assert_rejected_close_unchanged(&env, "wrong-mint primary dest rejection");

    let foreign_dest = env.token_account_for_mint(env.mint, Pubkey::new_unique(), 0);
    let foreign_close = close_slab_to(&mut env, foreign_dest);
    assert!(
        foreign_close.is_err(),
        "CloseSlab must reject a third-party primary destination"
    );
    assert_eq!(
        env.token_amount(foreign_dest),
        0,
        "foreign dest receives nothing"
    );
    assert_rejected_close_unchanged(&env, "foreign primary dest rejection");

    let good_dest = env.token_account(admin.pubkey(), 0);
    let good_close = close_slab_to(&mut env, good_dest);
    assert!(
        good_close.is_ok(),
        "valid CloseSlab still recovers final vault dust: {good_close:?}"
    );
    assert_eq!(
        env.token_amount(good_dest),
        7,
        "primary vault dust recovered to admin"
    );
    let closed_market = env.svm.get_account(&env.market).unwrap();
    assert_eq!(
        closed_market.lamports, 0,
        "market lamports reclaimed after valid close"
    );
    assert!(
        closed_market.data.iter().all(|b| *b == 0),
        "market data zeroed only after a valid close"
    );
}

// security.md sweep - stale marketauth final reclaim (#6/#48): CloseSlab is the terminal authority
// path that moves raw vault dust, closes the SPL vault, and reclaims the market slab. A rotated-out
// market authority must not be able to replay this final close after handoff.
#[test]
fn v16_attack_close_slab_rejects_stale_marketauth_after_rotation() {
    let mut env = V16CuEnv::new();
    let old_admin = env.admin.insecure_clone();
    let new_admin = Keypair::new();
    env.update_asset_authority_with_cu(&new_admin);
    assert_eq!(
        env.market_state().0.marketauth,
        new_admin.pubkey().to_bytes(),
        "test setup rotates marketauth away from the old key"
    );

    env.svm.expire_blockhash();
    let resolve = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ResolveMarket,
        vec![
            AccountMeta::new(new_admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&new_admin],
    );
    assert!(
        resolve.is_ok(),
        "the rotated-in market authority can resolve before final close: {resolve:?}"
    );
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 7);

    let stale_dest = env.token_account(old_admin.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let stale_dest_before = env.svm.get_account(&stale_dest).unwrap();

    env.svm.expire_blockhash();
    let stale_close = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(old_admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new(stale_dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&old_admin],
    );
    assert!(
        stale_close.is_err(),
        "rotated-out marketauth must not reclaim the final slab"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "stale CloseSlab must not zero or reclaim the market slab"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "stale CloseSlab must not transfer or close the primary vault"
    );
    assert_eq!(
        env.svm.get_account(&stale_dest).unwrap(),
        stale_dest_before,
        "stale CloseSlab must not send dust to the old authority"
    );

    let new_dest = env.token_account(new_admin.pubkey(), 0);
    env.svm.expire_blockhash();
    let good_close = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(new_admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new(new_dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&new_admin],
    );
    assert!(
        good_close.is_ok(),
        "rotated-in marketauth can still reclaim the final slab: {good_close:?}"
    );
    assert_eq!(
        env.token_amount(new_dest),
        7,
        "final vault dust recovered by the current market authority"
    );
    let closed_market = env.svm.get_account(&env.market).unwrap();
    assert_eq!(
        closed_market.lamports, 0,
        "market lamports reclaimed after current-authority CloseSlab"
    );
    assert!(
        closed_market.data.iter().all(|b| *b == 0),
        "market data zeroed only after current-authority CloseSlab"
    );
}

// full-interface sweep: a real market account can be a signing system-created keypair. If marketauth is
// rotated to that key, CloseSlab must still reject using the market slab itself as the lamport destination;
// otherwise the final reclaim can zero the data while leaving rent on a program-owned, closed slab.
#[test]
fn v16_attack_close_slab_rejects_market_as_lamport_destination() {
    let mut svm = LiteSVM::new();
    let program_id = percolator_prog::id();
    svm.add_program(
        program_id,
        &std::fs::read(program_path()).expect("read BPF"),
    );
    svm.add_program(
        spl_token::ID,
        &std::fs::read(spl_token_program_path()).expect("read token BPF"),
    );

    let payer = Keypair::new();
    let admin = Keypair::new();
    let market = Keypair::new();
    let mint = Pubkey::new_unique();
    let params = V16CuMarketParams::default();
    let vault_authority =
        Pubkey::find_program_address(&[b"vault", market.pubkey().as_ref()], &program_id).0;
    let vault = canonical_vault_ata(vault_authority, mint);
    svm.airdrop(&payer.pubkey(), 100_000_000_000).unwrap();
    svm.airdrop(&admin.pubkey(), 1_000_000_000).unwrap();
    svm.set_account(
        mint,
        Account {
            lamports: 1_000_000_000,
            data: make_mint_data(),
            owner: spl_token::ID,
            executable: false,
            rent_epoch: 0,
        },
    )
    .unwrap();
    svm.set_account(
        market.pubkey(),
        Account {
            lamports: 1_000_000_000,
            data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
            owner: program_id,
            executable: false,
            rent_epoch: 0,
        },
    )
    .unwrap();
    svm.set_account(
        vault,
        Account {
            lamports: 1_000_000_000,
            data: make_token_data(mint, vault_authority, 0),
            owner: spl_token::ID,
            executable: false,
            rent_epoch: 0,
        },
    )
    .unwrap();

    send_tx(
        &mut svm,
        program_id,
        &payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: params.max_portfolio_assets,
            h_min: params.h_min,
            h_max: params.h_max,
            initial_price: params.initial_price,
            min_nonzero_mm_req: params.min_nonzero_mm_req,
            min_nonzero_im_req: params.min_nonzero_im_req,
            maintenance_margin_bps: params.maintenance_margin_bps,
            initial_margin_bps: params.initial_margin_bps,
            max_trading_fee_bps: params.max_trading_fee_bps,
            trade_fee_base_bps: params.trade_fee_base_bps,
            liquidation_fee_bps: params.liquidation_fee_bps,
            liquidation_fee_cap: params.liquidation_fee_cap,
            min_liquidation_abs: params.min_liquidation_abs,
            max_price_move_bps_per_slot: params.max_price_move_bps_per_slot,
            max_accrual_dt_slots: params.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: params.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: params.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: params.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: params.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: params.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: params.public_b_chunk_atoms,
            maintenance_fee_per_slot: params.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market.pubkey(), false),
            AccountMeta::new_readonly(mint, false),
        ],
        &[&admin],
    )
    .expect("init market");

    svm.expire_blockhash();
    send_tx(
        &mut svm,
        program_id,
        &payer,
        ProgInstruction::UpdateAuthority {
            new_pubkey: market.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market.pubkey(), true),
            AccountMeta::new(market.pubkey(), false),
        ],
        &[&admin, &market],
    )
    .expect("rotate marketauth to signing market key");

    svm.expire_blockhash();
    send_tx(
        &mut svm,
        program_id,
        &payer,
        ProgInstruction::ResolveMarket,
        vec![
            AccountMeta::new(market.pubkey(), true),
            AccountMeta::new(market.pubkey(), false),
        ],
        &[&market],
    )
    .expect("market key can resolve after handoff");

    let dest = Pubkey::new_unique();
    svm.set_account(
        dest,
        Account {
            lamports: 1_000_000_000,
            data: make_token_data(mint, market.pubkey(), 0),
            owner: spl_token::ID,
            executable: false,
            rent_epoch: 0,
        },
    )
    .unwrap();
    let market_before = svm.get_account(&market.pubkey()).unwrap();
    let vault_before = svm.get_account(&vault).unwrap();
    let dest_before = svm.get_account(&dest).unwrap();

    svm.expire_blockhash();
    let rejected = send_tx(
        &mut svm,
        program_id,
        &payer,
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(market.pubkey(), true),
            AccountMeta::new(market.pubkey(), false),
            AccountMeta::new(vault, false),
            AccountMeta::new_readonly(vault_authority, false),
            AccountMeta::new(dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&market],
    );
    assert!(
        rejected.is_err(),
        "CloseSlab must reject market-as-destination alias"
    );
    assert_eq!(
        svm.get_account(&market.pubkey()).unwrap(),
        market_before,
        "market-as-destination rejection leaves the slab initialized"
    );
    assert_eq!(
        svm.get_account(&vault).unwrap(),
        vault_before,
        "market-as-destination rejection leaves the vault open"
    );
    assert_eq!(
        svm.get_account(&dest).unwrap(),
        dest_before,
        "market-as-destination rejection pays no dust"
    );
}

// security.md sweep - CloseSlab vault delegate/close-authority guard (#44/#48):
// CloseSlab is the terminal path that transfers any raw vault dust, closes the SPL vault account, and
// zeroes the market slab. Even with the canonical vault address, a delegated or separately closable
// vault must reject before the signed transfer/close instructions or slab reclaim can run.
#[test]
fn v16_attack_close_slab_rejects_delegated_or_closable_primary_vault() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.resolve();
    let dest = env.token_account(admin.pubkey(), 0);

    let set_primary_vault =
        |env: &mut V16CuEnv, delegate: COption<Pubkey>, close_authority: COption<Pubkey>| {
            let mut data = vec![0u8; TokenAccount::LEN];
            TokenAccount::pack(
                TokenAccount {
                    mint: env.mint,
                    owner: env.vault_authority,
                    amount: 7,
                    delegate,
                    state: AccountState::Initialized,
                    is_native: COption::None,
                    delegated_amount: 7,
                    close_authority,
                },
                &mut data,
            )
            .unwrap();
            env.svm
                .set_account(
                    env.vault,
                    Account {
                        lamports: 1_000_000_000,
                        data,
                        owner: spl_token::ID,
                        executable: false,
                        rent_epoch: 0,
                    },
                )
                .unwrap();
        };

    for (label, delegate, close_authority) in [
        (
            "delegated",
            COption::Some(Pubkey::new_unique()),
            COption::None,
        ),
        (
            "close-authority",
            COption::None,
            COption::Some(Pubkey::new_unique()),
        ),
    ] {
        set_primary_vault(&mut env, delegate, close_authority);
        let market_before = env.svm.get_account(&env.market).unwrap();
        let vault_before = env.svm.get_account(&env.vault).unwrap();
        let dest_before = env.svm.get_account(&dest).unwrap();

        env.svm.expire_blockhash();
        let rejected = env.send(
            ProgInstruction::CloseSlab,
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new(dest, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&admin],
        );
        assert!(
            rejected.is_err(),
            "CloseSlab must reject a {label} canonical primary vault"
        );
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "rejected {label} vault must not reclaim the market slab"
        );
        assert_eq!(
            env.svm.get_account(&env.vault).unwrap(),
            vault_before,
            "rejected {label} vault must not transfer or close the SPL vault"
        );
        assert_eq!(
            env.svm.get_account(&dest).unwrap(),
            dest_before,
            "rejected {label} vault must not pay the admin destination"
        );
    }

    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 7);
    env.svm.expire_blockhash();
    let ok = env.send(
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new(dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        ok.is_ok(),
        "clean canonical primary vault still closes after rejected guarded vaults: {ok:?}"
    );
    assert_eq!(env.token_amount(dest), 7);
    let closed_market = env.svm.get_account(&env.market).unwrap();
    assert_eq!(closed_market.lamports, 0);
    assert!(closed_market.data.iter().all(|b| *b == 0));
}

// full-interface sweep (cron31): CloseSlab must pin the primary vault to the current market's vault
// PDA before transferring dust, closing token accounts, or zeroing the slab. A canonical vault for a
// different market must reject atomically; otherwise a final cleanup could close or drain foreign
// market custody while reclaiming this market.
#[test]
fn v16_attack_close_slab_rejects_foreign_primary_vault() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.resolve();
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 7);

    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let vault_b = canonical_vault_ata(vault_authority_b, env.mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, vault_authority_b, 9),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&admin],
    )
    .expect("init market B");

    let dest = env.token_account(admin.pubkey(), 0);
    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let vault_a_before = env.svm.get_account(&env.vault).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();

    let close_with_vault = |env: &mut V16CuEnv, vault: Pubkey| -> Result<u64, String> {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::CloseSlab,
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new(dest, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&admin],
        )
    };

    let rejected = close_with_vault(&mut env, vault_b);
    assert!(
        rejected.is_err(),
        "CloseSlab must reject a primary vault owned by another market PDA"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_a_before,
        "rejected foreign-vault close must not reclaim market A"
    );
    assert_eq!(
        env.svm.get_account(&market_b).unwrap(),
        market_b_before,
        "rejected foreign-vault close must not mutate market B"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_a_before,
        "rejected foreign-vault close must not touch market A's vault"
    );
    assert_eq!(
        env.svm.get_account(&vault_b).unwrap(),
        vault_b_before,
        "rejected foreign-vault close must not drain or close market B's vault"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        dest_before,
        "rejected foreign-vault close must not pay the admin destination"
    );

    let vault_a = env.vault;
    let ok = close_with_vault(&mut env, vault_a);
    assert!(
        ok.is_ok(),
        "same-market CloseSlab succeeds after rejection: {ok:?}"
    );
    assert_eq!(env.token_amount(dest), 7);
    assert_eq!(env.token_amount(vault_b), 9);
    let closed_market = env.svm.get_account(&env.market).unwrap();
    assert_eq!(closed_market.lamports, 0);
    assert!(closed_market.data.iter().all(|b| *b == 0));
}

// security.md sweep — WithdrawInsuranceAsset operator authorization (#6): a per-asset insurance
// withdrawal must be signed by THAT asset's insurance_operator. A non-operator must reject — no
// draining an asset's insurance by an unauthorized caller.
#[test]
fn v16_attack_withdraw_insurance_asset_operator_gated() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000);
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    let (_, g0) = env.market_state();
    let dest = env.token_account_for_mint(env.mint, mallory.pubkey(), 0);
    // non-operator attempts a domain insurance withdrawal -> reject.
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsuranceAsset {
            asset_index: 0,
            amount: 500_000,
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&mallory],
    );
    assert!(
        r.is_err(),
        "non-operator asset insurance withdrawal must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no insurance drained by non-operator"
    );
    let (_, g1) = env.market_state();
    assert_eq!(g1.insurance, g0.insurance, "insurance unchanged");
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep - live insurance withdrawal vault pinning (#33/#44/#48): WithdrawInsuranceAsset
// debits live insurance budgets and may rewrite an optional ledger before paying tokens. It must only
// withdraw from the canonical vault, not any vault-authority-owned token fragment.
#[test]
fn v16_attack_withdraw_insurance_asset_rejects_noncanonical_vault() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.top_up_insurance_domain_with_authority(&admin, 0, 100);

    let fake_vault = Pubkey::new_unique();
    env.svm
        .set_account(
            fake_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, env.vault_authority, 100),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let dest = env.token_account_for_mint(env.mint, admin.pubkey(), 0);
    let ledger = env.insurance_ledger_account();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let canonical_vault_before = env.svm.get_account(&env.vault).unwrap();
    let fake_vault_before = env.svm.get_account(&fake_vault).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let ledger_before = env.svm.get_account(&ledger).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsuranceAsset {
            asset_index: 0,
            amount: 40,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(fake_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "WithdrawInsuranceAsset must reject a non-canonical vault fragment"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected insurance fragment withdrawal leaves market accounting unchanged"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        canonical_vault_before,
        "rejected insurance fragment withdrawal leaves canonical vault untouched"
    );
    assert_eq!(
        env.svm.get_account(&fake_vault).unwrap(),
        fake_vault_before,
        "rejected insurance fragment withdrawal leaves fake vault untouched"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        dest_before,
        "rejected insurance fragment withdrawal pays no tokens"
    );
    assert_eq!(
        env.svm.get_account(&ledger).unwrap(),
        ledger_before,
        "rejected insurance fragment withdrawal rewrites no ledger state"
    );

    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsuranceAsset {
            asset_index: 0,
            amount: 40,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&admin],
    )
    .expect("canonical live insurance withdrawal succeeds");
    assert_eq!(env.token_amount(dest), 40);
    assert_eq!(env.token_amount(fake_vault), 100);
    let ledger_state =
        state::read_insurance_ledger(&env.svm.get_account(&ledger).unwrap().data).unwrap();
    assert_eq!(ledger_state.total_withdrawn_atoms, 40);
    assert_eq!(ledger_state.last_observed_insurance_atoms, 60);
    let (_, group) = env.market_state();
    assert_eq!(group.insurance, 60);
    assert_eq!(group.insurance_domain_budget[0], 60);
    assert_eq!(group.vault as u64, env.token_amount(env.vault));
}

// security.md sweep — live asset insurance has a two-key split. The insurance_authority can fund
// the domain and recover terminal insurance after resolution; live asset withdrawals are gated to the
// insurance_operator. This keeps the key split explicit instead of accidentally letting the funding
// authority act as the hot withdrawal operator.
#[test]
fn v16_attack_live_asset_insurance_withdraw_uses_operator_not_authority() {
    let mut env = V16CuEnv::new();
    let insurance_authority = Keypair::new();
    let insurance_operator = Keypair::new();
    env.ensure_signer_account(insurance_operator.pubkey());
    env.activate_asset_with_authorities(
        1,
        1,
        100,
        insurance_authority.pubkey(),
        insurance_operator.pubkey(),
        env.admin.pubkey(),
        env.admin.pubkey(),
    );
    env.top_up_insurance_domain_with_authority(&insurance_authority, 2, 100);
    let (_, group_before) = env.market_state();
    assert_eq!(
        group_before.insurance_domain_budget[2], 100,
        "authority-funded domain makes the withdrawal check non-vacuous"
    );

    let authority_live_withdraw =
        env.try_withdraw_insurance_domain_with_authority(&insurance_authority, 2, 40);
    assert!(
        authority_live_withdraw.is_err(),
        "insurance_authority alone must not be the live domain withdrawal operator"
    );
    let (_, group_after_reject) = env.market_state();
    assert_eq!(
        group_after_reject.insurance_domain_budget[2], 100,
        "rejected authority withdrawal leaves domain budget intact"
    );
    assert_eq!(
        group_after_reject.insurance, group_before.insurance,
        "rejected authority withdrawal leaves insurance intact"
    );
    assert_eq!(
        env.token_amount(env.vault),
        group_before.vault as u64,
        "rejected authority withdrawal leaves real vault tokens intact"
    );

    let operator_dest = env.token_account(insurance_operator.pubkey(), 0);
    let ledger = env.insurance_ledger_account();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawInsuranceAsset {
            asset_index: 1,
            amount: 40,
        },
        vec![
            AccountMeta::new(insurance_operator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(operator_dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger, false),
        ],
        &[&insurance_operator],
    )
    .expect("insurance_operator can live-withdraw the funded domain");
    assert_eq!(
        env.token_amount(operator_dest),
        40,
        "operator receives the live domain withdrawal"
    );
    let ledger_state = state::read_insurance_ledger(&env.svm.get_account(&ledger).unwrap().data)
        .expect("operator withdrawal initializes the insurance ledger");
    assert_eq!(
        ledger_state.authority,
        insurance_authority.pubkey().to_bytes(),
        "domain withdrawal ledger is keyed to the cold insurance authority, not the hot operator"
    );
    assert_eq!(ledger_state.total_withdrawn_atoms, 40);
    assert_eq!(ledger_state.last_observed_insurance_atoms, 60);
    let (_, group_after_operator) = env.market_state();
    assert_eq!(group_after_operator.insurance_domain_budget[2], 60);
    assert_eq!(
        group_after_operator.insurance,
        group_before.insurance - 40,
        "operator withdrawal debits only the funded domain insurance"
    );
    assert_eq!(
        env.token_amount(env.vault),
        group_after_operator.vault as u64,
        "engine vault accounting matches SPL vault after operator withdrawal"
    );
}

// security.md sweep — RebalanceReduce owner gating (#6/#46): RebalanceReduce is OWNER-gated
// self-service risk reduction (with_one_portfolio_view enforces owner signs + matches the portfolio).
// A non-owner must NOT be able to force-reduce a victim's position (griefing); the owner may reduce
// their own. Verifies no permissionless force-close.
#[test]
fn v16_attack_rebalance_reduce_owner_gated() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 5_000, 10_000, 1_000);
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    let basis0 = env.portfolio_state(pa).legs[0].basis_pos_q.get();
    assert!(basis0 != 0, "la opened a position");
    let (_, g0) = env.market_state();

    // ATTACK: a non-owner tries to force-reduce la's position -> reject (owner mismatch).
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    env.svm.expire_blockhash();
    let r_grief = env.send(
        ProgInstruction::RebalanceReduce {
            asset_index: 0,
            reduce_q: POS_SCALE,
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(pa, false),
        ],
        &[&mallory],
    );
    assert!(
        r_grief.is_err(),
        "non-owner force-reduce of a victim's position must reject"
    );
    assert_eq!(
        env.portfolio_state(pa).legs[0].basis_pos_q.get(),
        basis0,
        "victim's position not reduced by attacker"
    );
    assert_eq!(
        env.market_state().1.vault,
        g0.vault,
        "vault unchanged by rejected griefing reduce"
    );

    // LEGITIMATE: the OWNER may reduce their own position (self-service risk reduction).
    env.svm.expire_blockhash();
    let r_owner = env.send(
        ProgInstruction::RebalanceReduce {
            asset_index: 0,
            reduce_q: POS_SCALE,
        },
        vec![
            AccountMeta::new(la.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(pa, false),
        ],
        &[&la],
    );
    assert!(
        r_owner.is_ok(),
        "owner self-reduce should succeed: {:?}",
        r_owner
    );
    assert!(
        env.portfolio_state(pa).legs[0]
            .basis_pos_q
            .get()
            .unsigned_abs()
            < basis0.unsigned_abs(),
        "owner reduced their own position"
    );
    let (_, g1) = env.market_state();
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
    assert_eq!(
        g1.assets[0].oi_eff_long_q, g1.assets[0].oi_eff_short_q,
        "OI still balanced"
    );
}

// security.md sweep - RebalanceReduce market isolation (#2/#44): the owner signature is not enough.
// A portfolio initialized under market A must not be reducible through market B's slab, or a user could
// corrupt market B's OI/accounting while preserving the correct portfolio owner signer.
#[test]
fn v16_attack_rebalance_reduce_rejects_cross_market_portfolio_substitution() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 5_000, 10_000, 1_000);
    let foreign_owner = Keypair::new();
    let foreign = env.create_portfolio(&foreign_owner);
    let foreign_short_owner = Keypair::new();
    let foreign_short = env.create_portfolio(&foreign_short_owner);
    env.deposit(&foreign_owner, foreign, 1_000_000);
    env.deposit(&foreign_short_owner, foreign_short, 1_000_000);
    env.trade_asset_with_cu(
        0,
        &foreign_owner,
        foreign,
        &foreign_short_owner,
        foreign_short,
        POS_SCALE as i128,
        100,
        0,
    );
    assert_eq!(
        env.portfolio_state(foreign)
            .provenance_header
            .market_group_id,
        env.market.to_bytes(),
        "foreign reduce target is genuinely bound to market A"
    );

    let params = V16CuMarketParams::default();
    let (market_b, _vault_authority_b, vault_b) =
        init_independent_market_same_mint(&mut env, params);
    let local_owner = Keypair::new();
    let local = init_portfolio_on_market(
        &mut env,
        market_b,
        &local_owner,
        params.max_portfolio_assets as usize,
    );
    let local_short_owner = Keypair::new();
    let local_short = init_portfolio_on_market(
        &mut env,
        market_b,
        &local_short_owner,
        params.max_portfolio_assets as usize,
    );
    deposit_to_market(&mut env, market_b, vault_b, &local_owner, local, 1_000_000);
    deposit_to_market(
        &mut env,
        market_b,
        vault_b,
        &local_short_owner,
        local_short,
        1_000_000,
    );
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TradeNoCpi {
            asset_index: 0,
            size_q: POS_SCALE as i128,
            exec_price: 100,
            fee_bps: 0,
        },
        vec![
            AccountMeta::new(local_owner.pubkey(), true),
            AccountMeta::new(local_short_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(local, false),
            AccountMeta::new(local_short, false),
        ],
        &[&local_owner, &local_short_owner],
    )
    .expect("open same-market B position");

    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let foreign_before = env.svm.get_account(&foreign).unwrap();
    let local_before = env.svm.get_account(&local).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();
    let reduce_q = POS_SCALE / 2;
    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::RebalanceReduce {
            asset_index: 0,
            reduce_q,
        },
        vec![
            AccountMeta::new(foreign_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(foreign, false),
        ],
        &[&foreign_owner],
    );
    assert!(
        rejected.is_err(),
        "RebalanceReduce must reject a market-A portfolio under market B"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_a_before);
    assert_eq!(env.svm.get_account(&market_b).unwrap(), market_b_before);
    assert_eq!(
        env.svm.get_account(&foreign).unwrap(),
        foreign_before,
        "foreign portfolio is not reduced or re-certified"
    );
    assert_eq!(
        env.svm.get_account(&local).unwrap(),
        local_before,
        "local market-B account is not touched by the rejected substitution"
    );
    assert_eq!(env.svm.get_account(&vault_b).unwrap(), vault_b_before);

    env.svm.expire_blockhash();
    let ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::RebalanceReduce {
            asset_index: 0,
            reduce_q,
        },
        vec![
            AccountMeta::new(local_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(local, false),
        ],
        &[&local_owner],
    );
    assert!(ok.is_ok(), "same-market RebalanceReduce succeeds: {ok:?}");
    let local_after = state::read_portfolio(&env.svm.get_account(&local).unwrap().data)
        .expect("market-B local portfolio");
    assert!(
        active_leg_for_asset(&local_after, 0)
            .basis_pos_q
            .unsigned_abs()
            < POS_SCALE,
        "same-market reduce advanced the local position"
    );
    let (_, market_b_after) =
        state::read_market(&env.svm.get_account(&market_b).unwrap().data).unwrap();
    assert_eq!(
        market_b_after.vault as u64,
        env.token_amount(vault_b),
        "market B accounting still matches SPL custody"
    );
    assert!(market_b_after.vault >= market_b_after.c_tot + market_b_after.insurance);
}

// security.md sweep - ForfeitRecoveryLeg market isolation (#2/#44/#48): the owner signature is not
// enough. In Recovery, forfeiting a leg realizes a loss and clears risk; a market-A portfolio must not be
// forfeit-able through market B's recovery slab even if market B has matching local OI.
#[test]
fn v16_attack_forfeit_recovery_leg_rejects_cross_market_portfolio_substitution() {
    let mut env = V16CuEnv::new();
    let foreign_owner = Keypair::new();
    let foreign = env.create_portfolio(&foreign_owner);
    let foreign_short_owner = Keypair::new();
    let foreign_short = env.create_portfolio(&foreign_short_owner);
    env.deposit(&foreign_owner, foreign, 10_000);
    env.deposit(&foreign_short_owner, foreign_short, 10_000);
    env.trade_with_cu(
        &foreign_owner,
        foreign,
        &foreign_short_owner,
        foreign_short,
        POS_SCALE as i128,
        100,
        0,
    );
    env.mutate_market(|_, group| {
        group.mode = MarketModeV16::Recovery;
        group.recovery_reason = Some(PermissionlessRecoveryReasonV16::BelowProgressFloor);
    });
    assert_eq!(
        env.portfolio_state(foreign)
            .provenance_header
            .market_group_id,
        env.market.to_bytes(),
        "foreign forfeit target is genuinely bound to market A"
    );

    let params = V16CuMarketParams::default();
    let (market_b, _vault_authority_b, vault_b) =
        init_independent_market_same_mint(&mut env, params);
    let local_owner = Keypair::new();
    let local = init_portfolio_on_market(
        &mut env,
        market_b,
        &local_owner,
        params.max_portfolio_assets as usize,
    );
    let local_short_owner = Keypair::new();
    let local_short = init_portfolio_on_market(
        &mut env,
        market_b,
        &local_short_owner,
        params.max_portfolio_assets as usize,
    );
    deposit_to_market(&mut env, market_b, vault_b, &local_owner, local, 10_000);
    deposit_to_market(
        &mut env,
        market_b,
        vault_b,
        &local_short_owner,
        local_short,
        10_000,
    );
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TradeNoCpi {
            asset_index: 0,
            size_q: POS_SCALE as i128,
            exec_price: 100,
            fee_bps: 0,
        },
        vec![
            AccountMeta::new(local_owner.pubkey(), true),
            AccountMeta::new(local_short_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(local, false),
            AccountMeta::new(local_short, false),
        ],
        &[&local_owner, &local_short_owner],
    )
    .expect("open same-market B position");
    let mut market_b_account = env.svm.get_account(&market_b).unwrap();
    let (cfg_b, mut group_b) = state::read_market(&market_b_account.data).unwrap();
    group_b.mode = MarketModeV16::Recovery;
    group_b.recovery_reason = Some(PermissionlessRecoveryReasonV16::BelowProgressFloor);
    state::write_market(&mut market_b_account.data, &cfg_b, &group_b).unwrap();
    env.svm.set_account(market_b, market_b_account).unwrap();
    assert_eq!(
        env.portfolio_state(local).provenance_header.market_group_id,
        market_b.to_bytes(),
        "control forfeit target is genuinely bound to market B"
    );

    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let foreign_before = env.svm.get_account(&foreign).unwrap();
    let local_before = env.svm.get_account(&local).unwrap();
    let vault_a_before = env.svm.get_account(&env.vault).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();
    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ForfeitRecoveryLeg {
            asset_index: 0,
            b_delta_budget: 1,
        },
        vec![
            AccountMeta::new(foreign_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(foreign, false),
        ],
        &[&foreign_owner],
    );
    assert!(
        rejected.is_err(),
        "ForfeitRecoveryLeg must reject a market-A portfolio under market B"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_a_before);
    assert_eq!(env.svm.get_account(&market_b).unwrap(), market_b_before);
    assert_eq!(
        env.svm.get_account(&foreign).unwrap(),
        foreign_before,
        "foreign portfolio is not forfeit-cleared"
    );
    assert_eq!(
        env.svm.get_account(&local).unwrap(),
        local_before,
        "local market-B account is not touched by the rejected substitution"
    );
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_a_before);
    assert_eq!(env.svm.get_account(&vault_b).unwrap(), vault_b_before);

    env.svm.expire_blockhash();
    let ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ForfeitRecoveryLeg {
            asset_index: 0,
            b_delta_budget: 1,
        },
        vec![
            AccountMeta::new(local_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(local, false),
        ],
        &[&local_owner],
    );
    assert!(
        ok.is_ok(),
        "same-market ForfeitRecoveryLeg succeeds: {ok:?}"
    );
    let local_after = env.portfolio_state(local);
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&local_after)),
        "same-market forfeit clears the local recovery leg"
    );
    assert_eq!(local_after.legs[0].basis_pos_q.get(), 0);
    let (_, market_b_after) =
        state::read_market(&env.svm.get_account(&market_b).unwrap().data).unwrap();
    assert_eq!(
        market_b_after.assets[0].oi_eff_long_q, 0,
        "same-market forfeit clears market-B long OI"
    );
    assert_eq!(
        market_b_after.vault as u64,
        env.token_amount(vault_b),
        "market B accounting still matches SPL custody"
    );
}

// security.md sweep — RefineResolvedUnreceiptedBound gating (#6/#30): this wind-down tool (decreases
// the unreceipted resolved claim bound) is admin-only and resolved-mode-only. A non-admin must
// reject, and it must reject in Live mode — no tampering with the resolved payout accounting.
#[test]
fn v16_attack_refine_resolved_bound_admin_and_mode_gated() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    // 1) Live mode: even the admin can't refine (mode != Resolved).
    env.svm.expire_blockhash();
    let r_live = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::RefineResolvedUnreceiptedBound { decrease_num: 1 },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(r_live.is_err(), "refine must reject in Live mode");
    // 2) Resolved mode: a NON-admin can't refine.
    env.resolve();
    env.svm.expire_blockhash();
    let r_nonadmin = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::RefineResolvedUnreceiptedBound { decrease_num: 1 },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&mallory],
    );
    assert!(
        r_nonadmin.is_err(),
        "non-admin refine must reject in resolved mode"
    );
    // user funds still fully recoverable (the rejected refines didn't corrupt the resolved accounting).
    let cr = env.close_resolved(&owner, p);
    assert_eq!(
        env.token_amount(cr),
        1_000_000,
        "user recovers full resolved payout after rejected refines"
    );
}

// security.md sweep - terminal payout bound refinement (#14/#21): even an authorized market admin
// must not be able to over-decrease the unreceipted claim bound. A bad refine would either underflow
// terminal accounting or lower the payout denominator incorrectly, locking or haircutting users.
#[test]
fn v16_attack_refine_resolved_bound_over_decrease_is_atomic() {
    let mut env = V16CuEnv::new();
    let owner_a = Keypair::new();
    let portfolio_a = env.create_portfolio(&owner_a);
    let owner_b = Keypair::new();
    let portfolio_b = env.create_portfolio(&owner_b);
    let owner_c = Keypair::new();
    let portfolio_c = env.create_portfolio(&owner_c);
    env.deposit(&owner_a, portfolio_a, 1_000_000);
    env.deposit(&owner_b, portfolio_b, 1_000_000);
    env.deposit(&owner_c, portfolio_c, 500_000);
    // Two PLAIN-JUNIOR positive-pnl winners (no source backing -> they flow through the junior
    // receipt pool / unreceipted bound, which is what the refine targets), funded by a third
    // account that donated its 500k capital into the junior residual. (Source-backed claims now
    // realize straight to capital and never populate the unreceipted bound.) Conservation holds:
    // vault 2.5M >= c_tot 2.0M + net positive pnl 0.5M.
    {
        let mut m = env.svm.get_account(&env.market).unwrap();
        let mut pa = env.svm.get_account(&portfolio_a).unwrap();
        let mut pb = env.svm.get_account(&portfolio_b).unwrap();
        let mut pc = env.svm.get_account(&portfolio_c).unwrap();
        let (cfg, mut g) = state::read_market(&m.data).unwrap();
        let mut a = state::read_portfolio(&pa.data).unwrap();
        let mut b = state::read_portfolio(&pb.data).unwrap();
        let mut c = state::read_portfolio(&pc.data).unwrap();
        // C donates its capital to the junior residual.
        g.c_tot -= 500_000;
        c.capital = percolator::V16PodU128::new(0);
        c.last_fee_slot = percolator::V16PodU64::new(1);
        // A and B hold matured junior positive pnl.
        a.pnl = percolator::V16PodI128::new(250_000);
        a.last_fee_slot = percolator::V16PodU64::new(1);
        b.pnl = percolator::V16PodI128::new(250_000);
        b.last_fee_slot = percolator::V16PodU64::new(1);
        g.pnl_pos_tot = 500_000;
        g.pnl_matured_pos_tot = 500_000;
        g.pnl_pos_bound_tot = 500_000;
        g.pnl_pos_bound_tot_num = 500_000 * BOUND_SCALE;
        g.mode = MarketModeV16::Resolved;
        g.resolved_slot = 1;
        g.current_slot = 1;
        state::write_market(&mut m.data, &cfg, &g).unwrap();
        state::write_portfolio(&mut pa.data, &a).unwrap();
        state::write_portfolio(&mut pb.data, &b).unwrap();
        state::write_portfolio(&mut pc.data, &c).unwrap();
        env.svm.set_account(env.market, m).unwrap();
        env.svm.set_account(portfolio_a, pa).unwrap();
        env.svm.set_account(portfolio_b, pb).unwrap();
        env.svm.set_account(portfolio_c, pc).unwrap();
    }

    let dest_a = env.close_resolved(&owner_a, portfolio_a);
    assert_eq!(
        env.token_amount(dest_a),
        1_250_000,
        "first winner receives capital + full junior claim and becomes an exact receipt"
    );

    let (_, group_before) = env.market_state();
    let bound = group_before
        .resolved_payout_ledger
        .terminal_claim_bound_unreceipted_num;
    assert!(
        bound > 0,
        "remaining junior user claim contributes to the unreceipted bound"
    );
    assert!(
        group_before
            .resolved_payout_ledger
            .terminal_claim_exact_receipts_num
            > 0,
        "first close converted one winner into an exact receipt"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio_b).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let admin = env.admin.insecure_clone();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::RefineResolvedUnreceiptedBound {
            decrease_num: bound + 1,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "authorized over-decrease of resolved payout bound must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected over-refine leaves resolved market accounting byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&portfolio_b).unwrap(),
        portfolio_before,
        "rejected over-refine leaves user payout state byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "rejected over-refine moves no custody"
    );

    let dest = env.close_resolved(&owner_b, portfolio_b);
    assert_eq!(
        env.token_amount(dest),
        1_250_000,
        "remaining user still recovers the full terminal payout after rejected over-refine"
    );
}

// Full-interface rollback sweep: RefineResolvedUnreceiptedBound is a market-only terminal mutator.
// Pin that an engine shape rejection becomes an instruction error and rolls back its payout edit.
#[test]
fn v16_attack_refine_resolved_bound_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new();
    env.mutate_market(|_, group| {
        group.mode = MarketModeV16::Resolved;
        group.resolved_slot = 1;
        group.current_slot = 1;
        group.payout_snapshot_captured = true;
        group.payout_snapshot = 100;
        group.resolved_payout_ledger = ResolvedPayoutLedgerV16 {
            snapshot_residual: 100,
            terminal_claim_exact_receipts_num: 0,
            terminal_claim_bound_unreceipted_num: 100 * BOUND_SCALE,
            current_payout_rate_num: 100 * BOUND_SCALE,
            current_payout_rate_den: 100 * BOUND_SCALE,
            snapshot_slot: 1,
            payout_halted: false,
            finalized: false,
        };
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
    });

    let admin = env.admin.insecure_clone();
    let before = env.svm.get_account(&env.market).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::RefineResolvedUnreceiptedBound {
            decrease_num: BOUND_SCALE,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "RefineResolvedUnreceiptedBound must not persist an invalid final market shape"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before,
        "failed refine must roll back payout accounting and invalid shape"
    );

    env.mutate_market(|_, group| {
        group.insurance_domain_budget[0] = group.insurance;
    });
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::RefineResolvedUnreceiptedBound {
            decrease_num: BOUND_SCALE,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        accepted.is_ok(),
        "valid resolved-bound refine remains live after invalid-shape rejection: {accepted:?}"
    );
    assert_eq!(
        env.market_state()
            .1
            .resolved_payout_ledger
            .terminal_claim_bound_unreceipted_num,
        99 * BOUND_SCALE
    );
}

// security.md sweep — TopUpInsuranceDomain authorization (#6): a per-domain insurance top-up is gated
// to the domain's insurance_authority (v16_program.rs:6577 expect_live_authority). A non-authority
// must reject — no manipulating a domain's insurance/budget accounting by an unauthorized caller.
#[test]
fn v16_attack_topup_insurance_domain_authority_gated() {
    let mut env = V16CuEnv::new();
    let (_, g0) = env.market_state();
    // a non-authority donor tries to top up domain 0's insurance -> reject (Unauthorized).
    let donor = Keypair::new();
    env.ensure_signer_account(donor.pubkey());
    let src = env.token_account_for_mint(env.mint, donor.pubkey(), 500);
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TopUpInsuranceDomain {
            domain: 0,
            amount: 500,
        },
        vec![
            AccountMeta::new(donor.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(src, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&donor],
    );
    assert!(
        r.is_err(),
        "non-authority domain insurance top-up must reject"
    );
    assert_eq!(env.token_amount(src), 500, "donor source untouched");
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.insurance, g0.insurance,
        "insurance unchanged by unauthorized top-up"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}
// security.md sweep — recovery-tool gating (#6): ForfeitRecoveryLeg is owner-gated
// (with_one_portfolio_view enforces owner signs + matches the portfolio). FinalizeResetSide is
// market-only and permissionless, so a bogus victim-portfolio account list must not be accepted.
#[test]
fn v16_attack_recovery_tools_owner_gated() {
    let mut env = V16CuEnv::new();
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    let basis0 = env.portfolio_state(pa).legs[0].basis_pos_q.get();
    let (_, g0) = env.market_state();
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());

    // non-owner ForfeitRecoveryLeg on la's portfolio -> reject (owner mismatch).
    env.svm.expire_blockhash();
    let r1 = env.send(
        ProgInstruction::ForfeitRecoveryLeg {
            asset_index: 0,
            b_delta_budget: 1,
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(pa, false),
        ],
        &[&mallory],
    );
    assert!(r1.is_err(), "non-owner ForfeitRecoveryLeg must reject");

    // malformed FinalizeResetSide with a victim portfolio account list -> reject.
    env.svm.expire_blockhash();
    let r2 = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(pa, false),
        ],
        &[&mallory],
    );
    assert!(
        r2.is_err(),
        "FinalizeResetSide must reject the wrong account layout"
    );

    // victim's position untouched, conservation.
    assert_eq!(
        env.portfolio_state(pa).legs[0].basis_pos_q.get(),
        basis0,
        "victim's position untouched by recovery-tool griefing"
    );
    let (_, g1) = env.market_state();
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert_eq!(
        g1.assets[0].oi_eff_long_q, g1.assets[0].oi_eff_short_q,
        "OI still balanced"
    );
}

// security.md sweep — permissionless reset finalizer (#31/#44): anyone may finalize a reset-pending
// side, but only after all engine reset blockers for that side are zero. A public finalizer must not
// be able to unlock trading while positions, stale accounts, pending obligations, or domain-loss
// barriers still need recovery/cranking.
#[test]
fn v16_attack_finalize_reset_side_requires_empty_side_counts() {
    let mut env = V16CuEnv::new();
    env.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::ResetPending;
        group.assets[0].stored_pos_count_long = 1;
    });

    env.svm.expire_blockhash();
    let r_stored = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        r_stored.is_err(),
        "stored positions must block reset finalization"
    );
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::ResetPending,
        "rejected finalization must leave the side locked",
    );

    env.mutate_market(|_, group| {
        group.assets[0].stored_pos_count_long = 0;
        group.assets[0].stale_account_count_long = 1;
    });
    env.svm.expire_blockhash();
    let r_stale = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        r_stale.is_err(),
        "stale accounts must block reset finalization"
    );
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::ResetPending,
        "stale-count rejection must leave the side locked",
    );

    env.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::ResetPending;
        group.assets[0].stale_account_count_long = 0;
        group.assets[0].pending_obligation_count_long = 1;
    });
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::ResetPending,
        "test precondition: side is reset-pending",
    );
    assert_eq!(
        env.market_state().1.assets[0].pending_obligation_count_long,
        1,
        "test precondition: pending obligation is persisted",
    );
    {
        let mut raw = env.svm.get_account(&env.market).unwrap();
        let (_cfg, view) = state::market_view_mut(&mut raw.data).unwrap();
        let asset = view.markets[0].engine.asset.try_to_runtime().unwrap();
        assert_eq!(
            asset.pending_obligation_count_long, 1,
            "test precondition: zero-copy view sees pending obligation",
        );
        assert_eq!(
            asset.mode_long,
            SideModeV16::ResetPending,
            "test precondition: zero-copy view sees reset-pending side",
        );
    }
    env.svm.expire_blockhash();
    let r_obligation = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        r_obligation.is_err(),
        "pending obligations must block reset finalization",
    );
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::ResetPending,
        "pending-obligation rejection must leave the side locked",
    );

    env.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::ResetPending;
        group.assets[0].pending_obligation_count_long = 0;
        group.pending_domain_loss_barriers[0] = 1;
    });
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::ResetPending,
        "test precondition: side is reset-pending",
    );
    assert_eq!(
        env.market_state().1.pending_domain_loss_barriers[0],
        1,
        "test precondition: domain-loss barrier is persisted",
    );
    env.svm.expire_blockhash();
    let r_barrier = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        r_barrier.is_err(),
        "pending domain-loss barriers must block reset finalization",
    );
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::ResetPending,
        "domain-barrier rejection must leave the side locked",
    );

    env.mutate_market(|_, group| {
        group.pending_domain_loss_barriers[0] = 0;
    });
    env.svm.expire_blockhash();
    let r_empty = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        r_empty.is_ok(),
        "anyone may finalize once the side is empty: {:?}",
        r_empty
    );
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::Normal,
        "empty reset-pending side unlocks",
    );
}

// Full-interface rollback sweep: FinalizeResetSide is market-only and permissionless, so it does not
// go through with_one_portfolio_view's wrapper-side validate_shape tail. Pin the engine-error boundary.
#[test]
fn v16_attack_finalize_reset_side_rejects_invalid_final_market_shape() {
    let mut env = V16CuEnv::new();
    env.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::ResetPending;
        group.insurance_domain_budget[0] = group.insurance.saturating_add(1);
    });
    let before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        rejected.is_err(),
        "FinalizeResetSide must not persist an invalid final market shape"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before,
        "failed reset finalization must roll back the mode change and invalid shape"
    );

    env.mutate_market(|_, group| {
        group.insurance_domain_budget[0] = group.insurance;
    });
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        accepted.is_ok(),
        "valid empty reset side remains finalizable after invalid-shape rejection: {accepted:?}"
    );
    assert_eq!(
        env.market_state().1.assets[0].mode_long,
        SideModeV16::Normal
    );
}

// security.md sweep - unsigned reset finalizer must not unlock drain-only sides (#30/#48):
// FinalizeResetSide is intentionally permissionless, and Normal is an idempotent no-op, but DrainOnly
// is a distinct risk throttle. A public caller must not be able to treat DrainOnly like ResetPending
// and reopen risk by finalizing it.
#[test]
fn v16_attack_finalize_reset_side_cannot_unlock_drain_only_modes() {
    let mut env = V16CuEnv::new();
    env.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::DrainOnly;
        group.assets[0].mode_short = SideModeV16::DrainOnly;
    });
    let before = env.svm.get_account(&env.market).unwrap();

    for (side, label) in [(0u8, "long"), (1u8, "short")] {
        env.svm.expire_blockhash();
        let rejected = env.send(
            ProgInstruction::FinalizeResetSide {
                asset_index: 0,
                side,
            },
            vec![AccountMeta::new(env.market, false)],
            &[],
        );
        assert!(
            rejected.is_err(),
            "permissionless finalizer must reject {label} DrainOnly mode"
        );
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            before,
            "rejected {label} DrainOnly finalization must leave the market unchanged"
        );
    }

    let (_, group) = env.market_state();
    assert_eq!(group.assets[0].mode_long, SideModeV16::DrainOnly);
    assert_eq!(group.assets[0].mode_short, SideModeV16::DrainOnly);

    // Control: the short-side ResetPending path still finalizes when the side is genuinely empty.
    let mut control = V16CuEnv::new();
    control.mutate_market(|_, group| {
        group.assets[0].mode_short = SideModeV16::ResetPending;
    });
    let risk_epoch_before = control.market_state().1.risk_epoch;
    control.svm.expire_blockhash();
    let accepted = control.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 1,
        },
        vec![AccountMeta::new(control.market, false)],
        &[],
    );
    assert!(
        accepted.is_ok(),
        "empty short ResetPending side remains permissionlessly finalizable: {accepted:?}"
    );
    let (_, control_group) = control.market_state();
    assert_eq!(control_group.assets[0].mode_short, SideModeV16::Normal);
    assert_eq!(
        control_group.risk_epoch,
        risk_epoch_before + 1,
        "real reset finalization bumps the risk epoch exactly once"
    );
}

// LoF/terminal-state sweep: FinalizeResetSide is permissionless and mutates side mode/risk_epoch for
// ResetPending sides. After resolution, terminal state must be frozen except for the explicit resolved
// payout/insurance wind-down routes; a public finalizer must not be able to rewrite side mode or risk
// epoch after ResolveMarket has captured the terminal market mode.
#[test]
fn v16_attack_finalize_reset_side_rejects_after_resolution() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::ResetPending;
    });

    env.svm.expire_blockhash();
    let resolved = env.send(
        ProgInstruction::ResolveMarket,
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        resolved.is_ok(),
        "test setup must reach a resolved market with a pending side: {resolved:?}"
    );
    let before = env.svm.get_account(&env.market).unwrap();
    let before_group = env.market_state().1;
    assert_eq!(before_group.mode, MarketModeV16::Resolved);
    assert_eq!(before_group.assets[0].mode_long, SideModeV16::ResetPending);

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        rejected.is_err(),
        "permissionless reset finalization must not mutate a resolved market"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before,
        "rejected post-resolve finalization leaves terminal market bytes unchanged"
    );

    let mut live = V16CuEnv::new();
    live.mutate_market(|_, group| {
        group.assets[0].mode_long = SideModeV16::ResetPending;
    });
    let risk_epoch_before = live.market_state().1.risk_epoch;
    live.svm.expire_blockhash();
    let accepted = live.send(
        ProgInstruction::FinalizeResetSide {
            asset_index: 0,
            side: 0,
        },
        vec![AccountMeta::new(live.market, false)],
        &[],
    );
    assert!(
        accepted.is_ok(),
        "live empty ResetPending side must remain finalizable: {accepted:?}"
    );
    let live_group = live.market_state().1;
    assert_eq!(live_group.assets[0].mode_long, SideModeV16::Normal);
    assert_eq!(live_group.risk_epoch, risk_epoch_before + 1);
}

// security.md sweep — operation-sequence conservation (#32/#33 fuzz-lite): a long varied sequence of
// deposits/trades/flips/price-moves/cranks/withdrawals must never drift the core invariants. Checks
// real-vault==accounting, c_tot==Σcapitals, senior conservation, OI balance at every checkpoint.
#[test]
fn v16_attack_long_sequence_conservation() {
    let mut env = V16CuEnv::new();
    env.configure_auth_mark_with_cu(0, 100);
    let k: Vec<Keypair> = (0..4).map(|_| Keypair::new()).collect();
    let p: Vec<Pubkey> = k.iter().map(|kp| env.create_portfolio(kp)).collect();
    for i in 0..4 {
        env.deposit(&k[i], p[i], 1_000_000);
    }
    let check = |env: &V16CuEnv, tag: &str| {
        let (_, g) = env.market_state();
        let sum: u128 = p
            .iter()
            .map(|pp| {
                state::read_portfolio(&env.svm.get_account(pp).unwrap().data)
                    .unwrap()
                    .capital
                    .get()
            })
            .sum();
        assert_eq!(g.c_tot, sum, "[{}] c_tot == Σcapitals", tag);
        assert!(
            g.vault >= g.c_tot + g.insurance,
            "[{}] senior conservation",
            tag
        );
        assert_eq!(
            g.vault as u64,
            env.token_amount(env.vault),
            "[{}] accounting vault == real vault balance",
            tag
        );
        assert_eq!(
            g.assets[0].oi_eff_long_q, g.assets[0].oi_eff_short_q,
            "[{}] OI balanced",
            tag
        );
    };
    check(&env, "deposits");
    // trades among the 4 accounts (open, partial close, flip).
    env.trade_asset_with_cu(
        0,
        &k[0],
        p[0],
        &k[1],
        p[1],
        (5_000 * POS_SCALE) as i128,
        100,
        0,
    );
    check(&env, "t1");
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(
        0,
        &k[2],
        p[2],
        &k[3],
        p[3],
        (3_000 * POS_SCALE) as i128,
        100,
        0,
    );
    check(&env, "t2");
    // price move + cranks.
    env.svm.warp_to_slot(10);
    env.push_auth_mark_with_cu(10, 108);
    for slot in [10u64, 11] {
        env.svm.warp_to_slot(slot);
        for pp in &p {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(*pp, false),
                ],
                &[],
            );
        }
    }
    check(&env, "after move+crank");
    // a deposit mid-stream + a flip.
    env.svm.expire_blockhash();
    env.deposit(&k[0], p[0], 200_000);
    check(&env, "mid-deposit");
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(
        0,
        &k[1],
        p[1],
        &k[0],
        p[0],
        (2_000 * POS_SCALE) as i128,
        108,
        0,
    );
    check(&env, "flip");
    // price back, settle, close everyone out.
    env.svm.warp_to_slot(20);
    env.push_auth_mark_with_cu(20, 100);
    for slot in 20u64..=25 {
        env.svm.warp_to_slot(slot);
        for pp in &p {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(*pp, false),
                ],
                &[],
            );
        }
    }
    check(&env, "settled");
    // total real vault still equals accounting; no value created across the whole sequence.
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "final: accounting == real vault"
    );
    assert!(
        g.vault <= 4_200_000,
        "no value created (total deposited 4*1M + 200k)"
    );
}

// security.md sweep — cross-margin divergent close conservation (#33/#22): a portfolio long on asset0
// and short on asset1, both winning under divergent moves, closes both legs. Value must be conserved
// through the multi-asset settlement+close (no leakage, senior conservation, accounting==real vault).
#[test]
fn v16_attack_cross_margin_divergent_close_conserves() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    let cfg = |env: &mut V16CuEnv, ix: ProgInstruction| {
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ix,
            vec![
                AccountMeta::new(env.admin.pubkey(), true),
                AccountMeta::new(env.market, false),
            ],
            &[&env.admin],
        )
        .expect("mark cfg");
    };
    cfg(
        &mut env,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: 100,
        },
    );
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 2_000_000);
    env.deposit(&lb, pb, 2_000_000);
    // la LONG asset0, SHORT asset1.
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, -(POS_SCALE as i128), 100, 0);
    // asset0 UP (la long wins), asset1 DOWN (la short wins) -> la wins both, lb loses both.
    env.svm.warp_to_slot(10);
    env.push_auth_mark_with_cu(10, 110);
    cfg(
        &mut env,
        ProgInstruction::PushAuthMark {
            asset_index: 1,
            now_slot: 10,
            mark_e6: 90,
        },
    );
    for slot in [10u64, 11] {
        env.svm.warp_to_slot(slot);
        for ai in [0u16, 1] {
            for p in [pa, pb] {
                env.svm.expire_blockhash();
                let _ = env.send(
                    ProgInstruction::PermissionlessCrank {
                        now_slot: slot,
                        close_q: 0,
                        observations: crank_observations(ai),
                    },
                    vec![
                        AccountMeta::new(env.payer.pubkey(), true),
                        AccountMeta::new(env.market, false),
                        AccountMeta::new(p, false),
                    ],
                    &[],
                );
            }
        }
    }
    // close both legs at the moved prices.
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, -(POS_SCALE as i128), 110, 0);
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, POS_SCALE as i128, 90, 0);
    let a = state::read_portfolio(&env.svm.get_account(&pa).unwrap().data).unwrap();
    let b = state::read_portfolio(&env.svm.get_account(&pb).unwrap().data).unwrap();
    let (_, g) = env.market_state();
    assert_eq!(g.assets[0].oi_eff_long_q, 0, "asset0 flat after close");
    assert_eq!(g.assets[1].oi_eff_long_q, 0, "asset1 flat after close");
    let total_equity =
        (a.capital.get() as i128 + a.pnl.get()) + (b.capital.get() as i128 + b.pnl.get());
    assert_eq!(
        total_equity, 4_000_000,
        "total equity conserved through divergent cross-asset close"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault balance"
    );
    let residual = g.vault as i128 - g.c_tot as i128 - g.insurance as i128;
    assert!(
        residual >= a.pnl.get().max(0) + b.pnl.get().max(0),
        "positive pnl backed by residual"
    );
}

// security.md sweep — maintenance fee accrual on a positioned account (#32/#30): fees accrue
// INCREMENTALLY, bounded by max_accrual_dt per sync (anti-retroactivity: a cranker cannot charge a
// huge retroactive fee in one jump). Each increment must conserve (capital -> insurance), leave the
// position intact, and keep senior conservation + accounting==real-vault.
#[test]
fn v16_attack_maintenance_fee_with_open_position_conserves() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 5_000, 10_000, 1_000, 58,
    );
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.update_maintenance_fee_policy_with_cu(0);
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    let basis0 = env.portfolio_state(pa).legs[0].basis_pos_q.get();
    let cap0 = env.portfolio_state(pa).capital.get();
    let (_, g0) = env.market_state();

    // accrue fees incrementally across several slots (each crank+sync advances bounded by max_accrual_dt).
    let mut max_step: u128 = 0;
    let mut prev_cap = cap0;
    for slot in 1..=6u64 {
        env.svm.warp_to_slot(slot);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(pa, false),
            ],
            &[],
        );
        env.svm.expire_blockhash();
        let _ = env.try_sync_maintenance_fee_with_cu(pa, None, slot);
        let cap = env.portfolio_state(pa).capital.get();
        let step = prev_cap - cap;
        max_step = max_step.max(step);
        prev_cap = cap;
    }
    let cap_final = env.portfolio_state(pa).capital.get();
    let fee = cap0 - cap_final;
    let (_, g1) = env.market_state();
    assert!(
        fee > 0,
        "maintenance fee accrued on the positioned account (non-vacuous)"
    );
    // anti-retroactivity: no single step charges more than max_accrual_dt(1) * fee_per_slot(58) (with slack).
    assert!(
        max_step <= 58 * 3,
        "per-step fee bounded by the dt cap (no huge retroactive jump): max_step={}",
        max_step
    );
    // conservation: the fee moved capital -> insurance exactly.
    assert_eq!(
        g1.insurance,
        g0.insurance + fee,
        "fee moved capital -> insurance exactly"
    );
    assert_eq!(
        g1.c_tot,
        g0.c_tot - fee,
        "c_tot decreased by exactly the fee"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged (fee internal)");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault balance"
    );
    assert_eq!(
        env.portfolio_state(pa).legs[0].basis_pos_q.get(),
        basis0,
        "fee accrual did not disturb the position"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
    assert_eq!(
        g1.assets[0].oi_eff_long_q, g1.assets[0].oi_eff_short_q,
        "OI still balanced"
    );
    assert_domain_budget_remaining_total_consistent(&g1, "maintenance fee open position");
}
// security.md sweep — deposit with parked pnl (#32/#33): depositing while holding junior (parked) pnl
// must credit capital exactly and leave the pnl and its residual backing untouched. No double-count,
// no disturbance of the junior pnl, conservation holds.
#[test]
fn v16_attack_deposit_with_parked_pnl_clean() {
    let mut env = V16CuEnv::new();
    env.configure_auth_mark_with_cu(0, 100);
    let lo_owner = Keypair::new();
    let lo = env.create_portfolio(&lo_owner);
    let sh_owner = Keypair::new();
    let sh = env.create_portfolio(&sh_owner);
    env.deposit(&lo_owner, lo, 1_000_000);
    env.deposit(&sh_owner, sh, 1_000_000);
    env.trade_asset_with_cu(
        0,
        &lo_owner,
        lo,
        &sh_owner,
        sh,
        (10_000 * POS_SCALE) as i128,
        100,
        0,
    );
    // price up -> long accrues parked pnl; settle.
    env.svm.warp_to_slot(10);
    env.push_auth_mark_with_cu(10, 110);
    for slot in [10u64, 11] {
        env.svm.warp_to_slot(slot);
        for p in [sh, lo] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    let a0 = env.portfolio_state(lo);
    assert!(a0.pnl.get() > 0, "long has parked pnl (non-vacuous)");
    let (_, g0) = env.market_state();
    let resid0 = g0.vault as i128 - g0.c_tot as i128 - g0.insurance as i128;

    // deposit MORE while holding the parked pnl.
    env.svm.expire_blockhash();
    env.deposit(&lo_owner, lo, 500_000);
    let a1 = env.portfolio_state(lo);
    let (_, g1) = env.market_state();
    assert_eq!(
        a1.capital.get(),
        a0.capital.get() + 500_000,
        "capital credited exactly by the deposit"
    );
    assert_eq!(
        a1.pnl.get(),
        a0.pnl.get(),
        "parked pnl UNCHANGED by the deposit (no double-count/disturbance)"
    );
    assert_eq!(
        g1.vault,
        g0.vault + 500_000,
        "vault grew by exactly the deposit"
    );
    assert_eq!(
        g1.c_tot,
        g0.c_tot + 500_000,
        "c_tot grew by exactly the deposit"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault balance"
    );
    // the parked pnl is still backed by (at least) the same residual.
    let resid1 = g1.vault as i128 - g1.c_tot as i128 - g1.insurance as i128;
    assert_eq!(
        resid1, resid0,
        "residual backing of the junior pnl unchanged by the deposit"
    );
    assert!(
        resid1 >= a1.pnl.get().max(0),
        "junior pnl still backed by residual"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — two-sided trade fee symmetry (#33/#37): a trade fee is charged to BOTH sides;
// each must pay exactly the same amount (no rounding asymmetry favoring one side), and the total fee
// must equal the insurance increase. Conservation: vault unchanged (fee is internal capital->insurance).
#[test]
fn v16_attack_two_sided_trade_fee_symmetric() {
    let mut env = V16CuEnv::new(); // max_trading_fee_bps = 10_000
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    let (_, g0) = env.market_state();
    let ca0 = env.portfolio_state(pa).capital.get();
    let cb0 = env.portfolio_state(pb).capital.get();
    // trade with a fee (notional 100 @ POS_SCALE, 100 bps).
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 100);
    let ca1 = env.portfolio_state(pa).capital.get();
    let cb1 = env.portfolio_state(pb).capital.get();
    let (_, g1) = env.market_state();
    let fee_a = ca0 - ca1;
    let fee_b = cb0 - cb1;
    assert!(fee_a > 0, "a fee was charged (non-vacuous)");
    assert_eq!(
        fee_a, fee_b,
        "both sides pay EXACTLY the same fee (no rounding asymmetry)"
    );
    // total fee -> insurance exactly; vault unchanged.
    assert_eq!(
        g1.insurance,
        g0.insurance + fee_a + fee_b,
        "total two-sided fee accrued to insurance"
    );
    assert_eq!(
        g1.c_tot,
        g0.c_tot - fee_a - fee_b,
        "c_tot decreased by exactly the total fee"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged (fee internal)");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — fee redirect policy (#6/#33): fee_redirect_to_market_0_bps splits fees to
// market 0's domain (INTERNAL), not an external party. It must be admin-gated, bounded to <=10000,
// and must never leak value out of the protocol (vault unchanged on a fee'd trade).
#[test]
fn v16_attack_fee_redirect_gated_bounded_no_leak() {
    let mut env = V16CuEnv::new();
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    // non-admin can't set the redirect.
    env.svm.expire_blockhash();
    let r_auth = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateFeeRedirectPolicy {
            redirect_bps: 5_000,
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&mallory],
    );
    assert!(r_auth.is_err(), "non-admin fee redirect update must reject");
    // out-of-range redirect rejected (admin).
    env.svm.expire_blockhash();
    let r_oob = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateFeeRedirectPolicy {
            redirect_bps: 20_000,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(r_oob.is_err(), "redirect_bps > 10000 must reject");
    // valid redirect set by admin.
    env.svm.expire_blockhash();
    let r_ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateFeeRedirectPolicy {
            redirect_bps: 5_000,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(
        r_ok.is_ok(),
        "admin redirect update should succeed: {:?}",
        r_ok
    );

    // a fee'd trade with redirect active: fee stays INTERNAL (vault unchanged, no external leak).
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    let (_, g0) = env.market_state();
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 100);
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.vault, g0.vault,
        "fee with redirect stays internal: vault unchanged (no external leak)"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
    // total value (c_tot + insurance + any domain attribution) still bounded by the vault.
    assert!(
        g1.c_tot + g1.insurance <= g1.vault,
        "no value created by the redirect split"
    );
}

// security.md sweep — UpdateBaseUnitMints guard (#44/#48): the collateral mint can only be changed
// when the market holds NO funds (vault==0 && c_tot==0 && insurance==0). Changing it with deposits
// present would strand them (mint confusion). Must reject while funds exist, and for a non-authority.
#[test]
fn v16_attack_update_base_unit_mints_guarded() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000); // market now holds funds
    let new_primary = env.create_mint();
    let new_secondary = env.create_mint();
    let (cfg0, g0) = env.market_state();

    // authority tries to change the collateral mint WHILE funds exist -> reject.
    env.svm.expire_blockhash();
    let r_funds = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: new_primary.to_bytes(),
            secondary_mint: new_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(new_primary, false),
            AccountMeta::new_readonly(new_secondary, false),
        ],
        &[&env.admin],
    );
    assert!(
        r_funds.is_err(),
        "changing collateral mint with funds present must reject"
    );

    // a non-authority also can't change it.
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    env.svm.expire_blockhash();
    let r_auth = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: new_primary.to_bytes(),
            secondary_mint: new_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(new_primary, false),
            AccountMeta::new_readonly(new_secondary, false),
        ],
        &[&mallory],
    );
    assert!(r_auth.is_err(), "non-authority mint change must reject");

    // collateral mint unchanged; funds intact and still withdrawable in the ORIGINAL mint.
    let (cfg1, g1) = env.market_state();
    assert_eq!(
        cfg1.collateral_mint, cfg0.collateral_mint,
        "collateral mint unchanged by rejected updates"
    );
    assert_eq!(g1.vault, g0.vault, "funds intact");
    let (d, _) = env.withdraw_with_cu(&owner, p, 500_000);
    assert_eq!(
        env.token_amount(d),
        500_000,
        "funds still withdrawable in the original mint"
    );
}

// full-interface sweep (cron18) — cross-market portfolio substitution must NOT drain a foreign market's
// vault. A portfolio is bound to its market via provenance_header.market_group_id (= the market account
// key, stamped at InitPortfolio); validate_with_market (called on every fund path) rejects a mismatch.
// Attack: deposit into market A (crediting P_a.capital.get()), then withdraw the same amount from a SECOND
// market B's vault using P_a — would drain market B's other users if the binding were missing.
#[test]
fn v16_attack_cross_market_portfolio_cannot_drain_foreign_vault() {
    let mut env = V16CuEnv::new();
    // Market A: attacker's portfolio P_a holds real capital (bound to market A).
    let attacker = Keypair::new();
    let pa = env.create_portfolio(&attacker);
    env.deposit(&attacker, pa, 1_000_000);

    // --- Stand up an independent market B in the SAME svm, reusing the same mint. ---
    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let vault_b = canonical_vault_ata(vault_authority_b, env.mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, vault_authority_b, 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&env.admin],
    )
    .expect("init market B");

    // Market B: a legit victim funds B's vault (1_000_000) via a portfolio bound to B.
    let victim = Keypair::new();
    let pb = Pubkey::new_unique();
    env.ensure_signer_account(victim.pubkey());
    env.svm
        .set_account(
            pb,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; env.portfolio_account_len],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(victim.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
        ],
        &[&victim],
    )
    .expect("init pb on market B");
    let src_b = Pubkey::new_unique();
    env.svm
        .set_account(
            src_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, victim.pubkey(), 1_000_000),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::Deposit { amount: 1_000_000 },
        vec![
            AccountMeta::new(victim.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
            AccountMeta::new(src_b, false),
            AccountMeta::new(vault_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&victim],
    )
    .expect("victim deposits into market B");
    assert_eq!(
        env.token_amount(vault_b),
        1_000_000,
        "market B vault funded"
    );

    // --- ATTACK: withdraw from market B's vault using the market-A-bound portfolio P_a. ---
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, attacker.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::Withdraw { amount: 1_000_000 },
        vec![
            AccountMeta::new(attacker.pubkey(), true),
            AccountMeta::new(market_b, false), // foreign market B
            AccountMeta::new(pa, false),       // portfolio bound to market A
            AccountMeta::new(dest, false),
            AccountMeta::new(vault_b, false), // market B's vault
            AccountMeta::new_readonly(vault_authority_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&attacker],
    );
    assert!(
        r.is_err(),
        "a portfolio bound to market A must NOT withdraw from market B's vault (provenance mismatch)"
    );
    assert_eq!(
        env.token_amount(vault_b),
        1_000_000,
        "market B vault must be intact after the cross-market drain attempt"
    );
    assert_eq!(env.token_amount(dest), 0, "attacker received nothing");

    // Make P_a otherwise closeable on its real market, then try to close it through market B.
    // If the market provenance check were missing, this could zero the market-A portfolio while
    // sweeping its rent to market B and leaving market A's materialized count stale.
    let (a_dest, _) = env.withdraw_with_cu(&attacker, pa, 1_000_000);
    assert_eq!(
        env.token_amount(a_dest),
        1_000_000,
        "market-A funds recovered before close probe"
    );
    assert_eq!(
        env.portfolio_state(pa).capital.get(),
        0,
        "P_a is flat and otherwise closeable"
    );
    let pa_before_close = env.svm.get_account(&pa).unwrap();
    let market_b_before_close = env.svm.get_account(&market_b).unwrap();
    env.svm.expire_blockhash();
    let close_foreign = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ClosePortfolio,
        vec![
            AccountMeta::new(attacker.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pa, false),
        ],
        &[&attacker],
    );
    assert!(
        close_foreign.is_err(),
        "market B must not close a market-A-bound portfolio"
    );
    assert_eq!(
        env.svm.get_account(&pa).unwrap(),
        pa_before_close,
        "foreign close leaves P_a intact"
    );
    assert_eq!(
        env.svm.get_account(&market_b).unwrap(),
        market_b_before_close,
        "foreign close sweeps no rent to market B and mutates no counter"
    );

    env.close_portfolio_with_cu(&attacker, pa);
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        0,
        "real market can still close P_a"
    );
}

// full-interface sweep (cron/audit-scan-off) — every public trade entrypoint must reject a portfolio
// initialized under a different market, even though the account id and owner signer are otherwise
// correct. This proves the default deployed build does not rely on the engine's cfg-gated
// `audit-scan` helpers for trade provenance. The CPI probes use a faithful matcher reply, so the only
// rejected precondition is the foreign-market portfolio binding; the entire tx must roll back,
// including matcher ctx writes.
#[test]
fn v16_attack_trade_paths_reject_cross_market_portfolio_substitution() {
    let mut env = V16CuEnv::new();
    let attacker = Keypair::new();
    let pa = env.create_portfolio(&attacker);
    env.deposit(&attacker, pa, 1_000_000);

    let params = V16CuMarketParams::default();
    let (market_b, _vault_authority_b, vault_b) =
        init_independent_market_same_mint(&mut env, params);
    let victim = Keypair::new();
    let pb = init_portfolio_on_market(
        &mut env,
        market_b,
        &victim,
        params.max_portfolio_assets as usize,
    );
    deposit_to_market(&mut env, market_b, vault_b, &victim, pb, 1_000_000);
    assert_eq!(
        env.token_amount(vault_b),
        1_000_000,
        "market B vault is genuinely funded"
    );
    assert_eq!(
        env.portfolio_state(pa).provenance_header.market_group_id,
        env.market.to_bytes(),
        "attack account is bound to market A"
    );
    assert_eq!(
        env.portfolio_state(pb).provenance_header.market_group_id,
        market_b.to_bytes(),
        "counterparty is bound to market B"
    );

    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &market_b,
        &pb,
        &victim.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let mut ctx_data = vec![0u8; MATCHER_CONTEXT_LEN];
    ctx_data[0] = 9; // hostile fixture's faithful mode: returns a valid oracle-priced fill.
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: ctx_data,
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    {
        let mut reject_atomically =
            |label: &str, ix: ProgInstruction, accounts: Vec<AccountMeta>, signers: &[&Keypair]| {
                let market_a_before = env.svm.get_account(&env.market).unwrap();
                let market_b_before = env.svm.get_account(&market_b).unwrap();
                let pa_before = env.svm.get_account(&pa).unwrap();
                let pb_before = env.svm.get_account(&pb).unwrap();
                let vault_b_before = env.svm.get_account(&vault_b).unwrap();
                let ctx_before = env.svm.get_account(&ctx).unwrap();
                env.svm.expire_blockhash();
                let result = send_tx(
                    &mut env.svm,
                    env.program_id,
                    &env.payer,
                    ix,
                    accounts,
                    signers,
                );
                assert!(
                    result.is_err(),
                    "{label} must reject a market-A portfolio under market B"
                );
                assert_eq!(
                    env.svm.get_account(&env.market).unwrap(),
                    market_a_before,
                    "{label}: market A unchanged"
                );
                assert_eq!(
                    env.svm.get_account(&market_b).unwrap(),
                    market_b_before,
                    "{label}: market B unchanged"
                );
                assert_eq!(
                    env.svm.get_account(&pa).unwrap(),
                    pa_before,
                    "{label}: foreign portfolio unchanged"
                );
                assert_eq!(
                    env.svm.get_account(&pb).unwrap(),
                    pb_before,
                    "{label}: local counterparty unchanged"
                );
                assert_eq!(
                    env.svm.get_account(&vault_b).unwrap(),
                    vault_b_before,
                    "{label}: market B vault unchanged"
                );
                assert_eq!(
                    env.svm.get_account(&ctx).unwrap(),
                    ctx_before,
                    "{label}: matcher ctx writes rolled back"
                );
            };

        reject_atomically(
            "TradeNoCpi",
            ProgInstruction::TradeNoCpi {
                asset_index: 0,
                size_q: POS_SCALE as i128,
                exec_price: 100,
                fee_bps: 100,
            },
            vec![
                AccountMeta::new(attacker.pubkey(), true),
                AccountMeta::new(victim.pubkey(), true),
                AccountMeta::new(market_b, false),
                AccountMeta::new(pa, false),
                AccountMeta::new(pb, false),
            ],
            &[&attacker, &victim],
        );
        reject_atomically(
            "BatchTradeNoCpi",
            ProgInstruction::BatchTradeNoCpi {
                legs: vec![BatchTradeLeg {
                    asset_index: 0,
                    size_q: POS_SCALE as i128,
                    exec_price: 100,
                    fee_bps: 100,
                }],
            },
            vec![
                AccountMeta::new(attacker.pubkey(), true),
                AccountMeta::new(victim.pubkey(), true),
                AccountMeta::new(market_b, false),
                AccountMeta::new(pa, false),
                AccountMeta::new(pb, false),
            ],
            &[&attacker, &victim],
        );
        reject_atomically(
            "TradeCpi",
            ProgInstruction::TradeCpi {
                asset_index: 0,
                size_q: POS_SCALE as i128,
                fee_bps: 100,
                limit_price: 0,
            },
            vec![
                AccountMeta::new(attacker.pubkey(), true),
                AccountMeta::new(market_b, false),
                AccountMeta::new(pa, false),
                AccountMeta::new(pb, false),
                AccountMeta::new_readonly(hostile, false),
                AccountMeta::new(ctx, false),
                AccountMeta::new_readonly(delegate, false),
            ],
            &[&attacker],
        );
        reject_atomically(
            "BatchTradeCpi",
            ProgInstruction::BatchTradeCpi {
                legs: vec![BatchTradeCpiLeg {
                    asset_index: 0,
                    size_q: POS_SCALE as i128,
                    fee_bps: 100,
                    limit_price: 0,
                }],
            },
            vec![
                AccountMeta::new(attacker.pubkey(), true),
                AccountMeta::new(market_b, false),
                AccountMeta::new(pa, false),
                AccountMeta::new(pb, false),
                AccountMeta::new_readonly(hostile, false),
                AccountMeta::new(ctx, false),
                AccountMeta::new_readonly(delegate, false),
            ],
            &[&attacker],
        );
    }

    let good_a = Keypair::new();
    let good_b = Keypair::new();
    let p_good_a = init_portfolio_on_market(
        &mut env,
        market_b,
        &good_a,
        params.max_portfolio_assets as usize,
    );
    let p_good_b = init_portfolio_on_market(
        &mut env,
        market_b,
        &good_b,
        params.max_portfolio_assets as usize,
    );
    deposit_to_market(&mut env, market_b, vault_b, &good_a, p_good_a, 1_000_000);
    deposit_to_market(&mut env, market_b, vault_b, &good_b, p_good_b, 1_000_000);
    env.svm.expire_blockhash();
    let direct_ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TradeNoCpi {
            asset_index: 0,
            size_q: POS_SCALE as i128,
            exec_price: 100,
            fee_bps: 100,
        },
        vec![
            AccountMeta::new(good_a.pubkey(), true),
            AccountMeta::new(good_b.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(p_good_a, false),
            AccountMeta::new(p_good_b, false),
        ],
        &[&good_a, &good_b],
    );
    assert!(
        direct_ok.is_ok(),
        "same-market TradeNoCpi control must execute: {direct_ok:?}"
    );

    let cpi_taker = Keypair::new();
    let cpi_lp = Keypair::new();
    let p_cpi_taker = init_portfolio_on_market(
        &mut env,
        market_b,
        &cpi_taker,
        params.max_portfolio_assets as usize,
    );
    let p_cpi_lp = init_portfolio_on_market(
        &mut env,
        market_b,
        &cpi_lp,
        params.max_portfolio_assets as usize,
    );
    deposit_to_market(
        &mut env,
        market_b,
        vault_b,
        &cpi_taker,
        p_cpi_taker,
        1_000_000,
    );
    deposit_to_market(&mut env, market_b, vault_b, &cpi_lp, p_cpi_lp, 1_000_000);
    let ctx_ok = Pubkey::new_unique();
    let delegate_ok = matcher_delegate_key(
        &env.program_id,
        &market_b,
        &p_cpi_lp,
        &cpi_lp.pubkey(),
        &hostile,
        &ctx_ok,
    );
    env.svm
        .set_account(
            delegate_ok,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let mut ctx_ok_data = vec![0u8; MATCHER_CONTEXT_LEN];
    ctx_ok_data[0] = 9;
    env.svm
        .set_account(
            ctx_ok,
            Account {
                lamports: 1_000_000_000,
                data: ctx_ok_data,
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::SetMatcherConfig { enabled: 1 },
        vec![
            AccountMeta::new(cpi_lp.pubkey(), true),
            AccountMeta::new_readonly(market_b, false),
            AccountMeta::new(p_cpi_lp, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new_readonly(ctx_ok, false),
            AccountMeta::new_readonly(delegate_ok, false),
        ],
        &[&cpi_lp],
    )
    .expect("set market-B LP matcher config");
    env.svm.expire_blockhash();
    let batch_cpi_ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::BatchTradeCpi {
            legs: vec![BatchTradeCpiLeg {
                asset_index: 0,
                size_q: POS_SCALE as i128,
                fee_bps: 100,
                limit_price: 0,
            }],
        },
        vec![
            AccountMeta::new(cpi_taker.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(p_cpi_taker, false),
            AccountMeta::new(p_cpi_lp, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new(ctx_ok, false),
            AccountMeta::new_readonly(delegate_ok, false),
        ],
        &[&cpi_taker],
    );
    assert!(
        batch_cpi_ok.is_ok(),
        "same-market BatchTradeCpi control must execute: {batch_cpi_ok:?}"
    );
}

// full-interface sweep (cron23): resolved payout is a terminal value-moving path. A portfolio bound
// to market A must not be closeable against resolved market B, even if its owner is named correctly and
// market B has enough vault value. Missing provenance here would pay market B's victims to the market-A
// portfolio owner or burn the market-A payout state.
#[test]
fn v16_attack_close_resolved_rejects_cross_market_portfolio_payout() {
    let mut env = V16CuEnv::new();

    let attacker = Keypair::new();
    let pa = env.create_portfolio(&attacker);
    env.deposit(&attacker, pa, 1_000_000);

    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let vault_b = canonical_vault_ata(vault_authority_b, env.mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, vault_authority_b, 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&env.admin],
    )
    .expect("init market B");

    let victim = Keypair::new();
    env.ensure_signer_account(victim.pubkey());
    let pb = Pubkey::new_unique();
    env.svm
        .set_account(
            pb,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; env.portfolio_account_len],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(victim.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
        ],
        &[&victim],
    )
    .expect("init market-B victim portfolio");
    let source_b = Pubkey::new_unique();
    env.svm
        .set_account(
            source_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, victim.pubkey(), 1_000_000),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::Deposit { amount: 1_000_000 },
        vec![
            AccountMeta::new(victim.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
            AccountMeta::new(source_b, false),
            AccountMeta::new(vault_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&victim],
    )
    .expect("victim deposits into market B");
    assert_eq!(
        env.token_amount(vault_b),
        1_000_000,
        "market B vault funded"
    );

    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ResolveMarket,
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
        ],
        &[&env.admin],
    )
    .expect("resolve market B");

    let attack_dest = env.token_account_for_mint(env.mint, attacker.pubkey(), 0);
    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let pa_before = env.svm.get_account(&pa).unwrap();
    let pb_before = env.svm.get_account(&pb).unwrap();
    let vault_a_before = env.svm.get_account(&env.vault).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(attacker.pubkey(), false),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pa, false),
            AccountMeta::new(attack_dest, false),
            AccountMeta::new(vault_b, false),
            AccountMeta::new_readonly(vault_authority_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "market-B CloseResolved must reject a market-A-bound portfolio"
    );
    assert_eq!(
        env.token_amount(attack_dest),
        0,
        "attacker receives no market-B payout"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_a_before);
    assert_eq!(env.svm.get_account(&market_b).unwrap(), market_b_before);
    assert_eq!(
        env.svm.get_account(&pa).unwrap(),
        pa_before,
        "rejected cross-market payout leaves market-A portfolio byte-identical"
    );
    assert_eq!(env.svm.get_account(&pb).unwrap(), pb_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_a_before);
    assert_eq!(
        env.svm.get_account(&vault_b).unwrap(),
        vault_b_before,
        "market-B vault remains intact"
    );

    let victim_dest = Pubkey::new_unique();
    env.svm
        .set_account(
            victim_dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, victim.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let victim_close = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::CloseResolved {
            fee_rate_per_slot: 0,
        },
        vec![
            AccountMeta::new_readonly(victim.pubkey(), false),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
            AccountMeta::new(victim_dest, false),
            AccountMeta::new(vault_b, false),
            AccountMeta::new_readonly(vault_authority_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        victim_close.is_ok(),
        "real market-B CloseResolved still pays: {victim_close:?}"
    );
    assert_eq!(env.token_amount(victim_dest), 1_000_000);

    env.resolve();
    let attacker_dest = env.close_resolved(&attacker, pa);
    assert_eq!(
        env.token_amount(attacker_dest),
        1_000_000,
        "market-A portfolio remains claimable on its real market"
    );
}

// full-interface sweep (cron24): ClaimResolvedPayoutTopup is intentionally unsigned so any cranker
// can finish a user's resolved payout. A market-A-bound receipt must not be claimable against market
// B's payout ledger and vault; otherwise a helper could drain one resolved market or burn another
// market's pending receipt by mixing otherwise-valid accounts.
#[test]
fn v16_attack_claim_resolved_topup_rejects_cross_market_portfolio_payout() {
    let mut env = V16CuEnv::new();

    let owner_a = Keypair::new();
    let pa = env.create_portfolio(&owner_a);

    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let vault_b = canonical_vault_ata(vault_authority_b, env.mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, vault_authority_b, 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&env.admin],
    )
    .expect("init market B");

    let owner_b = Keypair::new();
    env.ensure_signer_account(owner_b.pubkey());
    let pb = Pubkey::new_unique();
    env.svm
        .set_account(
            pb,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; env.portfolio_account_len],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(owner_b.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
        ],
        &[&owner_b],
    )
    .expect("init market-B portfolio");

    fn seed_pending_topup(
        env: &mut V16CuEnv,
        market: Pubkey,
        portfolio: Pubkey,
        vault: Pubkey,
        vault_authority: Pubkey,
    ) {
        let mut market_account = env.svm.get_account(&market).expect("market account");
        let mut portfolio_account = env.svm.get_account(&portfolio).expect("portfolio account");
        let (cfg, mut group) = state::read_market(&market_account.data).unwrap();
        let mut account = state::read_portfolio(&portfolio_account.data).unwrap();
        group.mode = MarketModeV16::Resolved;
        group.resolved_slot = 1;
        group.current_slot = 1;
        group.vault = 60;
        group.payout_snapshot_captured = true;
        group.payout_snapshot = 100;
        group.resolved_payout_ledger = ResolvedPayoutLedgerV16 {
            snapshot_residual: 100,
            terminal_claim_exact_receipts_num: 100 * BOUND_SCALE,
            terminal_claim_bound_unreceipted_num: 0,
            current_payout_rate_num: 100 * BOUND_SCALE,
            current_payout_rate_den: 100 * BOUND_SCALE,
            snapshot_slot: 1,
            payout_halted: false,
            finalized: false,
        };
        account.resolved_payout_receipt =
            percolator::ResolvedPayoutReceiptV16Account::from_runtime(&ResolvedPayoutReceiptV16 {
                present: true,
                prior_bound_contribution_num: 100 * BOUND_SCALE,
                live_released_face_at_receipt: 0,
                terminal_positive_claim_face: 100,
                paid_effective: 40,
                finalized: false,
            });
        state::write_market(&mut market_account.data, &cfg, &group).unwrap();
        state::write_portfolio(&mut portfolio_account.data, &account).unwrap();
        env.svm.set_account(market, market_account).unwrap();
        env.svm.set_account(portfolio, portfolio_account).unwrap();
        env.set_token_account_amount(vault, env.mint, vault_authority, 60);
    }

    let market_a = env.market;
    let vault_a = env.vault;
    let vault_authority_a = env.vault_authority;
    seed_pending_topup(&mut env, market_a, pa, vault_a, vault_authority_a);
    seed_pending_topup(&mut env, market_b, pb, vault_b, vault_authority_b);

    let attack_dest = env.token_account_for_mint(env.mint, owner_a.pubkey(), 0);
    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let pa_before = env.svm.get_account(&pa).unwrap();
    let pb_before = env.svm.get_account(&pb).unwrap();
    let vault_a_before = env.svm.get_account(&env.vault).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ClaimResolvedPayoutTopup,
        vec![
            AccountMeta::new_readonly(owner_a.pubkey(), false),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pa, false),
            AccountMeta::new(attack_dest, false),
            AccountMeta::new(vault_b, false),
            AccountMeta::new_readonly(vault_authority_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "market-B ClaimResolvedPayoutTopup must reject a market-A-bound receipt"
    );
    assert_eq!(
        env.token_amount(attack_dest),
        0,
        "attacker receives no market-B top-up"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_a_before);
    assert_eq!(env.svm.get_account(&market_b).unwrap(), market_b_before);
    assert_eq!(
        env.svm.get_account(&pa).unwrap(),
        pa_before,
        "rejected cross-market top-up leaves market-A receipt byte-identical"
    );
    assert_eq!(env.svm.get_account(&pb).unwrap(), pb_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_a_before);
    assert_eq!(
        env.svm.get_account(&vault_b).unwrap(),
        vault_b_before,
        "market-B vault remains intact"
    );

    let dest_b = Pubkey::new_unique();
    env.svm
        .set_account(
            dest_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner_b.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let claim_b = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ClaimResolvedPayoutTopup,
        vec![
            AccountMeta::new_readonly(owner_b.pubkey(), false),
            AccountMeta::new(market_b, false),
            AccountMeta::new(pb, false),
            AccountMeta::new(dest_b, false),
            AccountMeta::new(vault_b, false),
            AccountMeta::new_readonly(vault_authority_b, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[],
    );
    assert!(
        claim_b.is_ok(),
        "real market-B top-up still pays: {claim_b:?}"
    );
    assert_eq!(env.token_amount(dest_b), 60);

    let dest_a = env.token_account_for_mint(env.mint, owner_a.pubkey(), 0);
    let claim_a_cu = env.claim_resolved_payout_topup_with_cu(owner_a.pubkey(), pa, dest_a);
    assert_cu_within(
        "same-market ClaimResolvedPayoutTopup after rejected cross-market attempt",
        claim_a_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(dest_a),
        60,
        "market-A receipt remains claimable on its real market"
    );
}

// full-interface sweep (cron22) — PermissionlessCrank is intentionally unsigned for the target
// portfolio. A foreign-market portfolio with the same asset_index/market_id shape must still reject
// before any settlement/liquidation mutation; otherwise anyone could settle or liquidate a portfolio
// under the wrong market's oracle/accounting state.
#[test]
fn v16_attack_permissionless_crank_rejects_cross_market_target_portfolio() {
    let mut env = V16CuEnv::new();

    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let vault_b = canonical_vault_ata(vault_authority_b, env.mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, vault_authority_b, 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&env.admin],
    )
    .expect("init market B");

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    env.ensure_signer_account(long_owner.pubkey());
    env.ensure_signer_account(short_owner.pubkey());
    let long_b = Pubkey::new_unique();
    let short_b = Pubkey::new_unique();
    for portfolio in [long_b, short_b] {
        env.svm
            .set_account(
                portfolio,
                Account {
                    lamports: 1_000_000_000,
                    data: vec![0u8; env.portfolio_account_len],
                    owner: env.program_id,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
    }
    for (owner, portfolio) in [(&long_owner, long_b), (&short_owner, short_b)] {
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::InitPortfolio,
            vec![
                AccountMeta::new(owner.pubkey(), true),
                AccountMeta::new(market_b, false),
                AccountMeta::new(portfolio, false),
            ],
            &[owner],
        )
        .expect("init market-B portfolio");

        let source = Pubkey::new_unique();
        env.svm
            .set_account(
                source,
                Account {
                    lamports: 1_000_000_000,
                    data: make_token_data(env.mint, owner.pubkey(), 1_000_000),
                    owner: spl_token::ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::Deposit { amount: 1_000_000 },
            vec![
                AccountMeta::new(owner.pubkey(), true),
                AccountMeta::new(market_b, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new(source, false),
                AccountMeta::new(vault_b, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[owner],
        )
        .expect("deposit into market-B portfolio");
    }
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TradeNoCpi {
            asset_index: 0,
            size_q: POS_SCALE as i128,
            exec_price: 100,
            fee_bps: 0,
        },
        vec![
            AccountMeta::new(long_owner.pubkey(), true),
            AccountMeta::new(short_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(long_b, false),
            AccountMeta::new(short_b, false),
        ],
        &[&long_owner, &short_owner],
    )
    .expect("open a real market-B position");
    assert!(
        has_active_leg_for_asset(
            &state::read_portfolio(&env.svm.get_account(&long_b).unwrap().data).unwrap(),
            0
        ),
        "setup must create a non-vacuous market-B target portfolio"
    );

    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let long_b_before = env.svm.get_account(&long_b).unwrap();
    let short_b_before = env.svm.get_account(&short_b).unwrap();
    let vault_a_before = env.svm.get_account(&env.vault).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();

    env.svm.warp_to_slot(5);
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 5,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(long_b, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "market A PermissionlessCrank must reject a market-B-bound target portfolio"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_a_before);
    assert_eq!(env.svm.get_account(&market_b).unwrap(), market_b_before);
    assert_eq!(
        env.svm.get_account(&long_b).unwrap(),
        long_b_before,
        "foreign target crank rejection leaves target portfolio byte-identical"
    );
    assert_eq!(env.svm.get_account(&short_b).unwrap(), short_b_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_a_before);
    assert_eq!(env.svm.get_account(&vault_b).unwrap(), vault_b_before);

    env.svm.expire_blockhash();
    let ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::PermissionlessCrank {
            now_slot: 5,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(long_b, false),
        ],
        &[],
    );
    assert!(
        ok.is_ok(),
        "same-market market-B crank remains live: {ok:?}"
    );
    let (_, group_b_after) =
        state::read_market(&env.svm.get_account(&market_b).unwrap().data).unwrap();
    assert_eq!(
        group_b_after.current_slot, 5,
        "positive control advanced market B"
    );
    assert!(
        has_active_leg_for_asset(
            &state::read_portfolio(&env.svm.get_account(&long_b).unwrap().data).unwrap(),
            0
        ),
        "same-market crank does not erase the market-B position"
    );
}

// security.md sweep — partial liquidation exactness (#2/#33): liquidating with close_q < the position
// must reduce the position by at most close_q (no over-close), conserve value (vault unchanged,
// accounting==real), and never create value. Complements over-liquidation (batch 35).
#[test]
fn v16_attack_partial_liquidation_bounded_and_conserves() {
    let mut env = V16CuEnv::new();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 250);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    for (slot, mark) in [(1u64, 300u64), (2, 800)] {
        env.svm.warp_to_slot(slot);
        env.push_ewma_mark_with_cu(slot, mark);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(short_account, false),
            ],
            &[],
        );
    }
    let (_, g_pre) = env.market_state();
    let oi_pre = g_pre.assets[0].oi_eff_short_q;
    // partial liquidation: close only HALF (POS_SCALE/2) of the POS_SCALE position.
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: POS_SCALE / 2,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
        ],
        &[],
    );
    let (_, g_post) = env.market_state();
    // OI reduced by AT MOST close_q (bounded; the engine may close less if that resolves things).
    let closed = oi_pre.saturating_sub(g_post.assets[0].oi_eff_short_q);
    assert!(
        closed <= POS_SCALE / 2,
        "partial liquidation closed at most close_q (no over-close): closed={}",
        closed
    );
    assert!(
        g_post.assets[0].oi_eff_short_q <= oi_pre,
        "OI never increased"
    );
    // conservation: vault unchanged (internal), accounting==real, senior conservation.
    assert_eq!(
        g_post.vault, g_pre.vault,
        "vault unchanged by partial liquidation"
    );
    assert_eq!(
        g_post.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    assert!(
        g_post.vault >= g_post.c_tot + g_post.insurance,
        "senior conservation"
    );
}

// Public auto-crank liveness sweep: helper-driven liquidation tests retry when close_q != 0, which can
// hide whether a *current* liquidatable account makes progress in one public instruction. Start from a
// solvent but under-margin account with a current health cert, then submit one bounded liquidation step.
// The instruction must execute and close no more than the keeper's work budget.
#[test]
fn v16_attack_auto_crank_current_solvent_partial_liquidation_makes_progress() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, 100);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 3_000);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, 300);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    env.svm.warp_to_slot(3);
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
    );

    let before_group = env.market_state().1;
    let before_short = env.portfolio_state(short_account);
    let before_cert = health_cert(&before_short);
    assert!(
        before_cert.certified_liq_deficit != 0 && before_cert.certified_equity > 0,
        "setup must be solvent but liquidatable before partial liquidation: {before_cert:?}"
    );
    let oi_pre = before_group.assets[0].oi_eff_short_q;

    env.svm.expire_blockhash();
    let partial = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short_account, false),
        ],
        &[],
    );
    assert!(
        partial.is_ok(),
        "current solvent liquidation must make progress in one public auto-crank: {partial:?}"
    );

    let after_group = env.market_state().1;
    let after_short = env.portfolio_state(short_account);
    let closed = oi_pre.saturating_sub(after_group.assets[0].oi_eff_short_q);
    assert!(closed > 0, "partial liquidation must reduce open interest");
    assert!(
        closed <= POS_SCALE,
        "partial liquidation closed at most close_q: closed={closed}"
    );
    assert!(
        has_active_leg_for_asset(&after_short, 0),
        "partial close should leave the remaining position active"
    );
    assert_eq!(
        after_group.vault, before_group.vault,
        "liquidation fee is internal accounting, not a vault mint"
    );
    assert_eq!(after_group.vault as u64, env.token_amount(env.vault));
    assert!(after_group.vault >= after_group.c_tot + after_group.insurance);
}

// security.md sweep — insurance makes winner whole at resolution (#33/#9): with a funded insurance
// backstop, a winner facing a loser's bad debt should recover their full claim at resolution (insurance
// absorbs the deficit), bounded by available insurance. Value conserved; insurance only spent.
#[test]
fn v16_attack_insurance_makes_winner_whole_at_resolution() {
    let mut env = V16CuEnv::new();
    env.top_up_insurance(1_000_000); // backstop
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    let lo_owner = Keypair::new();
    let lo = env.create_portfolio(&lo_owner); // long winner
    let sh_owner = Keypair::new();
    let sh = env.create_portfolio(&sh_owner); // short loser (thin)
    env.deposit(&lo_owner, lo, 1_000_000);
    env.deposit(&sh_owner, sh, 250);
    env.trade_with_cu(&lo_owner, lo, &sh_owner, sh, POS_SCALE as i128, 100, 0);
    let ins_before = env.market_state().1.insurance;
    let vault_before = env.market_state().1.vault;
    // price up over slots -> short insolvent.
    for (slot, mark) in [(1u64, 300u64), (2, 800)] {
        env.svm.warp_to_slot(slot);
        env.push_ewma_mark_with_cu(slot, mark);
        for acct in [lo, sh] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(acct, false),
                ],
                &[],
            );
        }
    }
    // Liquidate the insolvent short, then resolve and wind down.
    env.crank(
        sh,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    env.resolve();
    let lo_dest = env.close_resolved(&lo_owner, lo);
    let _ = env.close_resolved(&sh_owner, sh);
    let won = env.token_amount(lo_dest) as u128;
    let (_, g) = env.market_state();
    // winner recovered MORE than just their capital — insurance covered the loser's bad debt.
    assert!(
        won > 1_000_000,
        "winner made (more) whole by insurance backstop: got {}",
        won
    );
    // insurance was SPENT (not conjured), bounded by what was available.
    assert!(
        g.insurance <= ins_before,
        "insurance only spent, never conjured ({} <= {})",
        g.insurance,
        ins_before
    );
    // no value printed: total tokens out + remaining vault accounted, no creation.
    assert!(g.vault <= vault_before, "vault not over-credited");
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
}

// security.md sweep — funding + maintenance fee combined (#32/#33): an account with a position accrues
// BOTH premium funding (zero-sum transfer to the counterparty) AND maintenance fees (to insurance).
// Both must apply together and conserve total value (no tokens created/destroyed; vault==deposited).
#[test]
fn v16_attack_funding_and_fee_combined_conserve() {
    const INITIAL_PRICE: u64 = 1_000_000;
    const DEPOSIT: u128 = 10_000_000;
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: INITIAL_PRICE,
        max_price_move_bps_per_slot: 1_000,
        max_accrual_dt_slots: 1,
        max_abs_funding_e9_per_slot: 1_000,
        min_funding_lifetime_slots: 1,
        maintenance_fee_per_slot: 58,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(0);
    env.configure_ewma_mark_with_cu(0, INITIAL_PRICE, 1, 0);
    env.update_maintenance_fee_policy_with_cu(0);
    let lo_owner = Keypair::new();
    let lo = env.create_portfolio(&lo_owner);
    let sh_owner = Keypair::new();
    let sh = env.create_portfolio(&sh_owner);
    env.deposit(&lo_owner, lo, DEPOSIT);
    env.deposit(&sh_owner, sh, DEPOSIT);
    env.trade_with_cu(
        &lo_owner,
        lo,
        &sh_owner,
        sh,
        POS_SCALE as i128,
        INITIAL_PRICE,
        0,
    );
    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, INITIAL_PRICE * 2); // premium
    for slot in 1..=6u64 {
        env.svm.warp_to_slot(slot);
        for p in [lo, sh] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
            env.svm.expire_blockhash();
            let _ = env.try_sync_maintenance_fee_with_cu(p, None, slot);
        }
    }
    let (_, g) = env.market_state();
    // funding actually accrued AND fees were charged (non-vacuous combination).
    assert!(
        g.assets[0].f_long_num != 0 || g.assets[0].f_short_num != 0,
        "funding accrued"
    );
    assert!(g.insurance > 0, "maintenance fees accrued to insurance");
    // total value conserved: no tokens minted/burned, everything accounted within the vault.
    assert_eq!(
        g.vault,
        2 * DEPOSIT,
        "vault == total deposited (funding zero-sum + fees internal)"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation under funding + fees"
    );
    assert_domain_budget_remaining_total_consistent(&g, "funding plus maintenance fee");
    let a = state::read_portfolio(&env.svm.get_account(&lo).unwrap().data).unwrap();
    let b = state::read_portfolio(&env.svm.get_account(&sh).unwrap().data).unwrap();
    let total_equity =
        (a.capital.get() as i128 + a.pnl.get()) + (b.capital.get() as i128 + b.pnl.get());
    assert!(
        total_equity + g.insurance as i128 <= g.vault as i128,
        "no value over-distributed"
    );
}

// security.md sweep — multi-party exposure transfer (#32/#33): A goes long vs B (short); then B closes
// by going long vs C (short). Exposure passes B->C. OI must stay balanced, B ends flat, and value is
// conserved through the chain (no leakage at the intermediary).
#[test]
fn v16_attack_exposure_transfer_chain_conserves() {
    let mut env = V16CuEnv::new();
    let a = Keypair::new();
    let pa = env.create_portfolio(&a);
    let b = Keypair::new();
    let pb = env.create_portfolio(&b);
    let c = Keypair::new();
    let pc = env.create_portfolio(&c);
    env.deposit(&a, pa, 1_000_000);
    env.deposit(&b, pb, 1_000_000);
    env.deposit(&c, pc, 1_000_000);
    let (_, g0) = env.market_state();
    // A long vs B short.
    env.trade_asset_with_cu(0, &a, pa, &b, pb, POS_SCALE as i128, 100, 0);
    assert_eq!(
        env.portfolio_state(pa).legs[0].basis_pos_q.get(),
        POS_SCALE as i128,
        "A long"
    );
    assert_eq!(
        env.portfolio_state(pb).legs[0].basis_pos_q.get(),
        -(POS_SCALE as i128),
        "B short"
    );
    // B closes by going long vs C (B: -1 -> 0; C: 0 -> -1). Exposure transferred B->C.
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(0, &b, pb, &c, pc, POS_SCALE as i128, 100, 0);
    assert_eq!(
        env.portfolio_state(pb).legs[0].basis_pos_q.get(),
        0,
        "B now flat (exposure passed to C)"
    );
    assert_eq!(
        env.portfolio_state(pc).legs[0].basis_pos_q.get(),
        -(POS_SCALE as i128),
        "C now short"
    );
    assert_eq!(
        env.portfolio_state(pa).legs[0].basis_pos_q.get(),
        POS_SCALE as i128,
        "A still long"
    );
    // OI balanced (A's long matched by C's short), conservation, accounting==real vault.
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.assets[0].oi_eff_long_q, g1.assets[0].oi_eff_short_q,
        "OI balanced after transfer"
    );
    assert_eq!(
        g1.c_tot, g0.c_tot,
        "c_tot conserved (no fees) through the chain"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — token program validation (#44): deposit/withdraw must verify the token program
// account is the real SPL Token program. Injecting a different program must reject — no routing the
// transfer CPI through an attacker-controlled program.
#[test]
fn v16_attack_wrong_token_program_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    let (_, g0) = env.market_state();
    let fake_token_program = Pubkey::new_unique(); // not spl_token::ID
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    // withdraw with a bogus token program -> reject.
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Withdraw { amount: 500_000 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(fake_token_program, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "withdraw with a non-SPL-token program must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no tokens delivered via a bogus token program"
    );
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000_000,
        "capital not debited"
    );
    assert_eq!(env.market_state().1.vault, g0.vault, "vault unchanged");
    // deposit with a bogus token program -> reject.
    let src = env.token_account_for_mint(env.mint, owner.pubkey(), 100);
    env.svm.expire_blockhash();
    let r2 = env.send(
        ProgInstruction::Deposit { amount: 100 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(src, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(fake_token_program, false),
        ],
        &[&owner],
    );
    assert!(
        r2.is_err(),
        "deposit with a non-SPL-token program must reject"
    );
    // correct token program still works.
    let (good, _) = env.withdraw_with_cu(&owner, p, 500_000);
    assert_eq!(
        env.token_amount(good),
        500_000,
        "withdraw with the real token program works"
    );
}

// security.md sweep — haircut proportionality with disparate claims (#33/#37): two resolved winners
// with very different positive-pnl faces (100 vs 900) sharing insufficient backing must be paid
// PROPORTIONALLY to their claim size (~1:9), and the total must not exceed the backing.
#[test]
fn v16_attack_haircut_proportional_to_claim_size() {
    const BACKING: u128 = 100;
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, BACKING, 10_000);
    let o1 = Keypair::new();
    let p1 = env.create_portfolio(&o1);
    let o2 = Keypair::new();
    let p2 = env.create_portfolio(&o2);
    env.deposit(&o1, p1, 1_000);
    env.deposit(&o2, p2, 1_000);
    env.add_source_positive_pnl(p1, 1, 100); // small claim
    env.add_source_positive_pnl(p2, 1, 900); // 9x larger claim
    env.resolve();
    // two close passes to converge the terminal haircut rate.
    let mut out1 = 0u128;
    let mut out2 = 0u128;
    for _ in 0..2 {
        let d1 = env.close_resolved(&o1, p1);
        out1 += env.token_amount(d1) as u128;
        let d2 = env.close_resolved(&o2, p2);
        out2 += env.token_amount(d2) as u128;
    }
    let hc1 = out1.saturating_sub(1_000); // haircut payout above senior capital
    let hc2 = out2.saturating_sub(1_000);
    // proportionality: the larger claim (9x) gets ~9x the haircut payout.
    assert!(
        hc1 > 0 && hc2 > 0,
        "both winners got some haircut payout (hc1={} hc2={})",
        hc1,
        hc2
    );
    assert!(
        hc2 >= hc1 * 8 && hc2 <= hc1 * 10,
        "payout ~proportional to claim size (9x): hc1={} hc2={}",
        hc1,
        hc2
    );
    // total haircut paid never exceeds the backing (no over-pay).
    assert!(
        hc1 + hc2 <= BACKING,
        "summed haircut payout {} <= backing {}",
        hc1 + hc2,
        BACKING
    );
    let (_, g) = env.market_state();
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — TopUpBackingBucket authorization (#6) + vault pinning (#44): funding a backing
// bucket is gated to the domain's backing_bucket_authority and routes only to the canonical vault
// (F-VAULT-FRAG fix). A non-authority must reject.
#[test]
fn v16_attack_topup_backing_bucket_authority_gated() {
    let mut env = V16CuEnv::new();
    let (_, g0) = env.market_state();
    let donor = Keypair::new();
    env.ensure_signer_account(donor.pubkey());
    let src = env.token_account_for_mint(env.mint, donor.pubkey(), 500);
    // non-authority backing top-up -> reject.
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TopUpBackingBucket {
            domain: 0,
            amount: 500,
            expiry_slot: 10_000,
        },
        vec![
            AccountMeta::new(donor.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(src, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&donor],
    );
    assert!(
        r.is_err(),
        "non-authority backing bucket top-up must reject"
    );
    assert_eq!(env.token_amount(src), 500, "donor source untouched");
    let (_, g1) = env.market_state();
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep - cross-asset backing withdrawal isolation (#6/#33/#48): a backing authority for
// asset 1 is a real privileged key, but it must only control asset 1's domains. A wrong target-domain
// authority lookup would let it drain asset 0's funded backing bucket.
#[test]
fn v16_attack_cross_asset_backing_authority_cannot_withdraw_other_asset_bucket() {
    let mut env = V16CuEnv::new();
    let asset1_backing = Keypair::new();
    env.activate_asset_with_authorities(
        1,
        1,
        100,
        env.admin.pubkey(),
        env.admin.pubkey(),
        asset1_backing.pubkey(),
        env.admin.pubkey(),
    );
    env.top_up_backing_bucket(0, 500, 10_000);
    env.top_up_backing_bucket_with_authority(&asset1_backing, 2, 300, 10_000);
    let (_, funded) = env.market_state();
    assert_eq!(
        funded.source_backing_buckets[0].fresh_unliened_backing_num,
        500 * BOUND_SCALE
    );
    assert_eq!(
        funded.source_backing_buckets[2].fresh_unliened_backing_num,
        300 * BOUND_SCALE
    );

    let dest = env.token_account_for_mint(env.mint, asset1_backing.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 0,
            amount: 100,
        },
        vec![
            AccountMeta::new(asset1_backing.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&asset1_backing],
    );
    assert!(
        rejected.is_err(),
        "asset-1 backing authority must not withdraw asset-0 backing"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected cross-asset backing withdrawal leaves market accounting unchanged"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "rejected cross-asset backing withdrawal leaves the canonical vault untouched"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        dest_before,
        "rejected cross-asset backing withdrawal pays no tokens"
    );

    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 2,
            amount: 100,
        },
        vec![
            AccountMeta::new(asset1_backing.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&asset1_backing],
    )
    .expect("asset-1 backing authority withdraws its own domain");
    assert_eq!(env.token_amount(dest), 100);
    let (_, after) = env.market_state();
    assert_eq!(
        after.source_backing_buckets[0].fresh_unliened_backing_num,
        500 * BOUND_SCALE,
        "asset-0 backing remains fully funded"
    );
    assert_eq!(
        after.source_backing_buckets[2].fresh_unliened_backing_num,
        200 * BOUND_SCALE,
        "asset-1 own-domain backing was debited"
    );
    assert_eq!(after.vault as u64, env.token_amount(env.vault));
}

// security.md sweep - cross-asset backing earnings isolation (#6/#33/#48): provider-fee earnings use
// a separate public withdrawal rail from principal backing buckets, with a mandatory domain ledger.
// An asset-1 backing authority must not be able to spend asset-0 earnings or rewrite asset-0 ledger
// counters, even when the target ledger is otherwise valid for asset 0.
#[test]
fn v16_attack_cross_asset_backing_authority_cannot_withdraw_other_asset_earnings() {
    let mut env = V16CuEnv::new();
    let asset1_backing = Keypair::new();
    env.activate_asset_with_authorities(
        1,
        1,
        100,
        env.admin.pubkey(),
        env.admin.pubkey(),
        asset1_backing.pubkey(),
        env.admin.pubkey(),
    );
    env.ensure_signer_account(asset1_backing.pubkey());

    let ledger0 = env.backing_domain_ledger_account();
    env.top_up_backing_bucket_with_ledger_with_cu(ledger0, 0, 500, 10_000);

    let ledger2 = env.backing_domain_ledger_account();
    let source2 = env.token_account(asset1_backing.pubkey(), 300);
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TopUpBackingBucket {
            domain: 2,
            amount: 300,
            expiry_slot: 10_000,
        },
        vec![
            AccountMeta::new(asset1_backing.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(source2, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(ledger2, false),
        ],
        &[&asset1_backing],
    )
    .expect("asset-1 backing authority tops up its own domain with ledger");

    env.mutate_market(|_, group| {
        group.source_backing_buckets[0].utilization_fee_earnings = 40;
        group.source_backing_buckets[2].utilization_fee_earnings = 25;
        group.vault += 65;
    });
    let (_, funded) = env.market_state();
    env.set_token_account_amount(
        env.vault,
        env.mint,
        env.vault_authority,
        funded.vault as u64,
    );
    assert_eq!(
        funded.source_backing_buckets[0].utilization_fee_earnings,
        40
    );
    assert_eq!(
        funded.source_backing_buckets[2].utilization_fee_earnings,
        25
    );

    let dest = env.token_account_for_mint(env.mint, asset1_backing.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let dest_before = env.svm.get_account(&dest).unwrap();
    let ledger0_before = env.svm.get_account(&ledger0).unwrap();
    let ledger2_before = env.svm.get_account(&ledger2).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucketEarnings {
            domain: 0,
            amount: 10,
        },
        vec![
            AccountMeta::new(asset1_backing.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(ledger0, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&asset1_backing],
    );
    assert!(
        rejected.is_err(),
        "asset-1 backing authority must not withdraw asset-0 backing earnings"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected cross-asset earnings withdrawal leaves market accounting unchanged"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "rejected cross-asset earnings withdrawal leaves the canonical vault untouched"
    );
    assert_eq!(
        env.svm.get_account(&dest).unwrap(),
        dest_before,
        "rejected cross-asset earnings withdrawal pays no tokens"
    );
    assert_eq!(
        env.svm.get_account(&ledger0).unwrap(),
        ledger0_before,
        "rejected cross-asset earnings withdrawal rewrites no target-domain ledger"
    );
    assert_eq!(
        env.svm.get_account(&ledger2).unwrap(),
        ledger2_before,
        "rejected cross-asset earnings withdrawal rewrites no attacker-domain ledger"
    );

    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucketEarnings {
            domain: 2,
            amount: 10,
        },
        vec![
            AccountMeta::new(asset1_backing.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(ledger2, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&asset1_backing],
    )
    .expect("asset-1 backing authority withdraws its own earnings");
    assert_eq!(env.token_amount(dest), 10);
    let (_, after) = env.market_state();
    assert_eq!(
        after.source_backing_buckets[0].utilization_fee_earnings, 40,
        "asset-0 earnings remain fully withdrawable"
    );
    assert_eq!(
        after.source_backing_buckets[2].utilization_fee_earnings, 15,
        "asset-1 own-domain earnings were debited"
    );
    assert_eq!(after.vault as u64, env.token_amount(env.vault));
    let ledger2_after =
        state::read_backing_domain_ledger(&env.svm.get_account(&ledger2).unwrap().data).unwrap();
    assert_eq!(ledger2_after.total_earnings_atoms, 25);
    assert_eq!(ledger2_after.total_earnings_withdrawn_atoms, 10);
    assert_eq!(ledger2_after.last_observed_bucket_earnings_atoms, 15);
}

// security.md sweep — F-VAULT-FRAG fix on a WITHDRAW path: WithdrawBackingBucket transfers FROM the
// vault; the canonical-ATA pin must apply here too. A withdrawal routed to a non-canonical
// vault-authority-owned account must reject (no draining a fragment / fabricating an outbound path).
#[test]
fn v16_attack_backing_withdraw_pinned_to_canonical_vault() {
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, 1_000, 10_000); // real backing in the canonical vault
    let (_, g0) = env.market_state();
    // a fake "vault" owned by vault_authority but NOT the canonical ATA.
    let fake_vault = Pubkey::new_unique();
    env.svm
        .set_account(
            fake_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, env.vault_authority, 5_000),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let dest = env.token_account_for_mint(env.mint, env.admin.pubkey(), 0);
    // backing withdraw routed to the fake vault -> reject (canonical pin).
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 1,
            amount: 500,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(fake_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&env.admin],
    );
    assert!(
        r.is_err(),
        "backing withdraw routed to a non-canonical vault must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no tokens out via the fragment vault"
    );
    assert_eq!(
        env.token_amount(fake_vault),
        5_000,
        "fragment vault untouched"
    );
    let (_, g1) = env.market_state();
    assert_eq!(g1.vault, g0.vault, "accounting vault unchanged");
    assert_eq!(
        env.token_amount(env.vault),
        g1.vault as u64,
        "real canonical vault intact == accounting"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — convert bounded by available backing (#33/#35): if a winner's positive pnl
// exceeds its source backing, ConvertReleasedPnl must release at most the AVAILABLE backing, never the
// full (partly-unbacked) pnl. Otherwise unbacked pnl would convert into withdrawable capital.
#[test]
fn v16_attack_convert_bounded_by_available_backing() {
    const BACKING: u128 = 40;
    let mut env = V16CuEnv::new();
    let ledger = env.backing_domain_ledger_account();
    env.top_up_backing_bucket_with_ledger_with_cu(ledger, 1, BACKING, 10);
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    // add MORE positive pnl (80) than the backing (40).
    env.add_source_positive_pnl(p, 1, 80);
    env.crank(
        p,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let cap_before = env.portfolio_state(p).capital.get();
    let (_, g0) = env.market_state();
    // convert with a huge cap -> released amount must be bounded by the available backing.
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::ConvertReleasedPnl {
            amount: 1_000_000_000,
        },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
        ],
        &[&owner],
    );
    let converted = env.portfolio_state(p).capital.get() - cap_before;
    assert!(
        converted <= BACKING,
        "convert released at most the available backing ({} <= {})",
        converted,
        BACKING
    );
    let (_, g1) = env.market_state();
    assert!(
        g1.vault >= g1.c_tot + g1.insurance,
        "senior conservation after convert"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    let _ = g0;
}

// security.md sweep — undersized portfolio account handling (#44/#37): InitPortfolio on an account
// smaller than the required size must NOT cause an out-of-bounds write. The wrapper safely REALLOCS
// the account up to the required length (zero-initialized) before any portfolio write — then it works
// correctly. (No OOB; this verifies the safe-resize path.)
#[test]
fn v16_attack_undersized_portfolio_account_realloced_safely() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    env.ensure_signer_account(owner.pubkey());
    // a program-owned account smaller than the required portfolio length.
    let small = Pubkey::new_unique();
    let small_len = env.portfolio_account_len / 2;
    env.svm
        .set_account(
            small,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; small_len],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    // InitPortfolio reallocs it to the required size (no OOB) and succeeds.
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(small, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_ok(),
        "InitPortfolio reallocs an undersized account safely: {:?}",
        r
    );
    assert!(
        env.svm.get_account(&small).unwrap().data.len() >= env.portfolio_account_len,
        "account realloced to >= required size"
    );
    // and the realloced portfolio works correctly (no corruption): a deposit credits exactly.
    env.deposit(&owner, small, 1_000);
    assert_eq!(
        env.portfolio_state(small).capital.get(),
        1_000,
        "realloced portfolio credits a deposit exactly (no OOB/corruption)"
    );
    let (_, g) = env.market_state();
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
}

// security.md sweep - legacy portfolio storage growth (#44/#48): after the matcher-config tail was
// added, an already-initialized portfolio with only the engine body must not become stuck. Deposit must
// grow the account through ensure_portfolio_storage_for_market_slots, preserve accounting, and leave the
// user able to withdraw.
#[test]
fn v16_attack_legacy_portfolio_storage_reallocs_on_deposit_without_corruption() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    let mut legacy = env.svm.get_account(&portfolio).unwrap();
    legacy.data.truncate(PORTFOLIO_ENGINE_ACCOUNT_LEN);
    env.svm.set_account(portfolio, legacy).unwrap();
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "test setup simulates an initialized legacy portfolio without the matcher tail"
    );

    env.deposit(&owner, portfolio, 1_000);
    assert_eq!(
        env.svm.get_account(&portfolio).unwrap().data.len(),
        env.portfolio_account_len,
        "Deposit must grow legacy portfolio storage before mutating it"
    );
    assert_eq!(
        env.portfolio_state(portfolio).capital.get(),
        1_000,
        "deposit credits exactly after legacy storage growth"
    );
    let (_, group_after_deposit) = env.market_state();
    assert_eq!(group_after_deposit.c_tot, 1_000);
    assert_eq!(
        group_after_deposit.vault as u64,
        env.token_amount(env.vault)
    );

    let dest = env.withdraw(&owner, portfolio, 1_000);
    assert_eq!(
        env.token_amount(dest),
        1_000,
        "withdraw recovers the full deposit after legacy storage growth"
    );
    assert_eq!(env.portfolio_state(portfolio).capital.get(), 0);
    let (_, group_after_withdraw) = env.market_state();
    assert_eq!(group_after_withdraw.c_tot, 0);
    assert_eq!(
        group_after_withdraw.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault after withdraw"
    );
}

// security.md sweep — max-leg multi-asset conservation (#32/#22): one portfolio holding positions on
// ALL asset slots must keep every invariant (c_tot==Σcapitals, accounting==real vault, per-asset OI
// balanced). Probes breadth across the full leg array.
#[test]
fn v16_attack_max_leg_multi_asset_conserves() {
    const N: u16 = 4;
    let mut env = V16CuEnv::new_with_market_params_and_price_move(N, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    for ai in 1..N {
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::ConfigureAuthMark {
                asset_index: ai,
                now_slot: 0,
                initial_mark_e6: 100,
            },
            vec![
                AccountMeta::new(env.admin.pubkey(), true),
                AccountMeta::new(env.market, false),
            ],
            &[&env.admin],
        )
        .expect("cfg mark");
    }
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 5_000_000);
    env.deposit(&lb, pb, 5_000_000);
    // open a long on every asset from pa vs pb.
    for ai in 0..N {
        env.svm.expire_blockhash();
        env.trade_asset_with_cu(ai, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    }
    // every leg opened, conservation across all of them.
    let (_, g) = env.market_state();
    for ai in 0..N as usize {
        assert!(
            g.assets[ai].oi_eff_long_q > 0,
            "asset {} position opened",
            ai
        );
        assert_eq!(
            g.assets[ai].oi_eff_long_q, g.assets[ai].oi_eff_short_q,
            "asset {} OI balanced",
            ai
        );
    }
    let sum: u128 = [pa, pb]
        .iter()
        .map(|p| {
            state::read_portfolio(&env.svm.get_account(p).unwrap().data)
                .unwrap()
                .capital
                .get()
        })
        .sum();
    assert_eq!(g.c_tot, sum, "c_tot == Σcapitals across all legs");
    assert_eq!(
        g.c_tot, 10_000_000,
        "no value created across the multi-leg open"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    // crank every asset; still conserves.
    env.svm.warp_to_slot(5);
    for ai in 0..N {
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 5,
                close_q: 0,
                observations: crank_observations(ai),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(pa, false),
            ],
            &[],
        );
    }
    let (_, g2) = env.market_state();
    assert_eq!(
        g2.vault as u64,
        env.token_amount(env.vault),
        "accounting==real vault after cranking all legs"
    );
    assert!(
        g2.vault >= g2.c_tot + g2.insurance,
        "senior conservation after crank"
    );
}

// security.md sweep — full fee'd round-trip conservation (#32/#33): deposit -> open (fee) -> close
// (fee) -> withdraw-all for both parties. Total tokens withdrawn + remaining insurance must equal the
// total deposited (every fee is accounted, nothing created or leaked).
#[test]
fn v16_attack_full_feed_roundtrip_conserves() {
    let mut env = V16CuEnv::new();
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    // open with a fee, then close with a fee (both flat).
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 100);
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, -(POS_SCALE as i128), 100, 100);
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(pa))),
        "la flat"
    );
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(pb))),
        "lb flat"
    );
    // both withdraw all their capital.
    let cap_a = env.portfolio_state(pa).capital.get();
    let cap_b = env.portfolio_state(pb).capital.get();
    env.svm.expire_blockhash();
    let da = env.withdraw(&la, pa, cap_a);
    env.svm.expire_blockhash();
    let db = env.withdraw(&lb, pb, cap_b);
    let out = env.token_amount(da) as u128 + env.token_amount(db) as u128;
    let (_, g) = env.market_state();
    // total accounting closes: tokens out + remaining insurance == total deposited.
    assert_eq!(
        out + g.insurance,
        2_000_000,
        "out ({}) + insurance ({}) == deposited 2M",
        out,
        g.insurance
    );
    assert!(g.insurance > 0, "fees accrued to insurance (non-vacuous)");
    assert_eq!(g.c_tot, 0, "all capital withdrawn");
    assert_eq!(
        g.vault, g.insurance,
        "remaining vault is exactly the insurance (the fees)"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real vault"
    );
    assert!(out <= 2_000_000, "no value created: out <= deposited");
}

// security.md sweep — long sequence with a liquidation (#32/#33 fuzz-lite): a realistic flow including
// an insolvency+liquidation event must keep accounting==real-vault and senior conservation at every
// checkpoint, with no value created across the whole sequence.
#[test]
fn v16_attack_sequence_with_liquidation_conserves() {
    let mut env = V16CuEnv::new();
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    let big = Keypair::new();
    let pbig = env.create_portfolio(&big);
    let thin = Keypair::new();
    let pthin = env.create_portfolio(&thin);
    let cp = Keypair::new();
    let pcp = env.create_portfolio(&cp);
    env.deposit(&big, pbig, 5_000_000);
    env.deposit(&thin, pthin, 250);
    env.deposit(&cp, pcp, 5_000_000);
    let check = |env: &V16CuEnv, tag: &str| {
        let (_, g) = env.market_state();
        assert_eq!(
            g.vault as u64,
            env.token_amount(env.vault),
            "[{}] accounting == real vault",
            tag
        );
        assert!(
            g.vault >= g.c_tot + g.insurance,
            "[{}] senior conservation",
            tag
        );
        let sum: u128 = [pbig, pthin, pcp]
            .iter()
            .map(|p| {
                state::read_portfolio(&env.svm.get_account(p).unwrap().data)
                    .unwrap()
                    .capital
                    .get()
            })
            .sum();
        assert_eq!(g.c_tot, sum, "[{}] c_tot == Σcapitals", tag);
    };
    check(&env, "deposits");
    // big long vs thin short.
    env.trade_with_cu(&big, pbig, &thin, pthin, POS_SCALE as i128, 100, 0);
    check(&env, "open");
    // price up -> thin insolvent.
    for (slot, mark) in [(1u64, 300u64), (2, 800)] {
        env.svm.warp_to_slot(slot);
        env.push_ewma_mark_with_cu(slot, mark);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(pthin, false),
            ],
            &[],
        );
    }
    check(&env, "thin insolvent");
    // Liquidate thin.
    env.crank(
        pthin,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    check(&env, "after liquidation");
    // crank big, then cp trades (fresh activity post-liquidation).
    env.svm.warp_to_slot(3);
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(pbig, false),
        ],
        &[],
    );
    check(&env, "settled");
    let (_, g) = env.market_state();
    assert!(
        g.vault <= 10_000_250,
        "no value created across the whole sequence (deposited 5M+250+5M)"
    );
}

// security.md sweep — EWMA mark halflife edge (#37): configuring the EWMA mark with halflife 0
// (instant) must be handled cleanly — no div-by-zero/panic, no settlement corruption. The mark/price
// stays in valid bounds and conservation holds.
#[test]
fn v16_attack_ewma_mark_halflife_zero_safe() {
    let mut env = V16CuEnv::new();
    // configure with halflife = 0 (instant). If accepted, settlement must stay safe.
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureEwmaMark {
            asset_index: 0,
            now_slot: 0,
            initial_mark_e6: 100,
            mark_ewma_halflife_slots: 0,
            mark_min_fee: 0,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    let lo = Keypair::new();
    let plo = env.create_portfolio(&lo);
    let sh = Keypair::new();
    let psh = env.create_portfolio(&sh);
    env.deposit(&lo, plo, 1_000_000);
    env.deposit(&sh, psh, 1_000_000);
    env.trade_with_cu(&lo, plo, &sh, psh, POS_SCALE as i128, 100, 0);
    // if the halflife=0 config was accepted, push a mark and crank — must not panic/corrupt.
    if r.is_ok() {
        env.svm.warp_to_slot(1);
        env.push_ewma_mark_with_cu(1, 150);
        for slot in [1u64, 2] {
            env.svm.warp_to_slot(slot);
            for p in [psh, plo] {
                env.svm.expire_blockhash();
                let _ = env.send(
                    ProgInstruction::PermissionlessCrank {
                        now_slot: slot,
                        close_q: 0,
                        observations: crank_observations(0),
                    },
                    vec![
                        AccountMeta::new(env.payer.pubkey(), true),
                        AccountMeta::new(env.market, false),
                        AccountMeta::new(p, false),
                    ],
                    &[],
                );
            }
        }
    }
    // regardless of accept/reject: no corruption, state decodes, conservation holds, price in bounds.
    let (_, g) = env.market_state();
    assert_eq!(g.vault, 2_000_000, "vault intact");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert!(
        g.assets[0].effective_price > 0
            && g.assets[0].effective_price <= percolator::MAX_ORACLE_PRICE,
        "price in valid bounds (no corruption)"
    );
    let _ = r;
}

// security.md sweep — vault delegate/close-authority guard (#44 defense-in-depth): the wrapper rejects
// a vault token account that has a delegate or close_authority set (verify_withdrawable_token_accounts).
// This prevents any delegated/closable drain path on the vault. Verify a delegated vault is rejected.
#[test]
fn v16_attack_vault_with_delegate_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000); // funds the canonical vault
    let real_bal = env.token_amount(env.vault);
    // overwrite the canonical vault with the SAME balance/mint/owner but a DELEGATE set.
    let attacker = Pubkey::new_unique();
    let mut delegated = vec![0u8; TokenAccount::LEN];
    TokenAccount::pack(
        TokenAccount {
            mint: env.mint,
            owner: env.vault_authority,
            amount: real_bal,
            delegate: COption::Some(attacker),
            state: AccountState::Initialized,
            is_native: COption::None,
            delegated_amount: real_bal,
            close_authority: COption::None,
        },
        &mut delegated,
    )
    .unwrap();
    env.svm
        .set_account(
            env.vault,
            Account {
                lamports: 1_000_000_000,
                data: delegated,
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    // withdraw against the delegated vault -> reject.
    env.svm.expire_blockhash();
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let r = env.send(
        ProgInstruction::Withdraw { amount: 500_000 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "withdraw against a delegated vault must reject (defense-in-depth)"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no tokens out via a delegated vault"
    );
    assert_eq!(
        env.token_amount(env.vault),
        real_bal,
        "vault balance intact"
    );
}

// security.md sweep — dest token account state validation (#44): withdraw must reject a dest that is
// not Initialized (uninitialized or frozen) — the transfer can't land, so capital must not be debited.
#[test]
fn v16_attack_withdraw_to_noninitialized_dest_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    let do_wd = |env: &mut V16CuEnv, dest: Pubkey| -> Result<u64, String> {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::Withdraw { amount: 500_000 },
            vec![
                AccountMeta::new(owner.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(p, false),
                AccountMeta::new(dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&owner],
        )
    };
    // uninitialized dest (zeroed spl-token-owned account).
    let uninit = Pubkey::new_unique();
    env.svm
        .set_account(
            uninit,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; TokenAccount::LEN],
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    assert!(
        do_wd(&mut env, uninit).is_err(),
        "withdraw to an uninitialized dest must reject"
    );
    // frozen dest.
    let frozen = Pubkey::new_unique();
    let mut fd = vec![0u8; TokenAccount::LEN];
    TokenAccount::pack(
        TokenAccount {
            mint: env.mint,
            owner: owner.pubkey(),
            amount: 0,
            delegate: COption::None,
            state: AccountState::Frozen,
            is_native: COption::None,
            delegated_amount: 0,
            close_authority: COption::None,
        },
        &mut fd,
    )
    .unwrap();
    env.svm
        .set_account(
            frozen,
            Account {
                lamports: 1_000_000_000,
                data: fd,
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    assert!(
        do_wd(&mut env, frozen).is_err(),
        "withdraw to a frozen dest must reject"
    );
    // capital not debited by either rejected withdraw.
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000_000,
        "capital intact after rejected withdraws"
    );
    assert_eq!(env.market_state().1.vault, 1_000_000, "vault unchanged");
    // a valid Initialized dest works.
    let (good, _) = env.withdraw_with_cu(&owner, p, 500_000);
    assert_eq!(
        env.token_amount(good),
        500_000,
        "withdraw to a valid Initialized dest works"
    );
}

// security.md sweep — vault_authority PDA validation (#44): the withdraw must verify the passed
// vault_authority account is the canonical derived PDA (expect_key). A wrong/attacker-chosen
// vault_authority must reject — otherwise a controlled authority could sign the vault transfer.
#[test]
fn v16_attack_wrong_vault_authority_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    let (_, g0) = env.market_state();
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let bad_authority = Pubkey::new_unique(); // not the derived vault PDA
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Withdraw { amount: 500_000 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(bad_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "withdraw with a non-canonical vault_authority must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no tokens out via a wrong vault_authority"
    );
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000_000,
        "capital not debited"
    );
    assert_eq!(env.market_state().1.vault, g0.vault, "vault unchanged");
    // the correct vault_authority still works.
    let (good, _) = env.withdraw_with_cu(&owner, p, 500_000);
    assert_eq!(
        env.token_amount(good),
        500_000,
        "withdraw with the canonical vault_authority works"
    );
}

// security.md sweep — InitPortfolio account-owner validation (#44/#45): initializing a portfolio on an
// account NOT owned by the program must reject (the program can't safely realloc/write a foreign
// account). No corrupting an account it doesn't own.
#[test]
fn v16_attack_init_portfolio_foreign_account_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    env.ensure_signer_account(owner.pubkey());
    // an account owned by SPL Token (a foreign program), sized like a portfolio.
    let foreign = Pubkey::new_unique();
    env.svm
        .set_account(
            foreign,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; env.portfolio_account_len],
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(foreign, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "InitPortfolio on a foreign-owned account must reject"
    );
    // the foreign account is unchanged (still spl-token-owned, not a portfolio).
    let acc = env.svm.get_account(&foreign).unwrap();
    assert_eq!(
        acc.owner,
        spl_token::ID,
        "foreign account ownership unchanged (not hijacked)"
    );
    // a proper program-owned account still initializes fine.
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000);
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000,
        "proper portfolio works"
    );
}

// security.md sweep — asset RETIRE authorization (#6/#48): RETIRE is gated to the asset_authority (or
// admin). A non-authority must NOT be able to retire an asset (which, if it held positions, could
// strand them). The engine additionally requires the asset to be EMPTY before retiring.
#[test]
fn v16_attack_retire_asset_authority_gated() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    )
    .expect("cfg mark");
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    assert!(
        env.market_state().1.assets[1].oi_eff_long_q > 0,
        "asset 1 has open positions"
    );
    // a NON-authority tries to retire asset 1 -> reject.
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    env.svm.warp_to_slot(5);
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_RETIRE,
            asset_index: 1,
            now_slot: 5,
            initial_price: 0,
            insurance_authority: [0u8; 32],
            insurance_operator: [0u8; 32],
            backing_bucket_authority: [0u8; 32],
            oracle_authority: [0u8; 32],
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&mallory],
    );
    assert!(r.is_err(), "non-authority asset RETIRE must reject");
    // positions intact, not stranded.
    assert!(
        env.market_state().1.assets[1].oi_eff_long_q > 0,
        "asset 1 positions NOT stranded by rejected retire"
    );
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}
// security.md sweep — self-crank maintenance fee (#32): an account syncing its OWN maintenance fee as
// the cranker (cranker_portfolio == self) must still conserve — the fee splits into the cranker share
// (back to self) and insurance, totaling exactly the fee charged. No value created by self-cranking.
#[test]
fn v16_attack_self_crank_maintenance_fee_conserves() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 580,
    );
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    env.deposit(&la, pa, 100_000_000);
    env.update_maintenance_fee_policy_with_cu(4_000); // cranker takes 40%
    let cap0 = env.portfolio_state(pa).capital.get();
    let (_, g0) = env.market_state();
    // la syncs its OWN fee, naming ITSELF as the cranker.
    env.svm.warp_to_slot(10);
    let _ = env.try_sync_maintenance_fee_with_cu(pa, Some(pa), 10);
    let cap1 = env.portfolio_state(pa).capital.get();
    let (_, g1) = env.market_state();
    // net effect on la's capital = -(fee) + (cranker share). insurance += (fee - cranker share).
    let net_loss = cap0.saturating_sub(cap1);
    let insurance_gain = g1.insurance - g0.insurance;
    // total value conserved: la's net loss == insurance gain (the cranker share returned to la nets out).
    assert_eq!(
        net_loss, insurance_gain,
        "self-crank: la's net loss == insurance gain (fee fully conserved)"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged (fee internal)");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert_eq!(g1.c_tot, cap1, "c_tot == la's capital (single account)");
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
    // la can't gain from self-cranking: its capital did not increase.
    assert!(
        cap1 <= cap0,
        "self-cranking never increases the caller's capital (no value extraction)"
    );
}

// security.md sweep — per-asset crank isolation (#32/#22): cranking one asset must not alter another
// asset's state. A crank+price-move on asset 0 must leave asset 1's effective_price and OI unchanged
// (no cross-asset corruption).
#[test]
fn v16_attack_per_asset_crank_isolation() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    )
    .expect("cfg mark");
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 2_000_000);
    env.deposit(&lb, pb, 2_000_000);
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    // record asset 1's state.
    let (_, g0) = env.market_state();
    let a1_price0 = g0.assets[1].effective_price;
    let a1_oi_long0 = g0.assets[1].oi_eff_long_q;
    let a1_oi_short0 = g0.assets[1].oi_eff_short_q;
    let a1_klong0 = g0.assets[1].k_long;
    // move ONLY asset 0's mark and crank ONLY asset 0.
    env.svm.warp_to_slot(10);
    env.push_auth_mark_with_cu(10, 130);
    for slot in [10u64, 11] {
        env.svm.warp_to_slot(slot);
        for p in [pa, pb] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    // asset 0 moved; asset 1's state must be UNCHANGED.
    let (_, g1) = env.market_state();
    assert!(
        g1.assets[0].effective_price > a1_price0,
        "asset 0 price moved (non-vacuous)"
    );
    assert_eq!(
        g1.assets[1].effective_price, a1_price0,
        "asset 1 effective_price UNCHANGED by asset-0 crank"
    );
    assert_eq!(
        g1.assets[1].oi_eff_long_q, a1_oi_long0,
        "asset 1 long OI unchanged"
    );
    assert_eq!(
        g1.assets[1].oi_eff_short_q, a1_oi_short0,
        "asset 1 short OI unchanged"
    );
    assert_eq!(
        g1.assets[1].k_long, a1_klong0,
        "asset 1 k_long (settlement index) unchanged"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — ClosePortfolio with parked pnl (#48): an account holding positive (junior) pnl
// must NOT be closeable — closing would discard the pnl and its residual backing. ClosePortfolio
// requires PnL == 0; a portfolio with pnl must reject (the value stays recoverable).
#[test]
fn v16_attack_close_portfolio_with_pnl_rejected() {
    let mut env = V16CuEnv::new();
    let ledger = env.backing_domain_ledger_account();
    env.top_up_backing_bucket_with_ledger_with_cu(ledger, 1, 40, 10);
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.add_source_positive_pnl(p, 1, 40); // p now has +40 pnl, 0 capital
    env.crank(
        p,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert!(
        env.portfolio_state(p).pnl.get() > 0,
        "p holds parked positive pnl (non-vacuous)"
    );
    // ClosePortfolio must reject (PnL != 0).
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::ClosePortfolio,
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
        ],
        &[&owner],
    );
    assert!(r.is_err(), "ClosePortfolio with parked pnl must reject");
    // the account and its pnl are intact (not discarded), conservation holds.
    assert!(
        env.portfolio_state(p).pnl.get() > 0,
        "parked pnl NOT discarded by the rejected close"
    );
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — backing-bucket expiry (#33): a winner's positive pnl backed by a backing bucket
// with an expiry. After the expiry passes, the payout must still be CONSERVING — the winner is paid at
// most the (still-available) backing, never more, and the system never over-pays expired backing.
// (Engine e833b7f / commit 6433346 "Expire lapsed backing at resolved close" makes the realize step
// expire past-expiry backing instead of stranding the winner with Stale — see the prior finding.)
#[test]
fn v16_attack_backing_expiry_no_overpay() {
    let mut env = V16CuEnv::new();
    let ledger = env.backing_domain_ledger_account();
    env.top_up_backing_bucket_with_ledger_with_cu(ledger, 1, 40, 5); // backing expires at slot 5
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000);
    env.add_source_positive_pnl(p, 1, 40);
    // advance PAST the backing expiry.
    env.svm.warp_to_slot(20);
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 20,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
        ],
        &[],
    );
    let vault_before = env.market_state().1.vault;
    env.resolve();
    // two close passes to converge.
    let mut out = 0u128;
    for _ in 0..2 {
        let d = env.close_resolved(&owner, p);
        out += env.token_amount(d) as u128;
    }
    let (_, g) = env.market_state();
    // winner gets at least its senior capital (1000) and at most capital + backing (1040) -- no over-pay.
    assert!(out >= 1_000, "winner recovers at least its senior capital");
    assert!(
        out <= 1_040,
        "winner paid at most capital + backing (no over-pay against expired backing): out={}",
        out
    );
    assert!(g.vault <= vault_before, "vault not over-credited");
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// security.md sweep — large-amount deposit boundary + TVL cap (#37): the vault is capped at
// MAX_VAULT_TVL (overflow prevention). A deposit above the cap must reject; a large deposit just below
// it must credit exactly (no truncation/wraparound in the u128 aggregates) and round-trip exactly.
#[test]
fn v16_attack_large_amount_deposit_withdraw_exact() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    const MAX_TVL: u128 = 10_000_000_000_000_000;
    // over-cap deposit -> reject.
    let over = MAX_TVL + 1;
    let src_over = env.token_account_for_mint(env.mint, owner.pubkey(), over as u64);
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Deposit { amount: over },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(src_over, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "deposit above MAX_VAULT_TVL must reject (overflow/abuse cap)"
    );
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        0,
        "no capital credited on over-cap deposit"
    );

    // large below-cap deposit -> exact credit, no overflow.
    let big: u128 = MAX_TVL - 7;
    env.deposit(&owner, p, big);
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        big,
        "capital credited exactly (no overflow/truncation)"
    );
    let (_, g1) = env.market_state();
    assert_eq!(g1.c_tot, big, "c_tot == the large deposit");
    assert_eq!(g1.vault, big, "vault == the large deposit");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    // withdraw it all back -> exact.
    let (dest, _) = env.withdraw_with_cu(&owner, p, big);
    assert_eq!(
        env.token_amount(dest) as u128,
        big,
        "withdrew exactly the large amount"
    );
    let (_, g2) = env.market_state();
    assert_eq!(g2.c_tot, 0, "c_tot back to 0");
    assert_eq!(g2.vault, 0, "vault drained exactly");
    assert!(g2.vault >= g2.c_tot + g2.insurance, "senior conservation");
}
// security.md sweep — TradeCpi atomic fill vs matcher capacity (#33/#39): a request exceeding the
// matcher's fill capacity must reject ATOMICALLY (no partial/phantom position, no OI), while a
// within-capacity request fills correctly. No phantom over-fill, conservation holds.
#[test]
fn v16_attack_tradecpi_atomic_fill_vs_capacity() {
    let mut env = V16CuEnv::new();
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let taker_owner = Keypair::new();
    let taker = env.create_portfolio(&taker_owner);
    let maker_owner = Keypair::new();
    let maker = env.create_portfolio(&maker_owner);
    env.deposit(&taker_owner, taker, 100_000_000);
    env.deposit(&maker_owner, maker, 100_000_000);
    let (ctx, delegate, _) = env.init_matcher_context_with_data_authorized(
        matcher_program,
        &maker_owner,
        maker,
        encode_matcher_init_passive(POS_SCALE),
    );
    let (_, g0) = env.market_state();
    // request 10x the cap -> rejects atomically (no partial/phantom fill).
    let r_over = env.try_trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker,
        &maker_owner,
        maker,
        matcher_program,
        ctx,
        delegate,
        0,
        (10 * POS_SCALE) as i128,
        100,
    );
    assert!(
        r_over.is_err(),
        "over-capacity TradeCpi must reject atomically"
    );
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.assets[0].oi_eff_long_q, 0,
        "no phantom OI from rejected over-capacity trade"
    );
    assert_eq!(
        env.portfolio_state(taker).legs[0].basis_pos_q.get(),
        0,
        "no partial/phantom position"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged by rejected trade");
    // within-capacity request fills correctly.
    let r_ok = env.try_trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker,
        &maker_owner,
        maker,
        matcher_program,
        ctx,
        delegate,
        0,
        POS_SCALE as i128,
        100,
    );
    assert!(r_ok.is_ok(), "within-capacity TradeCpi fills: {:?}", r_ok);
    let basis = env.portfolio_state(taker).legs[0].basis_pos_q.get();
    assert_eq!(
        basis, POS_SCALE as i128,
        "taker filled exactly the requested within-capacity amount"
    );
    let (_, g2) = env.market_state();
    assert_eq!(
        g2.assets[0].oi_eff_long_q, g2.assets[0].oi_eff_short_q,
        "OI balanced to the fill"
    );
    assert_eq!(
        g2.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g2.vault >= g2.c_tot + g2.insurance, "senior conservation");
}
// security.md sweep — third-party withdraw vs winner's pnl backing (#33/#22): a winner's parked pnl is
// backed by residual (vault - c_tot - insurance). An UNRELATED account withdrawing its own capital
// reduces vault and c_tot equally, so the residual — and thus the winner's backing — must be unchanged.
#[test]
fn v16_attack_third_party_withdraw_preserves_pnl_backing() {
    let mut env = V16CuEnv::new();
    env.configure_auth_mark_with_cu(0, 100);
    let lo = Keypair::new();
    let plo = env.create_portfolio(&lo);
    let sh = Keypair::new();
    let psh = env.create_portfolio(&sh);
    let c = Keypair::new();
    let pc = env.create_portfolio(&c);
    env.deposit(&lo, plo, 1_000_000);
    env.deposit(&sh, psh, 1_000_000);
    env.deposit(&c, pc, 1_000_000); // unrelated, no position
    env.trade_asset_with_cu(0, &lo, plo, &sh, psh, (10_000 * POS_SCALE) as i128, 100, 0);
    // price up -> long parks pnl, short realizes loss (freeing residual).
    env.svm.warp_to_slot(10);
    env.push_auth_mark_with_cu(10, 110);
    for slot in [10u64, 11] {
        env.svm.warp_to_slot(slot);
        for p in [psh, plo] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    let long_pnl = env.portfolio_state(plo).pnl.get();
    assert!(long_pnl > 0, "long has parked pnl (non-vacuous)");
    let (_, g0) = env.market_state();
    let resid0 = g0.vault as i128 - g0.c_tot as i128 - g0.insurance as i128;
    assert!(resid0 >= long_pnl, "long's pnl is backed by residual");

    // unrelated account C withdraws ALL its capital.
    env.svm.expire_blockhash();
    let (_d, _) = env.withdraw_with_cu(&c, pc, 1_000_000);
    let (_, g1) = env.market_state();
    let resid1 = g1.vault as i128 - g1.c_tot as i128 - g1.insurance as i128;
    // residual (and thus the winner's backing) is UNCHANGED by C's withdrawal.
    assert_eq!(
        resid1, resid0,
        "third-party withdraw did NOT change the residual backing the winner"
    );
    assert!(
        resid1 >= env.portfolio_state(plo).pnl.get().max(0),
        "long's pnl still fully backed"
    );
    assert_eq!(
        g1.vault,
        g0.vault - 1_000_000,
        "vault decreased by exactly C's withdrawal"
    );
    assert_eq!(
        g1.c_tot,
        g0.c_tot - 1_000_000,
        "c_tot decreased by exactly C's withdrawal"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — cumulative TVL cap (#37): MAX_VAULT_TVL must be enforced on the TOTAL vault, not
// per-deposit. After the vault reaches the cap, any further deposit must reject (the cumulative cap
// can't be bypassed by splitting deposits).
#[test]
fn v16_attack_cumulative_tvl_cap_enforced() {
    let mut env = V16CuEnv::new();
    const MAX_TVL: u128 = 10_000_000_000_000_000;
    let a = Keypair::new();
    let pa = env.create_portfolio(&a);
    let b = Keypair::new();
    let pb = env.create_portfolio(&b);
    // fill the vault to exactly the cap.
    env.deposit(&a, pa, MAX_TVL);
    assert_eq!(env.market_state().1.vault, MAX_TVL, "vault at the cap");
    // a SECOND deposit (even tiny) by another account must reject -- cumulative cap.
    let src = env.token_account_for_mint(env.mint, b.pubkey(), 100);
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Deposit { amount: 100 },
        vec![
            AccountMeta::new(b.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(pb, false),
            AccountMeta::new(src, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&b],
    );
    assert!(
        r.is_err(),
        "deposit pushing the vault over MAX_VAULT_TVL must reject (cumulative cap)"
    );
    assert_eq!(
        env.portfolio_state(pb).capital.get(),
        0,
        "no capital credited over the cap"
    );
    assert_eq!(
        env.market_state().1.vault,
        MAX_TVL,
        "vault still exactly at the cap"
    );
    assert_eq!(
        env.token_amount(src),
        100,
        "would-be depositor's source untouched"
    );
    // and the first depositor can still withdraw their funds (cap doesn't lock them).
    let (d, _) = env.withdraw_with_cu(&a, pa, 1_000_000);
    assert_eq!(
        env.token_amount(d),
        1_000_000,
        "funds withdrawable from a capped vault"
    );
}

// security.md sweep — cumulative TVL cap across top-up interfaces (#37/#44): deposit coverage alone
// does not prove the privileged top-up paths honor the same total-vault cap after their internal
// insurance/backing accounting mutations. Each over-cap attempt below uses a real token source and
// optional ledger account, rejects atomically, then a one-atom top-up succeeds exactly at the cap.
#[test]
fn v16_attack_topups_cannot_bypass_cumulative_tvl_cap() {
    fn fill_to_one_below_cap(env: &mut V16CuEnv) {
        let depositor = Keypair::new();
        let portfolio = env.create_portfolio(&depositor);
        env.deposit(&depositor, portfolio, percolator::MAX_VAULT_TVL - 1);
        assert_eq!(
            env.market_state().1.vault,
            percolator::MAX_VAULT_TVL - 1,
            "setup fills the vault to one atom below MAX_VAULT_TVL"
        );
        assert_eq!(
            env.token_amount(env.vault) as u128,
            percolator::MAX_VAULT_TVL - 1,
            "setup token vault matches accounting"
        );
    }

    {
        let mut env = V16CuEnv::new();
        fill_to_one_below_cap(&mut env);
        let admin = env.admin.insecure_clone();
        let source = env.token_account(admin.pubkey(), 2);
        let ledger = env.insurance_ledger_account();
        let market_before = env.svm.get_account(&env.market).unwrap();
        let ledger_before = env.svm.get_account(&ledger).unwrap();
        let source_before = env.svm.get_account(&source).unwrap();
        let vault_before = env.svm.get_account(&env.vault).unwrap();

        env.svm.expire_blockhash();
        let result = env.send(
            ProgInstruction::TopUpInsurance { amount: 2 },
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
                AccountMeta::new(ledger, false),
            ],
            &[&admin],
        );
        assert!(
            result.is_err(),
            "market insurance top-up pushing total vault over MAX_VAULT_TVL must reject"
        );
        assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
        assert_eq!(env.svm.get_account(&ledger).unwrap(), ledger_before);
        assert_eq!(env.svm.get_account(&source).unwrap(), source_before);
        assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);

        let ok_source = env.token_account(env.admin.pubkey(), 1);
        env.svm.expire_blockhash();
        env.top_up_insurance_from_admin_token_with_cu(ok_source, 1);
        let (_, group) = env.market_state();
        assert_eq!(group.vault, percolator::MAX_VAULT_TVL);
        assert_eq!(group.insurance, 1);
        assert_eq!(env.token_amount(ok_source), 0);
        assert_eq!(
            env.token_amount(env.vault) as u128,
            percolator::MAX_VAULT_TVL
        );
    }

    {
        let mut env = V16CuEnv::new();
        fill_to_one_below_cap(&mut env);
        let admin = env.admin.insecure_clone();
        let source = env.token_account(admin.pubkey(), 2);
        let ledger = env.insurance_ledger_account();
        let market_before = env.svm.get_account(&env.market).unwrap();
        let ledger_before = env.svm.get_account(&ledger).unwrap();
        let source_before = env.svm.get_account(&source).unwrap();
        let vault_before = env.svm.get_account(&env.vault).unwrap();

        env.svm.expire_blockhash();
        let result = env.send(
            ProgInstruction::TopUpInsuranceDomain {
                domain: 0,
                amount: 2,
            },
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
                AccountMeta::new(ledger, false),
            ],
            &[&admin],
        );
        assert!(
            result.is_err(),
            "domain insurance top-up pushing total vault over MAX_VAULT_TVL must reject"
        );
        assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
        assert_eq!(env.svm.get_account(&ledger).unwrap(), ledger_before);
        assert_eq!(env.svm.get_account(&source).unwrap(), source_before);
        assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);

        let ok_source = env.token_account(admin.pubkey(), 1);
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::TopUpInsuranceDomain {
                domain: 0,
                amount: 1,
            },
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(ok_source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&admin],
        )
        .expect("one-atom domain insurance top-up reaches the exact cap");
        let (_, group) = env.market_state();
        assert_eq!(group.vault, percolator::MAX_VAULT_TVL);
        assert_eq!(group.insurance, 1);
        assert_eq!(group.insurance_domain_budget[0], 1);
        assert_eq!(group.insurance_domain_budget_remaining_total, 1);
        assert_eq!(env.token_amount(ok_source), 0);
        assert_eq!(
            env.token_amount(env.vault) as u128,
            percolator::MAX_VAULT_TVL
        );
    }

    {
        let mut env = V16CuEnv::new();
        fill_to_one_below_cap(&mut env);
        let admin = env.admin.insecure_clone();
        let source = env.token_account(admin.pubkey(), 2);
        let ledger = env.backing_domain_ledger_account();
        let market_before = env.svm.get_account(&env.market).unwrap();
        let ledger_before = env.svm.get_account(&ledger).unwrap();
        let source_before = env.svm.get_account(&source).unwrap();
        let vault_before = env.svm.get_account(&env.vault).unwrap();

        env.svm.expire_blockhash();
        let result = env.send(
            ProgInstruction::TopUpBackingBucket {
                domain: 1,
                amount: 2,
                expiry_slot: 10_000,
            },
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
                AccountMeta::new(ledger, false),
            ],
            &[&admin],
        );
        assert!(
            result.is_err(),
            "backing bucket top-up pushing total vault over MAX_VAULT_TVL must reject"
        );
        assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
        assert_eq!(env.svm.get_account(&ledger).unwrap(), ledger_before);
        assert_eq!(env.svm.get_account(&source).unwrap(), source_before);
        assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);

        let ok_source = env.token_account(env.admin.pubkey(), 1);
        env.svm.expire_blockhash();
        env.top_up_backing_bucket_from_admin_token_with_cu(ok_source, 1, 1, 10_000);
        let (_, group) = env.market_state();
        assert_eq!(group.vault, percolator::MAX_VAULT_TVL);
        assert_eq!(
            group.source_backing_buckets[1].fresh_unliened_backing_num,
            BOUND_SCALE
        );
        assert_eq!(
            group.source_credit[1].fresh_reserved_backing_num,
            BOUND_SCALE
        );
        assert_eq!(env.token_amount(ok_source), 0);
        assert_eq!(
            env.token_amount(env.vault) as u128,
            percolator::MAX_VAULT_TVL
        );
    }
}

// security.md sweep — portfolio-as-market confusion (#44/#45): passing a portfolio account where the
// market is expected must reject (the market view decode fails on portfolio-shaped data). No cross-
// type confusion drains funds.
#[test]
fn v16_attack_portfolio_as_market_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    let other = Keypair::new();
    let p2 = env.create_portfolio(&other);
    env.deposit(&owner, p, 1_000_000);
    let (_, g0) = env.market_state();
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    // withdraw but pass a PORTFOLIO account (p2) in the MARKET slot.
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Withdraw { amount: 500_000 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(p2, false),
            AccountMeta::new(p, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "withdraw with a portfolio in the market slot must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no funds drained via type confusion"
    );
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000_000,
        "capital intact"
    );
    assert_eq!(env.market_state().1.vault, g0.vault, "vault unchanged");
}

// security.md sweep — wrong-mint vault (#44): the vault token account must hold the collateral mint.
// A vault of a different mint must reject (mint check + canonical-ATA pin), so no draining via a
// mismatched-mint vault.
#[test]
fn v16_attack_wrong_mint_vault_rejected() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    let real_bal = env.token_amount(env.vault);
    // overwrite the vault address with a token account of a DIFFERENT mint (still vault_authority-owned).
    let other_mint = Pubkey::new_unique();
    env.svm
        .set_account(
            env.vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(other_mint, env.vault_authority, real_bal),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Withdraw { amount: 500_000 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "withdraw against a wrong-mint vault must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no tokens out via a wrong-mint vault"
    );
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000_000,
        "capital not debited"
    );
}

// security.md sweep — no-fee liquidation cranker reward (#3): with no liquidation fee configured
// (default), a third-party cranker liquidating an insolvent account must receive ZERO reward — no
// value extraction from a no-fee liquidation. Conservation holds.
#[test]
fn v16_attack_no_fee_liquidation_cranker_gets_nothing() {
    let mut env = V16CuEnv::new(); // default: liquidation_fee_bps = 0
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    let cranker_account = env.create_portfolio(&cranker_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 250);
    env.deposit(&cranker_owner, cranker_account, 1_000);
    env.configure_ewma_mark_with_cu(0, 100, 1, 0);
    env.trade_with_cu(
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    for (slot, mark) in [(1u64, 300u64), (2, 800)] {
        env.svm.warp_to_slot(slot);
        env.push_ewma_mark_with_cu(slot, mark);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(short_account, false),
            ],
            &[],
        );
    }
    let cranker0 = env.portfolio_state(cranker_account).capital.get();
    let (_, g0) = env.market_state();
    // Liquidate without a reward tail: when reward sharing is disabled, the public crank
    // does not accept a cranker portfolio and cannot credit one.
    env.crank(
        short_account,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    // cranker got NO reward (no fee configured).
    assert_eq!(
        env.portfolio_state(cranker_account).capital.get(),
        cranker0,
        "cranker receives no reward in a no-fee liquidation"
    );
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.vault, g0.vault,
        "vault unchanged (internal liquidation, no fee out)"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// full-interface sweep: keeper bots may include a reward-portfolio hint even when governance has
// liquidation rewards disabled. With clean-crank tail parsing, that malformed extra program-owned
// tail must reject atomically rather than being treated as an oracle or reward account.
#[test]
fn v16_attack_liquidation_reward_hint_rejects_when_share_disabled() {
    const LIQ_SLOT: u64 = 30;

    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    assert_eq!(
        env.market_state().0.liquidation_cranker_fee_share_bps,
        0,
        "test setup keeps cranker rewards disabled while liquidation fees remain nonzero"
    );
    env.configure_auth_mark_with_cu(0, 1_000_000);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let hint_owner = Keypair::new();
    let keeper = Keypair::new();
    env.ensure_signer_account(keeper.pubkey());
    let long = env.create_portfolio(&long_owner);
    let short = env.create_portfolio(&short_owner);
    let reward_hint = env.create_portfolio(&hint_owner);
    env.deposit(&long_owner, long, 100_000_000);
    env.deposit(&short_owner, short, 100_000);
    env.trade_asset_with_cu(
        0,
        &long_owner,
        long,
        &short_owner,
        short,
        POS_SCALE as i128,
        1_000_000,
        0,
    );

    for slot in 1..=LIQ_SLOT {
        env.svm.warp_to_slot(slot);
        env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(short, false),
            ],
            &[],
        );
    }
    assert!(
        health_cert(&env.portfolio_state(short)).certified_liq_deficit != 0,
        "setup must make the target liquidatable before probing the disabled-reward hint"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let short_before = env.svm.get_account(&short).unwrap();
    let hint_before = env.svm.get_account(&reward_hint).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: LIQ_SLOT,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(keeper.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(short, false),
            AccountMeta::new(reward_hint, false),
        ],
        &[&keeper],
    );
    assert!(
        rejected.is_err(),
        "disabled reward share must not accept an extra reward-tail account"
    );
    let err = format!("{rejected:?}");
    assert!(
        err.contains("Custom(9)"),
        "expected InvalidInstruction for malformed disabled-reward tail, got {err}"
    );

    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "disabled reward hint rejection must roll back market bytes"
    );
    assert_eq!(
        env.svm.get_account(&short).unwrap(),
        short_before,
        "disabled reward hint rejection must roll back the liquidatable account"
    );
    assert_eq!(
        env.svm.get_account(&reward_hint).unwrap(),
        hint_before,
        "disabled reward hint must not be signer-checked, grown, or credited"
    );
}

// security.md sweep — withdraw requires flat account (#19/#46): withdraw_not_atomic requires the
// account to be FLAT (active_bitmap empty) — ANY open position blocks withdrawal, regardless of how
// small the position or how large the capital. After closing, the full capital is recoverable (no
// permanent lock). This documents the flatness gate (not a margin calc).
#[test]
fn v16_attack_withdraw_requires_flat_regardless_of_size() {
    let mut env = V16CuEnv::new();
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 10_000_000);
    env.deposit(&lb, pb, 10_000_000);
    // TINY position (notional 100) vs huge (10M) capital.
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    // even a tiny withdrawal is blocked while ANY position is open (flatness gate, not margin).
    let try_wd = |env: &mut V16CuEnv, amt: u128| -> bool {
        env.svm.expire_blockhash();
        let dd = Pubkey::new_unique();
        env.svm
            .set_account(
                dd,
                Account {
                    lamports: 1_000_000_000,
                    data: make_token_data(env.mint, la.pubkey(), 0),
                    owner: spl_token::ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        env.send(
            ProgInstruction::Withdraw { amount: amt },
            vec![
                AccountMeta::new(la.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(pa, false),
                AccountMeta::new(dd, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&la],
        )
        .is_ok()
    };
    assert!(
        !try_wd(&mut env, 1),
        "tiny withdraw blocked while a (tiny) position is open"
    );
    assert!(
        !try_wd(&mut env, 9_000_000),
        "bulk withdraw also blocked while positioned"
    );
    assert_eq!(
        env.portfolio_state(pa).capital.get(),
        10_000_000,
        "capital intact (no partial debit)"
    );
    // close the position -> full capital recoverable (no permanent lock).
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, -(POS_SCALE as i128), 100, 0);
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(pa))),
        "la flat after close"
    );
    let cap = env.portfolio_state(pa).capital.get();
    let (d2, _) = env.withdraw_with_cu(&la, pa, cap);
    assert_eq!(
        env.token_amount(d2) as u128,
        cap,
        "full capital recovered after closing (no permanent lock)"
    );
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}
// security.md sweep — withdraw blocked during active close (#22/#48): an account with an active/in-
// progress forced close must NOT be able to withdraw (withdraw_not_atomic rejects a non-inert close
// ledger). Prevents withdrawing funds out from under a forced close.
#[test]
fn v16_attack_withdraw_blocked_during_active_close() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    // seed an ACTIVE (cancellable) forced-close ledger.
    env.seed_cancellable_close_progress(p);
    // withdraw must reject while the close is active.
    env.svm.expire_blockhash();
    let dest = Pubkey::new_unique();
    env.svm
        .set_account(
            dest,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, owner.pubkey(), 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let r = env.send(
        ProgInstruction::Withdraw { amount: 500_000 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r.is_err(),
        "withdraw during an active forced-close must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no funds withdrawn during active close"
    );
    assert_eq!(
        env.portfolio_state(p).capital.get(),
        1_000_000,
        "capital intact"
    );
    // after curing+cancelling the close (Finding E), withdraw works again.
    let src = env.token_account(owner.pubkey(), 0);
    env.cure_and_cancel_close_with_cu(&owner, p, src, 0);
    let (d, _) = env.withdraw_with_cu(&owner, p, 500_000);
    assert_eq!(
        env.token_amount(d),
        500_000,
        "withdraw works after curing the close"
    );
}

// security.md sweep — trade blocked during active close (#22): an account with an active forced-close
// must not be able to open/modify positions (it's being wound down). Trading on it must reject.
#[test]
fn v16_attack_trade_blocked_during_active_close() {
    let mut env = V16CuEnv::new();
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.seed_cancellable_close_progress(pa); // la has an active forced-close
    let (_, g0) = env.market_state();
    // trading on la (with an active close) must reject.
    env.svm.expire_blockhash();
    let r = env.try_trade_asset_with_cu(0, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);
    assert!(
        r.is_err(),
        "trade on an account with an active forced-close must reject"
    );
    assert_eq!(
        env.portfolio_state(pa).legs[0].basis_pos_q.get(),
        0,
        "no position opened during active close"
    );
    let (_, g1) = env.market_state();
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert_eq!(g1.assets[0].oi_eff_long_q, 0, "no OI created");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// security.md sweep — per-asset funding isolation (#33/#22): funding accruing on one asset (its mark
// premium) must NOT alter another asset's funding ledger. Asset 0's funding must leave asset 1's
// f_long_num/f_short_num unchanged.
#[test]
fn v16_attack_per_asset_funding_isolation() {
    const IP: u64 = 1_000_000;
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        max_portfolio_assets: 2,
        initial_price: IP,
        max_price_move_bps_per_slot: 1_000,
        max_accrual_dt_slots: 1,
        max_abs_funding_e9_per_slot: 1_000,
        min_funding_lifetime_slots: 1,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(0);
    env.configure_ewma_mark_with_cu(0, IP, 1, 0);
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureEwmaMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: IP,
            mark_ewma_halflife_slots: 1,
            mark_min_fee: 0,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    )
    .expect("cfg ewma asset1");
    let lo = Keypair::new();
    let plo = env.create_portfolio(&lo);
    let sh = Keypair::new();
    let psh = env.create_portfolio(&sh);
    env.deposit(&lo, plo, 100_000_000);
    env.deposit(&sh, psh, 100_000_000);
    // balanced positions on BOTH assets.
    env.trade_with_cu(&lo, plo, &sh, psh, POS_SCALE as i128, IP, 0);
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(1, &lo, plo, &sh, psh, POS_SCALE as i128, IP, 0);
    let a1_flong0 = env.market_state().1.assets[1].f_long_num;
    let a1_fshort0 = env.market_state().1.assets[1].f_short_num;
    // induce a mark premium and accrue funding on asset 0 ONLY.
    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, IP * 2); // asset 0 premium
    for slot in 1..=4u64 {
        env.svm.warp_to_slot(slot);
        for p in [plo, psh] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    let (_, g) = env.market_state();
    // asset 0 funding accrued; asset 1's funding ledger UNCHANGED.
    assert!(
        g.assets[0].f_long_num != 0,
        "asset 0 funding accrued (non-vacuous)"
    );
    assert_eq!(
        g.assets[1].f_long_num, a1_flong0,
        "asset 1 f_long_num UNCHANGED by asset-0 funding"
    );
    assert_eq!(
        g.assets[1].f_short_num, a1_fshort0,
        "asset 1 f_short_num unchanged"
    );
    assert_eq!(g.vault, 200_000_000, "vault conserved");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — deposit during active close (#22): a plain deposit to an account with an active
// forced-close must be handled safely — whether allowed (adds capital toward curing) or rejected, it
// must conserve and never corrupt the close ledger or accounting.
#[test]
fn v16_attack_deposit_during_active_close_safe() {
    let mut env = V16CuEnv::new();
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000_000);
    env.seed_cancellable_close_progress(p);
    let cap0 = env.portfolio_state(p).capital.get();
    let (_, g0) = env.market_state();
    // attempt a plain deposit during the active close.
    let src = env.token_account_for_mint(env.mint, owner.pubkey(), 500);
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::Deposit { amount: 500 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(src, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    let cap1 = env.portfolio_state(p).capital.get();
    let (_, g1) = env.market_state();
    // either outcome must conserve: capital change == vault change == source debit, accounting intact.
    if r.is_ok() {
        assert_eq!(cap1, cap0 + 500, "deposit credited exactly during close");
        assert_eq!(
            g1.vault,
            g0.vault + 500,
            "vault grew by exactly the deposit"
        );
        assert_eq!(env.token_amount(src), 0, "source fully transferred");
    } else {
        assert_eq!(cap1, cap0, "rejected deposit: capital unchanged");
        assert_eq!(g1.vault, g0.vault, "rejected deposit: vault unchanged");
        assert_eq!(
            env.token_amount(src),
            500,
            "rejected deposit: source untouched"
        );
    }
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — fee-redirect split lands in the correct domains (#32/#33): with
// fee_redirect_to_market_0_bps set, a fee'd trade on market N must split EXACTLY: the redirect share
// to market 0's domain budget(s), the rest to market N's local domain budget(s). Total == fee
// charged (conservation), no value created/lost in the split.
#[test]
fn v16_attack_fee_redirect_split_lands_correctly() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    )
    .expect("cfg mark");
    env.update_fee_redirect_policy_with_cu(2_000); // 20% of market 1..N fees -> market 0 domain
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 5_000_000);
    env.deposit(&lb, pb, 5_000_000);
    let dom = |env: &V16CuEnv, d: usize| env.market_state().1.insurance_domain_budget[d];
    let (b0, b1, b2, b3) = (dom(&env, 0), dom(&env, 1), dom(&env, 2), dom(&env, 3));
    let ins0 = env.market_state().1.insurance;
    // fee'd trade on ASSET 1 (market 1) -> fees split between market 0 (domains 0,1) and market 1 (2,3).
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, (10_000 * POS_SCALE) as i128, 100, 100); // notional 1M -> fee large enough for the redirect
    let (g0d, g1d, g2d, g3d) = (
        dom(&env, 0) - b0,
        dom(&env, 1) - b1,
        dom(&env, 2) - b2,
        dom(&env, 3) - b3,
    );
    let total_to_mkt0 = g0d + g1d; // domains 0,1 belong to market 0
    let total_to_mkt1 = g2d + g3d; // domains 2,3 belong to market 1
    let total_fee = total_to_mkt0 + total_to_mkt1;
    assert!(total_fee > 0, "a fee was charged (non-vacuous)");
    // global insurance grew by exactly the total fee (conservation).
    assert_eq!(
        env.market_state().1.insurance,
        ins0 + total_fee,
        "insurance += total fee"
    );
    // the redirect share (20%) landed in market 0's domains; the rest (80%) stayed local in market 1.
    // each side: redirect = floor(fee_side * 2000/10000); allow +-1 per side for flooring.
    assert!(
        total_to_mkt0 >= total_fee * 2 / 10 - 2 && total_to_mkt0 <= total_fee * 2 / 10 + 2,
        "~20% of fee redirected to market 0 (got {} of {})",
        total_to_mkt0,
        total_fee
    );
    assert!(
        total_to_mkt1 >= total_fee * 8 / 10 - 2,
        "~80% of fee stayed local in market 1 (got {})",
        total_to_mkt1
    );
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_domain_budget_remaining_total_consistent(&g, "trade fee redirect split");
}

// security.md sweep — backing-fee policy authorization (#6) [fee-routing #7]: UpdateBackingFeePolicy
// (per-domain backing fee + insurance share) is gated to the domain's insurance_authority. A non-
// authority must reject, and an out-of-range share must reject. No unauthorized fee-policy tampering.
#[test]
fn v16_attack_backing_fee_policy_authority_gated() {
    let mut env = V16CuEnv::new();
    let (cfg0, _) = env.market_state();
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    // non-authority sets the backing fee policy -> reject.
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 0,
            fee_bps: 77,
            insurance_share_bps: 5_000,
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&mallory],
    );
    assert!(
        r.is_err(),
        "non-authority backing fee policy update must reject"
    );
    // out-of-range insurance share (>10000) by the real authority -> reject.
    env.svm.expire_blockhash();
    let r_oob = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 0,
            fee_bps: 77,
            insurance_share_bps: 20_000,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(r_oob.is_err(), "insurance_share_bps > 10000 must reject");
    // policy unchanged by the rejected updates.
    let (cfg1, _) = env.market_state();
    assert_eq!(
        cfg1.backing_trade_fee_bps_long, cfg0.backing_trade_fee_bps_long,
        "backing fee policy unchanged"
    );
    assert_eq!(
        cfg1.backing_trade_fee_insurance_share_bps_long,
        cfg0.backing_trade_fee_insurance_share_bps_long,
        "insurance share unchanged"
    );
    // the real authority CAN set it (control).
    env.update_backing_fee_policy_with_cu(0, 77, 5_000);
    assert_eq!(
        env.market_state()
            .0
            .backing_trade_fee_insurance_share_bps_long,
        5_000,
        "authority sets the insurance share"
    );
}

// security.md sweep - cross-asset fee-policy isolation (#6/#104): UpdateBackingFeePolicy is a
// shared config write guarded by the target domain's insurance_authority. An authority for asset 1
// must not be able to mutate asset 0's backing fee policy or the global nonzero-policy counter.
#[test]
fn v16_attack_cross_asset_insurance_authority_cannot_update_other_backing_fee_policy() {
    let mut env = V16CuEnv::new();
    let asset1_insurance = Keypair::new();
    env.activate_asset_with_authorities(
        1,
        1,
        100,
        asset1_insurance.pubkey(),
        env.admin.pubkey(),
        env.admin.pubkey(),
        env.admin.pubkey(),
    );
    env.ensure_signer_account(asset1_insurance.pubkey());

    let market_before = env.svm.get_account(&env.market).unwrap().data;
    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 0,
            fee_bps: 91,
            insurance_share_bps: 5_000,
        },
        vec![
            AccountMeta::new(asset1_insurance.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&asset1_insurance],
    );
    assert!(
        rejected.is_err(),
        "asset-1 insurance authority must not update asset-0 backing fee policy"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        market_before,
        "cross-asset policy rejection must not mutate shared config/profile bytes"
    );

    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 2,
            fee_bps: 91,
            insurance_share_bps: 5_000,
        },
        vec![
            AccountMeta::new(asset1_insurance.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&asset1_insurance],
    )
    .expect("asset-1 insurance authority updates its own backing fee policy");

    let market_after = env.svm.get_account(&env.market).unwrap();
    let (cfg_after, _) = env.market_state();
    let profile0 = state::read_asset_oracle_profile(&market_after.data, 0).unwrap();
    let profile1 = state::read_asset_oracle_profile(&market_after.data, 1).unwrap();
    assert_eq!(cfg_after.backing_trade_fee_policy_count, 1);
    assert_eq!(
        cfg_after.backing_trade_fee_bps_long, 0,
        "asset-0 backing fee policy remains unset"
    );
    assert_eq!(
        profile0.backing_trade_fee_bps_long, 0,
        "asset-0 profile remains untouched"
    );
    assert_eq!(profile1.backing_trade_fee_bps_long, 91);
    assert_eq!(profile1.backing_trade_fee_insurance_share_bps_long, 5_000);
}

// security.md sweep — global policy bounds (#3/#6/#37): marketauth controls cranker reward and
// fee policies, but even the authorized key must not be able to install over-100% reward shares,
// over-max trade fees, oversized permissionless-init fees, or a nonzero insurance split on a zero
// backing fee. These bad knobs can turn later public reward/top-up paths into DoS or over-credit
// surfaces. Rejected writes must leave the whole market byte-identical, and the prior bounded
// maintenance reward policy must remain live.
#[test]
fn v16_attack_global_policy_bounds_reject_grief_values() {
    let mut env = V16CuEnv::new_with_market_params_price_move_and_maintenance_fee(
        1, 10_000, 10_000, 10_000, 58,
    );
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.update_maintenance_fee_policy_with_cu(4_000);
    env.update_trade_fee_policy_with_cu(88);
    env.update_market_init_fee_policy_with_cu(40);

    let market_before = env.svm.get_account(&env.market).unwrap();
    let reject_unchanged = |env: &mut V16CuEnv, ix: ProgInstruction, label: &str| {
        env.svm.expire_blockhash();
        let rejected = send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ix,
            vec![
                AccountMeta::new(env.admin.pubkey(), true),
                AccountMeta::new(env.market, false),
            ],
            &[&env.admin],
        );
        assert!(rejected.is_err(), "{label} must reject");
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "{label} must leave the market byte-identical"
        );
    };

    reject_unchanged(
        &mut env,
        ProgInstruction::UpdateLiquidationFeePolicy {
            cranker_share_bps: 10_001,
        },
        "liquidation cranker share above 100%",
    );
    reject_unchanged(
        &mut env,
        ProgInstruction::UpdateMaintenanceFeePolicy {
            cranker_share_bps: 10_001,
        },
        "maintenance cranker share above 100%",
    );
    reject_unchanged(
        &mut env,
        ProgInstruction::UpdateTradeFeePolicy {
            trade_fee_base_bps: 10_001,
        },
        "trade fee above the market maximum",
    );
    reject_unchanged(
        &mut env,
        ProgInstruction::UpdateMarketInitFeePolicy {
            min_init_fee: u128::from(u64::MAX) + 1,
        },
        "permissionless init fee that cannot fit a token transfer",
    );
    reject_unchanged(
        &mut env,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 0,
            fee_bps: 0,
            insurance_share_bps: 1,
        },
        "nonzero backing insurance split on a zero backing fee",
    );

    let (cfg, _) = env.market_state();
    assert_eq!(cfg.liquidation_cranker_fee_share_bps, 5_000);
    assert_eq!(cfg.maintenance_cranker_fee_share_bps, 4_000);
    assert_eq!(cfg.trade_fee_base_bps, 88);
    assert_eq!(cfg.permissionless_market_init_fee, 40);
    assert_eq!(cfg.backing_trade_fee_policy_count, 0);

    let payer_owner = Keypair::new();
    let cranker_owner = Keypair::new();
    let payer_portfolio = env.create_portfolio(&payer_owner);
    let cranker_portfolio = env.create_portfolio(&cranker_owner);
    env.deposit(&payer_owner, payer_portfolio, 100_000_000);
    env.svm.warp_to_slot(10);
    env.sync_maintenance_fee_with_cu(payer_portfolio, Some(cranker_portfolio), 10);

    let payer = env.portfolio_state(payer_portfolio);
    let cranker = env.portfolio_state(cranker_portfolio);
    let (_, group) = env.market_state();
    assert_eq!(
        payer.capital.get(),
        100_000_000 - 580,
        "bounded policy charges exactly the elapsed maintenance fee"
    );
    assert_eq!(
        cranker.capital.get(),
        232,
        "preserved 40% maintenance cranker share still pays a real bounded reward"
    );
    assert_eq!(
        group.insurance, 348,
        "remaining maintenance fee stays in insurance"
    );
    assert_domain_budget_remaining_total_consistent(&group, "bounded global policy reward");
}

// Low-fee-cap markets are a separate public-interface branch from the global 10_000 bps cap:
// an authorized policy write must not raise the configured base fee above the market's own max.
#[test]
fn v16_attack_trade_fee_policy_respects_low_market_fee_cap() {
    const MAX_FEE_BPS: u64 = 37;

    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        max_trading_fee_bps: MAX_FEE_BPS,
        ..V16CuMarketParams::default()
    });
    let market_before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateTradeFeePolicy {
            trade_fee_base_bps: MAX_FEE_BPS + 1,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(
        rejected.is_err(),
        "authorized trade-fee update above a low market max must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected low-cap fee update must leave the market byte-identical"
    );
    assert_eq!(env.market_state().0.trade_fee_base_bps, 0);

    env.svm.expire_blockhash();
    env.update_trade_fee_policy_with_cu(MAX_FEE_BPS);
    assert_eq!(
        env.market_state().0.trade_fee_base_bps,
        MAX_FEE_BPS,
        "the exact market fee cap remains a live accepted policy value"
    );
}

// Backing-fee policy has its own public write path and policy counter/profile mirror. Low-fee-cap
// markets must reject authorized backing-fee writes above that market cap without partially touching
// the shared config, profile, or nonzero-policy count.
#[test]
fn v16_attack_backing_fee_policy_respects_low_market_fee_cap() {
    const MAX_FEE_BPS: u16 = 37;

    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        max_trading_fee_bps: u64::from(MAX_FEE_BPS),
        ..V16CuMarketParams::default()
    });
    let market_before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 0,
            fee_bps: MAX_FEE_BPS + 1,
            insurance_share_bps: 5_000,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(
        rejected.is_err(),
        "authorized backing-fee update above a low market max must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected low-cap backing-fee update must leave the market byte-identical"
    );

    let (cfg_after_reject, _) = env.market_state();
    assert_eq!(cfg_after_reject.backing_trade_fee_policy_count, 0);
    assert_eq!(cfg_after_reject.backing_trade_fee_bps_long, 0);
    assert_eq!(
        cfg_after_reject.backing_trade_fee_insurance_share_bps_long,
        0
    );

    env.svm.expire_blockhash();
    env.update_backing_fee_policy_with_cu(0, MAX_FEE_BPS, 5_000);
    let market_after = env.svm.get_account(&env.market).unwrap();
    let (cfg_after_accept, _) = env.market_state();
    let profile_after_accept = state::read_asset_oracle_profile(&market_after.data, 0).unwrap();
    assert_eq!(
        cfg_after_accept.backing_trade_fee_policy_count, 1,
        "exact-cap backing-fee policy installs one nonzero policy"
    );
    assert_eq!(cfg_after_accept.backing_trade_fee_bps_long, MAX_FEE_BPS);
    assert_eq!(
        cfg_after_accept.backing_trade_fee_insurance_share_bps_long,
        5_000
    );
    assert_eq!(profile_after_accept.backing_trade_fee_bps_long, MAX_FEE_BPS);
    assert_eq!(
        profile_after_accept.backing_trade_fee_insurance_share_bps_long,
        5_000
    );
}

// security.md sweep - trade-fee authority isolation (#6/#33): UpdateTradeFeePolicy is a
// market-wide economic knob, but the code intentionally gates it to asset-0's insurance authority.
// After asset-0 insurance is rotated away from marketauth, stale marketauth must not be able to raise
// the fee floor and grief trading; the new asset-0 insurance key can set it, and the fee is charged.
#[test]
fn v16_attack_trade_fee_policy_follows_asset0_insurance_authority() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let new_insurance = Keypair::new();
    env.try_update_per_asset_authority_with_cu(
        &admin,
        Some(&new_insurance),
        0,
        processor::ASSET_AUTH_INSURANCE,
        new_insurance.pubkey().to_bytes(),
    )
    .expect("rotate asset-0 insurance authority away from marketauth");
    assert_eq!(
        state::read_asset_oracle_profile(&env.svm.get_account(&env.market).unwrap().data, 0)
            .unwrap()
            .insurance_authority,
        new_insurance.pubkey().to_bytes()
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    env.svm.expire_blockhash();
    let stale_marketauth = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateTradeFeePolicy {
            trade_fee_base_bps: 500,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        stale_marketauth.is_err(),
        "old marketauth must not control the trade fee floor after asset-0 insurance rotates"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected stale marketauth fee update leaves market bytes unchanged"
    );
    assert_eq!(env.market_state().0.trade_fee_base_bps, 0);

    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateTradeFeePolicy {
            trade_fee_base_bps: 500,
        },
        vec![
            AccountMeta::new(new_insurance.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&new_insurance],
    )
    .expect("current asset-0 insurance authority updates the trade fee floor");
    assert_eq!(env.market_state().0.trade_fee_base_bps, 500);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long = env.create_portfolio(&long_owner);
    let short = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long, 1_000_000);
    env.deposit(&short_owner, short, 1_000_000);
    let insurance_before = env.market_state().1.insurance;

    env.svm.expire_blockhash();
    env.try_trade_asset_with_cu(
        0,
        &long_owner,
        long,
        &short_owner,
        short,
        POS_SCALE as i128,
        100,
        0,
    )
    .expect("trade succeeds with caller fee_bps=0 after the insurance authority sets the floor");
    let (_, group) = env.market_state();
    assert!(
        group.insurance > insurance_before,
        "trade paid the asset-0-insurance-authorized fee floor"
    );
    assert_eq!(
        group.vault,
        group.c_tot + group.insurance,
        "fee-floor trade remains exactly conserved"
    );
}

// security.md sweep - permissionless asset authority isolation (#6/#33): the creator of asset N owns
// that asset's local domain authorities, but must not be able to mutate market-wide knobs or market 0
// policies. Discriminating control: the same creator CAN update asset N's own backing-fee domain.
#[test]
fn v16_attack_permissionless_asset_authority_cannot_update_marketwide_policies() {
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(1);
    let creator = Keypair::new();
    env.svm.warp_to_slot(1);
    env.activate_permissionless_asset_with_fee(
        &creator,
        1,
        1,
        100,
        creator.pubkey(),
        creator.pubkey(),
        creator.pubkey(),
        creator.pubkey(),
        1,
    );
    let cfg_before = env.market_state().0;
    let profile = |env: &V16CuEnv, asset_index: usize| {
        state::read_asset_oracle_profile(
            &env.svm.get_account(&env.market).unwrap().data,
            asset_index,
        )
        .unwrap()
    };
    assert_eq!(
        profile(&env, 1).insurance_authority,
        creator.pubkey().to_bytes()
    );

    let mut attempt = |ix: ProgInstruction| -> Result<u64, String> {
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ix,
            vec![
                AccountMeta::new(creator.pubkey(), true),
                AccountMeta::new(env.market, false),
            ],
            &[&creator],
        )
    };

    assert!(
        attempt(ProgInstruction::UpdateTradeFeePolicy {
            trade_fee_base_bps: 123
        })
        .is_err(),
        "asset-1 authority must not control the market-wide trade fee"
    );
    assert!(
        attempt(ProgInstruction::UpdateFeeRedirectPolicy {
            redirect_bps: 5_000
        })
        .is_err(),
        "asset-1 authority must not control market-0 fee redirect"
    );
    assert!(
        attempt(ProgInstruction::UpdateMarketInitFeePolicy { min_init_fee: 9 }).is_err(),
        "asset-1 authority must not control permissionless init fee"
    );
    assert!(
        attempt(ProgInstruction::UpdateLiquidationFeePolicy {
            cranker_share_bps: 2_500
        })
        .is_err(),
        "asset-1 authority must not control global liquidation-fee policy"
    );
    assert!(
        attempt(ProgInstruction::UpdateMaintenanceFeePolicy {
            cranker_share_bps: 2_500
        })
        .is_err(),
        "asset-1 authority must not control global maintenance-fee policy"
    );
    assert!(
        attempt(ProgInstruction::UpdateBackingFeePolicy {
            domain: 0,
            fee_bps: 55,
            insurance_share_bps: 5_000,
        })
        .is_err(),
        "asset-1 authority must not control market-0 backing-fee policy"
    );

    let cfg_after_rejects = env.market_state().0;
    assert_eq!(
        cfg_after_rejects.trade_fee_base_bps,
        cfg_before.trade_fee_base_bps
    );
    assert_eq!(
        cfg_after_rejects.fee_redirect_to_market_0_bps,
        cfg_before.fee_redirect_to_market_0_bps
    );
    assert_eq!(
        cfg_after_rejects.permissionless_market_init_fee,
        cfg_before.permissionless_market_init_fee
    );
    assert_eq!(
        cfg_after_rejects.liquidation_cranker_fee_share_bps,
        cfg_before.liquidation_cranker_fee_share_bps
    );
    assert_eq!(
        cfg_after_rejects.maintenance_cranker_fee_share_bps,
        cfg_before.maintenance_cranker_fee_share_bps
    );
    assert_eq!(
        cfg_after_rejects.backing_trade_fee_bps_long,
        cfg_before.backing_trade_fee_bps_long
    );
    assert_eq!(
        cfg_after_rejects.backing_trade_fee_policy_count,
        cfg_before.backing_trade_fee_policy_count
    );

    env.svm.expire_blockhash();
    let local_ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBackingFeePolicy {
            domain: 2,
            fee_bps: 111,
            insurance_share_bps: 5_000,
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&creator],
    );
    assert!(
        local_ok.is_ok(),
        "same asset-1 authority may update its own backing-fee domain: {local_ok:?}"
    );
    let cfg_after_local = env.market_state().0;
    let asset1_profile = profile(&env, 1);
    assert_eq!(asset1_profile.backing_trade_fee_bps_long, 111);
    assert_eq!(
        asset1_profile.backing_trade_fee_insurance_share_bps_long,
        5_000
    );
    assert_eq!(
        cfg_after_local.backing_trade_fee_policy_count,
        cfg_before.backing_trade_fee_policy_count + 1
    );
    assert_eq!(
        cfg_after_local.trade_fee_base_bps, cfg_before.trade_fee_base_bps,
        "local domain update did not mutate market-wide trade fee"
    );
}

// security.md sweep — market 0 fees don't self-redirect (#32/#33) [fee-routing #2]: with
// fee_redirect_to_market_0_bps set, a fee on MARKET 0 itself must stay 100% local (the asset_index==0
// branch redirects 0). No spurious self-redirect / double-credit.
#[test]
fn v16_attack_market0_fees_stay_local() {
    let mut env = V16CuEnv::new();
    env.update_fee_redirect_policy_with_cu(2_000); // 20% redirect for markets 1..N
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 5_000_000);
    env.deposit(&lb, pb, 5_000_000);
    let dom = |env: &V16CuEnv, d: usize| env.market_state().1.insurance_domain_budget[d];
    let (b0, b1) = (dom(&env, 0), dom(&env, 1));
    let ins0 = env.market_state().1.insurance;
    // fee'd trade on ASSET 0 (market 0) with a large notional.
    env.trade_asset_with_cu(0, &la, pa, &lb, pb, (10_000 * POS_SCALE) as i128, 100, 100);
    let g0d = dom(&env, 0) - b0;
    let g1d = dom(&env, 1) - b1;
    let total_local = g0d + g1d;
    let total_fee = env.market_state().1.insurance - ins0;
    assert!(total_fee > 0, "a fee was charged (non-vacuous)");
    // ALL of market 0's fee stayed in market 0's domains (0,1) -- nothing redirected away or double-counted.
    assert_eq!(
        total_local, total_fee,
        "100% of market-0 fee stays in market-0 domains (no self-redirect)"
    );
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_domain_budget_remaining_total_consistent(&g, "market0 trade fees stay local");
}

// security.md sweep — fee-redirect 100% boundary (#32/#33) [fee-routing #4]: with redirect=10000, ALL
// of market N's fees must route to market 0's domains and NONE stays local. Boundary precision of the
// redirect split.
#[test]
fn v16_attack_fee_redirect_full_boundary() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    )
    .expect("cfg mark");
    env.update_fee_redirect_policy_with_cu(10_000); // 100% redirect to market 0
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 5_000_000);
    env.deposit(&lb, pb, 5_000_000);
    let dom = |env: &V16CuEnv, d: usize| env.market_state().1.insurance_domain_budget[d];
    let (b0, b1, b2, b3) = (dom(&env, 0), dom(&env, 1), dom(&env, 2), dom(&env, 3));
    let ins0 = env.market_state().1.insurance;
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, (10_000 * POS_SCALE) as i128, 100, 100);
    let to_mkt0 = (dom(&env, 0) - b0) + (dom(&env, 1) - b1);
    let to_mkt1 = (dom(&env, 2) - b2) + (dom(&env, 3) - b3);
    let total_fee = env.market_state().1.insurance - ins0;
    assert!(total_fee > 0, "fee charged (non-vacuous)");
    assert_eq!(
        to_mkt0, total_fee,
        "100% redirect: ALL of market-1 fee went to market 0"
    );
    assert_eq!(
        to_mkt1, 0,
        "100% redirect: NOTHING stayed local in market 1"
    );
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_domain_budget_remaining_total_consistent(&g, "full fee redirect boundary");
}

// security.md sweep — WithdrawInsurance wind-down gate: the global terminal WithdrawInsurance must be
// rejected (a) while the market is Live (mode != 1), and (b) after resolution while c_tot != 0 (open
// capital still backed). Attacker goal: drain insurance out from under accounts that still hold capital.
// We pre-fund domain-0's budget so the available-amount gate PASSES — isolating the wind-down gate as
// the sole reason for rejection. The same amount is then shown to SUCCEED once c_tot reaches 0.
#[test]
fn v16_attack_withdraw_insurance_requires_full_wind_down() {
    let mut env = V16CuEnv::new();
    // Fund domain-0 insurance budget so available_insurance(admin) >= the amount we attempt.
    env.top_up_insurance_domain_with_authority(&env.admin.insecure_clone(), 0, 1_000_000);
    let amount: u128 = 400_000;

    let attempt = |env: &mut V16CuEnv| {
        let dest = env.token_account(env.admin.pubkey(), 0);
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::WithdrawInsurance { amount },
            vec![
                AccountMeta::new(env.admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&env.admin.insecure_clone()],
        )
    };

    // (a) Live mode (mode==0): must reject — insurance is not withdrawable before resolution.
    assert_eq!(
        env.market_state().1.mode,
        percolator::MarketModeV16::Live,
        "starts Live"
    );
    assert!(
        attempt(&mut env).is_err(),
        "WithdrawInsurance must reject while Live"
    );

    // Open capital, then resolve. c_tot stays > 0 (depositor's capital is still on the book).
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 600_000);
    env.resolve();
    let g = env.market_state().1;
    assert_eq!(g.mode, percolator::MarketModeV16::Resolved, "resolved");
    assert!(
        g.c_tot > 0,
        "capital still open after resolve (non-vacuous gate)"
    );

    // (b) Resolved but c_tot != 0: still must reject — can't drain insurance from under open capital.
    assert!(
        attempt(&mut env).is_err(),
        "WithdrawInsurance must reject while c_tot != 0 (capital still backed)"
    );

    // Control: a FRESH env, identically funded, but fully wound down (no open capital, so c_tot == 0
    // after resolve). The SAME amount now SUCCEEDS — proving (a)/(b) rejected on the wind-down gate,
    // not the available-amount gate (the amount/budget is identical in all three).
    let mut env2 = V16CuEnv::new();
    env2.top_up_insurance_domain_with_authority(&env2.admin.insecure_clone(), 0, 1_000_000);
    env2.resolve();
    let g2 = env2.market_state().1;
    assert_eq!(
        g2.mode,
        percolator::MarketModeV16::Resolved,
        "control resolved"
    );
    assert_eq!(g2.c_tot, 0, "control fully wound down");
    assert!(
        attempt(&mut env2).is_ok(),
        "WithdrawInsurance succeeds once fully wound down (discriminating control)"
    );

    let g = env2.market_state().1;
    assert_eq!(
        g.vault as u64,
        env2.token_amount(env2.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — resolved-mode backing withdrawal wind-down gate (SOL-021/022): LP backing is the
// loss-absorption layer behind users. In RESOLVED mode handle_withdraw_backing_bucket (v16_program 7834)
// permits a withdrawal ONLY once materialized_portfolio_count == 0 AND c_tot == 0 — i.e. every user has
// been paid out and closed. If the backing_bucket_authority (or marketauth) could pull backing while
// resolved users still hold capital/claims, the vault would drop below what those users are owed (LOF).
// This is the backing parallel of v16_attack_withdraw_insurance_requires_full_wind_down (insurance), but a
// DISTINCT code path with a distinct condition (count+c_tot vs insurance wind-down). It was untested:
// 15135 covers the LIVE liened-winner case, not resolved-mode open capital. Non-vacuous: the same
// withdrawal succeeds on the live empty market first.
#[test]
fn v16_attack_resolved_backing_withdraw_requires_full_user_wind_down() {
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, 1_000, 100_000); // domain 1 (asset-0 short) backing, admin-authorized
    let dest = env.token_account(env.admin.pubkey(), 0);

    // Sanity: on a live, user-free market the backing authority CAN withdraw — proves authority + path
    // are fine, so the resolved-mode rejection below is caused by the wind-down gate, not a precondition.
    env.svm.expire_blockhash();
    env.withdraw_backing_bucket_to_admin_token_with_cu(dest, 1, 100);

    // Open user capital, then resolve. c_tot + materialized_portfolio_count stay > 0.
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 600_000);
    env.resolve();
    let g = env.market_state().1;
    assert_eq!(g.mode, percolator::MarketModeV16::Resolved, "resolved");
    assert!(
        g.c_tot > 0,
        "user capital still open after resolve (non-vacuous gate)"
    );
    assert!(
        g.materialized_portfolio_count > 0,
        "user portfolio still materialized after resolve"
    );

    let vault_before = g.vault;
    let dest_before = env.token_amount(dest);
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 1,
            amount: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&env.admin.insecure_clone()],
    );
    assert!(
        r.is_err(),
        "resolved-mode backing withdrawal must reject while users still hold capital/claims"
    );
    let g_after = env.market_state().1;
    assert_eq!(
        g_after.vault, vault_before,
        "rejected resolved backing withdrawal must leave the vault untouched"
    );
    assert_eq!(
        env.token_amount(dest),
        dest_before,
        "no backing tokens may leave to the authority before users are wound down"
    );
    assert!(
        g_after.vault >= g_after.c_tot + g_after.insurance,
        "senior conservation intact"
    );
}

// security.md sweep — per-asset WithdrawInsuranceAsset budget conservation (#6): the asset insurance
// operator may withdraw accrued asset budget in LIVE mode, but NEVER more than the asset's remaining
// long+short budget, and partial withdrawals must debit the remaining budget so it cannot be double-drained.
// Attacker goal: withdraw an asset's insurance twice (or over its budget) to extract more than accrued.
#[test]
fn v16_attack_withdraw_insurance_domain_budget_cannot_be_overdrawn() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    // Credit domain 0's budget with 1_000_000 (Live mode). insurance and domain-0 budget both = 1M.
    env.top_up_insurance_domain_with_authority(&admin, 0, 1_000_000);
    let g = env.market_state().1;
    assert_eq!(g.mode, percolator::MarketModeV16::Live, "Live");
    assert_eq!(
        g.insurance_domain_budget[0], 1_000_000,
        "domain-0 budget funded"
    );

    let conserve = |env: &V16CuEnv| {
        let g = env.market_state().1;
        assert_eq!(
            g.vault as u64,
            env.token_amount(env.vault),
            "accounting == real vault"
        );
        assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    };

    // (1) Over-budget in one shot must reject (amount > remaining domain budget).
    assert!(
        env.try_withdraw_insurance_domain_with_authority(&admin, 0, 1_000_001)
            .is_err(),
        "withdraw > domain budget must reject"
    );
    conserve(&env);

    // (2) Partial withdraw succeeds and debits the remaining budget (and insurance).
    let (_d, _cu) = env
        .try_withdraw_insurance_domain_with_authority(&admin, 0, 600_000)
        .expect("partial domain withdraw ok");
    let g = env.market_state().1;
    assert_eq!(
        g.insurance_domain_budget[0], 400_000,
        "budget debited to 400k"
    );
    assert_eq!(g.insurance, 400_000, "insurance debited to 400k");
    conserve(&env);

    // (3) A second withdraw exceeding the NEW remaining budget must reject (no double-drain).
    assert!(
        env.try_withdraw_insurance_domain_with_authority(&admin, 0, 500_000)
            .is_err(),
        "withdraw > remaining (400k) must reject — no double-drain"
    );
    let g = env.market_state().1;
    assert_eq!(
        g.insurance_domain_budget[0], 400_000,
        "rejected withdraw left budget intact"
    );
    conserve(&env);

    // (4) Draining exactly the remainder succeeds; budget -> 0.
    env.try_withdraw_insurance_domain_with_authority(&admin, 0, 400_000)
        .expect("drain remainder ok");
    let g = env.market_state().1;
    assert_eq!(g.insurance_domain_budget[0], 0, "budget fully drained");
    conserve(&env);

    // (5) Any further withdraw from the exhausted domain must reject.
    assert!(
        env.try_withdraw_insurance_domain_with_authority(&admin, 0, 1)
            .is_err(),
        "withdraw from exhausted domain budget must reject"
    );
    conserve(&env);
}

// security.md sweep — uniform live insurance API (#6/#23/#57): asset 0 and permissionless assets 1..N
// both withdraw through the same asset-indexed tag. The signer must be that asset's insurance_operator,
// and the withdrawal is bounded to that asset's own long+short insurance budget.
#[test]
fn v16_attack_live_insurance_asset_withdraw_uniform_for_asset0_and_permissionless_asset() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let creator = Keypair::new();
    let cp = creator.pubkey();

    env.update_market_init_fee_policy_with_cu(10);
    let (_fee_source, _cu) =
        env.activate_permissionless_asset_with_fee(&creator, 1, 1, 100, cp, cp, cp, cp, 10);

    // Permissionless create fee credits asset 0 insurance 5/5. Top up to exact 300/200.
    env.top_up_insurance_domain_with_authority(&admin, 0, 295);
    env.top_up_insurance_domain_with_authority(&admin, 1, 195);
    env.top_up_insurance_domain_with_authority(&creator, 2, 100);
    env.top_up_insurance_domain_with_authority(&creator, 3, 70);

    let g0 = env.market_state().1;
    assert_eq!(g0.insurance_domain_budget[0], 300);
    assert_eq!(g0.insurance_domain_budget[1], 200);
    assert_eq!(g0.insurance_domain_budget[2], 100);
    assert_eq!(g0.insurance_domain_budget[3], 70);

    assert!(
        env.try_withdraw_insurance_asset_with_authority(&creator, 0, 1)
            .is_err(),
        "permissionless asset creator must not operate asset-0 insurance"
    );
    assert!(
        env.try_withdraw_insurance_asset_with_authority(&admin, 1, 1)
            .is_err(),
        "marketauth must not operate a live permissionless asset's insurance"
    );

    let (asset0_dest, _cu0) = env
        .try_withdraw_insurance_asset_with_authority(&admin, 0, 450)
        .expect("asset-0 operator withdraws through unified tag");
    assert_eq!(env.token_amount(asset0_dest), 450);

    let (asset1_dest, _cu1) = env
        .try_withdraw_insurance_asset_with_authority(&creator, 1, 120)
        .expect("permissionless asset operator withdraws through unified tag");
    assert_eq!(env.token_amount(asset1_dest), 120);

    let g = env.market_state().1;
    assert_eq!(
        g.insurance_domain_budget[0], 0,
        "asset-0 withdraw drains long side first"
    );
    assert_eq!(g.insurance_domain_budget[1], 50);
    assert_eq!(
        g.insurance_domain_budget[2], 0,
        "asset-1 withdraw drains long side first"
    );
    assert_eq!(g.insurance_domain_budget[3], 50);
    assert_eq!(
        g.insurance, 100,
        "only each asset's remaining budget stays insured"
    );
    assert!(
        env.try_withdraw_insurance_asset_with_authority(&creator, 1, 51)
            .is_err(),
        "asset operator cannot withdraw beyond its own remaining long+short budget"
    );
    let g = env.market_state().1;
    assert_eq!(g.vault as u64, env.token_amount(env.vault));
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — removed live-insurance policy tags (#6/#23): live insurance withdrawal is now
// uniformly asset-scoped through tag 57. The old asset-0-only rate-limit tag and its policy-update tag
// must reject raw instruction bytes without mutating state.
#[test]
fn v16_attack_removed_limited_insurance_tags_reject_without_mutation() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.top_up_insurance_domain_with_authority(&admin, 0, 1_000);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let dest = env.token_account(admin.pubkey(), 0);

    let mut old_limited = vec![23u8];
    old_limited.extend_from_slice(&100u128.to_le_bytes());
    env.svm.expire_blockhash();
    let limited = send_raw_tx(
        &mut env.svm,
        &env.payer,
        Instruction {
            program_id: env.program_id,
            data: old_limited,
            accounts: vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(dest, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
        },
        &[&admin],
    );
    assert!(limited.is_err(), "old tag 23 must reject");

    let mut old_policy = vec![33u8];
    old_policy.extend_from_slice(&5_000u16.to_le_bytes());
    old_policy.push(0);
    old_policy.extend_from_slice(&10u64.to_le_bytes());
    env.svm.expire_blockhash();
    let policy = send_raw_tx(
        &mut env.svm,
        &env.payer,
        Instruction {
            program_id: env.program_id,
            data: old_policy,
            accounts: vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
            ],
        },
        &[&admin],
    );
    assert!(policy.is_err(), "old tag 33 must reject");

    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&env.vault).unwrap(), vault_before);
    assert_eq!(env.token_amount(dest), 0);
}

// security.md sweep — backing bucket top-up/withdraw input gates (#33/#44): a backing top-up with an
// already-expired (or zero) expiry must reject (no dead backing injected to skew freshness accounting),
// and a withdraw can never exceed the bucket's fresh-unliened principal. Complements the watermark/lien
// permutation tests (which cover liened backing) with the plain balance + expiry gates.
#[test]
fn v16_attack_backing_bucket_topup_withdraw_input_gates() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let cur = env.svm.get_sysvar::<Clock>().slot;

    // helper: inline TopUpBackingBucket returning Result (the env helper panics on reject).
    let top_up = |env: &mut V16CuEnv, amount: u128, expiry: u64| -> Result<u64, String> {
        let source = Pubkey::new_unique();
        env.svm
            .set_account(
                source,
                Account {
                    lamports: 1_000_000_000,
                    data: make_token_data(env.mint, admin.pubkey(), amount.max(1) as u64),
                    owner: spl_token::ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::TopUpBackingBucket {
                domain: 0,
                amount,
                expiry_slot: expiry,
            },
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&admin],
        )
    };

    // (1) expiry_slot <= current_slot must reject (no already-expired backing) — for a real (amount>0) top-up.
    assert!(
        top_up(&mut env, 1_000_000, cur).is_err(),
        "expiry == now must reject"
    );
    assert!(
        top_up(&mut env, 1_000_000, 0).is_err(),
        "expiry 0 must reject"
    );
    // (2) zero amount is a benign no-op: the engine add (which holds the expiry gate) is skipped, so it
    // succeeds without injecting any backing — even with an expired expiry. Nothing enters the vault.
    assert!(
        top_up(&mut env, 0, cur + 1_000_000).is_ok(),
        "zero-amount top-up is a no-op success"
    );
    assert!(
        top_up(&mut env, 0, 0).is_ok(),
        "zero-amount top-up no-op even with expired expiry"
    );
    // nothing entered the vault on any rejected top-up or zero no-op.
    assert_eq!(
        env.market_state().1.vault,
        0,
        "no backing injected by rejected/no-op top-ups"
    );
    assert_eq!(
        env.market_state().1.source_backing_buckets[0].fresh_unliened_backing_num,
        0,
        "no backing num"
    );

    // (3) a valid top-up succeeds; backing is Fresh & unliened.
    assert!(
        top_up(&mut env, 1_000_000, cur + 1_000_000).is_ok(),
        "valid top-up ok"
    );
    let g = env.market_state().1;
    assert_eq!(g.vault, 1_000_000, "vault holds the backing principal");
    // fresh_unliened_backing_num is in BOUND_SCALE units (amount * 1e12); just assert it's funded.
    assert!(
        g.source_backing_buckets[0].fresh_unliened_backing_num > 0,
        "backing is fresh-unliened"
    );

    // (4) withdraw beyond the fresh-unliened principal must reject.
    let dest = env.token_account_for_mint(env.mint, admin.pubkey(), 0);
    env.svm.expire_blockhash();
    let r_over = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::WithdrawBackingBucket {
            domain: 0,
            amount: 1_000_001,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(dest, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        r_over.is_err(),
        "withdraw > fresh-unliened principal must reject"
    );
    assert_eq!(
        env.token_amount(dest),
        0,
        "no backing paid out on rejected over-withdraw"
    );

    // (5) withdraw exactly the principal succeeds and conserves.
    env.svm.expire_blockhash();
    env.withdraw_backing_bucket_to_admin_token_with_cu(dest, 0, 1_000_000);
    assert_eq!(
        env.token_amount(dest),
        1_000_000,
        "exactly the principal withdrawn"
    );
    let g = env.market_state().1;
    assert_eq!(
        g.source_backing_buckets[0].fresh_unliened_backing_num, 0,
        "backing drained"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

#[test]
fn v16_attack_live_insurance_withdraw_rejects_exposed_target_effective_lag() {
    const INITIAL_MARK: u64 = 100_000_000;
    const TARGET_MARK: u64 = 90_000_000;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 10_000, 10_000, 24);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, INITIAL_MARK);
    env.enable_live_insurance_withdrawal();
    env.top_up_insurance(1_000_000);
    env.top_up_insurance_domain_with_authority(&env.admin.insecure_clone(), 0, 1_000_000);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_portfolio = env.create_portfolio(&long_owner);
    let short_portfolio = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_portfolio, 1_000_000_000);
    env.deposit(&short_owner, short_portfolio, 1_000_000_000);
    env.trade_with_cu(
        &long_owner,
        long_portfolio,
        &short_owner,
        short_portfolio,
        POS_SCALE as i128,
        INITIAL_MARK,
        0,
    );

    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, TARGET_MARK);
    env.crank(
        long_portfolio,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let g = env.market_state().1;
    assert_eq!(g.assets[0].raw_oracle_target_price, TARGET_MARK);
    assert_ne!(
        g.assets[0].raw_oracle_target_price, g.assets[0].effective_price,
        "test must create a real target/effective lag"
    );
    assert!(g.assets[0].oi_eff_long_q > 0 || g.assets[0].oi_eff_short_q > 0);
    assert!(!g.bankruptcy_hlock_active, "durable hlock stays clear");
    assert!(!g.threshold_stress_active, "threshold stress stays clear");
    assert!(!g.loss_stale_active, "loss-stale stays clear");

    let admin = env.admin.insecure_clone();
    let asset = env.try_withdraw_insurance_asset_with_authority(&admin, 0, 100);
    assert!(
        asset.is_err(),
        "live WithdrawInsuranceAsset must reject while its exposed asset has target/effective lag"
    );
    let g_after = env.market_state().1;
    assert_eq!(
        g_after.insurance, g.insurance,
        "rejected withdrawals leave insurance untouched"
    );
    assert_eq!(
        g_after.insurance_domain_budget[0], g.insurance_domain_budget[0],
        "rejected asset withdrawal leaves budget untouched"
    );
}

// security.md sweep — live insurance withdrawal must reject while insurance is still protecting
// unresolved loss (SOL-021/SOL-022 terminal/encumbered gating). live_domain_withdraw_health_or_shutdown
// _view (v16_program 4812) blocks WithdrawInsuranceAsset on a live market whenever bankruptcy_hlock_active
// / threshold_stress_active / loss_stale_active / recovery_reason is set — exactly the states where the
// fund is the users' backstop for in-flight loss/bankruptcy work. If an operator could drain insurance
// then, users lose their protection (LOF). The exposed target/effective lag branch is covered by
// v16_attack_live_insurance_withdraw_rejects_exposed_target_effective_lag; the DISTINCT stress/h-lock/
// loss-stale OR-branch (4822-4831) was untested. This sets each flag on an otherwise-healthy FLAT market
// (where the same withdrawal demonstrably succeeds) and asserts the withdrawal rejects with insurance +
// domain budget byte-unchanged — proving the stress flag is the sole blocker (non-vacuous).
#[test]
fn v16_attack_live_insurance_withdraw_rejects_while_stressed_or_hlocked() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 10_000, 10_000, 24);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_with_cu(1, 100_000_000);
    env.enable_live_insurance_withdrawal();
    env.top_up_insurance(1_000_000);
    env.top_up_insurance_domain_with_authority(&env.admin.insecure_clone(), 0, 1_000_000);
    let admin = env.admin.insecure_clone();

    // Sanity: on a healthy, flat, lag-free market the live asset withdrawal succeeds — so any rejection
    // below is caused specifically by the stress/h-lock flag, not by some unrelated precondition.
    env.svm.expire_blockhash();
    env.try_withdraw_insurance_asset_with_authority(&admin, 0, 100)
        .expect("flat healthy live insurance withdrawal must succeed");

    // Each engine "insurance still protecting loss" flag must independently block the withdrawal.
    let cases: [(&str, fn(&mut MarketGroupV16, bool)); 3] = [
        ("bankruptcy_hlock_active", |g, v| {
            g.bankruptcy_hlock_active = v
        }),
        ("threshold_stress_active", |g, v| {
            g.threshold_stress_active = v
        }),
        ("loss_stale_active", |g, v| g.loss_stale_active = v),
    ];
    for (label, set) in cases {
        env.mutate_market(|_cfg, group| set(group, true));
        let before = env.market_state().1;
        env.svm.expire_blockhash();
        let r = env.try_withdraw_insurance_asset_with_authority(&admin, 0, 100);
        assert!(
            r.is_err(),
            "live WithdrawInsuranceAsset must reject while {label} is set (insurance protecting loss)"
        );
        let after = env.market_state().1;
        assert_eq!(
            after.insurance, before.insurance,
            "rejected withdrawal under {label} must leave insurance untouched"
        );
        assert_eq!(
            after.insurance_domain_budget[0], before.insurance_domain_budget[0],
            "rejected withdrawal under {label} must leave the domain budget untouched"
        );
        // clear the flag so the next iteration tests its flag in isolation.
        env.mutate_market(|_cfg, group| set(group, false));
    }
}

#[test]
fn v16_attack_unrelated_refresh_cannot_mask_loss_stale_insurance_gate() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    env.enable_live_insurance_withdrawal();
    let admin = env.admin.insecure_clone();
    env.top_up_insurance_domain_with_authority(&admin, 2, 100);

    let stale_long_owner = Keypair::new();
    let stale_short_owner = Keypair::new();
    let stale_long = env.create_portfolio(&stale_long_owner);
    let stale_short = env.create_portfolio(&stale_short_owner);
    env.deposit(&stale_long_owner, stale_long, 1_000_000_000);
    env.deposit(&stale_short_owner, stale_short, 1_000_000_000);
    env.trade_asset_with_cu(
        1,
        &stale_long_owner,
        stale_long,
        &stale_short_owner,
        stale_short,
        (10 * POS_SCALE) as i128,
        100,
        0,
    );

    let cranker_owner = Keypair::new();
    let cranker = env.create_portfolio(&cranker_owner);
    env.svm.warp_to_slot(3);
    for _ in 0..3 {
        env.svm.expire_blockhash();
        env.crank(
            cranker,
            ProgInstruction::PermissionlessCrank {
                now_slot: 3,
                close_q: 0,
                observations: crank_observations(0),
            },
        );
    }
    env.svm.expire_blockhash();
    env.crank(
        cranker,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(1),
        },
    );

    let before_mask = env.market_state().1;
    assert!(before_mask.loss_stale_active);
    assert!(before_mask.assets[1].slot_last < before_mask.current_slot);
    assert!(
        env.try_withdraw_insurance_domain_with_authority(&admin, 2, 10)
            .is_err(),
        "asset-1 live insurance is initially locked by its loss-stale exposure"
    );

    env.svm.expire_blockhash();
    env.crank(
        cranker,
        ProgInstruction::PermissionlessCrank {
            now_slot: 3,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let after_unrelated_refresh = env.market_state().1;
    assert!(
        after_unrelated_refresh.assets[1].slot_last < after_unrelated_refresh.current_slot,
        "asset 1 remains locally loss-stale after the unrelated asset-0 refresh"
    );

    let withdraw = env.try_withdraw_insurance_domain_with_authority(&admin, 2, 10);
    assert!(
        withdraw.is_err(),
        "an unrelated refresh must not make asset-1 insurance withdrawable while asset 1 is loss-stale"
    );
    let after_withdraw_attempt = env.market_state().1;
    assert_eq!(
        after_withdraw_attempt.insurance_domain_budget[2],
        after_unrelated_refresh.insurance_domain_budget[2],
        "rejected stale-asset withdrawal must leave the domain budget untouched"
    );
    assert_eq!(
        after_withdraw_attempt.insurance, after_unrelated_refresh.insurance,
        "rejected stale-asset withdrawal must leave insurance untouched"
    );
}

#[test]
fn v16_attack_unexposed_target_move_cannot_grief_live_insurance_withdrawals() {
    let mut env = V16CuEnv::new_with_init_params_and_market_capacity(
        V16CuMarketParams {
            max_price_move_bps_per_slot: 24,
            ..V16CuMarketParams::default()
        },
        1,
    );
    env.activate_asset(1, 1, 100_000_000);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100_000_000);
    env.enable_live_insurance_withdrawal();
    env.top_up_insurance(1_000_000);
    env.top_up_insurance_domain_with_authority(&env.admin.insecure_clone(), 0, 1_000_000);

    let owner = Keypair::new();
    let flat_portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, flat_portfolio, 1_000_000);
    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(1, 2, 90_000_000);
    env.crank(
        flat_portfolio,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(1),
        },
    );
    let g = env.market_state().1;
    assert_eq!(
        g.assets[1].raw_oracle_target_price, g.assets[1].effective_price,
        "zero-OI asset catches effective price up to target immediately"
    );
    assert_eq!(g.assets[1].effective_price, 90_000_000);
    assert_eq!(
        g.assets[1].oi_eff_long_q, 0,
        "asset 1 is unexposed long side"
    );
    assert_eq!(
        g.assets[1].oi_eff_short_q, 0,
        "asset 1 is unexposed short side"
    );

    let admin = env.admin.insecure_clone();
    let asset = env.try_withdraw_insurance_asset_with_authority(&admin, 0, 100);
    assert!(
        asset.is_ok(),
        "unexposed lag on another asset must not DoS unrelated asset insurance withdrawal"
    );
}

// security.md sweep — SwapSecondaryForPrimary authority + balance bounds (#6/#33/#44): the 1:1 par
// collateral swap is base_unit_authority-gated and bounded by the secondary vault's balance. Attacker
// goals: (a) a non-authority drains the secondary reserve, (b) the authority over-swaps beyond the
// reserve to print/underflow. Must reject both; a valid swap conserves value exactly 1:1.
#[test]
fn v16_attack_swap_secondary_unauthorized_and_bounded() {
    let mut env = V16CuEnv::new();
    let secondary_mint = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary_mint);
    let secondary_vault = canonical_vault_ata(env.vault_authority, secondary_mint);
    env.svm
        .set_account(
            secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    let swap = |env: &mut V16CuEnv,
                signer: &Keypair,
                primary_source: Pubkey,
                secondary_dest: Pubkey,
                amount: u128|
     -> Result<u64, String> {
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::SwapSecondaryForPrimary { amount },
            vec![
                AccountMeta::new(signer.pubkey(), true),
                AccountMeta::new_readonly(env.market, false),
                AccountMeta::new(primary_source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new(secondary_dest, false),
                AccountMeta::new(secondary_vault, false),
                AccountMeta::new_readonly(env.vault_authority, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[signer],
        )
    };

    // (a) ATTACK: a non-base_unit_authority signer (mallory) tries to swap and drain the secondary reserve.
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    let m_primary = env.token_account_for_mint(env.mint, mallory.pubkey(), 50);
    let m_secondary = env.token_account_for_mint(secondary_mint, mallory.pubkey(), 0);
    assert!(
        swap(&mut env, &mallory, m_primary, m_secondary, 50).is_err(),
        "non-authority swap must reject"
    );
    assert_eq!(
        env.token_amount(secondary_vault),
        50,
        "secondary reserve untouched by unauthorized swap"
    );
    assert_eq!(
        env.token_amount(m_secondary),
        0,
        "no secondary drained to attacker"
    );
    assert_eq!(
        env.token_amount(m_primary),
        50,
        "attacker's primary not pulled"
    );

    // (b) ATTACK: the legit authority over-swaps beyond the secondary reserve (51 > 50) -> reject.
    let admin = env.admin.insecure_clone();
    let a_primary = env.token_account_for_mint(env.mint, admin.pubkey(), 100);
    let a_secondary = env.token_account_for_mint(secondary_mint, admin.pubkey(), 0);
    assert!(
        swap(&mut env, &admin, a_primary, a_secondary, 51).is_err(),
        "over-swap beyond secondary reserve must reject"
    );
    assert_eq!(
        env.token_amount(secondary_vault),
        50,
        "reserve untouched by rejected over-swap"
    );
    assert_eq!(
        env.token_amount(a_primary),
        100,
        "no primary pulled on rejected over-swap"
    );

    // (c) zero amount rejects.
    assert!(
        swap(&mut env, &admin, a_primary, a_secondary, 0).is_err(),
        "zero-amount swap rejects"
    );

    // (c2) ATTACK: even the legit authority cannot route the secondary payout to a third party.
    // The rejected swap must not pull primary first or mutate either vault.
    let foreign_secondary = env.token_account_for_mint(secondary_mint, mallory.pubkey(), 0);
    assert!(
        swap(&mut env, &admin, a_primary, foreign_secondary, 10).is_err(),
        "swap to a third-party secondary destination must reject",
    );
    assert_eq!(
        env.token_amount(a_primary),
        100,
        "primary not pulled on bad-dest swap"
    );
    assert_eq!(
        env.token_amount(foreign_secondary),
        0,
        "no secondary paid to third party"
    );
    assert_eq!(
        env.token_amount(secondary_vault),
        50,
        "secondary reserve untouched by bad-dest swap"
    );

    // (d) VALID: authority swaps exactly the reserve (50) -> 1:1, value-conserving.
    let vault_primary_before = env.token_amount(env.vault);
    assert!(
        swap(&mut env, &admin, a_primary, a_secondary, 50).is_ok(),
        "authorized in-bounds swap ok"
    );
    assert_eq!(env.token_amount(a_primary), 50, "exactly 50 primary pulled");
    assert_eq!(
        env.token_amount(env.vault),
        vault_primary_before + 50,
        "primary vault gained exactly 50"
    );
    assert_eq!(
        env.token_amount(a_secondary),
        50,
        "exactly 50 secondary delivered 1:1"
    );
    assert_eq!(
        env.token_amount(secondary_vault),
        0,
        "secondary reserve fully drained, not more"
    );
}

// security.md sweep - SwapSecondaryForPrimary account aliasing (#26/#35/#44): the primary source must
// be an authority-owned token account and the secondary destination must be authority-owned. Otherwise
// the authority could pass the primary vault as both source and destination for a no-op primary transfer
// that drains secondary, or burn primary into the vault while receiving no secondary.
#[test]
fn v16_attack_swap_secondary_rejects_vault_source_or_dest_aliases() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let secondary_mint = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary_mint);

    let depositor = Keypair::new();
    let portfolio = env.create_portfolio(&depositor);
    env.deposit(&depositor, portfolio, 1_000);

    let secondary_vault = canonical_vault_ata(env.vault_authority, secondary_mint);
    env.svm
        .set_account(
            secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let admin_secondary = env.token_account_for_mint(secondary_mint, admin.pubkey(), 0);

    let market_before = env.svm.get_account(&env.market).unwrap();
    let primary_vault_before = env.svm.get_account(&env.vault).unwrap();
    let secondary_vault_before = env.svm.get_account(&secondary_vault).unwrap();
    let admin_secondary_before = env.svm.get_account(&admin_secondary).unwrap();
    env.svm.expire_blockhash();
    let vault_source = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::SwapSecondaryForPrimary { amount: 10 },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new_readonly(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new(admin_secondary, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        vault_source.is_err(),
        "SwapSecondaryForPrimary must reject the primary vault as the source"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        primary_vault_before,
        "primary vault not used as a no-op source"
    );
    assert_eq!(
        env.svm.get_account(&secondary_vault).unwrap(),
        secondary_vault_before,
        "secondary reserve not drained by vault-source alias"
    );
    assert_eq!(
        env.svm.get_account(&admin_secondary).unwrap(),
        admin_secondary_before,
        "attacker receives no secondary on rejected vault-source alias"
    );

    let admin_primary = env.token_account_for_mint(env.mint, admin.pubkey(), 10);
    let admin_primary_before = env.svm.get_account(&admin_primary).unwrap();
    let primary_vault_before = env.svm.get_account(&env.vault).unwrap();
    let secondary_vault_before = env.svm.get_account(&secondary_vault).unwrap();
    env.svm.expire_blockhash();
    let vault_dest = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::SwapSecondaryForPrimary { amount: 10 },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new_readonly(env.market, false),
            AccountMeta::new(admin_primary, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        vault_dest.is_err(),
        "SwapSecondaryForPrimary must reject the secondary vault as the user destination"
    );
    assert_eq!(
        env.svm.get_account(&admin_primary).unwrap(),
        admin_primary_before
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        primary_vault_before
    );
    assert_eq!(
        env.svm.get_account(&secondary_vault).unwrap(),
        secondary_vault_before,
        "secondary vault not self-paid by bad-destination alias"
    );

    env.svm.expire_blockhash();
    let ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::SwapSecondaryForPrimary { amount: 10 },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new_readonly(env.market, false),
            AccountMeta::new(admin_primary, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new(admin_secondary, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        ok.is_ok(),
        "same accounts without aliasing swap cleanly: {ok:?}"
    );
    assert_eq!(env.token_amount(admin_primary), 0);
    assert_eq!(env.token_amount(admin_secondary), 10);
    assert_eq!(env.token_amount(secondary_vault), 40);
}

// full-interface sweep (cron30): SwapSecondaryForPrimary must pin the secondary reserve to the
// current market's vault PDA. A valid secondary-mint token account owned by another market's vault PDA
// must not be usable as the reserve, or one market's base-unit authority could drain another market's
// secondary collateral while depositing primary into its own vault.
#[test]
fn v16_attack_swap_secondary_rejects_foreign_market_vault() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let secondary_mint = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary_mint);

    let secondary_vault_a = canonical_vault_ata(env.vault_authority, secondary_mint);
    env.svm
        .set_account(
            secondary_vault_a,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let secondary_vault_b = canonical_vault_ata(vault_authority_b, secondary_mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&admin],
    )
    .expect("init market B");
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: secondary_mint.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(secondary_mint, false),
        ],
        &[&admin],
    )
    .expect("configure market B secondary mint");
    env.svm
        .set_account(
            secondary_vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, vault_authority_b, 70),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    let primary_source = env.token_account_for_mint(env.mint, admin.pubkey(), 10);
    let secondary_dest = env.token_account_for_mint(secondary_mint, admin.pubkey(), 0);
    let primary_vault_before = env.svm.get_account(&env.vault).unwrap();
    let secondary_vault_a_before = env.svm.get_account(&secondary_vault_a).unwrap();
    let secondary_vault_b_before = env.svm.get_account(&secondary_vault_b).unwrap();
    let source_before = env.svm.get_account(&primary_source).unwrap();
    let dest_before = env.svm.get_account(&secondary_dest).unwrap();

    let swap_with_secondary_vault =
        |env: &mut V16CuEnv, secondary_vault: Pubkey| -> Result<u64, String> {
            env.svm.expire_blockhash();
            send_tx(
                &mut env.svm,
                env.program_id,
                &env.payer,
                ProgInstruction::SwapSecondaryForPrimary { amount: 10 },
                vec![
                    AccountMeta::new(admin.pubkey(), true),
                    AccountMeta::new_readonly(env.market, false),
                    AccountMeta::new(primary_source, false),
                    AccountMeta::new(env.vault, false),
                    AccountMeta::new(secondary_dest, false),
                    AccountMeta::new(secondary_vault, false),
                    AccountMeta::new_readonly(env.vault_authority, false),
                    AccountMeta::new_readonly(spl_token::ID, false),
                ],
                &[&admin],
            )
        };

    let rejected = swap_with_secondary_vault(&mut env, secondary_vault_b);
    assert!(
        rejected.is_err(),
        "SwapSecondaryForPrimary must reject a reserve owned by a foreign market vault PDA"
    );
    assert_eq!(
        env.svm.get_account(&primary_source).unwrap(),
        source_before,
        "rejected foreign-vault swap must not pull primary collateral"
    );
    assert_eq!(
        env.svm.get_account(&secondary_dest).unwrap(),
        dest_before,
        "rejected foreign-vault swap must not pay secondary collateral"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        primary_vault_before,
        "rejected foreign-vault swap must not credit the current primary vault"
    );
    assert_eq!(
        env.svm.get_account(&secondary_vault_a).unwrap(),
        secondary_vault_a_before,
        "current market secondary reserve is untouched"
    );
    assert_eq!(
        env.svm.get_account(&secondary_vault_b).unwrap(),
        secondary_vault_b_before,
        "foreign market secondary reserve is untouched"
    );

    let ok = swap_with_secondary_vault(&mut env, secondary_vault_a);
    assert!(
        ok.is_ok(),
        "same-market secondary reserve swap succeeds: {ok:?}"
    );
    assert_eq!(env.token_amount(primary_source), 0);
    assert_eq!(env.token_amount(env.vault), 10);
    assert_eq!(env.token_amount(secondary_dest), 10);
    assert_eq!(env.token_amount(secondary_vault_a), 40);
    assert_eq!(env.token_amount(secondary_vault_b), 70);
}

// security.md sweep — CloseSlab with secondary collateral (#44/#48): if a secondary collateral mint is
// configured, closing the slab must not zero the market after closing only the primary vault. Any
// secondary reserve must be recovered atomically in the same close, or the PDA-held reserve is stranded.
#[test]
fn v16_attack_close_slab_requires_secondary_vault_recovery() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let secondary_mint = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary_mint);
    let secondary_vault = canonical_vault_ata(env.vault_authority, secondary_mint);
    env.svm
        .set_account(
            secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.resolve();
    let market_before = env.svm.get_account(&env.market).unwrap();

    let primary_dest = env.token_account(admin.pubkey(), 0);
    env.svm.expire_blockhash();
    let primary_only = env.send(
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new(primary_dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        primary_only.is_err(),
        "CloseSlab must reject when a configured secondary vault is omitted"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "omitted-secondary close leaves market intact"
    );
    assert_eq!(
        env.token_amount(secondary_vault),
        50,
        "secondary reserve remains recoverable after rejected close"
    );

    env.svm
        .set_account(
            env.vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, env.vault_authority, 7),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let primary_dest = env.token_account(admin.pubkey(), 0);
    let wrong_secondary_dest = env.token_account_for_mint(secondary_mint, Pubkey::new_unique(), 0);
    env.svm.expire_blockhash();
    let wrong_secondary_dest_close = env.send(
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new(primary_dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new(wrong_secondary_dest, false),
        ],
        &[&admin],
    );
    assert!(
        wrong_secondary_dest_close.is_err(),
        "CloseSlab must reject before closing any vault when the secondary destination is wrong"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "bad secondary destination leaves market intact"
    );
    assert_eq!(
        env.token_amount(env.vault),
        7,
        "primary vault dust remains recoverable"
    );
    assert_eq!(
        env.token_amount(primary_dest),
        0,
        "primary dust not paid before bad secondary validation"
    );
    assert_eq!(
        env.token_amount(secondary_vault),
        50,
        "secondary vault remains recoverable"
    );
    assert_eq!(
        env.token_amount(wrong_secondary_dest),
        0,
        "wrong secondary destination receives nothing"
    );

    let primary_dest = env.token_account(admin.pubkey(), 0);
    let secondary_dest = env.token_account_for_mint(secondary_mint, admin.pubkey(), 0);
    env.svm.expire_blockhash();
    let close_both = env.send(
        ProgInstruction::CloseSlab,
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new(primary_dest, false),
            AccountMeta::new_readonly(spl_token::ID, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new(secondary_dest, false),
        ],
        &[&admin],
    );
    assert!(
        close_both.is_ok(),
        "CloseSlab closes both configured vaults: {:?}",
        close_both
    );
    assert_eq!(
        env.token_amount(primary_dest),
        7,
        "primary vault dust recovered to admin"
    );
    assert_eq!(
        env.token_amount(secondary_dest),
        50,
        "secondary reserve recovered to admin"
    );
    assert!(
        env.svm
            .get_account(&env.market)
            .unwrap()
            .data
            .iter()
            .all(|b| *b == 0),
        "market reclaimed only after both vaults close"
    );
}

// full-interface sweep (cron32): CloseSlab's optional secondary vault must be bound to the current
// market's vault PDA, not merely be a valid token account for the configured secondary mint. A foreign
// market's canonical secondary reserve must reject before primary dust is swept or either vault/market
// is closed.
#[test]
fn v16_attack_close_slab_rejects_foreign_secondary_vault() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let secondary_mint = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary_mint);
    let secondary_vault_a = canonical_vault_ata(env.vault_authority, secondary_mint);
    env.svm
        .set_account(
            secondary_vault_a,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    let market_b = Pubkey::new_unique();
    let vault_authority_b =
        Pubkey::find_program_address(&[b"vault", market_b.as_ref()], &env.program_id).0;
    let secondary_vault_b = canonical_vault_ata(vault_authority_b, secondary_mint);
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&admin],
    )
    .expect("init market B");
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: secondary_mint.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(secondary_mint, false),
        ],
        &[&admin],
    )
    .expect("configure market B secondary mint");
    env.svm
        .set_account(
            secondary_vault_b,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary_mint, vault_authority_b, 70),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    env.resolve();
    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 7);
    let primary_dest = env.token_account(admin.pubkey(), 0);
    let secondary_dest = env.token_account_for_mint(secondary_mint, admin.pubkey(), 0);
    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let primary_vault_before = env.svm.get_account(&env.vault).unwrap();
    let secondary_vault_a_before = env.svm.get_account(&secondary_vault_a).unwrap();
    let secondary_vault_b_before = env.svm.get_account(&secondary_vault_b).unwrap();
    let primary_dest_before = env.svm.get_account(&primary_dest).unwrap();
    let secondary_dest_before = env.svm.get_account(&secondary_dest).unwrap();

    let close_with_secondary_vault =
        |env: &mut V16CuEnv, secondary_vault: Pubkey| -> Result<u64, String> {
            env.svm.expire_blockhash();
            env.send(
                ProgInstruction::CloseSlab,
                vec![
                    AccountMeta::new(admin.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(env.vault, false),
                    AccountMeta::new_readonly(env.vault_authority, false),
                    AccountMeta::new(primary_dest, false),
                    AccountMeta::new_readonly(spl_token::ID, false),
                    AccountMeta::new(secondary_vault, false),
                    AccountMeta::new(secondary_dest, false),
                ],
                &[&admin],
            )
        };

    let rejected = close_with_secondary_vault(&mut env, secondary_vault_b);
    assert!(
        rejected.is_err(),
        "CloseSlab must reject a secondary reserve owned by a foreign market vault PDA"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_a_before,
        "rejected foreign-secondary close must not reclaim market A"
    );
    assert_eq!(
        env.svm.get_account(&market_b).unwrap(),
        market_b_before,
        "rejected foreign-secondary close must not mutate market B"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        primary_vault_before,
        "primary vault dust is not swept before secondary validation"
    );
    assert_eq!(
        env.svm.get_account(&secondary_vault_a).unwrap(),
        secondary_vault_a_before,
        "current market secondary vault remains recoverable"
    );
    assert_eq!(
        env.svm.get_account(&secondary_vault_b).unwrap(),
        secondary_vault_b_before,
        "foreign secondary vault is not drained or closed"
    );
    assert_eq!(
        env.svm.get_account(&primary_dest).unwrap(),
        primary_dest_before,
        "primary destination receives nothing on rejected foreign-secondary close"
    );
    assert_eq!(
        env.svm.get_account(&secondary_dest).unwrap(),
        secondary_dest_before,
        "secondary destination receives nothing on rejected foreign-secondary close"
    );

    let ok = close_with_secondary_vault(&mut env, secondary_vault_a);
    assert!(
        ok.is_ok(),
        "same-market secondary reserve CloseSlab succeeds: {ok:?}"
    );
    assert_eq!(env.token_amount(primary_dest), 7);
    assert_eq!(env.token_amount(secondary_dest), 50);
    assert_eq!(env.token_amount(secondary_vault_b), 70);
    let closed_market = env.svm.get_account(&env.market).unwrap();
    assert_eq!(closed_market.lamports, 0);
    assert!(closed_market.data.iter().all(|b| *b == 0));
}

// security.md sweep — ForceCloseAbandonedAsset griefing protection (#2/#6/#9): the permissionless
// force-close is meant ONLY for an asset whose oracle died and that has aged into RECOVERY lifecycle
// past force_close_delay_slots. Attacker goal: a cranker force-closes a HEALTHY, actively-traded asset
// to nuke a victim's open position. Must reject (asset is ACTIVE, not RECOVERY); positions stay intact.
#[test]
fn v16_attack_force_close_healthy_asset_rejected() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 0,
            initial_mark_e6: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    )
    .expect("cfg asset1 mark");
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, POS_SCALE as i128, 100, 100);
    let (_, g0) = env.market_state();
    // non-vacuity at the market level (legs are slot-indexed, not asset-indexed): asset 1 carries OI.
    assert!(
        g0.assets[1].oi_eff_long_q > 0,
        "open interest exists on the healthy asset 1"
    );
    assert_eq!(
        g0.assets[1].oi_eff_long_q, g0.assets[1].oi_eff_short_q,
        "asset-1 OI balanced pre-attack"
    );

    // ATTACK: a permissionless cranker force-closes the ACTIVE asset 1. now_slot is far in the future so
    // any force_close_delay window would have elapsed — the ONLY thing blocking is that the asset is not
    // abandoned (lifecycle != RECOVERY). Must reject.
    let cranker = Keypair::new();
    let r = env.try_force_close_abandoned_asset_with_cu(&cranker, pa, pb, 1, 5_000_000, POS_SCALE);
    assert!(
        r.is_err(),
        "force-close of a healthy ACTIVE asset must reject (not abandoned)"
    );

    // positions untouched (OI intact at the market level), value conserved.
    let g1 = env.market_state().1;
    assert_eq!(
        g1.assets[1].oi_eff_long_q, g0.assets[1].oi_eff_long_q,
        "asset-1 long OI intact (no force-close)"
    );
    assert_eq!(
        g1.assets[1].oi_eff_short_q, g0.assets[1].oi_eff_short_q,
        "asset-1 short OI intact"
    );
    assert_eq!(
        g1.vault, g0.vault,
        "vault unchanged by rejected force-close"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — ForceCloseAbandonedAsset pair-shape gate (#2/#44): once an asset is abandoned and
// past its exit window, anyone may close a LONG/SHORT pair at the frozen mark. A cranker must NOT be able
// to pass two same-side accounts and mutate them or the book; malformed pairings reject atomically, while
// a valid opposite-side pair still closes.
#[test]
fn v16_attack_force_close_requires_opposite_sides() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    const DELAY: u64 = 5;
    const SHUT: u64 = 10;
    env.configure_permissionless_resolve_with_cu(100, DELAY);

    let long_owner_a = Keypair::new();
    let short_owner_a = Keypair::new();
    let long_owner_b = Keypair::new();
    let short_owner_b = Keypair::new();
    let long_a = env.create_portfolio(&long_owner_a);
    let short_a = env.create_portfolio(&short_owner_a);
    let long_b = env.create_portfolio(&long_owner_b);
    let short_b = env.create_portfolio(&short_owner_b);
    for (owner, portfolio) in [
        (&long_owner_a, long_a),
        (&short_owner_a, short_a),
        (&long_owner_b, long_b),
        (&short_owner_b, short_b),
    ] {
        env.deposit(owner, portfolio, 1_000_000);
    }
    env.trade_asset_with_cu(
        1,
        &long_owner_a,
        long_a,
        &short_owner_a,
        short_a,
        POS_SCALE as i128,
        100,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &long_owner_b,
        long_b,
        &short_owner_b,
        short_b,
        POS_SCALE as i128,
        100,
        0,
    );
    assert_eq!(
        active_leg_for_asset(&env.portfolio_state(long_a), 1).side,
        SideV16::Long
    );
    assert_eq!(
        active_leg_for_asset(&env.portfolio_state(long_b), 1).side,
        SideV16::Long
    );
    assert_eq!(env.market_state().1.assets[1].oi_eff_long_q, 2 * POS_SCALE);

    env.svm.warp_to_slot(SHUT);
    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_SHUTDOWN,
        1,
        SHUT,
        0,
    );
    env.svm.warp_to_slot(SHUT + DELAY + 1);

    let market_before = env.svm.get_account(&env.market).unwrap();
    let long_a_before = env.svm.get_account(&long_a).unwrap();
    let long_b_before = env.svm.get_account(&long_b).unwrap();
    let cranker = Keypair::new();
    let same_side = env.try_force_close_abandoned_asset_with_cu(
        &cranker,
        long_a,
        long_b,
        1,
        SHUT + DELAY + 1,
        POS_SCALE,
    );
    assert!(
        same_side.is_err(),
        "force-close must reject two same-side accounts"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "same-side force-close leaves market byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&long_a).unwrap(),
        long_a_before,
        "same-side force-close leaves first account byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&long_b).unwrap(),
        long_b_before,
        "same-side force-close leaves second account byte-identical"
    );

    let ok = env.try_force_close_abandoned_asset_with_cu(
        &cranker,
        long_a,
        short_a,
        1,
        SHUT + DELAY + 1,
        POS_SCALE,
    );
    assert!(
        ok.is_ok(),
        "valid opposite-side force-close still succeeds: {ok:?}"
    );
    let group = env.market_state().1;
    assert_eq!(
        group.assets[1].oi_eff_long_q, POS_SCALE,
        "one long remains after closing one valid pair"
    );
    assert_eq!(
        group.assets[1].oi_eff_short_q, POS_SCALE,
        "one short remains after closing one valid pair"
    );
    assert!(!has_active_leg_for_asset(&env.portfolio_state(long_a), 1));
    assert!(has_active_leg_for_asset(&env.portfolio_state(long_b), 1));
    assert_eq!(
        group.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        group.vault >= group.c_tot + group.insurance,
        "senior conservation"
    );
}

// security.md sweep - ForceCloseAbandonedAsset oversized close_q (#14/#33/#48): the cranker controls
// a u128 close_q, but the handler must clamp it to the opposing abandoned positions before casting to
// the signed trade request. A huge close_q must not wrap negative, over-close, or corrupt OI.
#[test]
fn v16_attack_force_close_oversized_close_q_clamps_before_i128_cast() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    const DELAY: u64 = 5;
    const SHUT: u64 = 10;
    env.configure_permissionless_resolve_with_cu(100, DELAY);

    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long = env.create_portfolio(&long_owner);
    let short = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long, 1_000_000);
    env.deposit(&short_owner, short, 1_000_000);
    env.trade_asset_with_cu(
        1,
        &long_owner,
        long,
        &short_owner,
        short,
        POS_SCALE as i128,
        100,
        0,
    );
    let before = env.market_state().1;
    assert_eq!(before.assets[1].oi_eff_long_q, POS_SCALE);
    assert_eq!(before.assets[1].oi_eff_short_q, POS_SCALE);

    env.svm.warp_to_slot(SHUT);
    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_SHUTDOWN,
        1,
        SHUT,
        0,
    );
    env.svm.warp_to_slot(SHUT + DELAY + 1);

    let cranker = Keypair::new();
    let close = env.try_force_close_abandoned_asset_with_cu(
        &cranker,
        long,
        short,
        1,
        SHUT + DELAY + 1,
        u128::MAX,
    );
    assert!(
        close.is_ok(),
        "oversized force-close close_q must clamp before i128 cast: {close:?}"
    );
    let after = env.market_state().1;
    assert_eq!(
        after.assets[1].oi_eff_long_q, 0,
        "oversized close_q closed exactly the real long OI"
    );
    assert_eq!(
        after.assets[1].oi_eff_short_q, 0,
        "oversized close_q closed exactly the real short OI"
    );
    assert!(
        !has_active_leg_for_asset(&env.portfolio_state(long), 1),
        "long abandoned leg fully closed"
    );
    assert!(
        !has_active_leg_for_asset(&env.portfolio_state(short), 1),
        "short abandoned leg fully closed"
    );
    assert_eq!(
        after.vault as u64,
        env.token_amount(env.vault),
        "force-close with huge close_q keeps accounting tied to custody"
    );
    assert!(
        after.vault >= after.c_tot + after.insurance,
        "senior conservation after oversized force-close"
    );
}

// security.md sweep — ForceCloseAbandonedAsset has no portfolio-owner signatures by design after a
// shutdown timeout, so it must prove portfolio provenance itself. A cranker must not be able to pair a
// market-A portfolio with a market-B abandoned asset and mutate either market/account. Same-market
// control proves the rejected path is specifically the foreign portfolio binding.
#[test]
fn v16_attack_force_close_rejects_cross_market_portfolio_substitution() {
    const DELAY: u64 = 5;
    const SHUT: u64 = 20;
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    env.configure_permissionless_resolve_with_cu(100, DELAY);

    let a_long_owner = Keypair::new();
    let a_short_owner = Keypair::new();
    let a_long = env.create_portfolio(&a_long_owner);
    let a_short = env.create_portfolio(&a_short_owner);
    env.deposit(&a_long_owner, a_long, 1_000_000);
    env.deposit(&a_short_owner, a_short, 1_000_000);
    env.trade_asset_with_cu(
        1,
        &a_long_owner,
        a_long,
        &a_short_owner,
        a_short,
        POS_SCALE as i128,
        100,
        0,
    );
    assert_eq!(
        env.portfolio_state(a_long)
            .provenance_header
            .market_group_id,
        env.market.to_bytes(),
        "foreign candidate is genuinely bound to market A"
    );
    assert_eq!(
        active_leg_for_asset(&env.portfolio_state(a_long), 1).side,
        SideV16::Long
    );

    let params = V16CuMarketParams {
        max_portfolio_assets: 2,
        ..V16CuMarketParams::default()
    };
    let (market_b, _vault_authority_b, vault_b) =
        init_independent_market_same_mint(&mut env, params);
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 1,
            now_slot: 1,
            initial_mark_e6: 100,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
        ],
        &[&env.admin],
    )
    .expect("configure market B asset-1 auth mark");
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigurePermissionlessResolve {
            stale_slots: 100,
            force_close_delay_slots: DELAY,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
        ],
        &[&env.admin],
    )
    .expect("configure market B force-close delay");

    let b_long_owner = Keypair::new();
    let b_short_owner = Keypair::new();
    let b_long = init_portfolio_on_market(
        &mut env,
        market_b,
        &b_long_owner,
        params.max_portfolio_assets as usize,
    );
    let b_short = init_portfolio_on_market(
        &mut env,
        market_b,
        &b_short_owner,
        params.max_portfolio_assets as usize,
    );
    deposit_to_market(
        &mut env,
        market_b,
        vault_b,
        &b_long_owner,
        b_long,
        1_000_000,
    );
    deposit_to_market(
        &mut env,
        market_b,
        vault_b,
        &b_short_owner,
        b_short,
        1_000_000,
    );
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::TradeNoCpi {
            asset_index: 1,
            size_q: POS_SCALE as i128,
            exec_price: 100,
            fee_bps: 0,
        },
        vec![
            AccountMeta::new(b_long_owner.pubkey(), true),
            AccountMeta::new(b_short_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(b_long, false),
            AccountMeta::new(b_short, false),
        ],
        &[&b_long_owner, &b_short_owner],
    )
    .expect("open market B asset-1 position");
    let (_, market_b_open) =
        state::read_market(&env.svm.get_account(&market_b).unwrap().data).expect("read market B");
    assert_eq!(market_b_open.assets[1].oi_eff_long_q, POS_SCALE);
    assert_eq!(market_b_open.assets[1].oi_eff_short_q, POS_SCALE);

    env.svm.warp_to_slot(SHUT);
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_SHUTDOWN,
            asset_index: 1,
            now_slot: SHUT,
            initial_price: 0,
            insurance_authority: env.admin.pubkey().to_bytes(),
            insurance_operator: env.admin.pubkey().to_bytes(),
            backing_bucket_authority: env.admin.pubkey().to_bytes(),
            oracle_authority: env.admin.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
        ],
        &[&env.admin],
    )
    .expect("shut down market B asset 1");
    env.svm.warp_to_slot(SHUT + DELAY + 1);

    let cranker = Keypair::new();
    env.ensure_signer_account(cranker.pubkey());
    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let a_long_before = env.svm.get_account(&a_long).unwrap();
    let b_short_before = env.svm.get_account(&b_short).unwrap();
    let vault_b_before = env.svm.get_account(&vault_b).unwrap();
    env.svm.expire_blockhash();
    let rejected = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ForceCloseAbandonedAsset {
            asset_index: 1,
            now_slot: SHUT + DELAY + 1,
            close_q: POS_SCALE,
        },
        vec![
            AccountMeta::new(cranker.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(a_long, false),
            AccountMeta::new(b_short, false),
        ],
        &[&cranker],
    );
    assert!(
        rejected.is_err(),
        "permissionless force-close must reject a market-A portfolio under market B"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_a_before);
    assert_eq!(env.svm.get_account(&market_b).unwrap(), market_b_before);
    assert_eq!(env.svm.get_account(&a_long).unwrap(), a_long_before);
    assert_eq!(env.svm.get_account(&b_short).unwrap(), b_short_before);
    assert_eq!(env.svm.get_account(&vault_b).unwrap(), vault_b_before);

    env.svm.expire_blockhash();
    let ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ForceCloseAbandonedAsset {
            asset_index: 1,
            now_slot: SHUT + DELAY + 1,
            close_q: POS_SCALE,
        },
        vec![
            AccountMeta::new(cranker.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(b_long, false),
            AccountMeta::new(b_short, false),
        ],
        &[&cranker],
    );
    assert!(
        ok.is_ok(),
        "same-market abandoned pair force-closes: {ok:?}"
    );
    let (_, market_b_after) = state::read_market(&env.svm.get_account(&market_b).unwrap().data)
        .expect("read market B after force-close");
    assert_eq!(market_b_after.assets[1].oi_eff_long_q, 0);
    assert_eq!(market_b_after.assets[1].oi_eff_short_q, 0);
    assert_eq!(market_b_after.vault as u64, env.token_amount(vault_b));
    assert!(market_b_after.vault >= market_b_after.c_tot + market_b_after.insurance);
}

// security.md sweep - stale-resolve abandoned-asset drift (#30/#35/#48): ForceCloseAbandonedAsset
// is intentionally unsigned after a shutdown timeout, but it still mutates live exposure and both
// portfolios. Once the base market is resolve-matured, an abandoned-asset force-close must freeze
// before the terminal snapshot can be influenced.
#[test]
fn v16_attack_force_close_abandoned_asset_rejects_when_resolve_matured() {
    const STALE_SLOTS: u64 = 20;
    const DELAY: u64 = 5;
    const SHUTDOWN_SLOT: u64 = 10;
    const FRESH_FORCE_SLOT: u64 = SHUTDOWN_SLOT + DELAY + 1;
    const STALE_FORCE_SLOT: u64 = 40;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_permissionless_resolve_with_cu(STALE_SLOTS, DELAY);
    env.configure_auth_mark_with_cu(0, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);

    let fresh_long_owner = Keypair::new();
    let fresh_short_owner = Keypair::new();
    let stale_long_owner = Keypair::new();
    let stale_short_owner = Keypair::new();
    let fresh_long = env.create_portfolio(&fresh_long_owner);
    let fresh_short = env.create_portfolio(&fresh_short_owner);
    let stale_long = env.create_portfolio(&stale_long_owner);
    let stale_short = env.create_portfolio(&stale_short_owner);
    for (owner, portfolio) in [
        (&fresh_long_owner, fresh_long),
        (&fresh_short_owner, fresh_short),
        (&stale_long_owner, stale_long),
        (&stale_short_owner, stale_short),
    ] {
        env.deposit(owner, portfolio, 1_000_000);
    }
    env.trade_asset_with_cu(
        1,
        &fresh_long_owner,
        fresh_long,
        &fresh_short_owner,
        fresh_short,
        POS_SCALE as i128,
        100,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &stale_long_owner,
        stale_long,
        &stale_short_owner,
        stale_short,
        POS_SCALE as i128,
        100,
        0,
    );

    env.svm.warp_to_slot(SHUTDOWN_SLOT);
    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_SHUTDOWN,
        1,
        SHUTDOWN_SLOT,
        0,
    );
    let recovery_group = env.market_state().1;
    assert_eq!(recovery_group.mode, MarketModeV16::Live);
    assert_eq!(
        recovery_group.assets[1].lifecycle,
        AssetLifecycleV16::Recovery
    );

    env.svm.warp_to_slot(FRESH_FORCE_SLOT);
    let (fresh_cfg, fresh_group) = env.market_state();
    assert_eq!(fresh_group.mode, MarketModeV16::Live);
    assert!(
        !oracle_v16::permissionless_stale_matured(&fresh_cfg, FRESH_FORCE_SLOT),
        "fresh control must be before the base permissionless-resolve boundary"
    );
    let cranker = Keypair::new();
    let fresh_cu = env.force_close_abandoned_asset_with_cu(
        &cranker,
        fresh_long,
        fresh_short,
        1,
        FRESH_FORCE_SLOT,
        POS_SCALE,
    );
    assert_cu_within(
        "fresh ForceCloseAbandonedAsset before resolve maturity",
        fresh_cu,
        TRADE_CU_LIMIT,
    );
    assert!(
        !has_active_leg_for_asset(&env.portfolio_state(fresh_long), 1),
        "fresh abandoned-asset force-close proves the public path is reachable"
    );
    assert!(
        has_active_leg_for_asset(&env.portfolio_state(stale_long), 1),
        "stale-path target must still have a leg to force-close"
    );

    env.svm.warp_to_slot(STALE_FORCE_SLOT);
    let (stale_cfg, stale_group) = env.market_state();
    assert_eq!(stale_group.mode, MarketModeV16::Live);
    assert!(
        oracle_v16::permissionless_stale_matured(&stale_cfg, STALE_FORCE_SLOT),
        "test setup must be beyond the base permissionless-resolve boundary"
    );
    for portfolio in [stale_long, stale_short] {
        let mut legacy = env.svm.get_account(&portfolio).unwrap();
        legacy.data.truncate(PORTFOLIO_ENGINE_ACCOUNT_LEN);
        env.svm.set_account(portfolio, legacy).unwrap();
    }
    let market_before = env.svm.get_account(&env.market).unwrap();
    let stale_long_before = env.svm.get_account(&stale_long).unwrap();
    let stale_short_before = env.svm.get_account(&stale_short).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    assert_eq!(
        stale_long_before.data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "stale long setup uses a legacy portfolio"
    );
    assert_eq!(
        stale_short_before.data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "stale short setup uses a legacy portfolio"
    );

    let rejected = env.try_force_close_abandoned_asset_with_cu(
        &cranker,
        stale_long,
        stale_short,
        1,
        STALE_FORCE_SLOT,
        POS_SCALE,
    );
    assert!(
        rejected.is_err(),
        "ForceCloseAbandonedAsset must reject once the base market is resolve-matured"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected stale ForceClose leaves market exposure unchanged"
    );
    assert_eq!(
        env.svm.get_account(&stale_long).unwrap(),
        stale_long_before,
        "rejected stale ForceClose leaves the long portfolio unchanged"
    );
    assert_eq!(
        env.svm.get_account(&stale_short).unwrap(),
        stale_short_before,
        "rejected stale ForceClose leaves the short portfolio unchanged"
    );
    assert_eq!(
        env.svm.get_account(&stale_long).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "rejected stale ForceClose rolls back long-account realloc"
    );
    assert_eq!(
        env.svm.get_account(&stale_short).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "rejected stale ForceClose rolls back short-account realloc"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "rejected stale ForceClose moves no custody"
    );

    env.svm.expire_blockhash();
    let resolve = env.send(
        ProgInstruction::ResolveStalePermissionless { now_slot: 0 },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        resolve.is_ok(),
        "permissionless resolve still succeeds after rejected stale ForceClose: {resolve:?}"
    );
    assert_eq!(env.market_state().1.mode, MarketModeV16::Resolved);
}

// security.md sweep — off-market exec_price wash trade (#9/#22/#33): exec_price is validated only as
// 0 < exec_price <= MAX_ORACLE_PRICE (NOT clamped to the oracle), so two colluding accounts can open a
// position at a price far from the mark, handing one side an instant profit. Attacker goal: print
// withdrawable value out of the off-market gap. Protection: the off-market profit settles as JUNIOR pnl
// backed only by the counterparty's realized loss (residual), and the vault is never minted into —
// strictly zero-sum. Asserts no value creation across the off-market open + crank.
#[test]
fn v16_attack_off_market_exec_price_wash_trade_prints_nothing() {
    let mut env = V16CuEnv::new();
    env.configure_auth_mark_with_cu(0, 100); // oracle/mark = 100
    let oa = Keypair::new();
    let a = env.create_portfolio(&oa); // both controlled by one attacker
    let ob = Keypair::new();
    let b = env.create_portfolio(&ob);
    let d: u128 = 1_000_000;
    env.deposit(&oa, a, d);
    env.deposit(&ob, b, d);
    let (_, g0) = env.market_state();
    assert_eq!(g0.vault, 2 * d, "vault holds exactly both deposits");

    // OFF-MARKET OPEN: a goes LONG at exec_price=50 while the mark is 100 -> a is handed an instant
    // (100-50)*size paper profit; b (short) takes the symmetric loss. Far below the mark on purpose.
    let size = POS_SCALE as i128;
    let r = env.try_trade_asset_with_cu(0, &oa, a, &ob, b, size, 50, 0);
    // Either the post-trade margin check rejects the lopsided open (b can't cover) -> nothing printed,
    // or it succeeds and the profit is junior. Drive settlement either way and check the invariants.
    for p in [a, b] {
        env.svm.warp_to_slot(1);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 1,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(p, false),
            ],
            &[],
        );
    }
    let g = env.market_state().1;

    // INVARIANT 1: no tokens were minted — the vault still holds exactly the two deposits.
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real on-chain vault"
    );
    assert_eq!(g.vault, 2 * d, "off-market trade minted no vault tokens");
    // INVARIANT 2: senior conservation — junior (positive) pnl is fully backed by residual, never senior.
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation: residual backs junior pnl"
    );
    // INVARIANT 3: withdrawable capital was never inflated past the deposits by the paper profit.
    assert!(
        g.c_tot <= 2 * d,
        "no phantom capital minted (c_tot <= total deposited)"
    );
    // INVARIANT 4: any junior positive-pnl claim is bounded by the residual that actually backs it.
    let residual = g.vault.saturating_sub(g.c_tot).saturating_sub(g.insurance);
    assert!(
        g.pnl_pos_tot <= residual + 1,
        "junior positive-pnl claim bounded by residual (no over-claim)"
    );
    if r.is_err() {
        // lopsided open rejected outright: nothing moved at all.
        assert_eq!(
            g.c_tot,
            2 * d,
            "rejected off-market open left both capitals intact"
        );
    }
}

// security.md sweep — F-TRADENOCPI-FEE fix regression: the TradeNoCpi fee is now billed on the asset
// mark (effective_price), so the caller-supplied exec_price can no longer be gamed to under-pay fees.
// Attacker criterion (must FAIL): declaring exec_price << mark charges a smaller fee than the mark.
#[test]
fn v16_attack_tradenocpi_fee_cannot_be_evaded_via_exec_price() {
    // fee charged (insurance delta) for the SAME mark-valued position at different declared exec_prices.
    let fee_for = |exec_price: u64| -> u128 {
        let mut env = V16CuEnv::new();
        env.configure_auth_mark_with_cu(0, 100); // mark = 100
        let oa = Keypair::new();
        let a = env.create_portfolio(&oa);
        let ob = Keypair::new();
        let b = env.create_portfolio(&ob);
        env.deposit(&oa, a, 100_000_000_000);
        env.deposit(&ob, b, 100_000_000_000);
        let ins0 = env.market_state().1.insurance;
        env.trade_asset_with_cu(
            0,
            &oa,
            a,
            &ob,
            b,
            (1000 * POS_SCALE) as i128,
            exec_price,
            100,
        );
        env.market_state().1.insurance - ins0
    };
    let fee_at_mark = fee_for(100);
    assert!(
        fee_at_mark > 0,
        "non-vacuous: a real fee is charged at the mark"
    );
    // The whole point of the fix: a tiny declared exec_price does NOT reduce the fee anymore.
    assert_eq!(
        fee_for(1),
        fee_at_mark,
        "exec_price=1 is billed the SAME mark-based fee (no evasion)"
    );
    assert_eq!(
        fee_for(50),
        fee_at_mark,
        "exec_price below mark is billed the mark-based fee"
    );
    // Declaring a HIGH exec_price must not over-bill either — fee is pinned to the mark, not the caller.
    assert_eq!(
        fee_for(100_000),
        fee_at_mark,
        "exec_price above mark is also billed the mark-based fee"
    );
}

#[derive(Clone, Copy, Debug)]
enum NoCpiReportedPricePath {
    Single,
    Batch,
}

#[allow(clippy::too_many_arguments)]
fn try_no_cpi_reported_price_trade_with_cu(
    env: &mut V16CuEnv,
    path: NoCpiReportedPricePath,
    owner_a: &Keypair,
    account_a: Pubkey,
    owner_b: &Keypair,
    account_b: Pubkey,
    size_q: i128,
    exec_price: u64,
    fee_bps: u64,
) -> Result<u64, String> {
    match path {
        NoCpiReportedPricePath::Single => env.try_trade_asset_with_cu(
            0, owner_a, account_a, owner_b, account_b, size_q, exec_price, fee_bps,
        ),
        NoCpiReportedPricePath::Batch => env.send(
            ProgInstruction::BatchTradeNoCpi {
                legs: vec![BatchTradeLeg {
                    asset_index: 0,
                    size_q,
                    exec_price,
                    fee_bps,
                }],
            },
            vec![
                AccountMeta::new(owner_a.pubkey(), true),
                AccountMeta::new(owner_b.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(account_a, false),
                AccountMeta::new(account_b, false),
            ],
            &[owner_a, owner_b],
        ),
    }
}

fn funded_no_cpi_reported_price_pair(
    env: &mut V16CuEnv,
    deposit: u128,
) -> (Keypair, Pubkey, Keypair, Pubkey) {
    let owner_a = Keypair::new();
    let account_a = env.create_portfolio(&owner_a);
    let owner_b = Keypair::new();
    let account_b = env.create_portfolio(&owner_b);
    env.deposit(&owner_a, account_a, deposit);
    env.deposit(&owner_b, account_b, deposit);
    (owner_a, account_a, owner_b, account_b)
}

fn assert_zero_reported_price_rejects_atomically(
    mut env: V16CuEnv,
    path: NoCpiReportedPricePath,
    label: &str,
) {
    let (owner_a, account_a, owner_b, account_b) =
        funded_no_cpi_reported_price_pair(&mut env, 10_000_000_000);
    let (_, group_before) = env.market_state();
    let mark = group_before.assets[0].effective_price;
    assert_eq!(mark, 1_000_000, "{label}: setup must use the intended mark");
    let market_before = env.svm.get_account(&env.market).unwrap();
    let account_a_before = env.svm.get_account(&account_a).unwrap();
    let account_b_before = env.svm.get_account(&account_b).unwrap();

    env.svm.expire_blockhash();
    let rejected = try_no_cpi_reported_price_trade_with_cu(
        &mut env,
        path,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        POS_SCALE as i128,
        0,
        0,
    );
    assert!(
        rejected.is_err(),
        "{label} {path:?}: zero reported exec_price must reject before it can drive the mark"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "{label} {path:?}: rejected zero-price trade must leave market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&account_a).unwrap(),
        account_a_before,
        "{label} {path:?}: rejected zero-price trade must leave account_a unchanged"
    );
    assert_eq!(
        env.svm.get_account(&account_b).unwrap(),
        account_b_before,
        "{label} {path:?}: rejected zero-price trade must leave account_b unchanged"
    );

    env.svm.expire_blockhash();
    let control = try_no_cpi_reported_price_trade_with_cu(
        &mut env,
        path,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        POS_SCALE as i128,
        mark,
        0,
    );
    assert!(
        control.is_ok(),
        "{label} {path:?}: at-mark no-CPI control trade must remain live: {control:?}"
    );
}

fn zero_reported_price_ewma_env() -> V16CuEnv {
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        max_price_move_bps_per_slot: 50,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(1);
    env.configure_ewma_mark_with_cu(1, 1_000_000, 1, 0);
    env.svm.warp_to_slot(2);
    env
}

fn zero_reported_price_hybrid_after_hours_env() -> V16CuEnv {
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        max_price_move_bps_per_slot: 50,
        ..V16CuMarketParams::default()
    });
    set_test_clock(&mut env, 1, 100);
    let feed = [0x4du8; 32];
    let pyth = env.set_pyth_price(&feed, 1_000_000, -6, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed, [0u8; 32], [0u8; 32]],
        &[pyth],
        1,
        100,
        0,
        0,
        1,
        0,
    )
    .expect("configure hybrid oracle");
    set_test_clock(&mut env, 2, 101);
    env
}

// No-CPI reported-price manipulation: fees are already pinned to the mark, but the original
// caller-supplied exec_price still feeds EWMA discovery in EWMA and stale-hybrid modes. A zero
// reported price used to bypass the per-slot clamp and move the mark toward zero via a wash trade.
#[test]
fn v16_attack_nocpi_zero_reported_price_cannot_drive_ewma_or_hybrid_mark() {
    for path in [
        NoCpiReportedPricePath::Single,
        NoCpiReportedPricePath::Batch,
    ] {
        assert_zero_reported_price_rejects_atomically(
            zero_reported_price_ewma_env(),
            path,
            "EWMA mark",
        );
        assert_zero_reported_price_rejects_atomically(
            zero_reported_price_hybrid_after_hours_env(),
            path,
            "Hybrid after-hours mark",
        );
    }
}

fn ewma_no_cpi_fee_and_mark_for_reported_price(
    path: NoCpiReportedPricePath,
    reported_price: u64,
) -> (u128, u64) {
    const MARK: u64 = 1_000_000;
    const CAP_BPS: u64 = 50;
    const TRADE_SLOT: u64 = 5;

    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: MARK,
        h_max: 20,
        max_price_move_bps_per_slot: CAP_BPS,
        max_accrual_dt_slots: 20,
        min_funding_lifetime_slots: 20,
        trade_fee_base_bps: 100,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(1);
    env.configure_ewma_mark_with_cu(1, MARK, 1, 0);
    let (_, configured_group) = env.market_state();
    assert_eq!(configured_group.assets[0].effective_price, MARK);
    assert_eq!(configured_group.assets[0].slot_last, 1);

    env.svm.warp_to_slot(TRADE_SLOT);
    let (owner_a, account_a, owner_b, account_b) =
        funded_no_cpi_reported_price_pair(&mut env, 3_000_000_000);
    let insurance_before = env.market_state().1.insurance;
    let size_q = (1000u128 * POS_SCALE) as i128;
    env.svm.expire_blockhash();
    try_no_cpi_reported_price_trade_with_cu(
        &mut env,
        path,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        size_q,
        reported_price,
        0,
    )
    .unwrap_or_else(|err| {
        panic!("{path:?}: no-CPI EWMA trade with reported_price={reported_price} failed: {err}")
    });
    let (cfg, group) = env.market_state();
    (group.insurance - insurance_before, cfg.mark_ewma_e6)
}

// No-CPI reported-price manipulation follow-up: an epsilon reported price is valid, so rejecting
// zero is insufficient. The wrapper must first bound the reported print to the same per-asset dt
// envelope the engine will accept, then use that accepted print consistently for fee notional,
// mark-movement fees, and EWMA movement. Otherwise epsilon can either under-pay fees or drive a
// different mark than the charged price justified.
#[test]
fn v16_attack_nocpi_epsilon_reported_price_uses_dt_clamped_fee_and_ewma_price() {
    const MARK: u64 = 1_000_000;
    const CAP_BPS: u64 = 50;
    const DT: u64 = 4;
    let dt_clamped_epsilon = oracle_v16::clamp_toward_engine_dt(MARK, 1, CAP_BPS, DT);
    assert_eq!(
        dt_clamped_epsilon, 980_000,
        "test setup must exercise a multi-slot engine dt clamp"
    );

    for path in [
        NoCpiReportedPricePath::Single,
        NoCpiReportedPricePath::Batch,
    ] {
        let epsilon = ewma_no_cpi_fee_and_mark_for_reported_price(path, 1);
        let clamped = ewma_no_cpi_fee_and_mark_for_reported_price(path, dt_clamped_epsilon);
        let at_mark = ewma_no_cpi_fee_and_mark_for_reported_price(path, MARK);

        assert_eq!(
            epsilon, clamped,
            "{path:?}: epsilon report must be normalized to the accepted dt-clamped price for fee and EWMA"
        );
        assert_ne!(
            epsilon.0, at_mark.0,
            "{path:?}: non-vacuous fee assertion; the accepted below-mark print must not be billed as old mark"
        );
        assert_ne!(
            epsilon.1, at_mark.1,
            "{path:?}: non-vacuous EWMA assertion; the accepted below-mark print must move the mark"
        );
        assert_eq!(
            at_mark.1, MARK,
            "{path:?}: at-mark control should not move EWMA"
        );
        assert!(
            epsilon.1 < at_mark.1,
            "{path:?}: lower accepted print should move EWMA below at-mark control"
        );
    }
}

fn assert_no_cpi_tiny_exit_accepts_extreme_reported_price(
    path: NoCpiReportedPricePath,
    reported_price: u64,
) {
    const MARK: u64 = 1_000_000;
    const CAP_BPS: u64 = 50;
    const OPEN_Q: i128 = (1000u128 * POS_SCALE) as i128;
    const CLOSE_Q: i128 = -(POS_SCALE as i128);

    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: MARK,
        h_max: 20,
        max_price_move_bps_per_slot: CAP_BPS,
        max_accrual_dt_slots: 20,
        min_funding_lifetime_slots: 20,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(1);
    env.configure_ewma_mark_with_cu(1, MARK, 1, 0);
    env.svm.warp_to_slot(5);
    let (owner_a, account_a, owner_b, account_b) =
        funded_no_cpi_reported_price_pair(&mut env, 10_000_000_000_000);

    env.svm.expire_blockhash();
    try_no_cpi_reported_price_trade_with_cu(
        &mut env, path, &owner_a, account_a, &owner_b, account_b, OPEN_Q, MARK, 0,
    )
    .unwrap_or_else(|err| panic!("{path:?}: setup open at mark failed: {err}"));
    let (_, opened_group) = env.market_state();
    let long_before = opened_group.assets[0].oi_eff_long_q;
    let short_before = opened_group.assets[0].oi_eff_short_q;
    let insurance_before_exit = opened_group.insurance;
    let mark_before_exit = env.market_state().0.mark_ewma_e6;
    assert_eq!(long_before, OPEN_Q.unsigned_abs());
    assert_eq!(short_before, OPEN_Q.unsigned_abs());

    env.svm.expire_blockhash();
    let exit = try_no_cpi_reported_price_trade_with_cu(
        &mut env,
        path,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        CLOSE_Q,
        reported_price,
        0,
    );
    assert!(
        exit.is_ok(),
        "{path:?}: risk-reducing exit must not be DoSed by valid reported_price={reported_price}: {exit:?}"
    );
    let (closed_cfg, closed_group) = env.market_state();
    assert_eq!(
        closed_group.assets[0].oi_eff_long_q,
        long_before - POS_SCALE,
        "{path:?}: long OI reduced by the close"
    );
    assert_eq!(
        closed_group.assets[0].oi_eff_short_q,
        short_before - POS_SCALE,
        "{path:?}: short OI reduced by the close"
    );
    assert!(
        closed_group.insurance > insurance_before_exit,
        "{path:?}: extreme reported_price={reported_price} close charged a bounded higher fee"
    );
    let close_fee_paid = closed_group.insurance - insurance_before_exit;
    let externality_notional = 2u128
        .checked_mul(long_before)
        .and_then(|v| v.checked_mul(MARK as u128))
        .and_then(|v| v.checked_div(POS_SCALE))
        .expect("externality notional");
    let paid_move_bps = close_fee_paid * 10_000 / externality_notional;
    let mark_move_bps =
        percolator_prog::policy_v16::price_move_bps_ceil(mark_before_exit, closed_cfg.mark_ewma_e6)
            .expect("mark move bps");
    assert!(
        mark_move_bps <= paid_move_bps as u64,
        "{path:?}: EWMA close move ({mark_move_bps} bps) must be covered by paid fee ({paid_move_bps} bps)"
    );
}

