// Trade liveness: reported no-CPI prices are adversarial mark-discovery inputs, not a reason to
// reject valid trades. Extreme valid reports may be clamped and charged higher fees, but tiny trades
// against large existing OI must still execute instead of failing the fee model.
#[test]
fn v16_attack_nocpi_trade_not_dosed_by_extreme_reported_price() {
    for path in [
        NoCpiReportedPricePath::Single,
        NoCpiReportedPricePath::Batch,
    ] {
        for reported_price in [1, percolator::MAX_ORACLE_PRICE] {
            assert_no_cpi_tiny_exit_accepts_extreme_reported_price(path, reported_price);
            assert_no_cpi_tiny_open_accepts_extreme_reported_price(path, reported_price);
        }
    }
}

fn assert_no_cpi_extreme_reported_price_caps_paid_ewma_move(
    path: NoCpiReportedPricePath,
    reported_price: u64,
) {
    const MARK: u64 = 1_000_000;
    const CAP_BPS: u64 = 50;
    const MAX_FEE_BPS: u64 = 37;
    const TRADE_SLOT: u64 = 5;
    const SIZE_Q: i128 = (1000u128 * POS_SCALE) as i128;

    let accepted_price = oracle_v16::clamp_toward_engine_dt(MARK, reported_price, CAP_BPS, 4);
    let candidate_mark =
        percolator_prog::policy_v16::ewma_update(MARK, accepted_price, 1, 1, TRADE_SLOT, 0, 0);
    let candidate_move_bps = percolator_prog::policy_v16::price_move_bps_ceil(MARK, candidate_mark)
        .expect("candidate move bps");
    assert!(
        candidate_move_bps > MAX_FEE_BPS,
        "{path:?}: setup must make the unclamped EWMA candidate exceed the market fee cap"
    );

    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: MARK,
        h_max: 20,
        max_trading_fee_bps: MAX_FEE_BPS,
        max_price_move_bps_per_slot: CAP_BPS,
        max_accrual_dt_slots: 20,
        min_funding_lifetime_slots: 20,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(1);
    env.configure_ewma_mark_with_cu(1, MARK, 1, 0);
    env.svm.warp_to_slot(TRADE_SLOT);
    let (owner_a, account_a, owner_b, account_b) =
        funded_no_cpi_reported_price_pair(&mut env, 3_000_000_000);
    let insurance_before = env.market_state().1.insurance;

    env.svm.expire_blockhash();
    let trade = try_no_cpi_reported_price_trade_with_cu(
        &mut env,
        path,
        &owner_a,
        account_a,
        &owner_b,
        account_b,
        SIZE_Q,
        reported_price,
        0,
    );
    assert!(
        trade.is_ok(),
        "{path:?}: capped EWMA movement must not reject valid reported_price={reported_price}: {trade:?}"
    );

    let (cfg, group) = env.market_state();
    let mark_move_bps = percolator_prog::policy_v16::price_move_bps_ceil(MARK, cfg.mark_ewma_e6)
        .expect("actual mark move bps");
    assert_eq!(
        mark_move_bps, MAX_FEE_BPS,
        "{path:?}: EWMA movement should bind at the market fee cap, not at the full candidate move"
    );
    assert!(
        group.insurance > insurance_before,
        "{path:?}: capped EWMA movement still charges a fee"
    );
    let trade_notional = SIZE_Q.unsigned_abs() * accepted_price as u128 / POS_SCALE;
    let externality_notional = trade_notional * 2;
    let paid_move_bps = (group.insurance - insurance_before) * 10_000 / externality_notional;
    assert!(
        mark_move_bps <= paid_move_bps as u64,
        "{path:?}: capped EWMA move ({mark_move_bps} bps) must be paid for by fees ({paid_move_bps} bps)"
    );
}

// The fee cap is not a liveness gate for no-CPI EWMA discovery. If the full EWMA candidate would
// require more fee than the market cap allows, the trade still executes and the internal mark move
// is reduced to what the capped fee actually pays for.
#[test]
fn v16_attack_nocpi_extreme_price_caps_ewma_move_without_dos() {
    for path in [
        NoCpiReportedPricePath::Single,
        NoCpiReportedPricePath::Batch,
    ] {
        for reported_price in [1, percolator::MAX_ORACLE_PRICE] {
            assert_no_cpi_extreme_reported_price_caps_paid_ewma_move(path, reported_price);
        }
    }
}

// security.md sweep — ADL deleverage precision/conservation (#9/#22/#33): when a bankrupt side is
// partially liquidated, the engine auto-deleverages the WINNING (opposite) side by scaling its a-factor
// by oi_after/oi_before (percolator/src/v16.rs:9834). Attacker goal: have the winner keep its full claim
// while the loser's shortfall is socialized (value creation), or have the deleverage mint vault value.
// Protection: the winner's a-factor is reduced exactly proportionally, and the vault is never minted.
#[test]
fn v16_attack_adl_deleverage_conserves_and_shrinks_winner_claim() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    let la = Keypair::new();
    let a = env.create_portfolio(&la); // long = winner (gets deleveraged)
    let lb = Keypair::new();
    let b = env.create_portfolio(&lb); // short = loser (driven insolvent)
    env.deposit(&la, a, 1_000);
    env.deposit(&lb, b, 900);
    env.trade_asset_with_cu(0, &la, a, &lb, b, (2 * POS_SCALE) as i128, 100, 0);
    let g0 = env.market_state().1;
    assert_eq!(g0.assets[0].a_long, ADL_ONE, "a_long starts at ADL_ONE");
    assert_eq!(g0.assets[0].a_short, ADL_ONE, "a_short starts at ADL_ONE");
    let oi_long_pre = g0.assets[0].oi_eff_long_q;
    assert_eq!(oi_long_pre, 2 * POS_SCALE, "balanced OI of 2*POS_SCALE");
    let vault_pre = g0.vault;

    // price 1x->5x: the short is under maintenance but still has enough capital to avoid
    // recovery-mode bankruptcy, so this reaches the live liquidation/ADL path.
    env.svm.warp_to_slot(6);
    env.push_auth_mark_with_cu(6, 500);
    for p in [b, a] {
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 6,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(p, false),
            ],
            &[],
        );
    }
    // PARTIAL liquidation of the short: close exactly half (POS_SCALE of the 2*POS_SCALE position).
    env.crank(
        b,
        ProgInstruction::PermissionlessCrank {
            now_slot: 6,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );

    let g1 = env.market_state().1;
    let oi_long_post = g1.assets[0].oi_eff_long_q;
    // ADL TRIGGERED: the WINNING long side is deleveraged exactly proportionally to the OI it lost.
    assert!(
        oi_long_post < oi_long_pre,
        "winning-side OI reduced by the liquidation"
    );
    let expected_a_long = (ADL_ONE as u128) * oi_long_post / oi_long_pre;
    assert_eq!(
        g1.assets[0].a_long, expected_a_long,
        "a_long deleveraged exactly oi_after/oi_before"
    );
    assert!(
        g1.assets[0].a_long < ADL_ONE,
        "winner's claim factor strictly shrunk (ADL applied, non-vacuous)"
    );
    assert_eq!(
        g1.assets[0].a_short, ADL_ONE,
        "bankrupt (short) side a-factor unchanged"
    );
    // CONSERVATION: the deleverage mints NOTHING — vault unchanged, senior conservation holds.
    assert_eq!(g1.vault, vault_pre, "ADL deleverage minted no vault value");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        g1.vault >= g1.c_tot + g1.insurance,
        "senior conservation through ADL"
    );
    assert_eq!(
        g1.assets[0].oi_eff_long_q, g1.assets[0].oi_eff_short_q,
        "OI still balanced post-liquidation"
    );
}

// security.md sweep — unsafe liquidation escalates to recovery (#9/#19/#30): when a position is so
// deeply insolvent that a normal Live-mode liquidation cannot safely socialize the shortfall, the
// engine returns EngineRecoveryRequired rather than processing a partial/unsafe liquidation. Attacker
// goal: force such a liquidation to partially apply (mint value / strand / corrupt OI). Protection:
// the crank is rejected and ALL market state rolls back unchanged — no value minted, no partial ADL.
#[test]
fn v16_attack_unsafe_liquidation_of_deep_insolvency_rejects_and_rolls_back() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    let la = Keypair::new();
    let a = env.create_portfolio(&la); // long winner
    let lb = Keypair::new();
    let b = env.create_portfolio(&lb); // short, will be DEEPLY bankrupt
    env.deposit(&la, a, 1_000);
    env.deposit(&lb, b, 1_000);
    env.trade_asset_with_cu(0, &la, a, &lb, b, (7 * POS_SCALE) as i128, 100, 0);
    // 5x move: short loss ≈ 2800 >> its 1000 capital -> deeply bankrupt (negative equity).
    env.svm.warp_to_slot(6);
    env.push_auth_mark_with_cu(6, 500);
    for p in [b, a] {
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 6,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(p, false),
            ],
            &[],
        );
    }
    // ATTACK: try a Live-mode partial liquidation of the deeply-bankrupt short.
    let liquidation_ix = ProgInstruction::PermissionlessCrank {
        now_slot: 6,
        close_q: 2 * POS_SCALE,
        observations: crank_observations(0),
    };
    let liquidation_accounts = vec![
        AccountMeta::new(env.payer.pubkey(), true),
        AccountMeta::new(env.market, false),
        AccountMeta::new(b, false),
    ];
    let before_initial = env.svm.get_account(&env.market).unwrap();
    let g_pre_initial = env.market_state().1;
    env.svm.expire_blockhash();
    let first = env.send(liquidation_ix.clone(), liquidation_accounts.clone(), &[]);
    let (before, g_pre, r) = if first.is_ok() {
        assert_eq!(
            active_leg_for_asset(&env.portfolio_state(b), 0).basis_pos_q,
            -((7 * POS_SCALE) as i128),
            "first auto-crank close attempt may only refresh before the rejecting liquidation"
        );
        let before = env.svm.get_account(&env.market).unwrap();
        let g_pre = env.market_state().1;
        env.svm.expire_blockhash();
        let second = env.send(liquidation_ix, liquidation_accounts, &[]);
        (before, g_pre, second)
    } else {
        (before_initial, g_pre_initial, first)
    };
    // must reject — the engine signals recovery is required, not an unsafe partial liquidation.
    assert!(r.is_err(), "deep-insolvency Live liquidation must reject");
    let err = format!("{:?}", r);
    assert!(
        err.contains("Custom(23)"),
        "must be EngineRecoveryRequired (Custom 23), got: {}",
        err
    );

    // ROLLBACK: the rejected crank leaves the entire market account byte-identical (no partial ADL / mint).
    let after = env.svm.get_account(&env.market).unwrap();
    assert_eq!(
        after.data, before.data,
        "rejected liquidation rolled back market state byte-for-byte"
    );
    let g_post = env.market_state().1;
    assert_eq!(
        g_post.assets[0].a_long, g_pre.assets[0].a_long,
        "no ADL applied on rejected liquidation"
    );
    assert_eq!(
        g_post.assets[0].a_long, ADL_ONE,
        "winner not deleveraged by a rejected unsafe liquidation"
    );
    assert_eq!(g_post.vault, g_pre.vault, "no vault value minted");
    assert_eq!(
        g_post.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        g_post.vault >= g_post.c_tot + g_post.insurance,
        "senior conservation preserved"
    );
}

// security.md sweep — recovery-mode risk lockout (#9/#19/#30): once a market is in Recovery (winding
// down), no NEW risk may be opened — only reductions/wind-down. Attacker goal: open a fresh position
// (or grow one) during recovery to extract value or corrupt the wind-down accounting. Protection: the
// trade handlers require Live mode, so a TradeNoCpi in Recovery rejects with state fully preserved.
#[test]
fn v16_attack_recovery_mode_blocks_new_risk() {
    let mut env = V16CuEnv::new();
    env.configure_auth_mark_with_cu(0, 100);
    let la = Keypair::new();
    let a = env.create_portfolio(&la);
    let lb = Keypair::new();
    let b = env.create_portfolio(&lb);
    env.deposit(&la, a, 1_000_000);
    env.deposit(&lb, b, 1_000_000);
    env.trade_asset_with_cu(0, &la, a, &lb, b, POS_SCALE as i128, 100, 0);
    // transition the market into Recovery (engine backdoor, mirrors v16_bpf_recovery_and_reset_tags).
    env.mutate_market(|_, group| {
        group.mode = MarketModeV16::Recovery;
        group.recovery_reason = Some(PermissionlessRecoveryReasonV16::BelowProgressFloor);
    });
    let before = env.svm.get_account(&env.market).unwrap();
    let g_pre = env.market_state().1;
    assert_eq!(g_pre.mode, MarketModeV16::Recovery, "market is in recovery");

    // ATTACK 1: grow OI on the existing position during recovery -> must reject (mode != Live).
    let r1 = env.try_trade_asset_with_cu(0, &la, a, &lb, b, POS_SCALE as i128, 100, 0);
    assert!(r1.is_err(), "opening new risk in recovery must reject");

    // ATTACK 2: even initializing a fresh portfolio is locked out during recovery.
    let lc = Keypair::new();
    env.ensure_signer_account(lc.pubkey());
    let c = Pubkey::new_unique();
    let plen = env.portfolio_account_len;
    env.svm
        .set_account(
            c,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; plen],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let r2 = env.send(
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(lc.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(c, false),
        ],
        &[&lc],
    );
    assert!(
        r2.is_err(),
        "InitPortfolio is locked out in recovery (no new accounts during wind-down)"
    );

    // the rejected trades must not have grown OI or minted value.
    let g_post = env.market_state().1;
    assert_eq!(
        g_post.assets[0].oi_eff_long_q, g_pre.assets[0].oi_eff_long_q,
        "OI not grown by rejected recovery trades"
    );
    assert_eq!(
        g_post.assets[0].oi_eff_long_q, g_post.assets[0].oi_eff_short_q,
        "OI still balanced"
    );
    assert!(
        g_post.vault >= g_post.c_tot + g_post.insurance,
        "senior conservation in recovery"
    );
    // the market-level trade-affected state is unchanged vs before the attacks (deposits to c/d only added capital).
    let _ = before;
}

// security.md sweep — cross-margin gross margin requirement (#9/#22): a portfolio's initial-margin
// requirement is the SUM of per-leg risk (gross), never netted across legs. Attacker goal: hold a
// second (opposite-direction, different-asset) position that a netting model would treat as offsetting,
// to keep margin low while carrying gross risk. Protection: the health cert checked_adds each leg's
// requirement, so the second leg strictly INCREASES the requirement (no offset).
#[test]
fn v16_attack_cross_margin_requirement_is_gross_not_netted() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    let xo = Keypair::new();
    let x = env.create_portfolio(&xo); // cross-margin attacker
    let yo = Keypair::new();
    let y = env.create_portfolio(&yo); // counterparty
    env.deposit(&xo, x, 1_000_000);
    env.deposit(&yo, y, 1_000_000);

    // Leg 1: x LONG asset 0.
    env.trade_asset_with_cu(0, &xo, x, &yo, y, POS_SCALE as i128, 100, 0);
    let req1 = health_cert(&env.portfolio_state(x)).certified_initial_req;
    assert!(
        req1 > 0,
        "single-leg initial margin requirement is positive (non-vacuous), req1={}",
        req1
    );

    // Leg 2: x SHORT asset 1 (opposite direction, different underlying — a netting model would 'offset').
    env.trade_asset_with_cu(1, &xo, x, &yo, y, -(POS_SCALE as i128), 100, 0);
    let xs = env.portfolio_state(x);
    let req2 = health_cert(&xs).certified_initial_req;
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&xs)),
        2,
        "x holds two legs"
    );

    // GROSS: the second leg STRICTLY increased the requirement — it was added, not netted/offset.
    assert!(
        req2 > req1,
        "second leg must INCREASE the margin requirement (gross, no netting): req1={} req2={}",
        req1,
        req2
    );
    // Same size/price on both legs -> the requirement is ~doubled (each leg's gross risk fully counted).
    assert_eq!(
        req2,
        2 * req1,
        "two equal legs charge exactly the gross sum (2x), no cross-leg offset"
    );

    let g = env.market_state().1;
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — multi-account asymmetric premium funding zero-sum (#32/#33): funding redistributes
// value between longs and shorts per-leg via floored math. With UNEQUAL leg sizes across 3 accounts the
// per-account floors need not cancel exactly. Attacker goal: drive the rounding so the system MINTS net
// value (vault grows / senior conservation breaks) or pays longs more than shorts lose into spendable
// capital. Protection: funding never touches the vault and any rounding excess is unbacked junior pnl.
#[test]
fn v16_attack_multi_account_asymmetric_funding_conserves() {
    const INITIAL_PRICE: u64 = 1_000_000;
    const DEPOSIT: u128 = 50_000_000;
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: INITIAL_PRICE,
        max_price_move_bps_per_slot: 1_000,
        max_accrual_dt_slots: 1,
        max_abs_funding_e9_per_slot: 1_000,
        min_funding_lifetime_slots: 1,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(0);
    env.configure_ewma_mark_with_cu(0, INITIAL_PRICE, 1, 0);
    let l1o = Keypair::new();
    let l1 = env.create_portfolio(&l1o); // long 3S
    let l2o = Keypair::new();
    let l2 = env.create_portfolio(&l2o); // long 1S
    let sho = Keypair::new();
    let sh = env.create_portfolio(&sho); // short 4S (counterparty to both)
    for (o, p) in [(&l1o, l1), (&l2o, l2), (&sho, sh)] {
        env.deposit(o, p, DEPOSIT);
    }
    // Build matched OI with UNEQUAL longs: long1=3S and long2=1S, short absorbs 4S total.
    env.trade_with_cu(
        &l1o,
        l1,
        &sho,
        sh,
        (3 * POS_SCALE) as i128,
        INITIAL_PRICE,
        0,
    );
    env.svm.expire_blockhash();
    env.trade_with_cu(&l2o, l2, &sho, sh, POS_SCALE as i128, INITIAL_PRICE, 0);

    // premium: push the mark above the index so funding accrues, then crank all three over several slots.
    env.svm.warp_to_slot(1);
    env.push_ewma_mark_with_cu(1, INITIAL_PRICE * 2);
    for slot in 1..=6u64 {
        env.svm.warp_to_slot(slot);
        for p in [l1, l2, sh] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(0),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    let g = env.market_state().1;
    // non-vacuity: funding actually accrued.
    assert!(
        g.assets[0].f_long_num != 0 || g.assets[0].f_short_num != 0,
        "funding accrued (non-vacuous)"
    );
    // CONSERVATION: funding is internal -> the vault is byte-exact 3*DEPOSIT, nothing minted/burned.
    // (Premium funding routes a protocol "premium cut" to insurance — internal redistribution, NOT
    // minting: the total vault is unchanged and insurance stays bounded by the conserved vault.)
    assert_eq!(
        g.vault,
        3 * DEPOSIT,
        "vault == total deposited (funding mints nothing despite unequal legs)"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
    assert!(
        g.insurance <= g.vault,
        "insurance (incl. premium cut) bounded by the conserved vault"
    );
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation under asymmetric funding"
    );
    // OI stayed balanced through all the funding cranks.
    assert_eq!(
        g.assets[0].oi_eff_long_q, g.assets[0].oi_eff_short_q,
        "OI balanced"
    );
    // senior side never exceeds what was deposited: sum(capital + realized losses) <= deposits.
    let mut senior: i128 = 0;
    for p in [l1, l2, sh] {
        let a = state::read_portfolio(&env.svm.get_account(&p).unwrap().data).unwrap();
        senior += a.capital.get() as i128 + a.pnl.get().min(0);
    }
    assert!(
        senior <= (3 * DEPOSIT) as i128,
        "senior value (capital + realized losses) never exceeds deposits: {}",
        senior
    );
}

// security.md sweep — ConvertReleasedPnl cannot mint from unbacked pnl (#33/#35/#22): the existing
// caller-cap test (#?) uses FULLY-backed pnl. Here the positive pnl (100) EXCEEDS its source backing
// (residual 40). Attacker goal: convert the full 100 into withdrawable senior capital, printing 60 of
// unbacked value. Protection: only the residual-backed portion converts to capital; the phantom excess
// is cleared (it was never realizable), the account's realizable value is conserved, and the vault is
// never minted.
#[test]
fn v16_attack_convert_released_pnl_cannot_mint_from_unbacked_pnl() {
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, 40, 10_000); // residual backing = 40 in domain 1
    let o = Keypair::new();
    let p = env.create_portfolio(&o);
    env.deposit(&o, p, 1_000);
    env.add_source_positive_pnl(p, 1, 100); // claim 100 -> only 40 is backed
    env.crank(
        p,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let pre = env.portfolio_state(p);
    let g_pre = env.market_state().1;
    let residual_pre = g_pre
        .vault
        .saturating_sub(g_pre.c_tot)
        .saturating_sub(g_pre.insurance);
    assert!(
        pre.pnl.get() > residual_pre as i128,
        "non-vacuous: pnl ({}) exceeds the backing residual ({})",
        pre.pnl.get(),
        residual_pre
    );

    // ATTACK: convert with a huge cap, trying to realize the full (partly-unbacked) pnl into capital.
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::ConvertReleasedPnl {
            amount: 1_000_000_000,
        },
        vec![
            AccountMeta::new(o.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
        ],
        &[&o],
    );
    assert!(
        r.is_ok(),
        "convert should succeed (converting the backed portion): {:?}",
        r
    );

    let post = env.portfolio_state(p);
    let g = env.market_state().1;
    let minted = post.capital.get() as i128 - pre.capital.get() as i128;
    // ANTI-MINT: capital grew by AT MOST the residual that actually backed the pnl — never the full 100.
    assert!(
        minted <= residual_pre as i128,
        "capital minted ({}) must not exceed backing residual ({})",
        minted,
        residual_pre
    );
    assert_eq!(
        minted, residual_pre as i128,
        "exactly the backed portion (40) converts to capital"
    );
    assert!(
        minted < pre.pnl.get(),
        "the unbacked excess (60) is NOT converted to capital"
    );
    // realizable value conserved: capital_before + backed (== capital_after); no phantom value created.
    assert_eq!(
        post.capital.get() as i128,
        pre.capital.get() as i128 + residual_pre as i128,
        "realizable value conserved"
    );
    // no vault minting + senior conservation.
    assert_eq!(
        g.vault, g_pre.vault,
        "ConvertReleasedPnl moves no vault tokens"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — ADL deleverage + subsequent settlement interaction (#9/#22/#33): after a partial
// liquidation deleverages the winning side (a_long < ADL_ONE), the winner's NEXT mark settlement uses
// its a_basis vs the reduced a_long (scaled_adl_delta). Attacker goal: have the winner still realize its
// FULL pre-ADL gain into spendable capital (escaping the deleverage), or have the combined ADL+settle
// sequence mint vault value. Protection: the winner's realizable value stays bounded by capital+residual
// and the vault is never minted across the whole sequence. (Interaction not covered by single-mechanism
// tests: #141 tests ADL's a-factor; this exercises ADL THEN settlement of the deleveraged leg.)
#[test]
fn v16_attack_adl_then_settlement_winner_cannot_escape_deleverage() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    let la = Keypair::new();
    let a = env.create_portfolio(&la); // long winner
    let lb = Keypair::new();
    let b = env.create_portfolio(&lb); // short loser
    env.deposit(&la, a, 1_000);
    env.deposit(&lb, b, 900);
    env.trade_asset_with_cu(0, &la, a, &lb, b, (2 * POS_SCALE) as i128, 100, 0);
    let vault0 = env.market_state().1.vault; // the only real tokens in the system

    // price up: short is under maintenance but not bankrupt; settle both, then PARTIAL
    // liquidate the short -> a_long deleverages.
    env.svm.warp_to_slot(6);
    env.push_auth_mark_with_cu(6, 500);
    for p in [b, a] {
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 6,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(p, false),
            ],
            &[],
        );
    }
    env.crank(
        b,
        ProgInstruction::PermissionlessCrank {
            now_slot: 6,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    let g_adl = env.market_state().1;
    assert!(
        g_adl.assets[0].a_long < ADL_ONE,
        "winner deleveraged (ADL engaged), a_long={}",
        g_adl.assets[0].a_long
    );

    // SECOND mark move + crank the winner: this settles the deleveraged leg (a_basis vs reduced a_long).
    env.svm.warp_to_slot(7);
    env.push_auth_mark_with_cu(7, 800);
    env.crank(
        a,
        ProgInstruction::PermissionlessCrank {
            now_slot: 7,
            close_q: 0,
            observations: crank_observations(0),
        },
    );

    let win = env.portfolio_state(a);
    let g = env.market_state().1;
    // non-vacuity: the winner really does carry a paper gain after the moves.
    assert!(
        win.pnl.get() > 0,
        "winner carries a positive paper gain (non-vacuous), pnl={}",
        win.pnl.get()
    );
    // NO MINT across the whole ADL+settle sequence: the vault still holds exactly the original deposits.
    assert_eq!(g.vault, vault0, "ADL + settlement minted no vault tokens");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    // the winner cannot escape the deleverage: its REALIZABLE value (capital + backed pnl) is bounded by
    // capital + residual — the deleveraged/unbacked gain is NOT spendable (certified equity reflects it).
    let residual = g.vault.saturating_sub(g.c_tot).saturating_sub(g.insurance);
    assert!(
        health_cert(&win).valid,
        "winner cert valid after settlement"
    );
    assert!(
        (health_cert(&win).certified_equity as u128) <= win.capital.get() + residual + 1,
        "winner realizable value bounded by capital+residual (deleverage not escaped): eq={} cap={} residual={}",
        health_cert(&win).certified_equity, win.capital.get(), residual
    );
    // The deleverage caps how much the winner can realize: the surviving gain equals exactly the backed
    // portion (a winner can never pull more than the system holds — and the vault was never minted, above).
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation through ADL + settlement"
    );
}

// security.md sweep — deposit does not dilute an existing junior-PnL holder's backing (#33/#22 interaction):
// a backed junior-PnL holder's realizable claim is funded by residual (vault - c_tot - insurance). A
// fresh deposit by ANOTHER account increases vault AND c_tot equally, so residual — and the holder's
// haircut-backed equity — must be UNCHANGED. Attacker/edge goal: a large third-party deposit shifts the
// backing math so the holder's realizable claim grows (mint) or shrinks (theft). Protection: residual is
// invariant to deposits, so the holder's certified equity is identical before/after.
#[test]
fn v16_attack_deposit_does_not_dilute_junior_backing() {
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, 40, 10_000); // backing for the junior holder
    let ho = Keypair::new();
    let h = env.create_portfolio(&ho); // junior-pnl holder
    env.deposit(&ho, h, 1_000);
    env.add_source_positive_pnl(h, 1, 40); // 40 backed positive pnl
    env.crank(
        h,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let h_pre = env.portfolio_state(h);
    let g_pre = env.market_state().1;
    let residual_pre = g_pre
        .vault
        .saturating_sub(g_pre.c_tot)
        .saturating_sub(g_pre.insurance);
    assert!(health_cert(&h_pre).valid, "holder cert valid");
    assert!(
        h_pre.pnl.get() > 0,
        "holder carries positive (backed) junior pnl, pnl={}",
        h_pre.pnl.get()
    );
    let eq_pre = health_cert(&h_pre).certified_equity;

    // a DIFFERENT account makes a large deposit.
    let wo = Keypair::new();
    let w = env.create_portfolio(&wo);
    env.deposit(&wo, w, 5_000_000);

    // refresh the holder's cert (deposit by w should not have changed the holder's backing).
    env.svm.expire_blockhash();
    env.crank(
        h,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let h_post = env.portfolio_state(h);
    let g_post = env.market_state().1;
    let residual_post = g_post
        .vault
        .saturating_sub(g_post.c_tot)
        .saturating_sub(g_post.insurance);

    // NON-DILUTION: residual is invariant to the third-party deposit (vault += D, c_tot += D).
    assert_eq!(
        residual_post, residual_pre,
        "residual unchanged by a third-party deposit (no dilution/mint)"
    );
    // the holder's realizable claim (capital + backed pnl) and pnl are byte-identical.
    assert_eq!(
        health_cert(&h_post).certified_equity,
        eq_pre,
        "holder certified equity unchanged by w's deposit"
    );
    assert_eq!(
        h_post.capital.get(),
        h_pre.capital.get(),
        "holder capital unchanged"
    );
    assert_eq!(
        h_post.pnl.get(),
        h_pre.pnl.get(),
        "holder junior pnl unchanged"
    );
    // conservation, and the deposit landed as real tokens.
    assert_eq!(
        g_post.vault,
        g_pre.vault + 5_000_000,
        "vault grew by exactly the deposit"
    );
    assert_eq!(
        g_post.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        g_post.vault >= g_post.c_tot + g_post.insurance,
        "senior conservation"
    );
}

// security.md sweep — insurance-fund ops do not touch junior-PnL backing (#6/#33/#22 interaction): a
// backed junior holder is funded by residual (vault − c_tot − insurance). A domain insurance top-up
// (+X to vault AND insurance) and a domain insurance withdrawal (−X to vault AND insurance) both leave
// residual invariant. Attacker/edge goal: route value through the insurance fund to shift a junior
// holder's realizable claim (mint by growing it / theft by shrinking it). Protection: residual — and the
// holder's certified equity — is identical across both insurance operations; senior conservation holds.
#[test]
fn v16_attack_insurance_ops_preserve_junior_backing() {
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, 40, 10_000);
    let ho = Keypair::new();
    let h = env.create_portfolio(&ho);
    env.deposit(&ho, h, 1_000);
    env.add_source_positive_pnl(h, 1, 40);
    env.crank(
        h,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let eq0 = health_cert(&env.portfolio_state(h)).certified_equity;
    let g0 = env.market_state().1;
    let residual0 = g0
        .vault
        .saturating_sub(g0.c_tot)
        .saturating_sub(g0.insurance);
    assert!(
        env.portfolio_state(h).pnl.get() > 0,
        "holder carries backed junior pnl"
    );

    let read = |env: &V16CuEnv| -> (i128, u128) {
        let g = env.market_state().1;
        (
            g.vault.saturating_sub(g.c_tot).saturating_sub(g.insurance) as i128,
            g.insurance,
        )
    };

    // (1) domain insurance TOP-UP: +1M to vault AND insurance -> residual unchanged.
    let admin = env.admin.insecure_clone();
    env.top_up_insurance_domain_with_authority(&admin, 0, 1_000_000);
    let (res1, ins1) = read(&env);
    assert_eq!(
        res1, residual0 as i128,
        "residual unchanged by insurance top-up"
    );
    assert_eq!(
        ins1,
        g0.insurance + 1_000_000,
        "insurance grew by the top-up"
    );

    // refresh the holder's cert: top-up must not have changed its backing.
    env.svm.expire_blockhash();
    env.crank(
        h,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    assert_eq!(
        health_cert(&env.portfolio_state(h)).certified_equity,
        eq0,
        "holder equity unchanged by insurance top-up"
    );

    // (2) domain insurance WITHDRAW: −600k from vault AND insurance -> residual STILL unchanged.
    env.try_withdraw_insurance_domain_with_authority(&admin, 0, 600_000)
        .expect("domain withdraw ok");
    let (res2, ins2) = read(&env);
    assert_eq!(
        res2, residual0 as i128,
        "residual unchanged by insurance withdrawal"
    );
    assert_eq!(ins2, ins1 - 600_000, "insurance dropped by the withdrawal");

    // refresh the holder's cert: withdrawal must not have touched its backing either.
    env.svm.expire_blockhash();
    env.crank(
        h,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let hf = env.portfolio_state(h);
    let gf = env.market_state().1;
    assert_eq!(
        health_cert(&hf).certified_equity,
        eq0,
        "holder equity unchanged across BOTH insurance ops"
    );
    assert_eq!(
        hf.pnl.get(),
        env.portfolio_state(h).pnl.get(),
        "holder pnl stable"
    );
    assert_eq!(
        gf.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        gf.vault >= gf.c_tot + gf.insurance,
        "senior conservation across insurance ops"
    );
}

// security.md sweep — recovery blocks junior→senior conversion (#6/#19/#33 interaction): ConvertReleasedPnl
// moves backed junior pnl into withdrawable senior capital, and is Live-only (the engine's release path
// requires Live mode). Attacker goal: during a Recovery wind-down, convert junior pnl to senior capital
// to jump the queue / extract ahead of the orderly resolution. Protection: ConvertReleasedPnl rejects in
// Recovery and the account/market state is fully preserved (the junior claim stays junior).
#[test]
fn v16_attack_recovery_blocks_pnl_conversion() {
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, 40, 10_000);
    let o = Keypair::new();
    let p = env.create_portfolio(&o);
    env.deposit(&o, p, 1_000);
    env.add_source_positive_pnl(p, 1, 40);
    env.crank(
        p,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let pre = env.portfolio_state(p);
    assert!(
        pre.pnl.get() > 0,
        "holder has backed junior pnl to (attempt to) convert, pnl={}",
        pre.pnl.get()
    );

    // transition to Recovery.
    env.mutate_market(|_, group| {
        group.mode = MarketModeV16::Recovery;
        group.recovery_reason = Some(PermissionlessRecoveryReasonV16::BelowProgressFloor);
    });
    let before = env.svm.get_account(&env.market).unwrap();
    let g_pre = env.market_state().1;

    // ATTACK: convert junior pnl -> senior capital during the wind-down.
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::ConvertReleasedPnl {
            amount: 1_000_000_000,
        },
        vec![
            AccountMeta::new(o.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
        ],
        &[&o],
    );
    assert!(
        r.is_err(),
        "ConvertReleasedPnl must reject in Recovery (Live-only)"
    );

    // ROLLBACK: the junior claim stays junior; account capital/pnl and the market are unchanged.
    let post = env.portfolio_state(p);
    let g_post = env.market_state().1;
    assert_eq!(
        post.capital.get(),
        pre.capital.get(),
        "no junior->senior conversion: capital unchanged"
    );
    assert_eq!(
        post.pnl.get(),
        pre.pnl.get(),
        "junior pnl stays junior (not converted)"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before.data,
        "market state byte-for-byte unchanged"
    );
    assert_eq!(
        g_post.c_tot, g_pre.c_tot,
        "c_tot unchanged (no capital minted from junior pnl)"
    );
    assert_eq!(
        g_post.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        g_post.vault >= g_post.c_tot + g_post.insurance,
        "senior conservation in recovery"
    );
}

// security.md sweep — liquidation/ADL isolation across assets (#9/#22 interaction): a liquidation (and
// its ADL deleverage) on asset A's market must not touch asset B's independent book. Attacker goal: a
// liquidation on one asset corrupts another asset's OI / a-factor / mark, or socializes A's loss onto
// B's holders. Protection: OI, a_long/a_short and effective_price are per-asset; asset B is byte-stable.
#[test]
fn v16_attack_liquidation_isolated_across_assets() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    // asset 0: a0 long vs b0 short (b0 will be liquidated)
    let a0o = Keypair::new();
    let a0 = env.create_portfolio(&a0o);
    let b0o = Keypair::new();
    let b0 = env.create_portfolio(&b0o);
    // asset 1: a1 long vs b1 short (independent, must be untouched)
    let a1o = Keypair::new();
    let a1 = env.create_portfolio(&a1o);
    let b1o = Keypair::new();
    let b1 = env.create_portfolio(&b1o);
    for (o, p, amount) in [
        (&a0o, a0, 1_000),
        (&b0o, b0, 900),
        (&a1o, a1, 1_000),
        (&b1o, b1, 1_000),
    ] {
        env.deposit(o, p, amount);
    }
    env.trade_asset_with_cu(0, &a0o, a0, &b0o, b0, (2 * POS_SCALE) as i128, 100, 0);
    env.trade_asset_with_cu(1, &a1o, a1, &b1o, b1, (3 * POS_SCALE) as i128, 100, 0);

    // snapshot asset 1's book BEFORE touching asset 0.
    let g_pre = env.market_state().1;
    let b1_oi_long = g_pre.assets[1].oi_eff_long_q;
    let b1_oi_short = g_pre.assets[1].oi_eff_short_q;
    let b1_a_long = g_pre.assets[1].a_long;
    let b1_a_short = g_pre.assets[1].a_short;
    let b1_price = g_pre.assets[1].effective_price;
    let a1_pre = env.portfolio_state(a1);
    let b1_pre = env.portfolio_state(b1);
    assert_eq!(b1_oi_long, 3 * POS_SCALE, "asset 1 carries its own OI");

    // drive ONLY asset 0's mark up; settle asset-0 accounts; partial-liquidate b0 (ADL on asset 0).
    env.svm.warp_to_slot(6);
    env.push_auth_mark_with_cu(6, 500);
    for p in [b0, a0] {
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 6,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(p, false),
            ],
            &[],
        );
    }
    env.crank(
        b0,
        ProgInstruction::PermissionlessCrank {
            now_slot: 6,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    let g_post = env.market_state().1;
    assert!(
        g_post.assets[0].a_long < ADL_ONE,
        "ADL engaged on asset 0 (non-vacuous)"
    );

    // ISOLATION: asset 1's entire book is byte-identical — OI, a-factors, mark, and the asset-1 portfolios.
    assert_eq!(
        g_post.assets[1].oi_eff_long_q, b1_oi_long,
        "asset-1 long OI untouched by asset-0 liquidation"
    );
    assert_eq!(
        g_post.assets[1].oi_eff_short_q, b1_oi_short,
        "asset-1 short OI untouched"
    );
    assert_eq!(
        g_post.assets[1].a_long, b1_a_long,
        "asset-1 a_long untouched (no cross-asset ADL)"
    );
    assert_eq!(
        g_post.assets[1].a_short, b1_a_short,
        "asset-1 a_short untouched"
    );
    assert_eq!(
        g_post.assets[1].effective_price, b1_price,
        "asset-1 mark untouched"
    );
    assert_eq!(
        env.portfolio_state(a1).legs,
        a1_pre.legs,
        "asset-1 long portfolio legs untouched"
    );
    assert_eq!(
        env.portfolio_state(b1).legs,
        b1_pre.legs,
        "asset-1 short portfolio legs untouched"
    );
    assert!(
        g_post.vault >= g_post.c_tot + g_post.insurance,
        "senior conservation"
    );
}

// security.md sweep — cross-margin leg close releases its margin (#9/#22 interaction): opening a 2nd leg
// adds its full requirement (gross, #145); closing one leg must SYMMETRICALLY remove that leg's
// requirement (no stale margin lock, and no under-margin by dropping too much). Attacker/edge goal: after
// closing a leg the requirement stays inflated (DoS lock) or collapses below the remaining leg's risk.
#[test]
fn v16_attack_cross_margin_leg_close_releases_its_margin() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    let xo = Keypair::new();
    let x = env.create_portfolio(&xo);
    let yo = Keypair::new();
    let y = env.create_portfolio(&yo);
    env.deposit(&xo, x, 1_000_000);
    env.deposit(&yo, y, 1_000_000);

    // open leg 0 (LONG asset 0) -> req1; then leg 1 (SHORT asset 1) -> req2 == 2*req1 (gross).
    env.trade_asset_with_cu(0, &xo, x, &yo, y, POS_SCALE as i128, 100, 0);
    let req1 = health_cert(&env.portfolio_state(x)).certified_initial_req;
    env.trade_asset_with_cu(1, &xo, x, &yo, y, -(POS_SCALE as i128), 100, 0);
    let req2 = health_cert(&env.portfolio_state(x)).certified_initial_req;
    assert_eq!(
        req2,
        2 * req1,
        "two legs charge the gross sum (precondition)"
    );
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&env.portfolio_state(x))),
        2,
        "x has 2 legs"
    );

    // CLOSE leg 0 (opposite trade on asset 0) -> x should be left with only the asset-1 leg.
    env.svm.expire_blockhash();
    env.trade_asset_with_cu(0, &xo, x, &yo, y, -(POS_SCALE as i128), 100, 0);
    let xs = env.portfolio_state(x);
    let req_after = health_cert(&xs).certified_initial_req;
    let g = env.market_state().1;

    // SYMMETRIC RELEASE: closing leg 0 removed exactly its requirement -> back to a single leg's req.
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&xs)),
        1,
        "asset-0 leg fully closed, one leg left"
    );
    assert_eq!(g.assets[0].oi_eff_long_q, 0, "asset-0 OI fully unwound");
    assert!(g.assets[1].oi_eff_short_q > 0, "asset-1 leg still open");
    assert_eq!(
        req_after, req1,
        "requirement drops back to exactly one leg's req (no stale lock, no under-margin)"
    );
    // x is still healthy (equity covers the remaining single-leg requirement).
    assert!(
        health_cert(&xs).valid && health_cert(&xs).certified_equity >= 0,
        "x healthy with the remaining leg"
    );
    assert!(
        (health_cert(&xs).certified_equity as u128) >= req_after,
        "equity still covers the remaining requirement"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — full winner extraction: convert backed pnl then withdraw (#33/#35/#44 interaction):
// a backed winner converts released junior pnl to senior capital, then withdraws. Attacker goal: extract
// MORE than (deposit + backed pnl) — print value on the way out. Protection: the conversion is bounded by
// the backing (#147) and withdraw moves only real capital, so total out == deposit + backing, no more,
// and the vault drains to exactly what the backing provider funded.
#[test]
fn v16_attack_convert_then_withdraw_extracts_exactly_backed() {
    const DEP: u128 = 1_000;
    const BACK: u128 = 40;
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, BACK, 10_000); // an LP backs the winner with 40
    let o = Keypair::new();
    let p = env.create_portfolio(&o);
    env.deposit(&o, p, DEP);
    env.add_source_positive_pnl(p, 1, BACK); // fully-backed 40 junior pnl
    env.crank(
        p,
        ProgInstruction::PermissionlessCrank {
            now_slot: 0,
            close_q: 0,
            observations: crank_observations(0),
        },
    );
    let vault0 = env.market_state().1.vault;
    assert_eq!(
        vault0,
        DEP + BACK,
        "vault holds the deposit + the LP backing"
    );

    // (1) convert the backed junior pnl into senior capital.
    env.svm.expire_blockhash();
    let rc = env.send(
        ProgInstruction::ConvertReleasedPnl {
            amount: 1_000_000_000,
        },
        vec![
            AccountMeta::new(o.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(p, false),
        ],
        &[&o],
    );
    assert!(rc.is_ok(), "convert backed pnl should succeed: {:?}", rc);
    let cap_after_convert = env.portfolio_state(p).capital.get();
    assert_eq!(
        cap_after_convert,
        DEP + BACK,
        "capital == deposit + the backed portion (exactly)"
    );

    // (2) withdraw the full converted capital (account is flat — no open position).
    env.svm.expire_blockhash();
    let dest = env.withdraw(&o, p, DEP + BACK);
    let out = env.token_amount(dest) as u128;

    // EXTRACTION BOUND: the winner pulled EXACTLY deposit + backing, never more.
    assert_eq!(
        out,
        DEP + BACK,
        "winner extracts exactly deposit + backed pnl, not a unit more"
    );
    let pf = env.portfolio_state(p);
    let g = env.market_state().1;
    assert_eq!(pf.capital.get(), 0, "winner fully withdrawn");
    assert_eq!(
        g.vault, 0,
        "vault drained to exactly the funded amount (deposit + LP backing), no residual mint"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — liquidation cranker reward bounded by the fee (#3): with a NONZERO liquidation
// fee configured, a cranker is paid cranker_share_bps of the fee. Attacker goal: self-liquidate (control
// both the liquidated account AND the cranker) to net-profit, i.e. cranker reward > fee paid. Protection:
// reward == cranker_share% of the fee (≤ fee), the fee is internal (vault unminted), and the remainder
// goes to insurance — so a self-liquidator nets ≤ 0 (here −fee + 50%·fee < 0). First BPF test to drive a
// nonzero liquidation_fee_bps (via production_risk_params, which satisfies the engine solvency envelope).
#[test]
fn v16_attack_liquidation_cranker_reward_bounded_by_fee() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000); // cranker share = 50%
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    let co = Keypair::new();
    let c = env.create_portfolio(&co); // cranker (could be a self-liquidator)
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000); // ~2x the 5% IM -> insolvent on a modest move
    env.deposit(&co, c, 1_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    let c0 = env.portfolio_state(c).capital.get();
    let (_, g0) = env.market_state();

    // liquidate the insolvent short, crediting the cranker portfolio.
    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(co.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&co],
    );
    assert!(r.is_ok(), "liquidation with a fee should proceed: {:?}", r);
    let (_, g1) = env.market_state();
    let cranker_reward = env.portfolio_state(c).capital.get() as i128 - c0 as i128;
    let ins_delta = g1.insurance as i128 - g0.insurance as i128;
    let total_fee = cranker_reward + ins_delta;

    // non-vacuity: a real liquidation fee was charged and the cranker got a real reward.
    assert!(
        cranker_reward > 0,
        "cranker received a reward (non-vacuous), got {}",
        cranker_reward
    );
    assert!(total_fee > 0, "a liquidation fee was charged");
    // BOUND: the reward never exceeds the fee, and at 50% share it is exactly half (rest to insurance).
    assert!(
        cranker_reward <= total_fee,
        "cranker reward must not exceed the fee (no profit beyond the fee)"
    );
    assert_eq!(
        cranker_reward, ins_delta,
        "50%% share: cranker reward == insurance share (exact split)"
    );
    assert!(
        cranker_reward < total_fee,
        "cranker gets < the full fee -> self-liquidation nets negative"
    );
    // NO MINT: the fee is internal (liquidated account -> cranker + insurance), vault unchanged.
    assert_eq!(g1.vault, g0.vault, "liquidation fee mints no vault tokens");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        g1.vault >= g1.c_tot + g1.insurance,
        "senior conservation through fee'd liquidation"
    );
}

// security.md sweep — liquidation cranker reward account aliasing (#3/#44): when cranker rewards are
// enabled, the optional reward portfolio must be distinct from the portfolio being liquidated. Otherwise
// a liquidated account could receive part of its own liquidation fee back in the same crank.
#[test]
fn v16_attack_liquidation_cranker_reward_cannot_alias_liquidated_account() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    let co = Keypair::new();
    let c = env.create_portfolio(&co);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000);
    env.deposit(&co, c, 1_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }

    let market_before = env.svm.get_account(&env.market).unwrap();
    let short_before = env.svm.get_account(&s).unwrap();
    let short_cap_before = env.portfolio_state(s).capital.get();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(so.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(s, false),
        ],
        &[&so],
    );
    assert!(
        rejected.is_err(),
        "liquidation reward portfolio must not alias the liquidated account"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "alias rejection leaves market byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&s).unwrap(),
        short_before,
        "alias rejection leaves liquidated account byte-identical"
    );
    assert_eq!(
        env.portfolio_state(s).capital.get(),
        short_cap_before,
        "no self-reward paid into the victim account"
    );

    env.svm.expire_blockhash();
    let rejected_market_reward = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(so.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(env.market, false),
        ],
        &[&so],
    );
    assert!(
        rejected_market_reward.is_err(),
        "liquidation reward portfolio must not alias the market slab"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "market-slab reward alias rejection leaves market byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&s).unwrap(),
        short_before,
        "market-slab reward alias rejection leaves liquidated account byte-identical"
    );

    let cranker_cap_before = env.portfolio_state(c).capital.get();
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(co.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&co],
    );
    assert!(
        accepted.is_ok(),
        "distinct reward portfolio liquidation succeeds: {:?}",
        accepted
    );
    assert!(
        env.portfolio_state(c).capital.get() > cranker_cap_before,
        "positive control: distinct cranker received a real reward"
    );
    let (_, group) = env.market_state();
    assert_eq!(
        group.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        group.vault >= group.c_tot + group.insurance,
        "senior conservation"
    );
}

// CU/DoS hardening: PermissionlessCrank must prove the target portfolio belongs to this market before
// it parses any supplied hybrid-oracle tail. The valid-target control reaches bogus oracle parsing;
// the foreign-market portfolio must fail as a provenance error first.
#[test]
fn v16_attack_crank_target_portfolio_rejects_before_oracle_tail_parse() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    set_test_clock(&mut env, 1, 100);
    let feed = [0xc7u8; 32];
    let initial_oracle = env.set_pyth_price_with_conf(&feed, 1_000_000, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed, [0u8; 32], [0u8; 32]],
        &[initial_oracle],
        1,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure hybrid oracle");

    let owner = Keypair::new();
    let valid_portfolio = env.create_portfolio(&owner);
    let foreign_owner = Keypair::new();
    let foreign_portfolio = Pubkey::new_unique();
    let mut foreign_data = vec![0u8; env.portfolio_account_len];
    state::init_portfolio_account_zero_copy(
        &mut foreign_data,
        Pubkey::new_unique().to_bytes(),
        foreign_portfolio.to_bytes(),
        foreign_owner.pubkey().to_bytes(),
        0,
        1,
    )
    .unwrap();
    env.svm
        .set_account(
            foreign_portfolio,
            Account {
                lamports: 1_000_000_000,
                data: foreign_data,
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let bogus_oracle = env.program_account(8);

    let send = |env: &mut V16CuEnv, portfolio: Pubkey| {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(portfolio, false),
                AccountMeta::new_readonly(bogus_oracle, false),
            ],
            &[],
        )
    };

    set_test_clock(&mut env, 2, 101);
    let valid_err = send(&mut env, valid_portfolio)
        .expect_err("valid target portfolio should reach bogus oracle parsing");
    assert!(
        !valid_err.contains("Custom(16)"),
        "valid target must not trip the provenance preflight: {valid_err}"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let foreign_before = env.svm.get_account(&foreign_portfolio).unwrap();
    let invalid_err = send(&mut env, foreign_portfolio)
        .expect_err("foreign target portfolio must reject before oracle parsing");
    assert!(
        invalid_err.contains("Custom(16)"),
        "foreign target must fail as EngineProvenanceMismatch before bogus oracle parsing, got {invalid_err}"
    );
    assert!(
        !invalid_err.contains("Custom(29)") && !invalid_err.contains("IllegalOwner"),
        "foreign target must not reach the bogus oracle parser: {invalid_err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "pre-oracle target rejection leaves market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&foreign_portfolio).unwrap(),
        foreign_before,
        "pre-oracle target rejection leaves foreign portfolio bytes unchanged"
    );
}

// security.md sweep - liquidation cranker reward owner binding (#6/#35/#44): the optional reward
// portfolio is validated after the crank path has already refreshed oracle/profile state. A same-market
// reward portfolio owned by a different user must reject transaction-atomically, or any signer could
// mutate another user's portfolio by sending them liquidation rewards without authorization.
#[test]
fn v16_attack_liquidation_cranker_reward_rejects_wrong_owner() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    let co = Keypair::new();
    let c = env.create_portfolio(&co);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000);
    env.deposit(&co, c, 1_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    assert!(
        health_cert(&env.portfolio_state(s)).certified_liq_deficit != 0,
        "short is liquidatable before probing the reward-owner gate"
    );

    let wrong_owner = Keypair::new();
    env.ensure_signer_account(wrong_owner.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let short_before = env.svm.get_account(&s).unwrap();
    let cranker_before = env.svm.get_account(&c).unwrap();
    let cranker_cap_before = env.portfolio_state(c).capital.get();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(wrong_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&wrong_owner],
    );
    assert!(
        rejected.is_err(),
        "wrong signer must not direct a liquidation reward into another user's portfolio"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "wrong-owner reward rejection rolls back the pre-validation oracle/profile write"
    );
    assert_eq!(
        env.svm.get_account(&s).unwrap(),
        short_before,
        "wrong-owner reward rejection leaves the liquidated portfolio byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&c).unwrap(),
        cranker_before,
        "wrong-owner reward rejection does not mutate the cranker portfolio"
    );
    assert_eq!(
        env.portfolio_state(c).capital.get(),
        cranker_cap_before,
        "no unauthorized reward is credited"
    );

    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(co.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&co],
    );
    assert!(
        accepted.is_ok(),
        "the actual reward portfolio owner can still claim the cranker reward: {accepted:?}"
    );
    assert!(
        env.portfolio_state(c).capital.get() > cranker_cap_before,
        "positive control: the authorized cranker receives a real reward"
    );
}

// CU/DoS hardening: when liquidation rewards are enabled, a wrong-owner reward tail must reject
// before the crank parses a supplied external oracle tail. The authorized control below reaches the
// bogus oracle and fails there; the wrong-owner attempt must fail as Unauthorized first.
#[test]
fn v16_attack_liquidation_reward_wrong_owner_rejects_before_oracle_tail_parse() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    set_test_clock(&mut env, 1, 100);
    let feed = [0xb1u8; 32];
    let initial_oracle = env.set_pyth_price_with_conf(&feed, 1_000_000, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed, [0u8; 32], [0u8; 32]],
        &[initial_oracle],
        1,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure hybrid oracle");

    let victim_owner = Keypair::new();
    let victim = env.create_portfolio(&victim_owner);
    let reward_owner = Keypair::new();
    let reward = env.create_portfolio(&reward_owner);
    let wrong_owner = Keypair::new();
    env.ensure_signer_account(wrong_owner.pubkey());
    let bogus_oracle = env.program_account(8);

    set_test_clock(&mut env, 2, 101);
    let send = |env: &mut V16CuEnv, signer: &Keypair| {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: POS_SCALE,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(signer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(victim, false),
                AccountMeta::new_readonly(bogus_oracle, false),
                AccountMeta::new(reward, false),
            ],
            &[signer],
        )
    };

    let authorized_oracle_err = send(&mut env, &reward_owner)
        .expect_err("authorized reward owner should reach bogus oracle parsing");
    assert!(
        !authorized_oracle_err.contains("Custom(8)"),
        "authorized reward owner must not trip the reward-owner gate: {authorized_oracle_err}"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let victim_before = env.svm.get_account(&victim).unwrap();
    let reward_before = env.svm.get_account(&reward).unwrap();
    let wrong_owner_err = send(&mut env, &wrong_owner)
        .expect_err("wrong reward owner must reject before oracle parsing");
    assert!(
        wrong_owner_err.contains("Custom(8)"),
        "wrong reward owner must fail as Unauthorized before bogus oracle parsing, got {wrong_owner_err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "wrong-owner preflight leaves market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&victim).unwrap(),
        victim_before,
        "wrong-owner preflight leaves victim bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&reward).unwrap(),
        reward_before,
        "wrong-owner preflight leaves reward bytes unchanged"
    );
}

// CU/DoS hardening: a reward-tail portfolio can have a valid wrapper header and signer binding
// while its embedded engine layout is stale. The optional reward preflight must reject that account
// before parsing the oracle tail or mutating the target/liquidation state.
#[test]
fn v16_attack_liquidation_reward_stale_layout_rejects_before_oracle_tail_parse() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    set_test_clock(&mut env, 1, 100);
    let feed = [0xb2u8; 32];
    let initial_oracle = env.set_pyth_price_with_conf(&feed, 1_000_000, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed, [0u8; 32], [0u8; 32]],
        &[initial_oracle],
        1,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure hybrid oracle");

    let victim_owner = Keypair::new();
    let victim = env.create_portfolio(&victim_owner);
    let reward_owner = Keypair::new();
    let reward = env.create_portfolio(&reward_owner);
    let bogus_oracle = env.program_account(8);

    set_test_clock(&mut env, 2, 101);
    let send = |env: &mut V16CuEnv| {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: POS_SCALE,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(reward_owner.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(victim, false),
                AccountMeta::new_readonly(bogus_oracle, false),
                AccountMeta::new(reward, false),
            ],
            &[&reward_owner],
        )
    };

    let authorized_oracle_err =
        send(&mut env).expect_err("fresh reward account should reach bogus oracle parsing");
    assert!(
        !authorized_oracle_err.contains("InvalidAccountData"),
        "fresh reward account must not trip account-data provenance before oracle parsing: {authorized_oracle_err}"
    );

    let mut reward_account = env.svm.get_account(&reward).unwrap();
    let mut reward_state = state::read_portfolio(&reward_account.data).unwrap();
    let current_layout = reward_state.provenance_header.layout_discriminator.get();
    assert!(
        current_layout > 0,
        "current engine layout discriminator is nonzero"
    );
    reward_state.provenance_header =
        percolator::ProvenanceHeaderV16Account::from_runtime(&percolator::ProvenanceHeaderV16 {
            market_group_id: reward_state.provenance_header.market_group_id,
            portfolio_account_id: reward_state.provenance_header.portfolio_account_id,
            owner: reward_state.provenance_header.owner,
            version: reward_state.provenance_header.version.get(),
            layout_discriminator: current_layout - 1,
        });
    state::write_portfolio(&mut reward_account.data, &reward_state).unwrap();
    env.svm.set_account(reward, reward_account).unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let victim_before = env.svm.get_account(&victim).unwrap();
    let reward_before = env.svm.get_account(&reward).unwrap();
    let stale_layout_err =
        send(&mut env).expect_err("stale-layout reward account must reject before oracle parsing");
    assert!(
        stale_layout_err.contains("InvalidAccountData"),
        "stale reward layout should fail in reward-account preflight, got {stale_layout_err}"
    );
    assert!(
        !stale_layout_err.contains("Custom(29)") && !stale_layout_err.contains("IllegalOwner"),
        "stale reward layout must not reach the bogus oracle parser: {stale_layout_err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "stale-layout reward preflight leaves market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&victim).unwrap(),
        victim_before,
        "stale-layout reward preflight leaves victim bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&reward).unwrap(),
        reward_before,
        "stale-layout reward preflight leaves reward bytes unchanged"
    );
}

// security.md sweep - liquidation reward legacy realloc rollback (#5/#6/#35/#44):
// the reward tail is detected before the crank path refreshes oracle/profile state, and a legacy-sized
// reward portfolio is grown before the later owner/provenance validation. A wrong signer must roll back
// that pre-validation realloc as well as the oracle write, liquidation mutation, and reward credit.
#[test]
fn v16_attack_liquidation_wrong_owner_rolls_back_legacy_reward_realloc() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    let co = Keypair::new();
    let c = env.create_portfolio(&co);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    assert!(
        health_cert(&env.portfolio_state(s)).certified_liq_deficit != 0,
        "short is liquidatable before probing the legacy reward rollback"
    );

    let cranker_cap_before = env.portfolio_state(c).capital.get();
    let mut legacy_cranker = env.svm.get_account(&c).unwrap();
    legacy_cranker.data.truncate(PORTFOLIO_ENGINE_ACCOUNT_LEN);
    env.svm.set_account(c, legacy_cranker).unwrap();
    let cranker_before = env.svm.get_account(&c).unwrap();
    assert_eq!(
        cranker_before.data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "test setup uses a legacy reward portfolio"
    );

    let wrong_owner = Keypair::new();
    env.ensure_signer_account(wrong_owner.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let short_before = env.svm.get_account(&s).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(wrong_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&wrong_owner],
    );
    assert!(
        rejected.is_err(),
        "wrong signer must not grow or credit another user's legacy reward portfolio"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "wrong-owner legacy reward rejection rolls back the pre-validation oracle/profile write"
    );
    assert_eq!(
        env.svm.get_account(&s).unwrap(),
        short_before,
        "wrong-owner legacy reward rejection leaves the liquidated portfolio byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&c).unwrap(),
        cranker_before,
        "wrong-owner legacy reward rejection rolls back reward-account realloc and bytes"
    );
    assert_eq!(
        env.svm.get_account(&c).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "failed liquidation leaves the reward account legacy-sized"
    );

    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(co.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&co],
    );
    assert!(
        accepted.is_ok(),
        "authorized owner can still grow the legacy reward account and claim the liquidation reward: {accepted:?}"
    );
    assert_eq!(
        env.svm.get_account(&c).unwrap().data.len(),
        env.portfolio_account_len,
        "successful retry grows the legacy reward portfolio"
    );
    assert!(
        env.portfolio_state(c).capital.get() > cranker_cap_before,
        "authorized retry credits a real cranker reward"
    );
}

// security.md sweep — liquidation cranker reward market binding (#3/#44): when cranker rewards are
// enabled, the reward portfolio must belong to the same market as the liquidated account. A foreign
// market portfolio can otherwise try to receive value from this market's insurance while validating under
// different market provenance. Rejection must be atomic; a same-market cranker remains the positive path.
#[test]
fn v16_attack_liquidation_rejects_cross_market_cranker_reward() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    assert!(
        health_cert(&env.portfolio_state(s)).certified_liq_deficit != 0,
        "short is liquidatable before the reward-account substitution attempt"
    );

    let market_b = Pubkey::new_unique();
    env.svm
        .set_account(
            market_b,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; state::market_account_len_for_capacity(1).unwrap()],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let p = V16CuMarketParams::default();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitMarket {
            max_portfolio_assets: p.max_portfolio_assets,
            h_min: p.h_min,
            h_max: p.h_max,
            initial_price: p.initial_price,
            min_nonzero_mm_req: p.min_nonzero_mm_req,
            min_nonzero_im_req: p.min_nonzero_im_req,
            maintenance_margin_bps: p.maintenance_margin_bps,
            initial_margin_bps: p.initial_margin_bps,
            max_trading_fee_bps: p.max_trading_fee_bps,
            trade_fee_base_bps: p.trade_fee_base_bps,
            liquidation_fee_bps: p.liquidation_fee_bps,
            liquidation_fee_cap: p.liquidation_fee_cap,
            min_liquidation_abs: p.min_liquidation_abs,
            max_price_move_bps_per_slot: p.max_price_move_bps_per_slot,
            max_accrual_dt_slots: p.max_accrual_dt_slots,
            max_abs_funding_e9_per_slot: p.max_abs_funding_e9_per_slot,
            min_funding_lifetime_slots: p.min_funding_lifetime_slots,
            max_account_b_settlement_chunks: p.max_account_b_settlement_chunks,
            max_bankrupt_close_chunks: p.max_bankrupt_close_chunks,
            max_bankrupt_close_lifetime_slots: p.max_bankrupt_close_lifetime_slots,
            public_b_chunk_atoms: p.public_b_chunk_atoms,
            maintenance_fee_per_slot: p.maintenance_fee_per_slot,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new_readonly(env.mint, false),
        ],
        &[&env.admin],
    )
    .expect("init market B");

    let foreign_owner = Keypair::new();
    env.ensure_signer_account(foreign_owner.pubkey());
    let foreign_cranker = Pubkey::new_unique();
    env.svm
        .set_account(
            foreign_cranker,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; env.portfolio_account_len],
                owner: env.program_id,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::InitPortfolio,
        vec![
            AccountMeta::new(foreign_owner.pubkey(), true),
            AccountMeta::new(market_b, false),
            AccountMeta::new(foreign_cranker, false),
        ],
        &[&foreign_owner],
    )
    .expect("init foreign cranker portfolio on market B");

    let market_a_before = env.svm.get_account(&env.market).unwrap();
    let market_b_before = env.svm.get_account(&market_b).unwrap();
    let short_before = env.svm.get_account(&s).unwrap();
    let foreign_before = env.svm.get_account(&foreign_cranker).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(foreign_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(foreign_cranker, false),
        ],
        &[&foreign_owner],
    );
    assert!(
        rejected.is_err(),
        "foreign-market cranker reward portfolio must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_a_before,
        "cross-market reward rejection leaves market A byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&market_b).unwrap(),
        market_b_before,
        "cross-market reward rejection leaves market B byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&s).unwrap(),
        short_before,
        "cross-market reward rejection leaves the liquidated account byte-identical"
    );
    assert_eq!(
        env.svm.get_account(&foreign_cranker).unwrap(),
        foreign_before,
        "cross-market reward rejection does not credit the foreign cranker"
    );

    let local_cranker = env.create_portfolio(&foreign_owner);
    let local_cap_before = env.portfolio_state(local_cranker).capital.get();
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(foreign_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(local_cranker, false),
        ],
        &[&foreign_owner],
    );
    assert!(
        accepted.is_ok(),
        "same-market cranker reward liquidation still succeeds: {:?}",
        accepted
    );
    assert!(
        env.portfolio_state(local_cranker).capital.get() > local_cap_before,
        "positive control: same-market cranker receives a real reward"
    );
    let (_, group) = env.market_state();
    assert_eq!(
        group.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        group.vault >= group.c_tot + group.insurance,
        "senior conservation"
    );
}

// security.md sweep — liquidation fee is bounded by liquidation_fee_cap (#3/#33): the liquidation fee is
// min(liquidation_fee_bps * notional, liquidation_fee_cap). Attacker/edge goal: a large liquidation
// charges an unbounded fee (bps*notional) draining the victim / over-feeding insurance+cranker past the
// configured cap. Protection: the total fee (cranker + insurance) never exceeds liquidation_fee_cap.
#[test]
fn v16_attack_liquidation_fee_capped() {
    const CAP: u128 = 100;
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        liquidation_fee_cap: CAP, // tiny cap; 5bps * ~1e6 notional would be ~535 uncapped
        ..production_risk_params()
    });
    env.update_liquidation_fee_policy_with_cu(5_000);
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    let co = Keypair::new();
    let c = env.create_portfolio(&co);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000);
    env.deposit(&co, c, 1_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    let c0 = env.portfolio_state(c).capital.get();
    let (_, g0) = env.market_state();

    env.svm.expire_blockhash();
    let r = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(co.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(s, false),
            AccountMeta::new(c, false),
        ],
        &[&co],
    );
    assert!(r.is_ok(), "liquidation should proceed: {:?}", r);
    let (_, g1) = env.market_state();
    let cranker_reward = (env.portfolio_state(c).capital.get() as i128 - c0 as i128) as u128;
    let ins_delta = (g1.insurance as i128 - g0.insurance as i128) as u128;
    let total_fee = cranker_reward + ins_delta;

    // CAP: the total liquidation fee is bounded by liquidation_fee_cap — NOT the uncapped bps*notional.
    assert!(total_fee > 0, "a fee was charged (non-vacuous)");
    assert!(
        total_fee <= CAP,
        "total liquidation fee {} must be capped at liquidation_fee_cap {}",
        total_fee,
        CAP
    );
    // the cap actually bit: 5bps of ~1e6 notional (~535) would have exceeded CAP=100 absent the cap.
    assert_eq!(
        total_fee, CAP,
        "the fee is the cap exactly (uncapped fee would be ~535 >> 100)"
    );
    assert_eq!(g1.vault, g0.vault, "fee is internal, no vault mint");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

#[test]
fn v16_attack_insurance_covered_liquidation_does_not_strand_empty_portfolio() {
    const SHORT_CAP: u128 = 55_000;
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(0);
    env.top_up_insurance(1_000_000);
    env.configure_auth_mark_with_cu(0, 1_000_000);

    let long_owner = Keypair::new();
    let long = env.create_portfolio(&long_owner);
    let short_owner = Keypair::new();
    let short = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long, 100_000_000);
    env.deposit(&short_owner, short, SHORT_CAP);
    env.trade_asset_with_cu(
        0,
        &long_owner,
        long,
        &short_owner,
        short,
        POS_SCALE as i128,
        1_000_000,
        0,
    );

    for slot in 1..=40u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 1_070_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(short, false),
            ],
            &[],
        );
    }

    env.crank(
        short,
        ProgInstruction::PermissionlessCrank {
            now_slot: 40,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    let short_after = env.portfolio_state(short);
    let ledger = close_progress(&short_after);
    assert_eq!(short_after.capital.get(), 0);
    assert_eq!(short_after.pnl.get(), 0);
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&short_after)),
        "full liquidation leaves the loser flat"
    );
    assert!(
        ledger.finalized && ledger.residual_remaining == 0,
        "probe must exercise the insurance-covered finalized close ledger"
    );

    let close_cu = env.close_portfolio_with_cu(&short_owner, short);
    assert_cu_within(
        "ClosePortfolio after insurance-covered liquidation",
        close_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.market_state().1.materialized_portfolio_count,
        1,
        "only the long counterparty remains materialized"
    );
}

// security.md sweep — repeated partial-liquidation fee stop (#3/#33): the liquidation fee is charged
// only for an engine-selected liquidation. Attacker/cranker goal: keep resubmitting the same partial
// close hint after the first liquidation restored health, charging the victim over and over. Protection:
// the first selected liquidation charges a fee; the second no-longer-liquidatable crank charges zero.
#[test]
fn v16_attack_repeated_partial_liquidation_stops_charging_after_health_restored() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(0); // all fee to insurance (clean single accumulator)
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 200_000); // enough to open 2*POS_SCALE at 5% IM, then go insolvent
    env.trade_asset_with_cu(0, &lo, l, &so, s, (2 * POS_SCALE) as i128, 1_000_000, 0);
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    // mark is now fixed (no further pushes). Liquidate in two equal POS_SCALE partials.
    let liq = |env: &mut V16CuEnv| -> u128 {
        let ins0 = env.market_state().1.insurance;
        env.crank(
            s,
            ProgInstruction::PermissionlessCrank {
                now_slot: 30,
                close_q: POS_SCALE,
                observations: crank_observations(0),
            },
        );
        env.market_state().1.insurance - ins0
    };
    let fee1 = liq(&mut env);
    let fee2 = liq(&mut env);

    // STOP: a real first liquidation charged a fee, but replaying the same close hint after the
    // account is no longer liquidatable cannot charge a second liquidation fee.
    assert!(
        fee1 > 0,
        "first partial charges a fee (non-vacuous), fee1={}",
        fee1
    );
    assert_eq!(
        fee2, 0,
        "second no-longer-liquidatable close hint charges no fee (fee1={} fee2={})",
        fee1, fee2
    );
    let g = env.market_state().1;
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
}

// security.md sweep — leveraged bad-debt socialization (#9/#22/#33): at 20x leverage (5% margin) a
// thin-margin short's loss can EXCEED its capital, creating bad debt. Attacker goal: the loser's
// unrecovered deficit is printed as the winner's spendable gain (vault mint / senior over-pay).
// Protection: the loser's capital floors at 0 (loss capped at capital), the unrecovered deficit is
// absorbed as un-backed junior pnl on the winner side (not minted), and the vault is never inflated.
#[test]
fn v16_attack_leveraged_bad_debt_socialized_not_printed() {
    const SHORT_CAP: u128 = 55_000; // ~10% above the 50_000 (5% of 1e6) initial margin
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(0);
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, SHORT_CAP);
    let total_deposits = 100_000_000u128 + SHORT_CAP;
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0);
    assert_eq!(
        env.market_state().1.vault,
        total_deposits,
        "vault == total deposits at open"
    );

    // drive the mark to 1.07e6: short loss ≈ 70_000 > its 55_000 capital -> 15_000 bad debt.
    for slot in 1..=40u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 1_070_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    // NON-VACUITY: the short is insolvent — its capital was fully consumed by the loss.
    assert_eq!(
        env.portfolio_state(s).capital.get(),
        0,
        "short capital wiped to 0 by the loss (bad debt exists)"
    );

    // liquidate the insolvent short.
    let (_, g_pre) = env.market_state();
    env.crank(
        s,
        ProgInstruction::PermissionlessCrank {
            now_slot: 40,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
    );
    let (_, g) = env.market_state();

    // NO MINT: the unrecovered bad debt is NOT printed — vault stays == total deposits the whole way.
    assert_eq!(
        g.vault, total_deposits,
        "vault never inflated by the bad debt (no mint)"
    );
    assert_eq!(
        g.vault, g_pre.vault,
        "liquidation of the insolvent short mints nothing"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    // short capital still 0 (never negative); senior conservation preserved through the bad-debt event.
    assert_eq!(
        env.portfolio_state(s).capital.get(),
        0,
        "short capital floored at 0 (never negative)"
    );
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation under leveraged bad debt"
    );
    // the winner's gain that exceeds the recoverable backing is un-backed junior pnl (residual-bounded),
    // not spendable senior capital -> the bad debt is socialized, not paid out.
    let lw = env.portfolio_state(l);
    let residual = g.vault.saturating_sub(g.c_tot).saturating_sub(g.insurance);
    assert!(
        (health_cert(&lw).certified_equity as u128) <= lw.capital.get() + residual + 1,
        "winner realizable bounded by capital+residual (bad debt not realizable)"
    );
}

// security.md sweep — dust-position margin floor (#9/#22): the per-leg initial margin requirement is
// floored at min_nonzero_im_req for any nonzero position. Attacker goal: open a tiny position whose
// proportional IM (bps * tiny notional) rounds below the floor, getting near-free leverage / a position
// that evades meaningful margin. Protection: certified_initial_req >= min_nonzero_im_req for a live leg.
#[test]
fn v16_attack_dust_position_margin_floored() {
    // production_risk_params: initial_margin_bps=500 (5%), min_nonzero_im_req=600.
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let xo = Keypair::new();
    let x = env.create_portfolio(&xo);
    let yo = Keypair::new();
    let y = env.create_portfolio(&yo);
    env.deposit(&xo, x, 1_000_000);
    env.deposit(&yo, y, 1_000_000);

    // a DUST position: size POS_SCALE/1000 -> notional ~1000 -> proportional IM (5%) ~50, BELOW the 600 floor.
    let dust = (POS_SCALE / 1_000) as i128;
    assert!(dust > 0, "dust size is nonzero");
    env.trade_asset_with_cu(0, &xo, x, &yo, y, dust, 1_000_000, 0);

    let xs = env.portfolio_state(x);
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&xs)),
        1,
        "dust position opened"
    );
    let req = health_cert(&xs).certified_initial_req;
    // FLOOR: the requirement is the min_nonzero_im_req floor (600), NOT the tiny proportional ~50.
    assert!(
        req >= 600,
        "dust-position initial margin floored at min_nonzero_im_req (600), got {}",
        req
    );
    // sanity: the floor is well above the naive proportional IM for this dust notional (~50).
    assert!(
        req > 50,
        "floor strictly exceeds the proportional dust IM (no near-free leverage)"
    );

    let g = env.market_state().1;
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// security.md sweep — IM/MM margin-gap zone (#9/#19/#46): with IM(100%) > MM(50%) a position whose
// equity sits BETWEEN the maintenance and initial requirements must be (a) NOT liquidatable (equity >
// maint_req) yet (b) UNABLE to increase risk (equity < init_req). Attacker goals: liquidate a healthy
// in-gap account to skim a fee/grief it, OR add risk while under-margined for it. Both must be blocked.
#[test]
fn v16_attack_margin_gap_zone_no_liq_no_risk_increase() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 5_000, 10_000, 1_000); // MM=50%, IM=100%
    env.configure_auth_mark_with_cu(0, 100);
    let xo = Keypair::new();
    let x = env.create_portfolio(&xo);
    let yo = Keypair::new();
    let y = env.create_portfolio(&yo);
    env.deposit(&xo, x, 100);
    env.deposit(&yo, y, 1_000_000);
    env.trade_asset_with_cu(0, &xo, x, &yo, y, -(POS_SCALE as i128), 100, 0); // x SHORT POS_SCALE
    let basis0 = env.portfolio_state(x).legs[0].basis_pos_q.get();
    assert!(basis0 != 0, "x opened a short");

    // move the mark up so x's requirements land between MM and IM (the gap).
    env.svm.warp_to_slot(2);
    env.push_auth_mark_with_cu(2, 110);
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(x, false),
        ],
        &[],
    );
    let xs = env.portfolio_state(x);
    let eq = health_cert(&xs).certified_equity;
    let mreq = health_cert(&xs).certified_maintenance_req as i128;
    let ireq = health_cert(&xs).certified_initial_req as i128;
    // precondition: equity is strictly inside the gap (MM < equity < IM).
    assert!(
        eq > mreq,
        "above maintenance (not liquidatable): eq={} mreq={}",
        eq,
        mreq
    );
    assert!(
        eq < ireq,
        "below initial (cannot add risk): eq={} ireq={}",
        eq,
        ireq
    );
    assert_eq!(
        health_cert(&xs).certified_liq_deficit,
        0,
        "no liquidation deficit in the gap"
    );

    // ATTACK (a): liquidate the in-gap (healthy) account -> must be a no-op (position intact).
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: POS_SCALE,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(x, false),
        ],
        &[],
    );
    assert_eq!(
        env.portfolio_state(x).legs[0].basis_pos_q.get(),
        basis0,
        "in-gap account NOT liquidated (position intact)"
    );

    // ATTACK (b): grow the short (increase risk) while in the gap -> must reject (equity < IM req).
    env.svm.expire_blockhash();
    let r = env.try_trade_asset_with_cu(0, &xo, x, &yo, y, -(POS_SCALE as i128), 110, 0);
    assert!(
        r.is_err(),
        "risk increase in the margin gap must reject (under-margined for IM)"
    );
    assert_eq!(
        env.portfolio_state(x).legs[0].basis_pos_q.get(),
        basis0,
        "position unchanged by rejected risk increase"
    );

    let g = env.market_state().1;
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// security.md sweep — dust-position MAINTENANCE floor (#9/#19): the per-leg maintenance requirement is
// floored at min_nonzero_mm_req for any nonzero leg (the liquidation-threshold counterpart to the IM
// floor in #161). Attacker goal: a dust position whose proportional maintenance margin (bps*tiny
// notional) rounds near 0 becomes effectively un-liquidatable (it never breaches a ~0 maintenance req).
// Protection: certified_maintenance_req >= min_nonzero_mm_req for a live leg.
#[test]
fn v16_attack_dust_position_maintenance_floored() {
    // production_risk_params: maintenance_margin_bps=500 (5%), min_nonzero_mm_req=599.
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let xo = Keypair::new();
    let x = env.create_portfolio(&xo);
    let yo = Keypair::new();
    let y = env.create_portfolio(&yo);
    env.deposit(&xo, x, 1_000_000);
    env.deposit(&yo, y, 1_000_000);
    let dust = (POS_SCALE / 1_000) as i128; // notional ~1000 -> proportional MM (5%) ~25
    env.trade_asset_with_cu(0, &xo, x, &yo, y, dust, 1_000_000, 0);

    let xs = env.portfolio_state(x);
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&xs)),
        1,
        "dust position opened"
    );
    let mreq = health_cert(&xs).certified_maintenance_req;
    // FLOOR: maintenance req is the min_nonzero_mm_req floor (599), not the proportional ~25.
    assert!(
        mreq >= 599,
        "dust maintenance req floored at min_nonzero_mm_req (599), got {}",
        mreq
    );
    assert!(
        mreq > 25,
        "floor strictly exceeds the proportional dust MM (no liquidation-immune dust)"
    );
    // and the maintenance floor is below the initial floor (a real gap remains for the dust leg).
    assert!(
        mreq <= health_cert(&xs).certified_initial_req,
        "maint floor <= initial floor"
    );

    let g = env.market_state().1;
    assert!(g.vault >= g.c_tot + g.insurance, "senior conservation");
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// security.md sweep — multi-asset cross-margin netting conservation (#9/#22 interaction): a portfolio
// holding a GAINING leg on asset 0 and a LOSING leg on asset 1 nets the two in equity (one offsets the
// other) while the requirement stays GROSS. Attacker goal: a simultaneous gain+loss across assets mints
// vault value or under-collateralizes the portfolio. Protection: price moves mint nothing (vault is
// byte-stable == deposits), the portfolio stays solvent, and senior conservation holds.
#[test]
fn v16_attack_cross_margin_netting_conserves() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_with_cu(0, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    let xo = Keypair::new();
    let x = env.create_portfolio(&xo);
    let y0o = Keypair::new();
    let y0 = env.create_portfolio(&y0o);
    let y1o = Keypair::new();
    let y1 = env.create_portfolio(&y1o);
    env.deposit(&xo, x, 10_000);
    env.deposit(&y0o, y0, 1_000_000);
    env.deposit(&y1o, y1, 1_000_000);
    let total_deposits = 10_000u128 + 1_000_000 + 1_000_000;
    env.trade_asset_with_cu(0, &xo, x, &y0o, y0, POS_SCALE as i128, 100, 0); // x LONG asset0
    env.trade_asset_with_cu(1, &xo, x, &y1o, y1, -(POS_SCALE as i128), 100, 0); // x SHORT asset1
    assert_eq!(
        env.market_state().1.vault,
        total_deposits,
        "vault == deposits at open"
    );

    // asset0 UP -> x's long GAINS; asset1 UP -> x's short LOSES (offsetting legs).
    let admin = env.admin.insecure_clone();
    env.svm.warp_to_slot(2);
    let _ = env.push_auth_mark_with_cu(2, 110);
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PushAuthMark {
            asset_index: 1,
            now_slot: 2,
            mark_e6: 110,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    for ai in [0u16, 1] {
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(ai),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(x, false),
            ],
            &[],
        );
    }

    let xs = env.portfolio_state(x);
    let g = env.market_state().1;
    // both legs live, requirement gross (covers both); portfolio solvent (equity covers maintenance).
    assert_eq!(
        percolator::active_bitmap_count_ones(active_bitmap(&xs)),
        2,
        "x holds both legs"
    );
    assert!(health_cert(&xs).valid, "x cert valid");
    assert!(
        health_cert(&xs).certified_equity >= health_cert(&xs).certified_maintenance_req as i128,
        "x solvent (equity >= maint req)"
    );
    assert!(
        g.assets[0].effective_price > 100 && g.assets[1].effective_price > 100,
        "both marks moved (non-vacuous)"
    );
    // NO MINT: the simultaneous gain+loss across assets nets internally — vault is byte-stable == deposits.
    assert_eq!(
        g.vault, total_deposits,
        "cross-asset gain+loss mints no vault value"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation across cross-margin netting"
    );
}

// security.md sweep — over-liquidation close_q clamps the FEE too (#3/#19): the liquidation fee is
// bps * CLOSED notional. A cranker passing close_q >> the position is clamped to the position size
// (#9376), but the FEE must be charged on the actually-closed amount, not the inflated close_q.
// Attacker goal: pass a giant close_q to extract a fee far larger than the position warrants.
#[test]
fn v16_attack_over_liquidation_fee_clamped_to_position() {
    let mut env = V16CuEnv::new_with_init_params(production_risk_params());
    env.update_liquidation_fee_policy_with_cu(0); // all to insurance
    env.configure_auth_mark_with_cu(0, 1_000_000);
    let lo = Keypair::new();
    let l = env.create_portfolio(&lo);
    let so = Keypair::new();
    let s = env.create_portfolio(&so);
    env.deposit(&lo, l, 100_000_000);
    env.deposit(&so, s, 100_000);
    env.trade_asset_with_cu(0, &lo, l, &so, s, POS_SCALE as i128, 1_000_000, 0); // POS_SCALE position only
    for slot in 1..=30u64 {
        env.svm.warp_to_slot(slot);
        let _ = env.push_auth_mark_with_cu(slot, 2_000_000);
        env.svm.expire_blockhash();
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(s, false),
            ],
            &[],
        );
    }
    let (_, g0) = env.market_state();

    // ATTACK: liquidate with close_q = 1000x the actual POS_SCALE position to inflate the fee.
    env.crank(
        s,
        ProgInstruction::PermissionlessCrank {
            now_slot: 30,
            close_q: 1_000 * POS_SCALE,
            observations: crank_observations(0),
        },
    );
    let (_, g1) = env.market_state();
    let fee = g1.insurance - g0.insurance;

    // CLAMP: the fee is on the actual POS_SCALE closed (~535 = 5bps * ~1.07e6), NOT 1000x that (~535_000).
    assert!(fee > 0, "a fee was charged (non-vacuous)");
    assert!(fee < 10_000, "fee {} reflects the ACTUAL closed POS_SCALE (~535), not the inflated 1000x close_q (~535_000)", fee);
    // the position is fully closed (clamped to the actual size), not over-closed into a phantom.
    let sl = env.portfolio_state(s);
    assert!(
        sl.legs[0].basis_pos_q.get().unsigned_abs() <= POS_SCALE,
        "position closed at most to its actual size (no phantom over-close)"
    );
    assert_eq!(g1.vault, g0.vault, "fee internal, no vault mint");
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
    assert!(g1.vault >= g1.c_tot + g1.insurance, "senior conservation");
}

// security.md sweep — TradeCpi short-fill is atomic / rejected (#22/#33): a matcher capped at
// max_fill_abs below the requested size cannot fully fill. Attacker goal: a short-filling matcher leaves
// the taker with an unexpected partial position (phantom OI / under-fill) while the trade still
// "succeeds". Protection: the trade is ATOMIC — a matcher that can't fill the requested size causes the
// whole TradeCpi to REJECT, leaving both accounts position-free and the book unchanged.
#[test]
fn v16_attack_tradecpi_short_fill_rejects_atomically() {
    let mut env = V16CuEnv::new();
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let taker_owner = Keypair::new();
    let maker_owner = Keypair::new();
    let taker_account = env.create_portfolio(&taker_owner);
    let maker_account = env.create_portfolio(&maker_owner);
    env.deposit(&taker_owner, taker_account, 1_000_000);
    env.deposit(&maker_owner, maker_account, 1_000_000);

    // matcher capped at 5*POS_SCALE.
    let cap: u128 = 5 * POS_SCALE;
    let (matcher_ctx, matcher_delegate, _) = env.init_matcher_context_with_data_authorized(
        matcher_program,
        &maker_owner,
        maker_account,
        encode_matcher_init_passive(cap),
    );
    let (_, g0) = env.market_state();

    // ATTACK: request 10*POS_SCALE (> cap) -> the matcher can't fully fill -> trade REJECTS atomically.
    let r = env.try_trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker_account,
        &maker_owner,
        maker_account,
        matcher_program,
        matcher_ctx,
        matcher_delegate,
        0,
        (10 * POS_SCALE) as i128,
        100,
    );
    assert!(
        r.is_err(),
        "a matcher that can't fully fill must reject the whole trade (atomic)"
    );

    // ROLLBACK: no partial position created on either side; book and vault unchanged.
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(taker_account))),
        "taker has NO position (no partial fill)"
    );
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(maker_account))),
        "maker has NO position"
    );
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.assets[0].oi_eff_long_q, 0,
        "no OI created by the rejected short-fill"
    );
    assert_eq!(
        g1.insurance, g0.insurance,
        "no fee charged on a rejected trade"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged");

    // DISCRIMINATING CONTROL: a request WITHIN the cap (the exact cap) fills cleanly -> the rejection
    // above was specifically because of the short-fill, not some unrelated failure.
    let _ = env.trade_cpi_with_cu_on_asset(
        &taker_owner,
        taker_account,
        &maker_owner,
        maker_account,
        matcher_program,
        matcher_ctx,
        matcher_delegate,
        0,
        cap as i128,
        100,
    );
    let taker = env.portfolio_state(taker_account);
    assert_eq!(
        taker.legs[0].basis_pos_q.get(),
        cap as i128,
        "an at-cap request fills fully and cleanly"
    );
    let g = env.market_state().1;
    assert_eq!(
        g.c_tot + g.insurance,
        g.vault,
        "conservation after the successful in-cap fill"
    );
}

// security.md sweep — TradeCpi fee is mark-pinned, not matcher-quoted (F-TRADENOCPI-FEE, CPI path):
// handle_trade_cpi_zero_copy delegates to handle_trade_nocpi_zero_copy (src/v16_program.rs:6428) passing
// the matcher's exec_price_e6, and the F-TRADENOCPI-FEE fix there pins the fee BASIS to the asset mark
// (effective_price), NOT the passed exec_price. Attacker goal: a colluding/malicious matcher quotes a
// low exec_price to under-bill the CPI trade fee (the TradeNoCpi attack, on the CPI path). Protection:
// the fee is computed on the mark, so the matcher's price-quoting knobs (spread) cannot change the fee.
#[test]
fn v16_attack_tradecpi_fee_is_mark_pinned_not_matcher_quoted() {
    let fee_for_spread = |base_spread: u32, max_total: u32| -> u128 {
        let mut env = V16CuEnv::new();
        let matcher_program = Pubkey::new_unique();
        let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
        env.svm.add_program(matcher_program, &matcher_bytes);
        let to = Keypair::new();
        let t = env.create_portfolio(&to);
        let mo = Keypair::new();
        let m = env.create_portfolio(&mo);
        env.deposit(&to, t, 100_000_000);
        env.deposit(&mo, m, 100_000_000);
        let (ctx, del, _) = env.init_matcher_context_with_passive_spread_authorized(
            matcher_program,
            &mo,
            m,
            base_spread,
            max_total,
        );
        let ins0 = env.market_state().1.insurance;
        let _ = env.trade_cpi_with_cu_on_asset(
            &to,
            t,
            &mo,
            m,
            matcher_program,
            ctx,
            del,
            0,
            (10 * POS_SCALE) as i128,
            100,
        );
        // entry is at the mark (effective_price==100) regardless of the matcher's spread.
        assert_eq!(
            env.market_state().1.assets[0].effective_price,
            100,
            "position priced at the mark"
        );
        assert_eq!(
            env.portfolio_state(t).pnl.get(),
            0,
            "no off-market PnL from the matcher quote"
        );
        env.market_state().1.insurance - ins0
    };
    // fee at the mark (no spread): 10*POS_SCALE @ 100 = notional 1000 -> 100bps -> 10/side -> 20 total.
    let fee_no_spread = fee_for_spread(0, 100);
    assert_eq!(fee_no_spread, 20, "baseline CPI fee is the mark-based fee");
    // a WIDE matcher spread (20%) charges the IDENTICAL fee -> the fee is on the mark, NOT the matcher's
    // (potentially manipulated) exec_price. A malicious matcher cannot under-bill the CPI fee.
    assert_eq!(
        fee_for_spread(2_000, 4_000),
        fee_no_spread,
        "matcher spread does not change the CPI fee (mark-pinned)"
    );
    assert_eq!(
        fee_for_spread(500, 1_000),
        fee_no_spread,
        "fee invariant to a moderate spread too"
    );
}

// security.md sweep — TradeCpi enforces the MAKER's margin too (#9/#22): the matcher fills the taker
// against the maker (LP), who takes the opposite side. Attacker goal: a matcher opens a large position
// against an under-capitalized maker (the maker can't margin its leg), fabricating OI / bad debt on the
// maker side. Protection: the post-trade margin check covers BOTH sides, so an under-margined maker
// causes the whole TradeCpi to reject; a well-capitalized maker fills cleanly.
#[test]
fn v16_attack_tradecpi_enforces_maker_margin() {
    let mut env = V16CuEnv::new();
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let to = Keypair::new();
    let t = env.create_portfolio(&to);
    let mo = Keypair::new();
    let m = env.create_portfolio(&mo);
    env.deposit(&to, t, 100_000_000); // taker well funded
    env.deposit(&mo, m, 100); // maker thin: cannot margin a 10*POS_SCALE leg (IM=100% -> req 1000)
    let (ctx, del, _) = env.init_matcher_context_authorized(matcher_program, &mo, m);
    let (_, g0) = env.market_state();

    // ATTACK: 10*POS_SCALE fill -> the maker would owe IM ~1000 >> its 100 capital -> reject.
    env.svm.expire_blockhash();
    let r = env.try_trade_cpi_with_cu_on_asset(
        &to,
        t,
        &mo,
        m,
        matcher_program,
        ctx,
        del,
        0,
        (10 * POS_SCALE) as i128,
        100,
    );
    assert!(
        r.is_err(),
        "TradeCpi against an under-margined maker must reject"
    );

    // ROLLBACK: no position on either side, no OI, vault unchanged.
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(t))),
        "taker has no position"
    );
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&env.portfolio_state(m))),
        "maker has no position"
    );
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.assets[0].oi_eff_long_q, 0,
        "no OI fabricated against the thin maker"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged");

    // DISCRIMINATING CONTROL: top the maker up so it CAN margin the leg -> the same trade fills cleanly.
    env.deposit(&mo, m, 2_000_000);
    env.svm.expire_blockhash();
    let ok = env.try_trade_cpi_with_cu_on_asset(
        &to,
        t,
        &mo,
        m,
        matcher_program,
        ctx,
        del,
        0,
        (10 * POS_SCALE) as i128,
        100,
    );
    assert!(ok.is_ok(), "well-capitalized maker fills cleanly: {:?}", ok);
    assert_eq!(
        env.portfolio_state(m).legs[0].basis_pos_q.get(),
        -((10 * POS_SCALE) as i128),
        "maker took the opposite leg"
    );
    let g = env.market_state().1;
    assert_eq!(
        g.c_tot + g.insurance,
        g.vault,
        "conservation after the in-margin fill"
    );
}

// security.md sweep — matcher CPI cannot be handed protocol state (reentrancy, #22/#21): the accounts
// forwarded to the matcher CPI (tail = accounts[8..]) are validated to EXCLUDE the market, both
// portfolios, the program id, and ANY account owned by the percolator program (src/v16_program.rs:6308).
// Attacker goal: pass a percolator-owned account (market/portfolio) into the matcher tail so a malicious
// matcher can reenter and read/write protocol state mid-trade. Protection: any such tail account rejects.
#[test]
fn v16_attack_tradecpi_matcher_tail_cannot_carry_protocol_state() {
    let mut env = V16CuEnv::new();
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(matcher_program_path()).expect("read matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let to = Keypair::new();
    let t = env.create_portfolio(&to);
    let mo = Keypair::new();
    let m = env.create_portfolio(&mo);
    let vo = Keypair::new();
    let victim = env.create_portfolio(&vo); // a third, unrelated portfolio
    env.deposit(&to, t, 1_000_000);
    env.deposit(&mo, m, 1_000_000);
    env.deposit(&vo, victim, 1_000_000);
    let (ctx, del, _) = env.init_matcher_context_authorized(matcher_program, &mo, m);
    let (_, g0) = env.market_state();

    let market = env.market;
    let base = |extra: Pubkey| {
        vec![
            AccountMeta::new(to.pubkey(), true),
            AccountMeta::new(market, false),
            AccountMeta::new(t, false),
            AccountMeta::new(m, false),
            AccountMeta::new_readonly(matcher_program, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(del, false),
            AccountMeta::new(extra, false), // tail account[7] -> handed to the matcher CPI
        ]
    };
    let ix = |asset_index, size_q| ProgInstruction::TradeCpi {
        asset_index,
        size_q,
        fee_bps: 100,
        limit_price: 0,
    };

    // ATTACK 1: forward the MARKET account into the matcher tail -> reject.
    env.svm.expire_blockhash();
    let r1 = env.send(ix(0u16, (10 * POS_SCALE) as i128), base(market), &[&to]);
    assert!(
        r1.is_err(),
        "matcher tail carrying the market account must reject"
    );
    // ATTACK 2: forward a third (percolator-owned) portfolio into the tail -> reject (ai.owner == program).
    env.svm.expire_blockhash();
    let r2 = env.send(ix(0u16, (10 * POS_SCALE) as i128), base(victim), &[&to]);
    assert!(
        r2.is_err(),
        "matcher tail carrying a protocol-owned portfolio must reject"
    );

    // no state touched by either rejected attempt.
    let (_, g1) = env.market_state();
    assert_eq!(
        g1.assets[0].oi_eff_long_q, 0,
        "no OI from rejected reentrancy attempts"
    );
    assert_eq!(g1.vault, g0.vault, "vault unchanged");
    assert_eq!(
        env.portfolio_state(victim).capital.get(),
        1_000_000,
        "victim portfolio untouched"
    );
    // control: the SAME trade WITHOUT a poisoned tail fills cleanly.
    env.svm.expire_blockhash();
    let ok = env.try_trade_cpi_with_cu_on_asset(
        &to,
        t,
        &mo,
        m,
        matcher_program,
        ctx,
        del,
        0,
        (10 * POS_SCALE) as i128,
        100,
    );
    assert!(
        ok.is_ok(),
        "clean TradeCpi (no poisoned tail) executes: {:?}",
        ok
    );
}

// security.md sweep - matcher-tail signer isolation (#22/#44/#49): the tail forwarded to an
// external matcher must not include the taker wallet signer. If it does, a hostile matcher can use
// that signer privilege in a nested System Program transfer before returning an otherwise valid fill.
#[test]
fn v16_attack_tradecpi_matcher_tail_cannot_forward_taker_signer() {
    let mut env = V16CuEnv::new();
    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let taker_account = env.create_portfolio(&taker);
    let lp_account = env.create_portfolio(&lp);
    env.deposit(&taker, taker_account, 1_000_000);
    env.deposit(&lp, lp_account, 1_000_000);

    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &lp_account,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let mut ctx_data = vec![0u8; MATCHER_CONTEXT_LEN];
    ctx_data[0] = 14; // hostile mode: transfer lamports from tail[0] to tail[1], then return valid fill.
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: ctx_data,
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.set_matcher_config(hostile, &lp, lp_account, ctx, delegate, 1);

    let tail_signer = Keypair::new();
    env.svm
        .set_account(
            tail_signer.pubkey(),
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: solana_sdk::system_program::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let recipient = Pubkey::new_unique();
    env.svm
        .set_account(
            recipient,
            Account {
                lamports: 1,
                data: vec![],
                owner: solana_sdk::system_program::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&taker_account).unwrap();
    let lp_before = env.svm.get_account(&lp_account).unwrap();
    let ctx_before = env.svm.get_account(&ctx).unwrap();
    let tail_signer_before = env.svm.get_account(&tail_signer.pubkey()).unwrap();
    let recipient_before = env.svm.get_account(&recipient).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::TradeCpi {
            asset_index: 0,
            size_q: (5 * POS_SCALE) as i128,
            fee_bps: 100,
            limit_price: 0,
        },
        vec![
            AccountMeta::new(taker.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(taker_account, false),
            AccountMeta::new(lp_account, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(delegate, false),
            AccountMeta::new(tail_signer.pubkey(), true),
            AccountMeta::new(recipient, false),
            AccountMeta::new_readonly(solana_sdk::system_program::ID, false),
        ],
        &[&taker, &tail_signer],
    );
    let rejected_err = rejected
        .expect_err("TradeCpi must not forward any user signer into a hostile matcher tail");
    assert!(
        rejected_err.contains("Custom(9)") || rejected_err.contains("custom program error: 0x9"),
        "signer matcher tail must reject in wrapper preflight as InvalidInstruction, got {rejected_err}"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&taker_account).unwrap(), taker_before);
    assert_eq!(env.svm.get_account(&lp_account).unwrap(), lp_before);
    assert_eq!(env.svm.get_account(&ctx).unwrap(), ctx_before);
    assert_eq!(
        env.svm.get_account(&tail_signer.pubkey()).unwrap(),
        tail_signer_before,
        "rejected matcher-tail signer forwarding must not debit the tail signer"
    );
    assert_eq!(
        env.svm.get_account(&recipient).unwrap(),
        recipient_before,
        "hostile matcher must not receive lamports from the tail signer"
    );

    let mut honest_ctx = env.svm.get_account(&ctx).unwrap();
    honest_ctx.data[0] = 9;
    env.svm.set_account(ctx, honest_ctx).unwrap();
    env.svm.expire_blockhash();
    let ok = env.try_trade_cpi_with_cu_on_asset(
        &taker,
        taker_account,
        &lp,
        lp_account,
        hostile,
        ctx,
        delegate,
        0,
        (5 * POS_SCALE) as i128,
        100,
    );
    assert!(
        ok.is_ok(),
        "the same authorized hostile fixture fills when no wallet signer is forwarded: {ok:?}"
    );
}

// security.md sweep - BatchTradeCpi matcher-tail isolation (#9/#27): the batched CPI fill path also
// forwards optional remaining accounts to an external matcher. It must reject the market account and
// any Percolator-owned portfolio in that tail, then still accept a clean permissionless LP fill.
#[test]
fn v16_attack_batch_tradecpi_matcher_tail_cannot_carry_protocol_state() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(auth_matcher_program_path()).expect("read auth matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let taker = Keypair::new();
    let lp = Keypair::new();
    let victim_owner = Keypair::new();
    let taker_account = env.create_portfolio(&taker);
    let lp_account = env.create_portfolio(&lp);
    let victim = env.create_portfolio(&victim_owner);
    env.deposit(&taker, taker_account, 1_000_000);
    env.deposit(&lp, lp_account, 1_000_000);
    env.deposit(&victim_owner, victim, 1_000_000);
    let (ctx, delegate, _) = env.init_auth_matcher_context(matcher_program, &lp, lp_account);
    let before = env.market_state().1;
    let victim_before = env.portfolio_state(victim);
    let sz = (5 * POS_SCALE) as i128;
    let ix = ProgInstruction::BatchTradeCpi {
        legs: vec![
            BatchTradeCpiLeg {
                asset_index: 0,
                size_q: sz,
                fee_bps: 100,
                limit_price: 0,
            },
            BatchTradeCpiLeg {
                asset_index: 1,
                size_q: -sz,
                fee_bps: 100,
                limit_price: 0,
            },
        ],
    };
    let market = env.market;
    let taker_key = taker.pubkey();
    let base = |extra: Option<Pubkey>| {
        let mut metas = vec![
            AccountMeta::new(taker_key, true),
            AccountMeta::new(market, false),
            AccountMeta::new(taker_account, false),
            AccountMeta::new(lp_account, false),
            AccountMeta::new_readonly(matcher_program, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(delegate, false),
        ];
        if let Some(extra) = extra {
            metas.push(AccountMeta::new(extra, false));
        }
        metas
    };

    env.svm.expire_blockhash();
    let market_tail = env.send(ix.clone(), base(Some(market)), &[&taker]);
    assert!(
        market_tail.is_err(),
        "BatchTradeCpi matcher tail carrying the market account must reject"
    );
    env.svm.expire_blockhash();
    let portfolio_tail = env.send(ix.clone(), base(Some(victim)), &[&taker]);
    assert!(
        portfolio_tail.is_err(),
        "BatchTradeCpi matcher tail carrying any Percolator-owned portfolio must reject"
    );
    let after_reject = env.market_state().1;
    assert_eq!(
        after_reject.assets[0].oi_eff_long_q, 0,
        "no asset-0 OI from rejected tail poison"
    );
    assert_eq!(
        after_reject.assets[1].oi_eff_long_q, 0,
        "no asset-1 OI from rejected tail poison"
    );
    assert_eq!(
        after_reject.vault, before.vault,
        "vault unchanged by rejected tail poison"
    );
    assert_eq!(
        env.portfolio_state(victim).capital.get(),
        victim_before.capital.get(),
        "victim portfolio untouched"
    );

    env.svm.expire_blockhash();
    let ok = env.send(ix, base(None), &[&taker]);
    assert!(
        ok.is_ok(),
        "clean BatchTradeCpi without poisoned tail executes: {ok:?}"
    );
    let taker_state = env.portfolio_state(taker_account);
    assert!(
        has_active_leg_for_asset(&taker_state, 0),
        "clean batch fills asset 0"
    );
    assert!(
        has_active_leg_for_asset(&taker_state, 1),
        "clean batch fills asset 1"
    );
}

// security.md sweep - batch matcher-tail signer isolation (#22/#44/#49): the batched CPI route must
// apply the same signer-forwarding boundary as single TradeCpi. A hostile matcher must not receive
// the taker wallet signer through the tail and use it in a nested System Program transfer.
#[test]
fn v16_attack_batch_tradecpi_matcher_tail_cannot_forward_taker_signer() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let taker_account = env.create_portfolio(&taker);
    let lp_account = env.create_portfolio(&lp);
    env.deposit(&taker, taker_account, 1_000_000);
    env.deposit(&lp, lp_account, 1_000_000);

    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &lp_account,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let mut ctx_data = vec![0u8; MATCHER_CONTEXT_LEN];
    ctx_data[0] = 14;
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: ctx_data,
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.set_matcher_config(hostile, &lp, lp_account, ctx, delegate, 1);

    let tail_signer = Keypair::new();
    env.svm
        .set_account(
            tail_signer.pubkey(),
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: solana_sdk::system_program::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let recipient = Pubkey::new_unique();
    env.svm
        .set_account(
            recipient,
            Account {
                lamports: 1,
                data: vec![],
                owner: solana_sdk::system_program::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&taker_account).unwrap();
    let lp_before = env.svm.get_account(&lp_account).unwrap();
    let ctx_before = env.svm.get_account(&ctx).unwrap();
    let tail_signer_before = env.svm.get_account(&tail_signer.pubkey()).unwrap();
    let recipient_before = env.svm.get_account(&recipient).unwrap();
    let legs = vec![
        BatchTradeCpiLeg {
            asset_index: 0,
            size_q: (5 * POS_SCALE) as i128,
            fee_bps: 100,
            limit_price: 0,
        },
        BatchTradeCpiLeg {
            asset_index: 1,
            size_q: -(5 * POS_SCALE as i128),
            fee_bps: 100,
            limit_price: 0,
        },
    ];

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::BatchTradeCpi { legs: legs.clone() },
        vec![
            AccountMeta::new(taker.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(taker_account, false),
            AccountMeta::new(lp_account, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(delegate, false),
            AccountMeta::new(tail_signer.pubkey(), true),
            AccountMeta::new(recipient, false),
            AccountMeta::new_readonly(solana_sdk::system_program::ID, false),
        ],
        &[&taker, &tail_signer],
    );
    let rejected_err = rejected
        .expect_err("BatchTradeCpi must not forward any user signer into a hostile matcher tail");
    assert!(
        rejected_err.contains("Custom(9)") || rejected_err.contains("custom program error: 0x9"),
        "batch signer matcher tail must reject in wrapper preflight as InvalidInstruction, got {rejected_err}"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&taker_account).unwrap(), taker_before);
    assert_eq!(env.svm.get_account(&lp_account).unwrap(), lp_before);
    assert_eq!(env.svm.get_account(&ctx).unwrap(), ctx_before);
    assert_eq!(
        env.svm.get_account(&tail_signer.pubkey()).unwrap(),
        tail_signer_before,
        "rejected batch signer forwarding must not debit the tail signer"
    );
    assert_eq!(
        env.svm.get_account(&recipient).unwrap(),
        recipient_before,
        "hostile batch matcher must not receive lamports from the tail signer"
    );

    let mut honest_ctx = env.svm.get_account(&ctx).unwrap();
    honest_ctx.data[0] = 9;
    env.svm.set_account(ctx, honest_ctx).unwrap();
    env.svm.expire_blockhash();
    let ok = env.send(
        ProgInstruction::BatchTradeCpi { legs },
        vec![
            AccountMeta::new(taker.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(taker_account, false),
            AccountMeta::new(lp_account, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(delegate, false),
        ],
        &[&taker],
    );
    assert!(
        ok.is_ok(),
        "the same authorized hostile fixture batch-fills when no wallet signer is forwarded: {ok:?}"
    );
}

// security.md sweep — oracle confidence filter rejects wide-confidence feeds (#37/#39): the hybrid
// (Pyth) oracle gates a feed by its confidence interval — `conf*10000 > price*conf_filter_bps` rejects
// (src/v16_program.rs:3844). Attacker goal: configure/use the oracle against a feed with a huge
// confidence interval (an uncertain/manipulable price) so the protocol trades on an unreliable mark.
// Protection: a wide-conf feed is rejected; only a feed whose confidence is within the filter is accepted.
#[test]
fn v16_attack_oracle_wide_confidence_feed_rejected() {
    let price: i64 = 200_000;
    // helper: configure a 1-leg hybrid oracle from a Pyth feed with the given confidence; conf_filter=2%.
    let configure = |conf: u64| -> (bool, bool) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feed = [0x55u8; 32];
        let acct = env.set_pyth_price_with_conf(&feed, price, -6, conf, 100);
        let before = env.svm.get_account(&env.market).unwrap().data;
        let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            100,
            0,
            0,
            100,
            200,
        );
        let after = env.svm.get_account(&env.market).unwrap().data;
        (r.is_ok(), before == after) // (configured?, market_unchanged?)
    };

    // NARROW confidence (0.1% of price) is within the 2% filter -> accepted.
    let (narrow_ok, _) = configure((price / 1000) as u64);
    assert!(
        narrow_ok,
        "a tight-confidence feed (0.1%) must configure (within the 2% filter)"
    );

    // WIDE confidence (50% of price) far exceeds the 2% filter -> REJECTED, market unmutated.
    let (wide_ok, wide_unchanged) = configure((price / 2) as u64);
    assert!(
        !wide_ok,
        "a wide-confidence feed (50%) must be REJECTED by the conf filter"
    );
    assert!(
        wide_unchanged,
        "rejected wide-conf configuration must not mutate the market"
    );

    // BORDERLINE just over the filter (2.5% > 2%) also rejects -> the bound is enforced precisely.
    let (over_ok, _) = configure((price as u64 * 250) / 10_000);
    assert!(
        !over_ok,
        "a feed just over the conf filter (2.5% > 2%) must reject"
    );
}

// security.md sweep — F-ORACLE-INVERT regression: invert-of-a-zero-composite rejects, never panics
// (#37/#39). A multi-leg DIVIDE composite can floor to 0 (a tiny numerator over large divisors); with
// invert=1 the engine would otherwise compute 1e12/0 and PANIC (aborting the program). The F-ORACLE-
// INVERT fix (src/v16_program.rs:4054) guards `price == 0 -> OracleInvalid` BEFORE the invert divide.
// Attacker goal: craft feeds whose composite floors to 0 under invert to crash/DoS the program or slip a
// garbage mark. Protection: graceful OracleInvalid (Custom 26), no panic, market unmutated.
#[test]
fn v16_attack_oracle_invert_of_zero_composite_rejects_no_panic() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let feeds = [[0x71u8; 32], [0x72u8; 32], [0x73u8; 32]];
    // leg0 = 1 (tiny) divided by two 4e9 legs -> composite floors to 0; invert=1 would do 1e12/0.
    let l0 = env.set_pyth_price_with_conf(&feeds[0], 1, -6, 0, 100);
    let l1 = env.set_pyth_price_with_conf(&feeds[1], 4_000_000_000, -6, 0, 100);
    let l2 = env.set_pyth_price_with_conf(&feeds[2], 4_000_000_000, -6, 0, 100);
    let flags = ORACLE_LEG_FLAG_DIVIDE_LEG2 | ORACLE_LEG_FLAG_DIVIDE_LEG3;
    let before = env.svm.get_account(&env.market).unwrap().data;

    let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        3,
        flags,
        feeds,
        &[l0, l1, l2],
        1,
        100,
        1, /*invert*/
        0,
        100,
        0,
    );

    // GRACEFUL: rejected with OracleInvalid (Custom 26) — NOT a panic/abort (the process is still here).
    assert!(
        r.is_err(),
        "invert of a zero-flooring composite must reject"
    );
    let err = r.unwrap_err();
    assert!(
        err.contains("Custom(26)"),
        "must be OracleInvalid (Custom 26 = the F-ORACLE-INVERT guard), got: {}",
        err
    );
    assert!(
        !err.contains("panic") && !err.contains("ProgramFailedToComplete"),
        "must NOT panic/abort: {}",
        err
    );
    // the rejected configuration left the market untouched.
    let after = env.svm.get_account(&env.market).unwrap().data;
    assert_eq!(
        after, before,
        "rejected invert-of-zero configuration must not mutate the market"
    );
}

// security.md sweep — composite divide-by-zero leg rejects, no crash (#37/#39): a multi-leg oracle
// that DIVIDES by a leg priced 0 would divide-by-zero. Attacker goal: a 0-priced divide leg crashes the
// program (DoS) or yields a garbage/infinite composite mark. Protection: `compose` guards `leg_e6 == 0
// -> OracleInvalid` (src/v16_program.rs:4073) BEFORE the divide. Complement to #167 (invert-of-zero).
#[test]
fn v16_attack_oracle_compose_divide_by_zero_leg_rejects() {
    let configure = |l1_price: i64| -> (bool, Option<String>, Vec<u8>) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feeds = [[0x81u8; 32], [0x82u8; 32], [0x83u8; 32]];
        let l0 = env.set_pyth_price_with_conf(&feeds[0], 4_000_000_000, -6, 0, 100);
        let l1 = env.set_pyth_price_with_conf(&feeds[1], l1_price, -6, 0, 100); // a DIVIDE leg
        let l2 = env.set_pyth_price_with_conf(&feeds[2], 200_000_000, -6, 0, 100);
        let flags = ORACLE_LEG_FLAG_DIVIDE_LEG2 | ORACLE_LEG_FLAG_DIVIDE_LEG3;
        let before = env.svm.get_account(&env.market).unwrap().data;
        let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            3,
            flags,
            feeds,
            &[l0, l1, l2],
            1,
            100,
            0,
            0,
            100,
            0,
        );
        let after = env.svm.get_account(&env.market).unwrap().data;
        (
            r.is_ok(),
            r.err(),
            if before == after { vec![] } else { vec![1] },
        )
    };

    // a 0-priced DIVIDE leg -> rejected with OracleInvalid (Custom 26), no panic, market unmutated.
    let (zero_ok, zero_err, zero_changed) = configure(0);
    assert!(
        !zero_ok,
        "a 0-priced divide leg must reject (no divide-by-zero)"
    );
    let e = zero_err.unwrap();
    assert!(
        e.contains("Custom(26)"),
        "must be OracleInvalid (Custom 26), got: {}",
        e
    );
    assert!(
        !e.contains("panic") && !e.contains("ProgramFailedToComplete"),
        "must NOT crash on the divide-by-zero: {}",
        e
    );
    assert!(
        zero_changed.is_empty(),
        "rejected zero-leg configuration must not mutate the market"
    );

    // DISCRIMINATING CONTROL: a normal divide leg configures cleanly -> the rejection is the zero leg.
    let (normal_ok, _, _) = configure(150_000_000);
    assert!(normal_ok, "a normally-priced divide leg configures cleanly");
}

// security.md sweep — composite price over MAX_ORACLE_PRICE rejects (#37/#39): tiny (but nonzero)
// divide legs inflate the composite to a huge value. Attacker goal: drive the composite past
// MAX_ORACLE_PRICE so the protocol marks at a garbage/overflowed price (mass mis-liquidation / value
// extraction). Protection: apply_transform's post-check `price > MAX_ORACLE_PRICE -> OracleInvalid`
// (src/v16_program.rs:4067) rejects it; checked arithmetic prevents silent overflow. Complement to
// #167 (invert-of-zero) and #168 (compose div-by-zero).
#[test]
fn v16_attack_oracle_composite_over_max_price_rejects() {
    let configure = |l1: i64, l2: i64| -> (bool, Option<String>, bool) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feeds = [[0x91u8; 32], [0x92u8; 32], [0x93u8; 32]];
        let a0 = env.set_pyth_price_with_conf(&feeds[0], 4_000_000_000, -6, 0, 100);
        let a1 = env.set_pyth_price_with_conf(&feeds[1], l1, -6, 0, 100);
        let a2 = env.set_pyth_price_with_conf(&feeds[2], l2, -6, 0, 100);
        let flags = ORACLE_LEG_FLAG_DIVIDE_LEG2 | ORACLE_LEG_FLAG_DIVIDE_LEG3;
        let before = env.svm.get_account(&env.market).unwrap().data;
        let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            3,
            flags,
            feeds,
            &[a0, a1, a2],
            1,
            100,
            0,
            0,
            100,
            0,
        );
        let after = env.svm.get_account(&env.market).unwrap().data;
        (r.is_ok(), r.err(), before == after)
    };

    // tiny divide legs (1, 1) -> 4e9 / 1 / 1 composite >> MAX_ORACLE_PRICE -> rejected, no overflow/garbage.
    let (huge_ok, huge_err, huge_unchanged) = configure(1, 1);
    assert!(
        !huge_ok,
        "a composite price over MAX_ORACLE_PRICE must reject"
    );
    let e = huge_err.unwrap();
    assert!(
        e.contains("Custom(26)"),
        "must be OracleInvalid (Custom 26), got: {}",
        e
    );
    assert!(
        !e.contains("panic") && !e.contains("ProgramFailedToComplete"),
        "must NOT overflow/crash: {}",
        e
    );
    assert!(
        huge_unchanged,
        "rejected over-max configuration must not mutate the market"
    );

    // DISCRIMINATING CONTROL: normal divide legs produce an in-range composite -> configures cleanly.
    let (normal_ok, _, _) = configure(150_000_000, 200_000_000);
    assert!(
        normal_ok,
        "a normal composite (in range) configures cleanly"
    );
}

// security.md sweep — oracle unit_scale transform: correct scaling + floor-to-0 rejected (#37/#39):
// apply_transform divides the price by unit_scale (`price /= unit_scale`, src/v16_program.rs:4064) and
// the post-check rejects a 0 result. Attacker goal: a unit_scale larger than the price floors the mark
// to 0 (slipping a garbage/zero mark) OR the scaling yields a wrong price. Protection: the mark is the
// exact divided price, and a scale that floors it to 0 -> OracleInvalid. Last degenerate-price path
// (complements the composite trio #167/#168/#169).
#[test]
fn v16_attack_oracle_unit_scale_transform_correct_and_floor0_rejected() {
    let configure = |scale: u32| -> (bool, u64, Option<String>) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feed = [0x55u8; 32];
        let acct = env.set_pyth_price_with_conf(&feed, 200_000, -6, 0, 100); // price_e6 = 200_000
        let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            100,
            0,
            scale,
            100,
            0,
        );
        let eff = if r.is_ok() {
            env.market_state().1.assets[0].effective_price
        } else {
            0
        };
        (r.is_ok(), eff, r.err())
    };

    // VALID scale: mark is the EXACT divided price (200_000 / 2 = 100_000).
    let (ok2, eff2, _) = configure(2);
    assert!(ok2, "a valid unit_scale configures");
    assert_eq!(
        eff2, 100_000,
        "unit_scale divides the mark exactly (200_000/2)"
    );
    // and unit_scale 4 -> 50_000.
    let (ok4, eff4, _) = configure(4);
    assert!(
        ok4 && eff4 == 50_000,
        "unit_scale=4 -> 200_000/4 = 50_000, got {}",
        eff4
    );

    // FLOOR-TO-0: a unit_scale > the price floors the mark to 0 -> rejected (no zero/garbage mark).
    let (ok_floor, _, floor_err) = configure(300_000);
    assert!(
        !ok_floor,
        "a unit_scale that floors the price to 0 must reject"
    );
    let e = floor_err.unwrap();
    assert!(
        e.contains("Custom(26)"),
        "floor-to-0 must be OracleInvalid (Custom 26), got: {}",
        e
    );
}

// security.md sweep — oracle staleness bound is exact (#37/#39): the hybrid oracle rejects a feed whose
// age (authenticated_unix − publish_time) exceeds max_staleness_secs. Attacker goal: configure/use a
// STALE feed (a price no longer current, e.g. a frozen/old quote) to mark against an outdated price.
// Protection: age > max_staleness_secs rejects; the bound is precise and uses the AUTHENTICATED clock
// (complements #6747 which proves the caller cannot spoof now_unix to make a stale feed look fresh).
#[test]
fn v16_attack_oracle_staleness_bound_exact() {
    // max_staleness_secs=60 (set by the helper); authenticated unix time = 1000.
    let configure = |publish_time: i64| -> bool {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 1000);
        let feed = [0x55u8; 32];
        let acct = env.set_pyth_price_with_conf(&feed, 200_000, -6, 0, publish_time);
        env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            1000,
            0,
            0,
            100,
            0,
        )
        .is_ok()
    };
    // FRESH (age 50s ≤ 60) and the EXACT edge (age 60s ≤ 60) configure.
    assert!(configure(950), "a 50s-old feed (≤ 60s) configures");
    assert!(
        configure(940),
        "a feed at exactly the 60s staleness edge configures (inclusive bound)"
    );
    // JUST OVER (age 61s) and clearly STALE (age 70s) reject.
    assert!(
        !configure(939),
        "a 61s-old feed (> 60s) must reject (one second past the bound)"
    );
    assert!(!configure(930), "a 70s-old feed must reject");
}

// security.md sweep — Pyth feed negative/zero price rejected (#37/#39): a Pyth price is an i64 and can
// be negative or zero. Attacker goal: a malicious/garbage feed reporting a negative or zero price injects
// an invalid mark (settlement at a nonsensical price / sign flip). Protection: the oracle parse accepts
// only a positive price; negative or zero -> OracleInvalid. Completes the oracle price-domain coverage.
#[test]
fn v16_attack_oracle_negative_or_zero_price_rejected() {
    let configure = |price: i64| -> (bool, Option<String>) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feed = [0x55u8; 32];
        let acct = env.set_pyth_price_with_conf(&feed, price, -6, 0, 100);
        let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            100,
            0,
            0,
            100,
            0,
        );
        (r.is_ok(), r.err())
    };
    // a positive price configures.
    let (pos_ok, _) = configure(200_000);
    assert!(pos_ok, "a positive Pyth price configures");
    // a NEGATIVE price is rejected (no sign-flipped mark).
    let (neg_ok, neg_err) = configure(-200_000);
    assert!(!neg_ok, "a negative Pyth price must reject");
    assert!(
        neg_err.unwrap().contains("Custom(26)"),
        "negative price must be OracleInvalid (Custom 26)"
    );
    // a ZERO price is rejected (no zero mark / downstream div-by-zero).
    let (zero_ok, zero_err) = configure(0);
    assert!(!zero_ok, "a zero Pyth price must reject");
    assert!(
        zero_err.unwrap().contains("Custom(26)"),
        "zero price must be OracleInvalid (Custom 26)"
    );
}

// security.md sweep — oracle feed account owner validation (#37/#44): a Pyth feed account must be owned
// by the Pyth receiver program. Attacker goal: substitute a self-owned account holding crafted "Pyth"
// data to inject an arbitrary oracle price (full oracle spoof). Protection: the wrapper rejects a feed
// whose owner is not the Pyth receiver program (IllegalOwner) — the data is never even parsed.
#[test]
fn v16_attack_oracle_feed_wrong_owner_rejected() {
    let configure = |owner: Pubkey| -> (bool, Option<String>) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feed = [0x55u8; 32];
        let acct = Pubkey::new_unique();
        // valid-looking Pyth data, but planted under an attacker-chosen owner.
        env.svm
            .set_account(
                acct,
                Account {
                    lamports: 1_000_000_000,
                    data: make_pyth_data(&feed, 200_000, -6, 0, 100),
                    owner,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        let r = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            100,
            0,
            0,
            100,
            0,
        );
        (r.is_ok(), r.err())
    };
    // genuinely Pyth-owned -> configures.
    let (real_ok, _) = configure(oracle_v16::PYTH_RECEIVER_PROGRAM_ID);
    assert!(real_ok, "a genuinely Pyth-receiver-owned feed configures");
    // attacker-owned account with crafted Pyth data -> rejected on the OWNER check (IllegalOwner),
    // before the crafted price is ever parsed.
    let (fake_ok, fake_err) = configure(Pubkey::new_unique());
    assert!(
        !fake_ok,
        "a feed owned by an attacker (non-Pyth) program must reject — no oracle spoof"
    );
    assert!(
        fake_err.unwrap().contains("IllegalOwner"),
        "must reject on the feed owner check (IllegalOwner)"
    );
}

// security.md sweep - oracle feed-id binding (#37/#44): even a Pyth-owned PriceUpdate account must
// carry the configured feed id. Otherwise an attacker could substitute a valid update for a different
// asset and drive the configured market with the wrong oracle.
#[test]
fn v16_attack_oracle_feed_id_mismatch_rejected() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let expected_feed = [0x55u8; 32];
    let wrong_feed = [0x56u8; 32];
    let wrong_acct = env.set_pyth_price_with_conf(&wrong_feed, 200_000, -6, 0, 100);
    let before = env.svm.get_account(&env.market).unwrap().data;

    let bad = env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [expected_feed, [0u8; 32], [0u8; 32]],
        &[wrong_acct],
        1,
        100,
        0,
        0,
        100,
        0,
    );
    assert!(
        bad.is_err(),
        "a PriceUpdate for the wrong feed id must reject"
    );
    let err = bad.err().unwrap();
    assert!(
        err.contains("Custom(29)"),
        "wrong feed id should reject as InvalidOracleKey (Custom 29), got: {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "rejected wrong-feed config must not mutate the market"
    );

    let correct_acct = env.set_pyth_price_with_conf(&expected_feed, 200_000, -6, 0, 100);
    let ok = env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [expected_feed, [0u8; 32], [0u8; 32]],
        &[correct_acct],
        1,
        100,
        0,
        0,
        100,
        0,
    );
    assert!(
        ok.is_ok(),
        "the matching configured feed id configures: {:?}",
        ok
    );
}

// security.md sweep — Chainlink oracle parser hardening (#37/#44): a Chainlink-owned transmissions
// account is accepted as a hybrid oracle leg, so malformed header/transmission fields must reject
// through the public ConfigureHybridOracle path without partially installing a bad oracle profile.
#[test]
fn v16_attack_chainlink_oracle_malformed_fields_reject_without_mutation() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let valid = || make_chainlink_data(1, 8, 1, 1, 1, 100, 10_000);
    let install = |env: &mut V16CuEnv, data: Vec<u8>| -> Pubkey {
        let key = Pubkey::new_unique();
        env.svm
            .set_account(
                key,
                Account {
                    lamports: 1_000_000_000,
                    data,
                    owner: oracle_v16::CHAINLINK_STORE_PROGRAM_ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        key
    };

    let before = env.svm.get_account(&env.market).unwrap().data;
    let mut cases: Vec<(&str, Vec<u8>)> = Vec::new();
    let mut bad_disc = valid();
    bad_disc[0] ^= 0xff;
    cases.push(("bad discriminator", bad_disc));
    cases.push((
        "zero version",
        make_chainlink_data(0, 8, 1, 1, 1, 100, 10_000),
    ));
    cases.push((
        "zero latest round",
        make_chainlink_data(1, 8, 0, 1, 1, 100, 10_000),
    ));
    cases.push((
        "non-single live length",
        make_chainlink_data(1, 8, 1, 2, 1, 100, 10_000),
    ));
    cases.push(("zero slot", make_chainlink_data(1, 8, 1, 1, 0, 100, 10_000)));
    cases.push((
        "zero publish time",
        make_chainlink_data(1, 8, 1, 1, 1, 0, 10_000),
    ));
    cases.push((
        "decimals over bound",
        make_chainlink_data(1, 19, 1, 1, 1, 100, 10_000),
    ));
    cases.push((
        "negative answer",
        make_chainlink_data(1, 8, 1, 1, 1, 100, -10_000),
    ));

    for (label, data) in cases {
        let acct = install(&mut env, data);
        env.svm.expire_blockhash();
        let rejected = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [acct.to_bytes(), [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            100,
            0,
            0,
            100,
            0,
        );
        assert!(rejected.is_err(), "malformed Chainlink {label} must reject");
        assert_eq!(
            env.svm.get_account(&env.market).unwrap().data,
            before,
            "malformed Chainlink {label} must not mutate market state"
        );
    }

    let ok_acct = install(&mut env, valid());
    env.svm.expire_blockhash();
    let ok = env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [ok_acct.to_bytes(), [0u8; 32], [0u8; 32]],
        &[ok_acct],
        1,
        100,
        0,
        0,
        100,
        0,
    );
    assert!(ok.is_ok(), "valid Chainlink leg configures: {ok:?}");
    assert_eq!(
        env.market_state().1.assets[0].effective_price,
        100,
        "valid Chainlink answer/decimals seeds the expected mark"
    );
}

// Chainlink spoofing gate: Chainlink feeds are account-key-bound like Switchboard. A valid-looking
// transmissions account under the wrong key, or under an attacker owner, must reject atomically.
#[test]
fn v16_attack_chainlink_owner_and_key_binding_reject_spoofed_feed() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let install = |env: &mut V16CuEnv, owner: Pubkey| -> Pubkey {
        let key = Pubkey::new_unique();
        env.svm
            .set_account(
                key,
                Account {
                    lamports: 1_000_000_000,
                    data: make_chainlink_data(1, 8, 1, 1, 1, 100, 10_000),
                    owner,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        key
    };
    let configure = |env: &mut V16CuEnv, expected_feed: Pubkey, account: Pubkey| {
        env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [expected_feed.to_bytes(), [0u8; 32], [0u8; 32]],
            &[account],
            1,
            100,
            0,
            0,
            100,
            0,
        )
    };
    let before = env.svm.get_account(&env.market).unwrap().data;

    let wrong_key = install(&mut env, oracle_v16::CHAINLINK_STORE_PROGRAM_ID);
    let expected_key = Pubkey::new_unique();
    env.svm.expire_blockhash();
    let key_spoof = configure(&mut env, expected_key, wrong_key);
    assert!(
        key_spoof.is_err(),
        "a Chainlink transmissions account must match the configured account key"
    );
    let key_err = key_spoof.unwrap_err();
    assert!(
        key_err.contains("Custom(29)"),
        "wrong Chainlink account key must reject as InvalidOracleKey (Custom 29), got: {key_err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "wrong-key Chainlink spoof must not mutate the market"
    );

    let fake_owner = install(&mut env, Pubkey::new_unique());
    env.svm.expire_blockhash();
    let owner_spoof = configure(&mut env, fake_owner, fake_owner);
    assert!(
        owner_spoof.is_err(),
        "attacker-owned Chainlink-shaped data must reject before parsing the price"
    );
    let owner_err = owner_spoof.unwrap_err();
    assert!(
        owner_err.contains("IllegalOwner"),
        "attacker-owned Chainlink feed must reject as IllegalOwner, got: {owner_err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "attacker-owned Chainlink spoof must not mutate the market"
    );

    let valid = install(&mut env, oracle_v16::CHAINLINK_STORE_PROGRAM_ID);
    env.svm.expire_blockhash();
    configure(&mut env, valid, valid).expect("real Chainlink owner/key pair should configure");
    assert_eq!(
        env.market_state().1.assets[0].effective_price,
        100,
        "valid Chainlink owner/key pair seeds the expected mark"
    );
}

// Chainlink staleness gate: a well-formed transmissions account with an old timestamp must not seed
// an outdated mark. This covers the Chainlink-specific timestamp offset and OracleStale branch.
#[test]
fn v16_attack_chainlink_stale_feed_rejected_without_mutation() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 10, 1_000);
    let install = |env: &mut V16CuEnv, publish_time: u32| -> Pubkey {
        let key = Pubkey::new_unique();
        env.svm
            .set_account(
                key,
                Account {
                    lamports: 1_000_000_000,
                    data: make_chainlink_data(1, 8, 1, 1, 1, publish_time, 10_000),
                    owner: oracle_v16::CHAINLINK_STORE_PROGRAM_ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        key
    };
    let configure = |env: &mut V16CuEnv, feed: Pubkey| {
        env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed.to_bytes(), [0u8; 32], [0u8; 32]],
            &[feed],
            10,
            1_000,
            0,
            0,
            100,
            0,
        )
    };
    let stale = install(&mut env, 1);
    let before = env.svm.get_account(&env.market).unwrap().data;

    env.svm.expire_blockhash();
    let rejected = configure(&mut env, stale);
    assert!(
        rejected.is_err(),
        "a stale Chainlink feed must reject instead of seeding the oracle"
    );
    let err = rejected.unwrap_err();
    assert!(
        err.contains("Custom(27)"),
        "stale Chainlink feed must reject as OracleStale (Custom 27), got: {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "rejected stale Chainlink config must not mutate the market"
    );

    let fresh = install(&mut env, 1_000);
    env.svm.expire_blockhash();
    configure(&mut env, fresh).expect("fresh Chainlink feed should configure");
    assert_eq!(
        env.market_state().1.assets[0].effective_price,
        100,
        "fresh Chainlink answer/decimals seeds the expected mark"
    );
}

// LoF/DoS sweep: future-dated oracle updates are distinct from merely stale updates. If accepted,
// they can pin the stored leg publish time ahead of honest feeds and block later oracle progress.
// Exercise the negative-age OracleStale branch for all external oracle sources through the public
// configure route, then prove a current-timestamp feed of the same source still configures.
#[test]
fn v16_attack_future_dated_oracle_feeds_reject_without_pinning_publish_time() {
    const NOW_SLOT: u64 = 10;
    const NOW_TS: i64 = 1_000;
    const FUTURE_TS: i64 = 1_060;
    const SOFT_STALE_SLOTS: u64 = 100;
    const SWITCHBOARD_SCALE: i128 = 1_000_000_000_000;

    let configure = |env: &mut V16CuEnv, feed: [u8; 32], account: Pubkey| {
        env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[account],
            NOW_SLOT,
            NOW_TS,
            0,
            0,
            SOFT_STALE_SLOTS,
            0,
        )
    };

    let mut pyth_env = V16CuEnv::new();
    set_test_clock(&mut pyth_env, NOW_SLOT, NOW_TS);
    let pyth_feed = [0x41u8; 32];
    let future_pyth = pyth_env.set_pyth_price_with_conf(&pyth_feed, 100, 0, 0, FUTURE_TS);
    let pyth_before = pyth_env.svm.get_account(&pyth_env.market).unwrap().data;
    pyth_env.svm.expire_blockhash();
    let pyth_rejected = configure(&mut pyth_env, pyth_feed, future_pyth);
    assert!(pyth_rejected.is_err(), "future-dated Pyth feed must reject");
    let pyth_err = pyth_rejected.unwrap_err();
    assert!(
        pyth_err.contains("Custom(27)"),
        "future-dated Pyth feed must reject as OracleStale (Custom 27), got: {pyth_err}"
    );
    assert_eq!(
        pyth_env.svm.get_account(&pyth_env.market).unwrap().data,
        pyth_before,
        "future-dated Pyth reject must not pin oracle state"
    );
    let current_pyth = pyth_env.set_pyth_price_with_conf(&pyth_feed, 100, 0, 0, NOW_TS);
    pyth_env.svm.expire_blockhash();
    configure(&mut pyth_env, pyth_feed, current_pyth)
        .expect("current Pyth feed configures after future-dated reject");

    let mut switchboard_env = V16CuEnv::new();
    set_test_clock(&mut switchboard_env, NOW_SLOT, NOW_TS);
    let future_switchboard =
        switchboard_env.set_switchboard_price(100 * SWITCHBOARD_SCALE, 1, FUTURE_TS);
    let switchboard_before = switchboard_env
        .svm
        .get_account(&switchboard_env.market)
        .unwrap()
        .data;
    switchboard_env.svm.expire_blockhash();
    let switchboard_rejected = configure(
        &mut switchboard_env,
        future_switchboard.to_bytes(),
        future_switchboard,
    );
    assert!(
        switchboard_rejected.is_err(),
        "future-dated Switchboard feed must reject"
    );
    let switchboard_err = switchboard_rejected.unwrap_err();
    assert!(
        switchboard_err.contains("Custom(27)"),
        "future-dated Switchboard feed must reject as OracleStale (Custom 27), got: {switchboard_err}"
    );
    assert_eq!(
        switchboard_env
            .svm
            .get_account(&switchboard_env.market)
            .unwrap()
            .data,
        switchboard_before,
        "future-dated Switchboard reject must not pin oracle state"
    );
    let current_switchboard =
        switchboard_env.set_switchboard_price(100 * SWITCHBOARD_SCALE, 1, NOW_TS);
    switchboard_env.svm.expire_blockhash();
    configure(
        &mut switchboard_env,
        current_switchboard.to_bytes(),
        current_switchboard,
    )
    .expect("current Switchboard feed configures after future-dated reject");

    let mut chainlink_env = V16CuEnv::new();
    set_test_clock(&mut chainlink_env, NOW_SLOT, NOW_TS);
    let install_chainlink = |env: &mut V16CuEnv, publish_time: i64| -> Pubkey {
        let key = Pubkey::new_unique();
        env.svm
            .set_account(
                key,
                Account {
                    lamports: 1_000_000_000,
                    data: make_chainlink_data(1, 8, 1, 1, 1, publish_time as u32, 10_000),
                    owner: oracle_v16::CHAINLINK_STORE_PROGRAM_ID,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        key
    };
    let future_chainlink = install_chainlink(&mut chainlink_env, FUTURE_TS);
    let chainlink_before = chainlink_env
        .svm
        .get_account(&chainlink_env.market)
        .unwrap()
        .data;
    chainlink_env.svm.expire_blockhash();
    let chainlink_rejected = configure(
        &mut chainlink_env,
        future_chainlink.to_bytes(),
        future_chainlink,
    );
    assert!(
        chainlink_rejected.is_err(),
        "future-dated Chainlink feed must reject"
    );
    let chainlink_err = chainlink_rejected.unwrap_err();
    assert!(
        chainlink_err.contains("Custom(27)"),
        "future-dated Chainlink feed must reject as OracleStale (Custom 27), got: {chainlink_err}"
    );
    assert_eq!(
        chainlink_env
            .svm
            .get_account(&chainlink_env.market)
            .unwrap()
            .data,
        chainlink_before,
        "future-dated Chainlink reject must not pin oracle state"
    );
    let current_chainlink = install_chainlink(&mut chainlink_env, NOW_TS);
    chainlink_env.svm.expire_blockhash();
    configure(
        &mut chainlink_env,
        current_chainlink.to_bytes(),
        current_chainlink,
    )
    .expect("current Chainlink feed configures after future-dated reject");
}

// Hybrid oracle leg-shape gate: duplicate feed identities, stray feeds, and impossible divide flags
// must reject before installing an oracle profile. Otherwise a config could double-count one feed or
// advertise a divide leg that has no corresponding account.
#[test]
fn v16_attack_hybrid_oracle_rejects_duplicate_or_malformed_leg_config() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let feed0 = [0xa0u8; 32];
    let feed1 = [0xa1u8; 32];
    let feed2 = [0xa2u8; 32];
    let oracle0 = env.set_pyth_price_with_conf(&feed0, 200_000, -6, 0, 100);
    let oracle1 = env.set_pyth_price_with_conf(&feed1, 300_000, -6, 0, 100);
    let oracle2 = env.set_pyth_price_with_conf(&feed2, 400_000, -6, 0, 100);
    let configure =
        |env: &mut V16CuEnv, count: u8, flags: u8, feeds: [[u8; 32]; 3], accounts: &[Pubkey]| {
            env.try_configure_hybrid_asset_with_conf_filter_cu(
                0, count, flags, feeds, accounts, 1, 100, 0, 0, 100, 0,
            )
        };
    let before = env.svm.get_account(&env.market).unwrap().data;

    for (label, count, flags, feeds, accounts) in [
        (
            "count-1 stray second feed",
            1,
            0,
            [feed0, feed1, [0u8; 32]],
            vec![oracle0],
        ),
        (
            "count-2 duplicate first feed",
            2,
            0,
            [feed0, feed0, [0u8; 32]],
            vec![oracle0, oracle1],
        ),
        (
            "count-2 divide third flag",
            2,
            ORACLE_LEG_FLAG_DIVIDE_LEG3,
            [feed0, feed1, [0u8; 32]],
            vec![oracle0, oracle1],
        ),
        (
            "count-3 duplicate third feed",
            3,
            0,
            [feed0, feed1, feed1],
            vec![oracle0, oracle1, oracle2],
        ),
    ] {
        env.svm.expire_blockhash();
        let rejected = configure(&mut env, count, flags, feeds, &accounts);
        assert!(rejected.is_err(), "hybrid oracle {label} must reject");
        assert_eq!(
            env.svm.get_account(&env.market).unwrap().data,
            before,
            "rejected hybrid oracle {label} must not mutate the market"
        );
    }

    env.svm.expire_blockhash();
    configure(&mut env, 1, 0, [feed0, [0u8; 32], [0u8; 32]], &[oracle0])
        .expect("well-formed one-leg hybrid oracle should configure");
    assert_eq!(
        env.market_state().1.assets[0].effective_price,
        200_000,
        "valid one-leg control seeds the expected mark"
    );
}

// security.md sweep - Hybrid oracle scalar bounds (#37/#39/#44): feed-shape tests cover duplicate
// and missing legs; this covers the scalar knobs that can otherwise install a malformed after-hours
// fallback profile. Rejected scalar configs must leave the market byte-identical.
#[test]
fn v16_attack_hybrid_oracle_scalar_bounds_reject_atomically() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let admin = env.admin.insecure_clone();
    let feed = [0xba; 32];
    let oracle = env.set_pyth_price_with_conf(&feed, 200_000, -6, 0, 100);
    let feeds = [feed, [0u8; 32], [0u8; 32]];
    let accounts = vec![
        AccountMeta::new(admin.pubkey(), true),
        AccountMeta::new(env.market, false),
        AccountMeta::new_readonly(oracle, false),
    ];

    let reject_unchanged = |env: &mut V16CuEnv,
                            oracle_leg_count: u8,
                            max_staleness_secs: u64,
                            hybrid_soft_stale_slots: u64,
                            mark_ewma_halflife_slots: u64,
                            invert: u8,
                            conf_filter_bps: u16,
                            label: &str| {
        let before = env.svm.get_account(&env.market).unwrap();
        env.svm.expire_blockhash();
        let rejected = send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::ConfigureHybridOracle {
                asset_index: 0,
                now_slot: 1,
                now_unix_ts: 100,
                oracle_leg_count,
                oracle_leg_flags: 0,
                max_staleness_secs,
                hybrid_soft_stale_slots,
                mark_ewma_halflife_slots,
                mark_min_fee: 0,
                invert,
                unit_scale: 0,
                conf_filter_bps,
                oracle_leg_feeds: feeds,
            },
            accounts.clone(),
            &[&admin],
        );
        assert!(rejected.is_err(), "{label} must reject");
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            before,
            "{label} must leave the market byte-identical"
        );
    };

    reject_unchanged(&mut env, 0, 60, 3, 10, 0, 500, "zero leg count");
    reject_unchanged(&mut env, 4, 60, 3, 10, 0, 500, "leg count over cap");
    reject_unchanged(&mut env, 1, 0, 3, 10, 0, 500, "zero max staleness");
    reject_unchanged(&mut env, 1, 60, 0, 10, 0, 500, "zero soft-stale slots");
    reject_unchanged(&mut env, 1, 60, 3, 0, 0, 500, "zero fallback EWMA halflife");
    reject_unchanged(&mut env, 1, 60, 3, 10, 2, 500, "bad invert flag");
    reject_unchanged(
        &mut env,
        1,
        60,
        3,
        10,
        0,
        10_001,
        "confidence filter over 100%",
    );

    env.svm.expire_blockhash();
    let ok = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureHybridOracle {
            asset_index: 0,
            now_slot: 1,
            now_unix_ts: 100,
            oracle_leg_count: 1,
            oracle_leg_flags: 0,
            max_staleness_secs: 60,
            hybrid_soft_stale_slots: 3,
            mark_ewma_halflife_slots: 10,
            mark_min_fee: 0,
            invert: 0,
            unit_scale: 0,
            conf_filter_bps: 500,
            oracle_leg_feeds: feeds,
        },
        accounts,
        &[&admin],
    );
    assert!(
        ok.is_ok(),
        "valid Hybrid oracle config remains live after scalar-bound probes: {ok:?}"
    );
    let (cfg, group) = env.market_state();
    assert_eq!(
        cfg.oracle_mode,
        percolator_prog::constants::ORACLE_MODE_HYBRID_AFTER_HOURS
    );
    assert_eq!(cfg.mark_ewma_halflife_slots, 10);
    assert_eq!(group.assets[0].effective_price, 200_000);
}

// security.md sweep — Pyth exponent bounds (#37/#39): exponent scaling is part of the trusted mark.
// Out-of-range exponents, over-max scaled prices, and floor-to-zero scaled prices must reject through
// ConfigureHybridOracle without installing a malformed oracle profile.
#[test]
fn v16_attack_oracle_pyth_exponent_bounds_enforced() {
    let configure = |price: i64, expo: i32| -> (bool, bool) {
        let mut env = V16CuEnv::new();
        set_test_clock(&mut env, 1, 100);
        let feed = [0xa5u8; 32];
        let acct = env.set_pyth_price_with_conf(&feed, price, expo, 0, 100);
        let before = env.svm.get_account(&env.market).unwrap().data;
        let result = env.try_configure_hybrid_asset_with_conf_filter_cu(
            0,
            1,
            0,
            [feed, [0u8; 32], [0u8; 32]],
            &[acct],
            1,
            100,
            0,
            0,
            100,
            0,
        );
        let after = env.svm.get_account(&env.market).unwrap().data;
        (result.is_ok(), before == after)
    };

    let (ok, _) = configure(200_000, -6);
    assert!(ok, "normal Pyth exponent configures");

    for (label, price, expo) in [
        ("positive exponent over bound", 1, 19),
        ("negative exponent over bound", 1_000_000_000, -19),
        ("positive exponent scales over max", 1, 18),
        ("negative exponent floors to zero", 1, -18),
    ] {
        let (configured, unchanged) = configure(price, expo);
        assert!(
            !configured,
            "Pyth {label} must reject instead of installing a malformed mark"
        );
        assert!(
            unchanged,
            "Pyth {label} rejection must leave market state unchanged"
        );
    }
}

// security.md sweep — oracle mode isolation (#6/#37): once an asset is configured as a Hybrid/external
// oracle, even the correct oracle_authority must not bypass the external feed by calling pushed-mark
// entrypoints. The legitimate update path remains PermissionlessCrank with the oracle tail.
#[test]
fn v16_attack_pushed_mark_cannot_override_external_oracle_asset() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let feed = [0xb6u8; 32];
    let initial = env.set_pyth_price_with_conf(&feed, 100, 0, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed, [0u8; 32], [0u8; 32]],
        &[initial],
        1,
        100,
        0,
        0,
        100,
        0,
    )
    .expect("configure a one-leg external oracle");
    assert_eq!(env.market_state().1.assets[0].effective_price, 100_000_000);

    let admin = env.admin.insecure_clone();
    let hybrid_before = env.svm.get_account(&env.market).unwrap();
    set_test_clock(&mut env, 2, 101);
    env.svm.expire_blockhash();
    let auth_push = env.send(
        ProgInstruction::PushAuthMark {
            asset_index: 0,
            now_slot: 2,
            mark_e6: 9_999_999,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        auth_push.is_err(),
        "PushAuthMark must not override a Hybrid/external oracle asset"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        hybrid_before,
        "rejected PushAuthMark leaves the Hybrid oracle profile unchanged"
    );

    env.svm.expire_blockhash();
    let ewma_push = env.send(
        ProgInstruction::PushEwmaMark {
            asset_index: 0,
            now_slot: 2,
            mark_e6: 9_999_999,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        ewma_push.is_err(),
        "PushEwmaMark must not override a Hybrid/external oracle asset"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        hybrid_before,
        "rejected PushEwmaMark leaves the Hybrid oracle profile unchanged"
    );

    let cranker = Keypair::new();
    let cranker_portfolio = env.create_portfolio(&cranker);
    let updated = env.set_pyth_price_with_conf(&feed, 110, 0, 0, 101);
    env.svm.expire_blockhash();
    env.crank_with_oracle_tail(
        cranker_portfolio,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
        &[updated],
    );
    assert_eq!(
        env.market_state().1.assets[0].raw_oracle_target_price,
        110_000_000,
        "external oracle tail remains the valid update path"
    );
}

#[test]
fn v16_attack_crank_oracle_feed_id_mismatch_rejects_without_mutation() {
    let mut env = V16CuEnv::new();
    set_test_clock(&mut env, 1, 100);
    let expected_feed = [0x77u8; 32];
    let wrong_feed = [0x78u8; 32];
    let initial_acct = env.set_pyth_price_with_conf(&expected_feed, 200_000, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [expected_feed, [0u8; 32], [0u8; 32]],
        &[initial_acct],
        1,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure matching one-leg hybrid oracle");

    let cranker_owner = Keypair::new();
    let cranker_portfolio = env.create_portfolio(&cranker_owner);
    set_test_clock(&mut env, 2, 101);
    let wrong_acct = env.set_pyth_price_with_conf(&wrong_feed, 500_000, -6, 0, 101);
    let market_before = env.svm.get_account(&env.market).unwrap().data;
    let portfolio_before = env.svm.get_account(&cranker_portfolio).unwrap().data;

    env.svm.expire_blockhash();
    let bad = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations_with_accounts(0, 1),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(cranker_portfolio, false),
            AccountMeta::new_readonly(wrong_acct, false),
        ],
        &[],
    );
    assert!(
        bad.is_err(),
        "permissionless crank must reject a PriceUpdate for the wrong configured feed"
    );
    let err = bad.err().unwrap();
    assert!(
        err.contains("Custom(29)"),
        "wrong feed id should reject as InvalidOracleKey (Custom 29), got: {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        market_before,
        "wrong-feed crank must not partially update the oracle profile or market state"
    );
    assert_eq!(
        env.svm.get_account(&cranker_portfolio).unwrap().data,
        portfolio_before,
        "wrong-feed crank must not mutate the cranker portfolio"
    );

    let correct_acct = env.set_pyth_price_with_conf(&expected_feed, 210_000, -6, 0, 101);
    env.svm.expire_blockhash();
    env.crank_with_oracle_tail(
        cranker_portfolio,
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations(0),
        },
        &[correct_acct],
    );
    let (cfg, group) = env.market_state();
    assert_eq!(cfg.last_good_oracle_slot, 2);
    assert_eq!(group.assets[0].raw_oracle_target_price, 210_000);
}

// Public auto-crank observation sweep: multiple oracle observations are parsed and applied before
// the engine auto-selector runs. A malformed later hint must not leave an earlier accepted oracle
// update committed. This catches the boundary where wrapper-side oracle mutation, engine error
// propagation, and SVM rollback must line up.
#[test]
fn v16_attack_crank_duplicate_observation_rolls_back_prior_oracle_update() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    let keeper = Keypair::new();
    let keeper_portfolio = env.create_portfolio(&keeper);
    set_test_clock(&mut env, 1, 100);

    let feed0 = [0x31u8; 32];
    let feed1 = [0x32u8; 32];
    let initial0 = env.set_pyth_price_with_conf(&feed0, 200_000, -6, 0, 100);
    let initial1 = env.set_pyth_price_with_conf(&feed1, 300_000, -6, 0, 100);
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        0,
        1,
        0,
        [feed0, [0u8; 32], [0u8; 32]],
        &[initial0],
        1,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure asset-0 hybrid oracle");
    env.try_configure_hybrid_asset_with_conf_filter_cu(
        1,
        1,
        0,
        [feed1, [0u8; 32], [0u8; 32]],
        &[initial1],
        1,
        100,
        0,
        0,
        10,
        0,
    )
    .expect("configure asset-1 hybrid oracle");

    set_test_clock(&mut env, 2, 101);
    let fresh0 = env.set_pyth_price_with_conf(&feed0, 210_000, -6, 0, 101);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let keeper_before = env.svm.get_account(&keeper_portfolio).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: vec![
                CrankObservationHint {
                    asset_index: 0,
                    oracle_accounts: 1,
                },
                CrankObservationHint {
                    asset_index: 0,
                    oracle_accounts: 1,
                },
            ],
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(keeper_portfolio, false),
            AccountMeta::new_readonly(fresh0, false),
        ],
        &[],
    );
    assert!(
        rejected.is_err(),
        "duplicate observation hints must reject after the first observation has run"
    );
    let err = rejected.unwrap_err();
    assert!(
        err.contains("Custom(9)"),
        "duplicate observation should reject as InvalidInstruction, got {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "failed multi-observation crank must roll back the earlier oracle/profile update"
    );
    assert_eq!(
        env.svm.get_account(&keeper_portfolio).unwrap(),
        keeper_before,
        "failed multi-observation crank must not mutate the target portfolio"
    );

    env.svm.expire_blockhash();
    let ok = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 2,
            close_q: 0,
            observations: crank_observations_with_accounts(0, 1),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(keeper_portfolio, false),
            AccountMeta::new_readonly(fresh0, false),
        ],
        &[],
    );
    assert!(
        ok.is_ok(),
        "valid single-observation crank remains live after duplicate rejection: {ok:?}"
    );
    let (cfg, group) = env.market_state();
    assert_eq!(cfg.last_good_oracle_slot, 2);
    assert_eq!(group.assets[0].raw_oracle_target_price, 210_000);
    assert_eq!(
        group.assets[1].raw_oracle_target_price, 300_000,
        "duplicate rejection and valid retry do not touch the unrelated observed asset"
    );
}

// Public auto-crank observation sweep: a later observation can fail with a raw
// NotEnoughAccountKeys error after an earlier observation has already updated the
// in-memory oracle profile. That error must still roll back the whole instruction.
