// hostile public-interface sweep: even the legitimate oracle authority must not be able to
// reconfigure an oracle anchor/mode after traders have live exposure. Otherwise a compromised or
// adversarial authority could reset the official price basis under open positions and cause LoF/DoS.
#[test]
fn v16_attack_oracle_reconfiguration_rejects_after_positions_enter_market() {
    let mut env = V16CuEnv::new();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 10_000);
    env.deposit(&short_owner, short_account, 10_000);
    env.trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );

    let before = env.svm.get_account(&env.market).unwrap().data;
    let (_, before_group) = state::read_market(&before).unwrap();
    assert_eq!(before_group.assets[0].oi_eff_long_q, POS_SCALE);
    assert_eq!(before_group.assets[0].oi_eff_short_q, POS_SCALE);

    env.svm.warp_to_slot(1);
    env.svm.expire_blockhash();
    let auth_reconfig = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureAuthMark {
            asset_index: 0,
            now_slot: 1,
            initial_mark_e6: 500,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(
        auth_reconfig.is_err(),
        "AuthMark reconfiguration with live OI must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "failed AuthMark reconfiguration must not mutate market state"
    );

    env.svm.expire_blockhash();
    let ewma_reconfig = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureEwmaMark {
            asset_index: 0,
            now_slot: 1,
            initial_mark_e6: 500,
            mark_ewma_halflife_slots: 1,
            mark_min_fee: 0,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&env.admin],
    );
    assert!(
        ewma_reconfig.is_err(),
        "EwmaMark reconfiguration with live OI must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "failed EwmaMark reconfiguration must not mutate market state"
    );

    let feed = [42u8; 32];
    let pyth = env.set_pyth_price(&feed, 500, 0, 1);
    let mut feeds = [[0u8; 32]; percolator_prog::constants::ORACLE_LEG_CAP];
    feeds[0] = feed;
    env.svm.expire_blockhash();
    let hybrid_reconfig = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::ConfigureHybridOracle {
            asset_index: 0,
            now_slot: 1,
            now_unix_ts: 1,
            oracle_leg_count: 1,
            oracle_leg_flags: 0,
            max_staleness_secs: 60,
            hybrid_soft_stale_slots: 3,
            mark_ewma_halflife_slots: 1,
            mark_min_fee: 0,
            invert: 0,
            unit_scale: 0,
            conf_filter_bps: 500,
            oracle_leg_feeds: feeds,
        },
        vec![
            AccountMeta::new(env.admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(pyth, false),
        ],
        &[&env.admin],
    );
    assert!(
        hybrid_reconfig.is_err(),
        "Hybrid reconfiguration with live OI must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap().data,
        before,
        "failed Hybrid reconfiguration must not mutate market state"
    );
}

// security.md sweep — EWMA-mark mode respects the per-slot circuit breaker (#6/#9/#37): the auth-mark
// test (#10533) proves AUTH_MARK clamps to <= max_price_move_bps_per_slot; EWMA_MARK is a SEPARATE
// pricing mode (halflife smoothing toward a pushed mark) and could, if the clamp lived only in the
// auth-mark path, let the mark authority move the effective settlement price arbitrarily fast in one
// slot. Attacker goal: as mark authority, push the EWMA mark to 100x and have the NEXT crank settle the
// effective price (used for liquidation/funding/PnL) at the full 100x in a single slot. Protection: the
// per-slot move gate is mode-INDEPENDENT — it lives in accrue_asset_to_not_atomic (percolator/src/v16.rs:
// 8052: price_diff*MAX_MARGIN_BPS <= max_price_move_bps_per_slot*segment_dt*old_price, else RecoveryRequired),
// so an EWMA push beyond the budget either clamps or is refused; the effective price cannot jump past the
// per-slot cap. Complements #10533 with the EWMA mode.
#[test]
fn v16_attack_ewma_mark_respects_per_slot_circuit_breaker() {
    const INITIAL_PRICE: u64 = 1_000_000;
    const MOVE_BPS: u64 = 1_000; // 10% / slot circuit breaker
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: INITIAL_PRICE,
        max_price_move_bps_per_slot: MOVE_BPS,
        max_accrual_dt_slots: 1,
        max_abs_funding_e9_per_slot: 1_000,
        min_funding_lifetime_slots: 1,
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(0);
    // EWMA mark mode with an aggressive halflife (1 slot) so the smoothed target races toward any push.
    env.configure_ewma_mark_with_cu(0, INITIAL_PRICE, 1, 0);
    let lo_owner = Keypair::new();
    let lo = env.create_portfolio(&lo_owner);
    let sh_owner = Keypair::new();
    let sh = env.create_portfolio(&sh_owner);
    env.deposit(&lo_owner, lo, 50_000_000);
    env.deposit(&sh_owner, sh, 50_000_000);
    // open matched OI so equity is active (the move gate at v16.rs:8060 only fires when equity_active).
    env.trade_asset_with_cu(
        0,
        &lo_owner,
        lo,
        &sh_owner,
        sh,
        POS_SCALE as i128,
        INITIAL_PRICE,
        0,
    );

    let mut prev_price = INITIAL_PRICE;
    // push the EWMA mark to 100x EVERY slot and crank; the effective price must never jump past the cap.
    for slot in 1..=4u64 {
        env.svm.warp_to_slot(slot);
        env.push_ewma_mark_with_cu(slot, INITIAL_PRICE * 100); // 100,000,000 — 100x
        env.svm.expire_blockhash();
        // crank may succeed (clamped move) or be refused (RecoveryRequired) — either way price is bounded.
        let _ = env.send(
            ProgInstruction::PermissionlessCrank {
                now_slot: slot,
                close_q: 0,
                observations: crank_observations(0),
            },
            vec![
                AccountMeta::new(env.payer.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(lo, false),
            ],
            &[],
        );
        let g = env.market_state().1;
        let ep = g.assets[0].effective_price;
        // PER-SLOT CAP: the move from the previous settled price is at most MOVE_BPS (10%); a small
        // tolerance covers rounding in the EWMA target. The mark authority CANNOT jump the price 100x.
        let cap = prev_price + prev_price * (MOVE_BPS + 1) / 10_000;
        assert!(
            ep <= cap,
            "slot {}: effective price {} clamped to <= per-slot cap {} (prev {})",
            slot,
            ep,
            cap,
            prev_price
        );
        prev_price = ep;
        assert!(
            g.vault >= g.c_tot + g.insurance,
            "senior conservation under clamped EWMA move"
        );
        assert_eq!(
            g.vault as u64,
            env.token_amount(env.vault),
            "accounting vault == real on-chain vault"
        );
    }
    // NON-VACUITY + the headline: after FOUR slots of pushing to 100,000,000, the effective settlement
    // price is still nowhere near it — the EWMA mode did NOT bypass the circuit breaker.
    let final_price = env.market_state().1.assets[0].effective_price;
    assert!(final_price < INITIAL_PRICE * 2, "after 4 clamped slots the price ({}) is far below the 100x push (circuit breaker held across EWMA mode)", final_price);
    // NON-VACUITY: the price DID move toward the push (the clamp throttled a real move, it wasn't a no-op).
    assert!(
        final_price > INITIAL_PRICE,
        "the EWMA mark actually moved the price (clamped, not frozen): {} > {}",
        final_price,
        INITIAL_PRICE
    );
}

// security.md sweep — crank dt-clamp prevents retroactive one-shot settlement after a long gap (#9/#22):
// the per-crank segment is clamped to max_accrual_dt_slots (percolator/src/v16.rs:8037), and a crank
// advances slot_last by only that clamped segment (v16.rs:8089), NOT all the way to now_slot. This dt is
// the multiplier on EVERY time-scaled accrual (funding: v16.rs:8072 funding_rate*segment_dt*price; and the
// price-move budget: v16.rs:8057 cap*segment_dt). Attacker goal: leave the market un-cranked for a long
// time so a large accrual window builds up, then fire ONE crank to retroactively settle the FULL elapsed
// window in a single shot — a one-block funding windfall to the favoured side, or a surprise margin blow-up
// of the other side that skips the per-slot price-move circuit breaker. Protection: each crank settles at
// most max_accrual_dt_slots; slot_last creeps forward by the clamp per crank, so catch-up is bounded and
// many cranks (each itself re-clamped) are required to close the gap — no one-shot retroactive settlement.
// (Not covered by the conservation tests, which all crank every slot so dt is always 1.)
#[test]
fn v16_attack_crank_dt_clamp_blocks_retroactive_settle() {
    const INITIAL_PRICE: u64 = 1_000_000;
    const DT_CLAMP: u64 = 3; // max_accrual_dt_slots
    let mut env = V16CuEnv::new_with_init_params(V16CuMarketParams {
        initial_price: INITIAL_PRICE,
        max_price_move_bps_per_slot: 1_000,
        max_accrual_dt_slots: DT_CLAMP,
        max_abs_funding_e9_per_slot: 1_000,
        min_funding_lifetime_slots: DT_CLAMP, // lifetime >= accrual window (config validity)
        ..V16CuMarketParams::default()
    });
    env.svm.warp_to_slot(0);
    env.configure_ewma_mark_with_cu(0, INITIAL_PRICE, 1, 0);
    let lo_owner = Keypair::new();
    let lo = env.create_portfolio(&lo_owner);
    let sh_owner = Keypair::new();
    let sh = env.create_portfolio(&sh_owner);
    env.deposit(&lo_owner, lo, 50_000_000);
    env.deposit(&sh_owner, sh, 50_000_000);
    env.trade_asset_with_cu(
        0,
        &lo_owner,
        lo,
        &sh_owner,
        sh,
        POS_SCALE as i128,
        INITIAL_PRICE,
        0,
    );
    let slot_last_0 = env.market_state().1.assets[0].slot_last;
    assert_eq!(
        slot_last_0, 0,
        "asset starts settled at slot 0 (open position is live)"
    );

    // ATTACK: leave the market UNCRANKED for a huge window, then fire ONE crank that tries to settle it all.
    const GAP_SLOT: u64 = 500;
    env.svm.warp_to_slot(GAP_SLOT);
    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: GAP_SLOT,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(lo, false),
        ],
        &[],
    );
    assert!(r.is_ok(), "the catch-up crank itself succeeds: {:?}", r);

    let g1 = env.market_state().1;
    // ANTI-RETROACTIVITY (the headline): the settled segment is the dt CLAMP (3), NOT the 500-slot gap.
    // A naive retroactive settle would jump slot_last to 500 and apply ~166x the funding/move budget in one
    // block; the clamp holds the advance to exactly max_accrual_dt_slots.
    assert_eq!(
        g1.assets[0].slot_last,
        slot_last_0 + DT_CLAMP,
        "one crank settles only max_accrual_dt_slots ({}), NOT the full {}-slot gap (slot_last={})",
        DT_CLAMP,
        GAP_SLOT,
        g1.assets[0].slot_last
    );
    assert!(GAP_SLOT > 50 * DT_CLAMP, "non-vacuous: the elapsed gap ({}) dwarfs the clamp ({}) — the clamp is the binding constraint", GAP_SLOT, DT_CLAMP);
    assert_eq!(
        g1.current_slot, GAP_SLOT,
        "header current_slot advances to now (the asset is intentionally left 'behind' by design)"
    );
    // conservation: whatever was settled is internal redistribution; nothing minted.
    assert_eq!(
        g1.vault, 100_000_000,
        "vault unchanged (settlement mints nothing)"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
    assert!(
        g1.vault >= g1.c_tot + g1.insurance,
        "senior conservation under the clamped catch-up"
    );

    // A SECOND crank at the same now_slot advances slot_last by ANOTHER clamp window — catch-up is bounded
    // PER crank, so closing a 500-slot gap needs ~167 separately-clamped cranks, each re-subject to the
    // per-slot price-move circuit breaker. There is no single transaction that settles the whole window.
    env.svm.expire_blockhash();
    let r2 = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: GAP_SLOT,
            close_q: 0,
            observations: crank_observations(0),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(lo, false),
        ],
        &[],
    );
    assert!(r2.is_ok(), "second catch-up crank succeeds: {:?}", r2);
    let g2 = env.market_state().1;
    assert_eq!(
        g2.assets[0].slot_last,
        slot_last_0 + 2 * DT_CLAMP,
        "second crank advances another clamp window (bounded per-crank catch-up)"
    );
    assert!(g2.assets[0].slot_last < GAP_SLOT, "even after two cranks the asset is still far short of the gap (catch-up is throttled, not instant)");
    assert!(
        g2.vault >= g2.c_tot + g2.insurance,
        "senior conservation after second crank"
    );
}

// security.md sweep — haircut rounding across MANY tiny winners (#22/#33/#35): when the backing residual
// is smaller than total positive-pnl claims, the haircut rate h = residual / total_claims is applied to
// each winner's claim. The classic precision attack on any proportional split is per-winner round-UP: with
// N winners each rounding their floor(claim_i * h) UP, the summed payout can exceed the residual, MINTING
// value from rounding dust. The 2-winner test (#11314) checks proportionality; this stresses the rounding
// edge with EIGHT winners holding coprime claims against a tiny residual (max cumulative rounding error).
// Attacker goal: split a claim across many small accounts so the rounded-up dust sums to more than the
// backing actually held — a free mint. Protection: the engine rounds haircut payouts conservatively
// (down/toward the protocol), so sum(payouts) <= residual no matter how the claims are partitioned.
#[test]
fn v16_attack_haircut_rounding_many_winners_no_mint() {
    const BACKING: u128 = 100; // tiny residual -> aggressive haircut, max rounding pressure
                               // eight coprime/awkward claims so claim_i * h rarely lands on an integer (forces rounding every winner).
    const CLAIMS: [u128; 8] = [7, 11, 13, 17, 19, 23, 29, 31]; // sum = 150 >> 100 backing
    let mut env = V16CuEnv::new();
    env.top_up_backing_bucket(1, BACKING, 10_000);
    let mut owners = Vec::new();
    let mut ports = Vec::new();
    for &claim in CLAIMS.iter() {
        let o = Keypair::new();
        let p = env.create_portfolio(&o);
        env.deposit(&o, p, 1_000);
        env.add_source_positive_pnl(p, 1, claim);
        owners.push(o);
        ports.push(p);
    }
    let total_claims: u128 = CLAIMS.iter().sum();
    assert!(
        total_claims > BACKING,
        "non-vacuous: claims ({}) exceed backing ({}) so the haircut bites",
        total_claims,
        BACKING
    );

    env.resolve();
    // converge the terminal haircut rate across all winners (a few passes, like the 2-winner test).
    let mut hc_total = 0u128;
    let mut payouts = vec![0u128; CLAIMS.len()];
    for _ in 0..3 {
        for (i, (o, p)) in owners.iter().zip(ports.iter()).enumerate() {
            let d = env.close_resolved(o, *p);
            payouts[i] += env.token_amount(d) as u128;
        }
    }
    // haircut payout = anything paid ABOVE each winner's own senior capital (1_000 deposited).
    for (i, &paid) in payouts.iter().enumerate() {
        let hc = paid.saturating_sub(1_000);
        hc_total += hc;
        // each winner's haircut payout is bounded by its own claim (never paid MORE than it claimed).
        assert!(
            hc <= CLAIMS[i],
            "winner {} haircut payout {} <= its claim {}",
            i,
            hc,
            CLAIMS[i]
        );
    }
    // THE HEADLINE: summed haircut payout across all eight winners never exceeds the backing residual —
    // per-winner rounding dust cannot accumulate into a mint, however the claims are partitioned.
    assert!(
        hc_total <= BACKING,
        "summed haircut payout {} must not exceed backing {} (no rounding mint)",
        hc_total,
        BACKING
    );
    // non-vacuity: the haircut actually paid out a meaningful fraction of the backing (not a degenerate zero).
    assert!(
        hc_total > BACKING / 2,
        "non-vacuous: the winners collectively received a real haircut payout ({} of {})",
        hc_total,
        BACKING
    );
    // conservation: no vault minting, senior invariant intact.
    let (_, g) = env.market_state();
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation after many-winner haircut"
    );
}

// security.md sweep — market capacity: >64 assets per market + a position holding any 14 legs (#22/#32).
// The real per-market asset count is config.max_market_slots (u32), grown one slot at a time by
// handle_update_asset_lifecycle's append/realloc path.
// There is NO hardcoded 64 cap. This test proves: (1) a single market grows to >64 assets, (2) the per-
// position leg cap stays at WRAPPER_MAX_PORTFOLIO_ASSETS=14 INDEPENDENT of the market's asset count, and
// (3) a position can carry 14 legs drawn from arbitrary HIGH indices across the full set (not just 0..13).
// Conservation holds across a 14-leg cross-margin portfolio spanning the grown asset set.
#[test]
fn v16_attack_market_exceeds_64_assets_position_holds_any_14_legs() {
    const PRICE: u64 = 100;
    const TARGET: usize = 70;
    // per-position leg cap = 14; the market starts with 14 configured asset slots (max_market_slots == 14).
    // The account is PRE-SIZED to capacity TARGET so init sets asset_slot_capacity=TARGET (init derives it
    // from the account length, src/v16_program.rs:2397). This exercises the append-grow LOGIC (max_market_slots
    // bumping 14->TARGET) independently of in-instruction realloc (which LiteSVM handles separately).
    let mut env = V16CuEnv::new_with_init_params_and_market_capacity(
        V16CuMarketParams {
            max_portfolio_assets: 14,
            maintenance_margin_bps: 10_000,
            initial_margin_bps: 10_000,
            max_price_move_bps_per_slot: 10_000,
            ..V16CuMarketParams::default()
        },
        TARGET,
    );
    let start = env.market_state().1.config.max_market_slots as usize;
    assert_eq!(
        start, 14,
        "market starts at 14 configured slots (== per-position leg cap)"
    );

    // GROW PAST 64: append new asset slots as the asset_authority (admin => fee-free). Each append reallocs
    // the market account (+1 slot) and bumps max_market_slots by one — the genuine on-chain grow path
    // (handle_update_asset_lifecycle append: src/v16_program.rs:8620 realloc + :8728 activate_dynamic_asset_slot).
    // NOTE: each activation MUST occur at a strictly-advancing slot (the append enforces slot progress); two
    // activations in the same slot are rejected. There is NO hardcoded 64 cap (the line-81 comment is stale).
    for idx in start..TARGET {
        env.activate_asset(idx as u16, idx as u64 + 1, PRICE);
    }
    let g = env.market_state().1;
    assert!(
        g.config.max_market_slots as usize >= 65,
        "market grew PAST 64 assets (max_market_slots={})",
        g.config.max_market_slots
    );
    assert_eq!(
        g.config.max_market_slots as usize, TARGET,
        "grew to exactly {} assets",
        TARGET
    );
    assert!(
        g.assets.len() >= TARGET,
        "asset array reallocated to hold the grown set (len={})",
        g.assets.len()
    );
    // the per-position leg cap is UNCHANGED by the market's asset count.
    assert_eq!(
        g.config.max_portfolio_assets, 14,
        "per-position leg cap stays 14 regardless of the >64 asset count"
    );

    // move past the activation slots; configure marks + trade in a single later slot.
    const TRADE_SLOT: u64 = TARGET as u64 + 10;
    env.svm.warp_to_slot(TRADE_SLOT);

    // ANY 14 LEGS FROM THE FULL SET: a single portfolio opens positions on 14 distinct HIGH indices
    // (all > 14, i.e. from the grown region), proving a position can hold any 14 of the >64 assets.
    let cfg_auth_mark = |env: &mut V16CuEnv, ai: u16| {
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::ConfigureAuthMark {
                asset_index: ai,
                now_slot: TRADE_SLOT,
                initial_mark_e6: PRICE,
            },
            vec![
                AccountMeta::new(env.admin.pubkey(), true),
                AccountMeta::new(env.market, false),
            ],
            &[&env.admin],
        )
        .expect("configure auth mark for high asset index");
    };
    let legs: [u16; 14] = [15, 19, 23, 28, 31, 37, 41, 47, 52, 56, 60, 63, 66, 69];
    for &ai in legs.iter() {
        cfg_auth_mark(&mut env, ai);
    }

    // portfolios in an N-asset market are sized for max_market_slots (2N source-domain slots): pre-size the
    // portfolio account to the grown N so InitPortfolio allocates it up front (the genuine on-chain flow;
    // a single realloc across a large N jump would exceed Solana's 10240-byte per-instruction limit).
    env.portfolio_account_len = state::portfolio_account_len_for_market_slots(TARGET).unwrap();
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 5_000_000);
    env.deposit(&lb, pb, 5_000_000);
    for &ai in legs.iter() {
        env.svm.expire_blockhash();
        env.trade_asset_with_cu(ai, &la, pa, &lb, pb, POS_SCALE as i128, PRICE, 0);
    }
    // all 14 high-index legs are open on the SAME portfolio.
    let g2 = env.market_state().1;
    for &ai in legs.iter() {
        assert!(
            g2.assets[ai as usize].oi_eff_long_q > 0,
            "leg on high asset index {} is open",
            ai
        );
        assert_eq!(
            g2.assets[ai as usize].oi_eff_long_q, g2.assets[ai as usize].oi_eff_short_q,
            "asset {} OI balanced",
            ai
        );
    }
    // The 14 legs are drawn from arbitrary HIGH indices (15..69) of the 70-asset set — proving a position
    // can carry any 14 of the >64 assets, not just the first 14. (The per-position leg cap is bounded by the
    // engine portfolio bitmap, independent of the market's total asset count.)

    // conservation across the 14-leg cross-margin portfolio spanning the grown set.
    assert_eq!(
        g2.c_tot, 10_000_000,
        "no capital created/destroyed across the 14-leg multi-asset portfolio"
    );
    assert_eq!(
        g2.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
    assert!(
        g2.vault >= g2.c_tot + g2.insurance,
        "senior conservation across a >64-asset market"
    );
}

// security.md sweep — cross-asset domain-insurance isolation (#22/#32): a permissionless asset is
// untrusted, so a position/insolvency on asset 1 must NEVER consume asset 0's domain insurance. The
// existing isolation test (#13376) checks OI/ADL/price isolation; this checks the per-DOMAIN INSURANCE
// budget. Attacker goal: drive an insolvency (bad debt) on asset 1 and have its socialization reach into
// asset 0's funded domain-insurance budget (draining funds that back asset-0 traders). Protection: domain
// insurance budgets are per-domain (asset i -> domains 2i, 2i+1); asset-1 bad debt is bounded to asset-1's
// own domains, so asset 0's domain-insurance bytes are unchanged. Senior conservation holds throughout.
#[test]
fn v16_attack_asset1_insolvency_cannot_drain_asset0_domain_insurance() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    // fund BOTH assets' domain insurance (asset 0 -> domains 0,1; asset 1 -> domains 2,3). admin is the
    // domain insurance authority for every domain (set at init / activation).
    let admin = env.admin.insecure_clone();
    env.top_up_insurance_domain_with_authority(&admin, 0, 1_000);
    env.top_up_insurance_domain_with_authority(&admin, 1, 1_000);
    env.top_up_insurance_domain_with_authority(&admin, 2, 500);
    env.top_up_insurance_domain_with_authority(&admin, 3, 500);
    let g0 = env.market_state().1;
    let a0_dom0 = g0.insurance_domain_budget[0];
    let a0_dom1 = g0.insurance_domain_budget[1];
    assert_eq!(a0_dom0, 1_000, "asset-0 long-domain insurance funded");
    assert_eq!(a0_dom1, 1_000, "asset-0 short-domain insurance funded");

    // asset-1 position: tiny-capital short that will be driven insolvent (bad debt on asset 1).
    let a1o = Keypair::new();
    let a1 = env.create_portfolio(&a1o);
    let b1o = Keypair::new();
    let b1 = env.create_portfolio(&b1o);
    env.deposit(&a1o, a1, 1_000_000);
    env.deposit(&b1o, b1, 250); // tiny -> insolvent short
    env.trade_asset_with_cu(1, &a1o, a1, &b1o, b1, POS_SCALE as i128, 100, 0);

    // push ONLY asset-1 mark up across slots (each step <= 2x, within the 100%/slot breaker): 100->800.
    // short's loss (units * (P-100)) = 1 * 700 = 700 >> 250 capital -> insolvent.
    for (slot, mark) in [(2u64, 200u64), (3, 400), (4, 800)] {
        env.svm.warp_to_slot(slot);
        env.push_auth_mark_for_asset_as_admin(1, slot, mark);
        for p in [a1, b1] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(1),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    // liquidate the insolvent asset-1 short (socializes its bad debt).
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 4,
            close_q: POS_SCALE,
            observations: crank_observations(1),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(b1, false),
        ],
        &[],
    );

    let g1 = env.market_state().1;
    // non-vacuity: asset-1 actually reached insolvency.
    assert_eq!(
        env.portfolio_state(b1).capital.get(),
        0,
        "asset-1 short was driven insolvent (non-vacuous)"
    );
    assert!(
        g1.assets[1].effective_price >= 200,
        "asset-1 mark actually moved (non-vacuous, got {})",
        g1.assets[1].effective_price
    );
    // ISOLATION (headline): asset-0's domain insurance budgets are byte-identical — asset-1 bad debt
    // could not reach into asset-0's insurance.
    assert_eq!(
        g1.insurance_domain_budget[0], a0_dom0,
        "asset-0 long-domain insurance UNTOUCHED by asset-1 insolvency"
    );
    assert_eq!(
        g1.insurance_domain_budget[1], a0_dom1,
        "asset-0 short-domain insurance UNTOUCHED by asset-1 insolvency"
    );
    // senior conservation + accounting integrity across the whole sequence.
    assert!(
        g1.vault >= g1.c_tot + g1.insurance,
        "senior conservation under cross-asset insolvency"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting vault == real on-chain vault"
    );
}

// Product spec — per-asset cold-storage admin keys (governance): EVERY asset (including asset 0) has
// its OWN admin that can rotate that asset's domain authorities (insurance/operator/backing/oracle)
// and itself, and the asset admin can be BURNED to 0; isolated — it can never act on another asset. Asset 0's
// asset_admin is bootstrapped to the market admin at InitMarket and is rotated/burned through the same
// UpdateAssetAuthority path as assets 1..N. Each domain authority can also self-rotate through a
// co-signed handoff, but cannot be burned to zero after activation.
#[test]
fn v16_attack_per_asset_admin_rotates_keys_isolated_and_burnable() {
    let mut env = V16CuEnv::new(); // 1 slot (asset 0); asset 1 is APPENDED permissionlessly below
    env.configure_auth_mark_with_cu(0, 100);
    env.activate_asset(1, 2, 100); // APPEND asset 1 -> profile.asset_admin bootstraps to the activator (admin)
    let prof = |env: &V16CuEnv, ai: usize| {
        state::read_asset_oracle_profile(&env.svm.get_account(&env.market).unwrap().data, ai)
            .unwrap()
    };
    assert_eq!(
        prof(&env, 1).asset_admin,
        env.admin.pubkey().to_bytes(),
        "asset-1 admin = activator"
    );
    // asset 0 carries a real stored profile whose asset_admin is the market admin (bootstrapped at init).
    assert_eq!(
        prof(&env, 0).asset_admin,
        env.admin.pubkey().to_bytes(),
        "asset-0 admin = market admin"
    );
    let admin = env.admin.insecure_clone();
    let upd = |env: &mut V16CuEnv,
               signer: &Keypair,
               co: Option<&Keypair>,
               ai: u16,
               kind: u8,
               new: [u8; 32]| {
        env.ensure_signer_account(signer.pubkey());
        let mut signers = vec![signer];
        let co_key = co
            .map(|k| {
                env.ensure_signer_account(k.pubkey());
                k.pubkey()
            })
            .unwrap_or(env.payer.pubkey());
        if let Some(k) = co {
            signers.push(k);
        }
        env.svm.expire_blockhash();
        send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::UpdateAssetAuthority {
                asset_index: ai,
                kind,
                new_pubkey: new,
            },
            vec![
                AccountMeta::new(signer.pubkey(), true),
                AccountMeta::new(co_key, co.is_some()),
                AccountMeta::new(env.market, false),
            ],
            &signers,
        )
    };

    // 1) the per-asset admin rotates the asset's ORACLE authority (new key co-signs).
    let new_oracle = Keypair::new();
    assert!(
        upd(
            &mut env,
            &admin,
            Some(&new_oracle),
            1,
            processor::ASSET_AUTH_ORACLE,
            new_oracle.pubkey().to_bytes()
        )
        .is_ok(),
        "per-asset admin rotates the asset's oracle authority"
    );
    assert_eq!(
        prof(&env, 1).oracle_authority,
        new_oracle.pubkey().to_bytes(),
        "oracle authority rotated"
    );

    // 2) a non-admin / non-holder cannot rotate.
    let mallory = Keypair::new();
    let m2 = Keypair::new();
    assert!(
        upd(
            &mut env,
            &mallory,
            Some(&m2),
            1,
            processor::ASSET_AUTH_INSURANCE,
            m2.pubkey().to_bytes()
        )
        .is_err(),
        "non-admin cannot rotate the asset's authorities"
    );

    // 3) ASSET 0 uses the SAME per-asset path: its asset_admin (the market admin) rotates asset-0's
    //    insurance authority — and this is ISOLATED, leaving asset 1's authorities byte-identical.
    let a0_ins = Keypair::new();
    let a1_oracle_before = prof(&env, 1).oracle_authority;
    let a1_ins_before = prof(&env, 1).insurance_authority;
    assert!(
        upd(
            &mut env,
            &admin,
            Some(&a0_ins),
            0,
            processor::ASSET_AUTH_INSURANCE,
            a0_ins.pubkey().to_bytes()
        )
        .is_ok(),
        "asset-0 admin rotates asset-0 insurance authority via UpdateAssetAuthority"
    );
    assert_eq!(
        prof(&env, 0).insurance_authority,
        a0_ins.pubkey().to_bytes(),
        "asset-0 insurance authority rotated"
    );
    assert_eq!(
        prof(&env, 1).oracle_authority,
        a1_oracle_before,
        "asset-1 oracle UNTOUCHED by asset-0 rotation"
    );
    assert_eq!(
        prof(&env, 1).insurance_authority,
        a1_ins_before,
        "asset-1 insurance UNTOUCHED by asset-0 rotation"
    );

    // 3b) ISOLATION the other way: the asset-1 admin cannot reach asset 0.
    let a0_prof_before = prof(&env, 0);
    assert!(
        upd(
            &mut env,
            &admin,
            Some(&new_oracle),
            1,
            processor::ASSET_AUTH_ORACLE,
            new_oracle.pubkey().to_bytes()
        )
        .is_ok(),
        "asset-1 admin rotates asset-1 oracle (re-establish a known holder)"
    );
    assert_eq!(
        prof(&env, 0).insurance_authority,
        a0_prof_before.insurance_authority,
        "asset-0 insurance UNTOUCHED by asset-1 rotation"
    );
    assert_eq!(
        prof(&env, 0).asset_admin,
        a0_prof_before.asset_admin,
        "asset-0 admin UNTOUCHED by asset-1 rotation"
    );

    // 4) BURN the per-asset admin to 0 (asset becomes credibly admin-free).
    assert!(
        upd(
            &mut env,
            &admin,
            None,
            1,
            processor::ASSET_AUTH_ADMIN,
            [0u8; 32]
        )
        .is_ok(),
        "asset admin can be burned"
    );
    assert_eq!(prof(&env, 1).asset_admin, [0u8; 32], "asset-1 admin burned");

    // 5) after burn the admin can't be revived (no live admin to sign)...
    assert!(
        upd(
            &mut env,
            &admin,
            Some(&admin),
            1,
            processor::ASSET_AUTH_ADMIN,
            admin.pubkey().to_bytes()
        )
        .is_err(),
        "a burned asset admin cannot be revived"
    );
    // ...but a domain authority still self-rotates (its current holder signs).
    let cold = Keypair::new();
    assert!(
        upd(
            &mut env,
            &new_oracle,
            Some(&cold),
            1,
            processor::ASSET_AUTH_ORACLE,
            cold.pubkey().to_bytes()
        )
        .is_ok(),
        "domain authority self-rotates even after the asset admin is burned"
    );
    assert_eq!(
        prof(&env, 1).oracle_authority,
        cold.pubkey().to_bytes(),
        "oracle self-rotated post-burn"
    );

    // 6) asset-0 admin can also BURN asset-0's own admin (same as 1..N).
    assert!(
        upd(
            &mut env,
            &admin,
            None,
            0,
            processor::ASSET_AUTH_ADMIN,
            [0u8; 32]
        )
        .is_ok(),
        "asset-0 admin can be burned"
    );
    assert_eq!(prof(&env, 0).asset_admin, [0u8; 32], "asset-0 admin burned");
}

// security.md sweep — zero required authority anti-brick (#6/#30/#48): activation rejects zero domain
// authorities because they can strand domain funds or oracle liveness during terminal wind-down.
// UpdateAssetAuthority must preserve that invariant too: an admin/operator cannot burn the
// insurance/operator/backing/oracle authorities to zero after activation. The domains remain
// withdrawable after resolve.
#[test]
fn v16_attack_update_asset_authority_rejects_zero_domain_authority() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    env.top_up_insurance_domain_with_authority(&admin, 0, 500);
    env.top_up_backing_bucket_with_authority(&admin, 0, 300, 100_000);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let (_, group_before) = env.market_state();
    assert_eq!(
        group_before.insurance_domain_budget[0], 500,
        "funded domain makes the test non-vacuous"
    );
    assert_eq!(
        group_before.source_backing_buckets[0].fresh_unliened_backing_num,
        300 * BOUND_SCALE,
        "funded backing bucket makes the backing-authority case non-vacuous"
    );

    for (kind, label) in [
        (processor::ASSET_AUTH_INSURANCE, "insurance authority"),
        (
            processor::ASSET_AUTH_INSURANCE_OPERATOR,
            "insurance operator",
        ),
        (processor::ASSET_AUTH_BACKING_BUCKET, "backing authority"),
        (processor::ASSET_AUTH_ORACLE, "oracle authority"),
    ] {
        env.svm.expire_blockhash();
        let burn = send_tx(
            &mut env.svm,
            env.program_id,
            &env.payer,
            ProgInstruction::UpdateAssetAuthority {
                asset_index: 0,
                kind,
                new_pubkey: [0u8; 32],
            },
            vec![
                AccountMeta::new(admin.pubkey(), true),
                AccountMeta::new_readonly(Pubkey::default(), false),
                AccountMeta::new(env.market, false),
            ],
            &[&admin],
        );
        assert!(
            burn.is_err(),
            "burning the {label} would strand funds or oracle liveness after terminal resolve"
        );
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "rejected {label} burn leaves market state unchanged"
        );
        assert_eq!(
            env.svm.get_account(&env.vault).unwrap(),
            vault_before,
            "rejected {label} burn does not touch real vault tokens"
        );
    }

    env.resolve();
    let (insurance_dest, insurance_cu) =
        env.withdraw_terminal_insurance_with_authority(&admin, 500);
    assert_cu_within(
        "terminal insurance after rejected zero-authority burn",
        insurance_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(insurance_dest),
        500,
        "original insurance authority can recover the funded domain"
    );
    assert_eq!(
        env.market_state().1.insurance,
        0,
        "insurance fully drained for CloseSlab"
    );
    let backing_dest = env.token_account(admin.pubkey(), 0);
    let backing_cu = env.withdraw_backing_bucket_to_admin_token_with_cu(backing_dest, 0, 300);
    assert_cu_within(
        "terminal backing after rejected zero-authority burn",
        backing_cu,
        CUSTODY_CU_LIMIT,
    );
    assert_eq!(
        env.token_amount(backing_dest),
        300,
        "original backing authority can recover the funded bucket"
    );
    env.close_slab_with_cu();
}

// Product spec — cross-asset BACKING isolation (counterpart to the domain-insurance isolation test):
// a faulty/insolvent permissionless asset must not drain ANOTHER asset's backing bucket. Fund both
// assets' backing, drive asset 1 insolvent + liquidate, and assert asset 0's backing buckets are
// byte-identical.
#[test]
fn v16_attack_asset1_insolvency_cannot_drain_asset0_backing() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    // fund BOTH assets' backing buckets (asset 0 -> domains 0,1; asset 1 -> domains 2,3), long expiry.
    env.top_up_backing_bucket(0, 1_000, 100_000);
    env.top_up_backing_bucket(1, 1_000, 100_000);
    env.top_up_backing_bucket(2, 500, 100_000);
    env.top_up_backing_bucket(3, 500, 100_000);
    let bk = |env: &V16CuEnv, d: usize| {
        env.market_state().1.source_backing_buckets[d].fresh_unliened_backing_num
    };
    let (a0d0, a0d1) = (bk(&env, 0), bk(&env, 1));
    assert!(a0d0 > 0 && a0d1 > 0, "asset-0 backing funded (non-vacuous)");

    // asset-1: tiny-capital short driven insolvent (bad debt on asset 1).
    let a1o = Keypair::new();
    let a1 = env.create_portfolio(&a1o);
    let b1o = Keypair::new();
    let b1 = env.create_portfolio(&b1o);
    env.deposit(&a1o, a1, 1_000_000);
    env.deposit(&b1o, b1, 250);
    env.trade_asset_with_cu(1, &a1o, a1, &b1o, b1, POS_SCALE as i128, 100, 0);
    for (slot, mark) in [(2u64, 200u64), (3, 400), (4, 800)] {
        env.svm.warp_to_slot(slot);
        env.push_auth_mark_for_asset_as_admin(1, slot, mark);
        for p in [a1, b1] {
            env.svm.expire_blockhash();
            let _ = env.send(
                ProgInstruction::PermissionlessCrank {
                    now_slot: slot,
                    close_q: 0,
                    observations: crank_observations(1),
                },
                vec![
                    AccountMeta::new(env.payer.pubkey(), true),
                    AccountMeta::new(env.market, false),
                    AccountMeta::new(p, false),
                ],
                &[],
            );
        }
    }
    env.svm.expire_blockhash();
    let _ = env.send(
        ProgInstruction::PermissionlessCrank {
            now_slot: 4,
            close_q: POS_SCALE,
            observations: crank_observations(1),
        },
        vec![
            AccountMeta::new(env.payer.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(b1, false),
        ],
        &[],
    );

    let g1 = env.market_state().1;
    assert_eq!(
        env.portfolio_state(b1).capital.get(),
        0,
        "asset-1 short driven insolvent (non-vacuous)"
    );
    // ISOLATION: asset-0's backing buckets are byte-identical — asset-1 bad debt can't reach asset-0 backing.
    assert_eq!(
        g1.source_backing_buckets[0].fresh_unliened_backing_num, a0d0,
        "asset-0 long-domain backing UNTOUCHED"
    );
    assert_eq!(
        g1.source_backing_buckets[1].fresh_unliened_backing_num, a0d1,
        "asset-0 short-domain backing UNTOUCHED"
    );
    assert!(
        g1.vault >= g1.c_tot + g1.insurance,
        "senior conservation under cross-asset insolvency"
    );
    assert_eq!(
        g1.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// Product spec — force-shutdown with a timeout so traders can exit (no rug): marketauth can
// shut down any asset (ASSET_ACTION_SHUTDOWN -> RECOVERY with a frozen mark), but the permissionless
// force-close (which winds the asset down) is gated behind force_close_delay_slots. So there is a
// window after shutdown during which the asset is NOT yet force-closed — traders can exit — and only
// after the delay can the wind-down proceed. Asserts: shutdown -> RECOVERY; force-close REJECTS before
// the delay; force-close SUCCEEDS after it.
#[test]
fn v16_attack_force_shutdown_timeout_lets_traders_exit_before_close() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    env.configure_auth_mark_with_cu(0, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    const DELAY: u64 = 50;
    env.configure_permissionless_resolve_with_cu(100, DELAY); // force_close_delay_slots = 50

    // open an asset-1 position (a trader is exposed when the shutdown lands).
    let la = Keypair::new();
    let pa = env.create_portfolio(&la);
    let lb = Keypair::new();
    let pb = env.create_portfolio(&lb);
    env.deposit(&la, pa, 1_000_000);
    env.deposit(&lb, pb, 1_000_000);
    env.trade_asset_with_cu(1, &la, pa, &lb, pb, POS_SCALE as i128, 100, 0);

    // GATE: only `marketauth` or the asset's local asset_admin may shut an asset down. A fresh key
    // that is neither is rejected before any state changes.
    const SHUT: u64 = 10;
    env.svm.warp_to_slot(SHUT);
    env.svm.expire_blockhash();
    let mallory = Keypair::new();
    env.ensure_signer_account(mallory.pubkey());
    let stranger = send_tx(
        &mut env.svm,
        env.program_id,
        &env.payer,
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_SHUTDOWN,
            asset_index: 1,
            now_slot: SHUT,
            initial_price: 0,
            insurance_authority: mallory.pubkey().to_bytes(),
            insurance_operator: mallory.pubkey().to_bytes(),
            backing_bucket_authority: mallory.pubkey().to_bytes(),
            oracle_authority: mallory.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(mallory.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&mallory],
    );
    assert!(
        stranger.is_err(),
        "a signer that is neither marketauth nor asset_admin must NOT be able to force-shutdown an asset"
    );
    assert_eq!(
        env.market_state().1.assets[1].lifecycle,
        AssetLifecycleV16::Active,
        "asset 1 still ACTIVE after the rejected non-marketauth shutdown"
    );

    // marketauth (the init signer) force-shuts-down asset 1 at slot 10 -> RECOVERY (frozen mark, not yet wound down).
    env.svm.expire_blockhash();
    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_SHUTDOWN,
        1,
        SHUT,
        0,
    );
    assert_eq!(
        env.market_state().1.assets[1].lifecycle,
        AssetLifecycleV16::Recovery,
        "asset 1 is in RECOVERY after shutdown (not instantly force-closed)"
    );

    // WINDOW: before the delay elapses, the permissionless force-close is REJECTED -> traders still have
    // time to exit; the asset is not rugged out from under them.
    let cranker = Keypair::new();
    env.svm.warp_to_slot(SHUT + DELAY - 1);
    let early = env.try_force_close_abandoned_asset_with_cu(
        &cranker,
        pa,
        pb,
        1,
        SHUT + DELAY - 1,
        POS_SCALE,
    );
    assert!(
        early.is_err(),
        "force-close must REJECT before force_close_delay_slots elapses (exit window open)"
    );
    assert_eq!(
        env.market_state().1.assets[1].lifecycle,
        AssetLifecycleV16::Recovery,
        "asset still RECOVERY, not closed"
    );

    // after the delay, the wind-down may proceed.
    env.svm.warp_to_slot(SHUT + DELAY + 5);
    env.svm.expire_blockhash();
    let late = env.try_force_close_abandoned_asset_with_cu(
        &cranker,
        pa,
        pb,
        1,
        SHUT + DELAY + 5,
        POS_SCALE,
    );
    assert!(
        late.is_ok(),
        "force-close succeeds once the delay has elapsed: {:?}",
        late
    );
    let g = env.market_state().1;
    assert!(
        g.vault >= g.c_tot + g.insurance,
        "senior conservation across shutdown + delayed force-close"
    );
    assert_eq!(
        g.vault as u64,
        env.token_amount(env.vault),
        "accounting == real vault"
    );
}

// LoF/DoS sweep (cron135): shutdown puts an asset into Recovery with a frozen mark and a
// force-close delay so users can exit. The pushed-mark profile can still be AuthMark across
// that transition, so the public PushAuthMark route must be lifecycle-gated; otherwise the
// same oracle/admin key could move the recovery mark during the exit window.
#[test]
fn v16_attack_recovery_asset_push_auth_mark_is_frozen_until_restart() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 10_000, 10_000, 10_000);
    let admin = env.admin.insecure_clone();
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    env.configure_permissionless_resolve_with_cu(100, 50);

    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(1, 2, 120);
    let active_profile =
        state::read_asset_oracle_profile(&env.svm.get_account(&env.market).unwrap().data, 1)
            .unwrap();
    assert_eq!(
        active_profile.oracle_mode, ORACLE_MODE_AUTH_MARK,
        "setup is a non-vacuous pushed-mark asset"
    );
    assert_eq!(
        active_profile.oracle_target_price_e6, 120,
        "active pushed mark updated the per-asset oracle profile before shutdown"
    );

    env.svm.warp_to_slot(3);
    env.svm.expire_blockhash();
    env.try_shutdown_asset_with_authority(&admin, 1, 3)
        .expect("marketauth shuts down asset 1");
    assert_eq!(
        env.market_state().1.assets[1].lifecycle,
        AssetLifecycleV16::Recovery
    );
    let shutdown_profile =
        state::read_asset_oracle_profile(&env.svm.get_account(&env.market).unwrap().data, 1)
            .unwrap();
    assert_eq!(
        shutdown_profile.oracle_mode, ORACLE_MODE_AUTH_MARK,
        "shutdown preserved the pushed-mark profile, so this probes the lifecycle gate"
    );
    assert_eq!(
        shutdown_profile.mark_ewma_e6, 100,
        "shutdown freezes the profile back to the current effective mark"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    env.svm.warp_to_slot(4);
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::PushAuthMark {
            asset_index: 1,
            now_slot: 4,
            mark_e6: 200,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "Recovery asset marks must be frozen until RestartAssetOracle"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected recovery mark push leaves the frozen mark byte-identical"
    );

    env.svm.warp_to_slot(5);
    env.svm.expire_blockhash();
    env.try_restart_asset_oracle_with_authority(&admin, 1, 5, 125)
        .expect("asset admin can explicitly restart the recovery asset");
    env.configure_auth_mark_for_asset_as_admin(1, 5, 125);
    env.svm.warp_to_slot(6);
    env.push_auth_mark_for_asset_as_admin(1, 6, 130);
    assert_eq!(
        state::read_asset_oracle_profile(&env.svm.get_account(&env.market).unwrap().data, 1)
            .unwrap()
            .oracle_target_price_e6,
        130,
        "proper restart restores the normal pushed-mark path"
    );
}

// lifecycle sweep — explicit DrainOnly is a public UpdateAssetLifecycle action, distinct from
// shutdown/recovery. It must be marketauth-gated, reject malformed slot/price args, block new risk,
// and still let existing matched positions reduce to zero.
#[test]
fn v16_attack_drain_only_blocks_new_risk_but_allows_reduce() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 5_000, 10_000, 1_000);
    let admin = env.admin.insecure_clone();
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 1_000_000);
    env.trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    let before = env.svm.get_account(&env.market).unwrap();

    let stranger = Keypair::new();
    env.ensure_signer_account(stranger.pubkey());
    env.svm.expire_blockhash();
    let unauthorized = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_DRAIN_ONLY,
            asset_index: 0,
            now_slot: 0,
            initial_price: 0,
            insurance_authority: stranger.pubkey().to_bytes(),
            insurance_operator: stranger.pubkey().to_bytes(),
            backing_bucket_authority: stranger.pubkey().to_bytes(),
            oracle_authority: stranger.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(stranger.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&stranger],
    );
    assert!(
        unauthorized.is_err(),
        "non-marketauth DrainOnly must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before,
        "rejected DrainOnly by non-marketauth leaves the market unchanged"
    );

    env.svm.expire_blockhash();
    let malformed = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_DRAIN_ONLY,
            asset_index: 0,
            now_slot: 1,
            initial_price: 0,
            insurance_authority: admin.pubkey().to_bytes(),
            insurance_operator: admin.pubkey().to_bytes(),
            backing_bucket_authority: admin.pubkey().to_bytes(),
            oracle_authority: admin.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
        ],
        &[&admin],
    );
    assert!(
        malformed.is_err(),
        "DrainOnly must reject caller-supplied now_slot/price material"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        before,
        "malformed DrainOnly leaves the market unchanged"
    );

    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_DRAIN_ONLY,
        0,
        0,
        0,
    );
    let (_, drain_group) = env.market_state();
    assert_eq!(
        drain_group.assets[0].lifecycle,
        AssetLifecycleV16::DrainOnly
    );
    assert_eq!(drain_group.assets[0].oi_eff_long_q, POS_SCALE);
    assert_eq!(drain_group.assets[0].oi_eff_short_q, POS_SCALE);

    let new_long_owner = Keypair::new();
    let new_short_owner = Keypair::new();
    let new_long_account = env.create_portfolio(&new_long_owner);
    let new_short_account = env.create_portfolio(&new_short_owner);
    env.deposit(&new_long_owner, new_long_account, 1_000_000);
    env.deposit(&new_short_owner, new_short_account, 1_000_000);
    let open = env.try_trade_asset_with_cu(
        0,
        &new_long_owner,
        new_long_account,
        &new_short_owner,
        new_short_account,
        POS_SCALE as i128,
        100,
        0,
    );
    assert!(
        open.is_err(),
        "DrainOnly must reject a new risk-increasing open"
    );
    assert_eq!(env.market_state().1.assets[0].oi_eff_long_q, POS_SCALE);

    let close = env.try_trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        -(POS_SCALE as i128),
        100,
        0,
    );
    assert!(
        close.is_ok(),
        "DrainOnly must still allow existing matched risk to reduce: {close:?}"
    );
    let (_, closed_group) = env.market_state();
    assert_eq!(closed_group.assets[0].oi_eff_long_q, 0);
    assert_eq!(closed_group.assets[0].oi_eff_short_q, 0);
    assert!(closed_group.vault >= closed_group.c_tot + closed_group.insurance);
}

// Lifecycle sweep: BatchTradeNoCpi routes through a separate wrapper path from single TradeNoCpi.
// DrainOnly must still block a fresh risk-increasing batch while allowing an existing matched
// position to reduce, or batch users could either reopen a draining asset or get stuck exiting it.
#[test]
fn v16_attack_batch_nocpi_drain_only_blocks_new_risk_but_allows_reduce() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 5_000, 10_000, 1_000);
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 1_000_000);
    env.deposit(&short_owner, short_account, 1_000_000);
    env.trade_asset_with_cu(
        0,
        &long_owner,
        long_account,
        &short_owner,
        short_account,
        (2 * POS_SCALE) as i128,
        100,
        0,
    );

    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_DRAIN_ONLY,
        0,
        0,
        0,
    );
    assert_eq!(
        env.market_state().1.assets[0].lifecycle,
        AssetLifecycleV16::DrainOnly
    );

    let fresh_long_owner = Keypair::new();
    let fresh_short_owner = Keypair::new();
    let fresh_long = env.create_portfolio(&fresh_long_owner);
    let fresh_short = env.create_portfolio(&fresh_short_owner);
    env.deposit(&fresh_long_owner, fresh_long, 1_000_000);
    env.deposit(&fresh_short_owner, fresh_short, 1_000_000);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let fresh_long_before = env.svm.get_account(&fresh_long).unwrap();
    let fresh_short_before = env.svm.get_account(&fresh_short).unwrap();
    env.svm.expire_blockhash();
    let open = env.send(
        ProgInstruction::BatchTradeNoCpi {
            legs: vec![BatchTradeLeg {
                asset_index: 0,
                size_q: POS_SCALE as i128,
                exec_price: 100,
                fee_bps: 0,
            }],
        },
        vec![
            AccountMeta::new(fresh_long_owner.pubkey(), true),
            AccountMeta::new(fresh_short_owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(fresh_long, false),
            AccountMeta::new(fresh_short, false),
        ],
        &[&fresh_long_owner, &fresh_short_owner],
    );
    assert!(
        open.is_err(),
        "DrainOnly must reject a fresh risk-increasing BatchTradeNoCpi"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&fresh_long).unwrap(), fresh_long_before);
    assert_eq!(
        env.svm.get_account(&fresh_short).unwrap(),
        fresh_short_before
    );

    env.svm.expire_blockhash();
    let reduce_cu = env
        .send(
            ProgInstruction::BatchTradeNoCpi {
                legs: vec![BatchTradeLeg {
                    asset_index: 0,
                    size_q: -(POS_SCALE as i128),
                    exec_price: 100,
                    fee_bps: 0,
                }],
            },
            vec![
                AccountMeta::new(long_owner.pubkey(), true),
                AccountMeta::new(short_owner.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(long_account, false),
                AccountMeta::new(short_account, false),
            ],
            &[&long_owner, &short_owner],
        )
        .expect("DrainOnly must allow existing BatchTradeNoCpi risk reduction");
    assert_cu_within(
        "DrainOnly BatchTradeNoCpi reduce",
        reduce_cu,
        CUSTODY_CU_LIMIT,
    );
    let long_after = env.portfolio_state(long_account);
    let short_after = env.portfolio_state(short_account);
    assert_eq!(
        active_leg_for_asset(&long_after, 0).basis_pos_q,
        POS_SCALE as i128
    );
    assert_eq!(
        active_leg_for_asset(&short_after, 0).basis_pos_q,
        -(POS_SCALE as i128)
    );
    let (_, group_after) = env.market_state();
    assert_eq!(group_after.assets[0].oi_eff_long_q, POS_SCALE);
    assert_eq!(group_after.assets[0].oi_eff_short_q, POS_SCALE);
    assert!(group_after.vault >= group_after.c_tot + group_after.insurance);
}

// security.md sweep — §6.2 backing-yield fee split (#5): when a risk-increasing trade GROWS an
// account's source-credit IM lien that draws a fresh counterparty backing bucket, the wrapper charges
// a backing-domain trade fee = fee_bps * Δbacking and splits it three ways: insurance_share to the
// market insurance pool (asset-0), the SAME amount earmarked into that domain's insurance budget, and
// the remainder to the backing provider's bucket earnings. Verify the split conserves on real BPF
// state: charged == insurance_pool_delta + provider_delta, and the domain budget mirrors the insurance
// share. The lien is formed organically (cross-margin positive PnL used as IM), not injected.
#[test]
fn v16_attack_backing_fee_split_conserves() {
    const INITIAL_PRICE: u64 = 100;
    const ASSET0_SIZE_Q: i128 = 200 * POS_SCALE as i128;
    const ASSET1_SIZE_Q: i128 = 100 * POS_SCALE as i128;
    const SAFE_INCREASE_Q: i128 = 20 * POS_SCALE as i128;
    const DEPOSIT: u128 = 3_130;
    const WINNING_DOMAIN: usize = 1;
    const FEE_BPS: u16 = 5_000; // 10% of consumed backing
    const INSURANCE_SHARE_BPS: u16 = 2_500; // 25% of the fee to insurance, 75% to provider

    let mut env = V16CuEnv::new_with_market_params_and_price_move(4, 1_000, 1_000, 500);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_for_asset_as_admin(0, 1, INITIAL_PRICE);
    env.configure_auth_mark_for_asset_as_admin(1, 1, INITIAL_PRICE);
    env.update_backing_fee_policy_with_cu(WINNING_DOMAIN as u16, FEE_BPS, INSURANCE_SHARE_BPS);
    // Reconfigure the asset-0 oracle after setting the policy. Asset 0 carries both market-wide
    // config and a stored per-asset profile; the fee policy must survive this path because the
    // backing-fee collector reads the stored profile.
    env.svm.expire_blockhash();
    env.configure_auth_mark_for_asset_as_admin(0, 1, INITIAL_PRICE);

    let cross_owner = Keypair::new();
    let counterparty_owner = Keypair::new();
    let cross_account = env.create_portfolio(&cross_owner);
    let counterparty_account = env.create_portfolio(&counterparty_owner);
    env.deposit(&cross_owner, cross_account, DEPOSIT);
    env.deposit(&counterparty_owner, counterparty_account, 10_000);
    env.top_up_backing_bucket(WINNING_DOMAIN as u16, 1_500, 10);

    // Build cross_account's source-backed positive PnL on asset0 (a long that wins as the mark rises).
    env.trade_asset_with_cu(
        0,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        ASSET0_SIZE_Q,
        INITIAL_PRICE,
        0,
    );
    env.trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        ASSET1_SIZE_Q,
        INITIAL_PRICE,
        0,
    );
    env.svm.warp_to_slot(2);
    env.push_auth_mark_for_asset_as_admin(0, 2, 105);
    env.push_auth_mark_for_asset_as_admin(1, 2, 95);
    for (portfolio, asset_index) in [
        (counterparty_account, 0),
        (cross_account, 0),
        (counterparty_account, 1),
    ] {
        env.crank(
            portfolio,
            ProgInstruction::PermissionlessCrank {
                now_slot: 2,
                close_q: 0,
                observations: crank_observations(asset_index),
            },
        );
    }
    // Force capital low so the parked positive-PnL claim is NEEDED as IM (triggers the source lien).
    env.force_portfolio_capital_for_benchmark(cross_account, 2_600);
    assert_eq!(
        env.portfolio_state(cross_account).pnl.get(),
        1_000,
        "setup must create source-backed positive PnL"
    );

    // Trim the bucket to the exact watermark, then refill generously so the risk increase liens against
    // fresh counterparty backing.
    let (_, g0) = env.market_state();
    let surplus = (g0.source_credit[WINNING_DOMAIN].fresh_reserved_backing_num
        - g0.source_credit[WINNING_DOMAIN].positive_claim_bound_num)
        / BOUND_SCALE;
    if surplus > 0 {
        let dest = env.token_account(env.admin.pubkey(), 0);
        env.withdraw_backing_bucket_to_admin_token_with_cu(dest, WINNING_DOMAIN as u16, surplus);
    }
    env.top_up_backing_bucket(WINNING_DOMAIN as u16, 50_000, 10);
    env.deposit(&cross_owner, cross_account, 500);
    env.deposit(&counterparty_owner, counterparty_account, 500);
    env.svm.warp_to_slot(3);

    // Snapshot the three sinks + the payers before the lien-growing trade.
    let (_, gb) = env.market_state();
    let insurance_before = gb.insurance;
    let budget_before = gb.insurance_domain_budget[WINNING_DOMAIN];
    let provider_before = gb.source_backing_buckets[WINNING_DOMAIN].utilization_fee_earnings;
    let ctot_before = gb.c_tot;
    let cap_cross_before = env.portfolio_state(cross_account).capital.get();
    let cap_cp_before = env.portfolio_state(counterparty_account).capital.get();
    let lien_before: u128 = env
        .portfolio_state(cross_account)
        .source_domains
        .iter()
        .map(|slot| slot.source_lien_counterparty_backing_num.get())
        .sum();

    // Risk-increasing trade: grows the IM source-credit lien -> draws fresh backing -> charges the fee.
    let r = env.try_trade_asset_with_cu(
        1,
        &cross_owner,
        cross_account,
        &counterparty_owner,
        counterparty_account,
        SAFE_INCREASE_Q,
        95,
        0,
    );
    assert!(r.is_ok(), "backed risk increase must succeed: {r:?}");

    let (_, ga) = env.market_state();
    let insurance_delta = ga.insurance - insurance_before;
    let budget_delta = ga.insurance_domain_budget[WINNING_DOMAIN] - budget_before;
    let provider_delta =
        ga.source_backing_buckets[WINNING_DOMAIN].utilization_fee_earnings - provider_before;
    let cap_cross_after = env.portfolio_state(cross_account).capital.get();
    let cap_cp_after = env.portfolio_state(counterparty_account).capital.get();
    let lien_after: u128 = env
        .portfolio_state(cross_account)
        .source_domains
        .iter()
        .map(|slot| slot.source_lien_counterparty_backing_num.get())
        .sum();
    let charged = (cap_cross_before - cap_cross_after) + (cap_cp_before - cap_cp_after);

    // The trade must actually grow the counterparty-backing lien (else the fee is vacuous).
    assert!(
        lien_after > lien_before,
        "trade must grow the counterparty-backing lien (before={lien_before} after={lien_after})"
    );
    assert!(charged > 0, "a positive backing fee must be charged");
    // Route 1+2+3: charged splits exactly into insurance pool + provider earnings, no atoms created/lost.
    assert_eq!(insurance_delta + provider_delta, charged, "fee must split with no leakage: ins={insurance_delta} prov={provider_delta} charged={charged}");
    // Insurance share is floor(charged * share_bps): asset-0 pool and the per-domain budget move together.
    let expected_insurance = charged * INSURANCE_SHARE_BPS as u128 / 10_000;
    assert_eq!(
        insurance_delta, expected_insurance,
        "insurance pool gets floor(fee*share)"
    );
    assert_eq!(
        budget_delta, insurance_delta,
        "per-domain insurance budget mirrors the insurance share"
    );
    // c_tot drops by exactly the fee debited from collateral (insurance + provider leave c_tot).
    assert_eq!(
        ctot_before - ga.c_tot,
        charged,
        "c_tot decreases by exactly the charged fee"
    );
    assert_domain_budget_remaining_total_consistent(&ga, "backing fee insurance share");
}

// security.md sweep — permissionless asset-create fee gate (#5 / README L52): when the configured
// permissionless market-init fee is ZERO, asset creation is NOT permissionless — only the market-wide
// asset authority may append a new asset; a stranger is rejected with Unauthorized.
#[test]
fn v16_attack_permissionless_create_requires_nonzero_fee() {
    let mut env = V16CuEnv::new(); // default permissionless_market_init_fee == 0
    let market = env.market;
    env.svm.warp_to_slot(1);
    let append = |env: &mut V16CuEnv, signer: &Keypair| -> Result<u64, String> {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::UpdateAssetLifecycle {
                action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
                asset_index: 1,
                now_slot: 1,
                initial_price: 100,
                insurance_authority: signer.pubkey().to_bytes(),
                insurance_operator: signer.pubkey().to_bytes(),
                backing_bucket_authority: signer.pubkey().to_bytes(),
                oracle_authority: signer.pubkey().to_bytes(),
            },
            vec![
                AccountMeta::new(signer.pubkey(), true),
                AccountMeta::new(market, false),
            ],
            &[signer],
        )
    };
    let stranger = Keypair::new();
    env.ensure_signer_account(stranger.pubkey());
    assert!(
        append(&mut env, &stranger).is_err(),
        "fee=0: a stranger must NOT be able to append an asset"
    );
    let (_, g_after_reject) = env.market_state();
    assert_ne!(
        g_after_reject.assets.get(1).map(|a| a.lifecycle),
        Some(AssetLifecycleV16::Active),
        "no asset created by the rejected stranger"
    );
    // The market-wide asset authority (admin) appends for free.
    let admin = env.admin.insecure_clone();
    append(&mut env, &admin).expect("the asset authority may append for free when fee=0");
    assert_eq!(
        env.market_state().1.assets[1].lifecycle,
        AssetLifecycleV16::Active,
        "authority append activated asset 1"
    );
}

// security.md sweep — permissionless create fee preflight (#5 / README L59): an underfunded
// permissionless creator must not grow the market, install asset authorities, or credit market-0
// insurance. The funded control proves the rejection is the fee gate, not a dead activation path.
#[test]
fn v16_attack_permissionless_create_underfunded_fee_does_not_activate_or_credit() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let (_, group_before) = env.market_state();
    assert_eq!(
        group_before.config.max_market_slots, 1,
        "starts as a one-asset market"
    );

    let underfunded_source = env.token_account(creator.pubkey(), FEE as u64 - 1);
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(underfunded_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        rejected.is_err(),
        "underfunded permissionless init fee must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "market account unchanged by rejected create"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "vault token account unchanged by rejected create"
    );
    assert_eq!(
        env.token_amount(underfunded_source),
        FEE as u64 - 1,
        "rejected create pulls no fee"
    );
    let (_, rejected_group) = env.market_state();
    assert_eq!(
        rejected_group.config.max_market_slots, 1,
        "rejected create did not append a slot"
    );
    assert_eq!(
        rejected_group.insurance, group_before.insurance,
        "rejected create did not credit insurance"
    );
    assert_eq!(
        rejected_group.vault, group_before.vault,
        "rejected create did not credit accounting vault"
    );
    assert_eq!(
        rejected_group.insurance_domain_budget,
        group_before.insurance_domain_budget
    );
    assert_domain_budget_remaining_total_consistent(&rejected_group, "underfunded create rollback");

    let funded_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(funded_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    )
    .expect("properly funded permissionless create succeeds");
    let (_, funded_group) = env.market_state();
    assert_eq!(
        env.token_amount(funded_source),
        0,
        "funded create pulls the fee"
    );
    assert_eq!(
        funded_group.config.max_market_slots, 2,
        "funded create appends exactly one slot"
    );
    assert_eq!(funded_group.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert_eq!(
        funded_group.insurance - group_before.insurance,
        FEE,
        "fee credited to market-0 insurance"
    );
    assert_eq!(
        funded_group.vault - group_before.vault,
        FEE,
        "fee credited to accounting vault"
    );
    assert_domain_budget_remaining_total_consistent(&funded_group, "funded permissionless create");
}

// LoF sweep: UpdateMarketInitFeePolicy caps the base fee to u64, but the actual
// permissionless activation fee doubles every 32 asset slots. A high-index public
// append whose computed fee is u64::MAX+1 must reject before growing the market
// or crediting accounting; a lower exact fee at the same slot remains live.
#[test]
fn v16_attack_permissionless_scaled_init_fee_over_u64_rejects_before_activation() {
    const TARGET_ASSET: u16 = 32;
    const HIGH_BASE_FEE: u128 = (u64::MAX as u128 / 2) + 1;

    let mut env = V16CuEnv::new_with_init_params_and_market_capacity(
        V16CuMarketParams {
            max_portfolio_assets: percolator_prog::constants::WRAPPER_MAX_PORTFOLIO_ASSETS,
            ..V16CuMarketParams::default()
        },
        TARGET_ASSET as usize + 1,
    );
    env.svm.warp_to_slot(1);
    let start = env.market_state().1.config.max_market_slots as u16;
    for asset_index in start..TARGET_ASSET {
        env.activate_asset(asset_index, asset_index as u64, 100);
    }
    let (_, ready_group) = env.market_state();
    assert_eq!(
        ready_group.config.max_market_slots, TARGET_ASSET as u32,
        "admin setup reaches the high-index permissionless append frontier"
    );

    env.update_market_init_fee_policy_with_cu(HIGH_BASE_FEE);
    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let source = env.token_account(creator.pubkey(), HIGH_BASE_FEE as u64);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let source_before = env.svm.get_account(&source).unwrap();

    env.svm.warp_to_slot(TARGET_ASSET as u64);
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: TARGET_ASSET,
            now_slot: TARGET_ASSET as u64,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    let err = rejected.expect_err("scaled init fee above u64 must reject");
    assert!(
        err.contains("Custom(9)"),
        "scaled init fee must reject as InvalidInstruction, got {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "over-u64 scaled fee must not grow the market or install authorities"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "over-u64 scaled fee must not credit custody"
    );
    assert_eq!(
        env.svm.get_account(&source).unwrap(),
        source_before,
        "over-u64 scaled fee must not pull creator tokens"
    );

    env.update_market_init_fee_policy_with_cu(1);
    let control_source = env.token_account(creator.pubkey(), 2);
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: TARGET_ASSET,
            now_slot: TARGET_ASSET as u64,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(control_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        accepted.is_ok(),
        "same high-index append succeeds when the scaled fee fits u64: {accepted:?}"
    );
    let (_, accepted_group) = env.market_state();
    assert_eq!(
        accepted_group.config.max_market_slots,
        TARGET_ASSET as u32 + 1
    );
    assert_eq!(
        accepted_group.assets[TARGET_ASSET as usize].lifecycle,
        AssetLifecycleV16::Active
    );
    assert_eq!(env.token_amount(control_source), 0);
    assert_eq!(
        env.token_amount(env.vault),
        2,
        "asset-32 fee is doubled from base fee 1 to 2"
    );
    assert_eq!(accepted_group.vault, 2);
    assert_eq!(accepted_group.insurance, 2);
    assert_domain_budget_remaining_total_consistent(
        &accepted_group,
        "permissionless scaled init fee control",
    );
}

// LoF/DoS sweep (cron135): permissionless activation's init fee must be paid in the
// configured primary collateral mint before the market account grows. A wrong-mint fee source
// cannot install a new asset, credit accounting, or consume the creator's unrelated tokens.
#[test]
fn v16_attack_permissionless_create_rejects_wrong_mint_fee_source_before_realloc() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let wrong_mint = env.create_mint();
    let wrong_source = env.token_account_for_mint(wrong_mint, creator.pubkey(), FEE as u64);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let wrong_source_before = env.svm.get_account(&wrong_source).unwrap();
    let (_, group_before) = env.market_state();
    assert_eq!(
        group_before.config.max_market_slots, 1,
        "starts as a one-asset market"
    );

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(wrong_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    let err = rejected.expect_err("wrong-mint permissionless init fee source must reject");
    assert!(
        err.contains("Custom(10)"),
        "wrong-mint permissionless init fee source must reject as InvalidMint, got {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "wrong-mint fee source must not realloc or install a new asset"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "wrong-mint fee source must not touch canonical vault custody"
    );
    assert_eq!(
        env.svm.get_account(&wrong_source).unwrap(),
        wrong_source_before,
        "wrong-mint fee source must not spend unrelated tokens"
    );
    let (_, rejected_group) = env.market_state();
    assert_eq!(
        rejected_group.config.max_market_slots, group_before.config.max_market_slots,
        "wrong-mint fee source must not append a market slot"
    );
    assert_eq!(rejected_group.vault, group_before.vault);
    assert_eq!(rejected_group.insurance, group_before.insurance);
    assert_eq!(
        rejected_group.insurance_domain_budget,
        group_before.insurance_domain_budget
    );

    let valid_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(valid_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        accepted.is_ok(),
        "same permissionless activation works with the primary-mint fee source: {accepted:?}"
    );
    let (_, accepted_group) = env.market_state();
    assert_eq!(accepted_group.config.max_market_slots, 2);
    assert_eq!(
        accepted_group.assets[1].lifecycle,
        AssetLifecycleV16::Active
    );
    assert_eq!(env.token_amount(valid_source), 0);
    assert_eq!(env.token_amount(env.vault), FEE as u64);
    assert_eq!(accepted_group.vault, FEE);
    assert_eq!(accepted_group.insurance, FEE);
    assert_domain_budget_remaining_total_consistent(
        &accepted_group,
        "permissionless wrong-mint fee-source control",
    );
}

// LoF/DoS sweep (cron135): permissionless lifecycle activation is not a plain value-in route.
// It can realloc a new market slot or reactivate a retired slot and credit insurance before the
// fee transfer. A frozen primary-mint fee source must be rejected before either lifecycle mutation.
#[test]
fn v16_attack_permissionless_lifecycle_rejects_frozen_fee_source_before_slot_mutation() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());

    let frozen_append_source = env.token_account(creator.pubkey(), FEE as u64);
    let mut source_account = env.svm.get_account(&frozen_append_source).unwrap();
    source_account.data = make_frozen_token_data(env.mint, creator.pubkey(), FEE as u64);
    env.svm
        .set_account(frozen_append_source, source_account)
        .unwrap();

    let append_market_before = env.svm.get_account(&env.market).unwrap();
    let append_source_before = env.svm.get_account(&frozen_append_source).unwrap();
    let append_vault_before = env.svm.get_account(&env.vault).unwrap();
    let (_, append_group_before) = env.market_state();
    env.svm.expire_blockhash();
    let rejected_append = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(frozen_append_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        rejected_append.is_err(),
        "permissionless append must reject a frozen fee source before realloc"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        append_market_before,
        "frozen-source append must not realloc or install a new slot"
    );
    assert_eq!(
        env.svm.get_account(&frozen_append_source).unwrap(),
        append_source_before,
        "frozen-source append must not spend the creator source"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        append_vault_before,
        "frozen-source append must not move vault custody"
    );
    let (_, append_group_after) = env.market_state();
    assert_eq!(
        append_group_after.config.max_market_slots,
        append_group_before.config.max_market_slots
    );
    assert_eq!(append_group_after.vault, append_group_before.vault);
    assert_eq!(append_group_after.insurance, append_group_before.insurance);

    let clean_append_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    let accepted_append = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(clean_append_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        accepted_append.is_ok(),
        "clean permissionless append remains live after frozen-source rejection: {accepted_append:?}"
    );

    env.svm.warp_to_slot(3);
    env.update_asset_lifecycle_as_admin_with_cu(
        percolator_prog::processor::ASSET_ACTION_RETIRE,
        1,
        3,
        0,
    );
    let (retired_cfg, retired_group) = env.market_state();
    assert_eq!(retired_cfg.free_market_slot_count, 1);
    assert_eq!(
        retired_group.assets[1].lifecycle,
        AssetLifecycleV16::Retired
    );

    let frozen_reuse_source = env.token_account(creator.pubkey(), FEE as u64);
    let mut source_account = env.svm.get_account(&frozen_reuse_source).unwrap();
    source_account.data = make_frozen_token_data(env.mint, creator.pubkey(), FEE as u64);
    env.svm
        .set_account(frozen_reuse_source, source_account)
        .unwrap();

    env.svm.warp_to_slot(4);
    let reuse_market_before = env.svm.get_account(&env.market).unwrap();
    let reuse_source_before = env.svm.get_account(&frozen_reuse_source).unwrap();
    let reuse_vault_before = env.svm.get_account(&env.vault).unwrap();
    env.svm.expire_blockhash();
    let rejected_reuse = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 4,
            initial_price: 250,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(frozen_reuse_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        rejected_reuse.is_err(),
        "permissionless retired-slot reuse must reject a frozen fee source"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        reuse_market_before,
        "frozen-source reuse must not reactivate the retired slot or consume the counter"
    );
    assert_eq!(
        env.svm.get_account(&frozen_reuse_source).unwrap(),
        reuse_source_before,
        "frozen-source reuse must not spend the creator source"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        reuse_vault_before,
        "frozen-source reuse must not move vault custody"
    );
    let (reuse_cfg_after, reuse_group_after) = env.market_state();
    assert_eq!(reuse_cfg_after.free_market_slot_count, 1);
    assert_eq!(
        reuse_group_after.assets[1].lifecycle,
        AssetLifecycleV16::Retired
    );
    assert_eq!(reuse_group_after.vault, retired_group.vault);
    assert_eq!(reuse_group_after.insurance, retired_group.insurance);

    let clean_reuse_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    let accepted_reuse = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 4,
            initial_price: 250,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(clean_reuse_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        accepted_reuse.is_ok(),
        "clean retired-slot reuse remains live after frozen-source rejection: {accepted_reuse:?}"
    );
    let (reused_cfg, reused_group) = env.market_state();
    assert_eq!(reused_cfg.free_market_slot_count, 0);
    assert_eq!(reused_group.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert_eq!(reused_group.assets[1].effective_price, 250);
    assert_eq!(env.token_amount(clean_reuse_source), 0);
    assert_eq!(env.token_amount(env.vault), (FEE * 2) as u64);
    assert_eq!(reused_group.vault, FEE * 2);
    assert_eq!(reused_group.insurance, FEE * 2);
    assert_domain_budget_remaining_total_consistent(
        &reused_group,
        "permissionless lifecycle frozen-fee-source control",
    );
}

// security.md sweep - permissionless init-fee vault binding (#44/#48): asset activation charges
// the public creator before growing a new market slot. A funded creator must not be able to route the
// fee into a non-canonical vault-authority-owned token account and still install a new asset, which
// would fragment custody and strand the market-init fee outside the canonical vault.
#[test]
fn v16_attack_permissionless_create_rejects_noncanonical_fee_vault() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let source = env.token_account(creator.pubkey(), FEE as u64);
    let fake_vault = Pubkey::new_unique();
    env.svm
        .set_account(
            fake_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, env.vault_authority, 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    assert_ne!(fake_vault, env.vault, "fake vault is not the canonical ATA");

    let market_before = env.svm.get_account(&env.market).unwrap();
    let canonical_vault_before = env.svm.get_account(&env.vault).unwrap();
    let fake_vault_before = env.svm.get_account(&fake_vault).unwrap();
    let source_before = env.svm.get_account(&source).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(source, false),
            AccountMeta::new(fake_vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        rejected.is_err(),
        "permissionless create must reject a non-canonical fee vault"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected fake-vault activation must not realloc or install asset authorities"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        canonical_vault_before,
        "canonical vault remains untouched by the fake-vault attempt"
    );
    assert_eq!(
        env.svm.get_account(&fake_vault).unwrap(),
        fake_vault_before,
        "fake vault receives no fee"
    );
    assert_eq!(
        env.svm.get_account(&source).unwrap(),
        source_before,
        "creator source is not debited"
    );
    assert_eq!(
        env.market_state().1.config.max_market_slots,
        1,
        "rejected fake-vault activation does not append a market slot"
    );

    let control_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(control_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        accepted.is_ok(),
        "canonical fee-vault permissionless create still succeeds: {accepted:?}"
    );
    let (_, group) = env.market_state();
    assert_eq!(group.config.max_market_slots, 2);
    assert_eq!(group.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert_eq!(env.token_amount(control_source), 0);
    assert_eq!(env.token_amount(env.vault), FEE as u64);
    assert_eq!(group.vault, FEE);
    assert_eq!(group.insurance, FEE);
}

// security.md sweep - permissionless init-fee source/vault alias (#26/#44/#48): the creator's fee
// source must be a creator-owned token account, not the already-funded canonical vault. Otherwise a
// duplicate source==destination transfer could no-op while the program credits market insurance.
#[test]
fn v16_attack_permissionless_create_rejects_vault_as_fee_source() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);

    let honest_owner = Keypair::new();
    let honest_portfolio = env.create_portfolio(&honest_owner);
    env.deposit(&honest_owner, honest_portfolio, FEE * 10);
    assert!(
        env.token_amount(env.vault) >= FEE as u64,
        "canonical vault is funded enough that this is not an underfunded-source reject"
    );

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    env.svm.warp_to_slot(1);

    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let portfolio_before = env.svm.get_account(&honest_portfolio).unwrap();
    let (_, group_before) = env.market_state();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        rejected.is_err(),
        "permissionless create must reject the canonical vault as the fee source"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected vault-source activation must not realloc or install the new asset"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "source==vault attempt must not move or self-transfer vault tokens"
    );
    assert_eq!(
        env.svm.get_account(&honest_portfolio).unwrap(),
        portfolio_before,
        "honest depositor state is untouched by the rejected vault-source attempt"
    );
    let (_, rejected_group) = env.market_state();
    assert_eq!(
        rejected_group.config.max_market_slots,
        group_before.config.max_market_slots
    );
    assert_eq!(
        rejected_group.insurance, group_before.insurance,
        "rejected vault-source attempt does not credit insurance"
    );
    assert_eq!(
        rejected_group.vault, group_before.vault,
        "rejected vault-source attempt does not credit accounting vault"
    );

    let valid_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(valid_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    )
    .expect("canonical vault with a creator-owned fee source still activates");
    let (_, group) = env.market_state();
    assert_eq!(group.config.max_market_slots, 2);
    assert_eq!(group.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert_eq!(env.token_amount(valid_source), 0);
    assert_eq!(env.token_amount(env.vault), (FEE * 11) as u64);
    assert_eq!(group.vault, FEE * 11);
    assert_eq!(group.insurance, FEE);
}

// security.md sweep - sparse append DoS: permissionless activation may append exactly the next
// configured slot, or reuse a retired slot, but it must not accept sparse jumps. Otherwise a stranger
// could force large market-account growth or create holes in the asset table.
#[test]
fn v16_attack_permissionless_sparse_append_indices_rejected_without_realloc_or_fee() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let (cfg_before, group_before) = env.market_state();
    assert_eq!(
        group_before.config.max_market_slots, 1,
        "starts as a one-asset market"
    );
    assert_eq!(
        cfg_before.free_market_slot_count, 0,
        "no retired slots are reusable"
    );

    for bad_index in [2u16, 7, u16::MAX] {
        let source = env.token_account(creator.pubkey(), FEE as u64);
        let source_before = env.svm.get_account(&source).unwrap();
        env.svm.expire_blockhash();
        let rejected = env.send(
            ProgInstruction::UpdateAssetLifecycle {
                action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
                asset_index: bad_index,
                now_slot: 1,
                initial_price: 100,
                insurance_authority: creator.pubkey().to_bytes(),
                insurance_operator: creator.pubkey().to_bytes(),
                backing_bucket_authority: creator.pubkey().to_bytes(),
                oracle_authority: creator.pubkey().to_bytes(),
            },
            vec![
                AccountMeta::new(creator.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&creator],
        );
        assert!(
            rejected.is_err(),
            "permissionless sparse append at index {bad_index} must reject"
        );
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "rejected sparse append at index {bad_index} did not realloc or mutate the market"
        );
        assert_eq!(
            env.svm.get_account(&env.vault).unwrap(),
            vault_before,
            "rejected sparse append at index {bad_index} did not move vault tokens"
        );
        assert_eq!(
            env.svm.get_account(&source).unwrap(),
            source_before,
            "rejected sparse append at index {bad_index} did not debit the creator"
        );
        let (_, rejected_group) = env.market_state();
        assert_eq!(
            rejected_group.config.max_market_slots, group_before.config.max_market_slots,
            "rejected sparse append at index {bad_index} did not advance configured slots"
        );
        assert_eq!(
            rejected_group.insurance_domain_budget, group_before.insurance_domain_budget,
            "rejected sparse append at index {bad_index} did not credit any domain budget"
        );
    }

    let valid_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(valid_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    )
    .expect("contiguous permissionless append still succeeds after sparse attempts");
    let (_, valid_group) = env.market_state();
    assert_eq!(
        valid_group.config.max_market_slots, 2,
        "valid append advances exactly one slot"
    );
    assert_eq!(valid_group.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert_eq!(
        env.token_amount(valid_source),
        0,
        "valid append pulls only the real fee"
    );
}

// security.md sweep — dynamic append rollback (#44/#48): the append path reallocs the market account
// before activate_dynamic_asset_slot rejects zero authorities. A rejected append must roll back account
// length, slot counters, fee collection, and all market-0 budget credits.
#[test]
fn v16_attack_permissionless_append_zero_authority_rolls_back_realloc_and_fee() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let source = env.token_account(creator.pubkey(), FEE as u64);
    let (_, group_before) = env.market_state();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: [0u8; 32],
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        rejected.is_err(),
        "permissionless append with a zero authority must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected append rolls back the pre-write market realloc"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        vault_before,
        "vault token account unchanged"
    );
    assert_eq!(
        env.token_amount(source),
        FEE as u64,
        "fee was not pulled by rejected append"
    );
    let (_, rejected_group) = env.market_state();
    assert_eq!(
        rejected_group.config.max_market_slots,
        group_before.config.max_market_slots
    );
    assert_eq!(rejected_group.insurance, group_before.insurance);
    assert_eq!(rejected_group.vault, group_before.vault);
    assert_eq!(
        rejected_group.insurance_domain_budget,
        group_before.insurance_domain_budget
    );

    let valid_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(valid_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    )
    .expect("valid permissionless append succeeds after rejected zero-authority attempt");
    let (_, valid_group) = env.market_state();
    assert_eq!(env.token_amount(valid_source), 0, "valid append pulls fee");
    assert_eq!(
        valid_group.config.max_market_slots,
        group_before.config.max_market_slots + 1
    );
    assert_eq!(valid_group.assets[1].lifecycle, AssetLifecycleV16::Active);
}

// security.md sweep - permissionless append invalid oracle price rollback (#5/#24/#44/#48):
// asset activation accepts a caller-supplied initial oracle price and reaches the dynamic append
// path after validating the fee accounts. A zero or over-MAX price must not install an unusable
// asset, grow the market, or pull the permissionless init fee.
#[test]
fn v16_attack_permissionless_append_invalid_price_rolls_back_realloc_and_fee() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);

    let creator = Keypair::new();
    env.ensure_signer_account(creator.pubkey());
    let market_before = env.svm.get_account(&env.market).unwrap();
    let vault_before = env.svm.get_account(&env.vault).unwrap();
    let (_, group_before) = env.market_state();

    for (label, bad_price) in [
        ("zero initial price", 0),
        (
            "initial price above MAX_ORACLE_PRICE",
            percolator::MAX_ORACLE_PRICE + 1,
        ),
    ] {
        let source = env.token_account(creator.pubkey(), FEE as u64);
        let source_before = env.svm.get_account(&source).unwrap();
        env.svm.expire_blockhash();
        let rejected = env.send(
            ProgInstruction::UpdateAssetLifecycle {
                action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
                asset_index: 1,
                now_slot: 1,
                initial_price: bad_price,
                insurance_authority: creator.pubkey().to_bytes(),
                insurance_operator: creator.pubkey().to_bytes(),
                backing_bucket_authority: creator.pubkey().to_bytes(),
                oracle_authority: creator.pubkey().to_bytes(),
            },
            vec![
                AccountMeta::new(creator.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(source, false),
                AccountMeta::new(env.vault, false),
                AccountMeta::new_readonly(spl_token::ID, false),
            ],
            &[&creator],
        );
        assert!(rejected.is_err(), "{label} must reject");
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "{label} must roll back the dynamic-append market realloc"
        );
        assert_eq!(
            env.svm.get_account(&env.vault).unwrap(),
            vault_before,
            "{label} must not move canonical vault custody"
        );
        assert_eq!(
            env.svm.get_account(&source).unwrap(),
            source_before,
            "{label} must not pull the creator's init fee"
        );
        let (_, rejected_group) = env.market_state();
        assert_eq!(
            rejected_group.config.max_market_slots, group_before.config.max_market_slots,
            "{label} must not append a market slot"
        );
        assert_eq!(
            rejected_group.insurance, group_before.insurance,
            "{label} must not credit market insurance"
        );
        assert_eq!(
            rejected_group.vault, group_before.vault,
            "{label} must not credit accounting vault"
        );
    }

    let valid_source = env.token_account(creator.pubkey(), FEE as u64);
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::UpdateAssetLifecycle {
            action: percolator_prog::processor::ASSET_ACTION_ACTIVATE,
            asset_index: 1,
            now_slot: 1,
            initial_price: 100,
            insurance_authority: creator.pubkey().to_bytes(),
            insurance_operator: creator.pubkey().to_bytes(),
            backing_bucket_authority: creator.pubkey().to_bytes(),
            oracle_authority: creator.pubkey().to_bytes(),
        },
        vec![
            AccountMeta::new(creator.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(valid_source, false),
            AccountMeta::new(env.vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&creator],
    );
    assert!(
        accepted.is_ok(),
        "valid permissionless append still succeeds after rejected bad prices: {accepted:?}"
    );
    let (_, group_after) = env.market_state();
    assert_eq!(group_after.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert_eq!(group_after.assets[1].effective_price, 100);
    assert_eq!(env.token_amount(valid_source), 0);
}

// security.md sweep — permissionless create fee funds asset-0 insurance (#5 / README L59): the fee a
// stranger pays to permissionlessly create asset N flows entirely into asset-0's insurance (the market
// insurance pool + asset-0's per-domain budgets), conserving every atom.
#[test]
fn v16_attack_permissionless_create_fee_funds_asset0_insurance() {
    const FEE: u128 = 40;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);
    env.svm.warp_to_slot(1);
    let (_, before) = env.market_state();
    let stranger = Keypair::new();
    let ins_auth = Keypair::new();
    let admin_pk = env.admin.pubkey();
    let (fee_src, _cu) = env.activate_permissionless_asset_with_fee(
        &stranger,
        1,
        1,
        100,
        ins_auth.pubkey(),
        ins_auth.pubkey(),
        ins_auth.pubkey(),
        admin_pk,
        FEE,
    );
    let (_, after) = env.market_state();
    assert_eq!(env.token_amount(fee_src), 0, "creator's fee fully pulled");
    assert_eq!(
        after.vault - before.vault,
        FEE,
        "fee deposited into the vault"
    );
    assert_eq!(
        after.insurance - before.insurance,
        FEE,
        "entire create fee funds asset-0 insurance pool"
    );
    let b0 = after.insurance_domain_budget[0] - before.insurance_domain_budget[0];
    let b1 = after.insurance_domain_budget[1] - before.insurance_domain_budget[1];
    assert_eq!(
        b0 + b1,
        FEE,
        "fee earmarked into asset-0's insurance domains (0=long,1=short), no leakage"
    );
    assert_eq!(after.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert!(
        after.vault >= after.c_tot + after.insurance,
        "senior conservation"
    );
    assert_domain_budget_remaining_total_consistent(&after, "permissionless create fee");
}

// security.md sweep — permissionless append liveness (#44/#48): a stranger may legitimately grow
// the asset set, but that must not strand a flat user who deposited before the epoch change. The
// user has no asset-1 exposure, so a post-append full withdrawal must remain live and exact.
#[test]
fn v16_attack_permissionless_append_cannot_freeze_flat_withdrawal() {
    const FEE: u128 = 40;
    const DEPOSIT: u128 = 1_000;
    let mut env = V16CuEnv::new();
    env.update_market_init_fee_policy_with_cu(FEE);

    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, DEPOSIT);
    let (_, before) = env.market_state();
    assert_eq!(
        before.config.max_market_slots, 1,
        "starts as a one-asset market"
    );
    assert_eq!(env.portfolio_state(portfolio).capital.get(), DEPOSIT);

    let creator = Keypair::new();
    let cp = creator.pubkey();
    env.svm.warp_to_slot(1);
    env.activate_permissionless_asset_with_fee(&creator, 1, 1, 100, cp, cp, cp, cp, FEE);
    let (_, appended) = env.market_state();
    assert_eq!(
        appended.config.max_market_slots, 2,
        "permissionless append grew exactly one unrelated asset slot"
    );
    assert_eq!(appended.assets[1].lifecycle, AssetLifecycleV16::Active);
    assert!(
        appended.asset_set_epoch > before.asset_set_epoch,
        "asset-set epoch advanced across the append"
    );

    let (dest, _cu) = env.withdraw_with_cu(&owner, portfolio, DEPOSIT);
    let account = env.portfolio_state(portfolio);
    let (_, after_withdraw) = env.market_state();
    assert_eq!(
        env.token_amount(dest),
        DEPOSIT as u64,
        "full pre-append capital withdraws after the unrelated append"
    );
    assert_eq!(account.capital.get(), 0, "portfolio capital fully debited");
    assert!(
        percolator::active_bitmap_is_empty(active_bitmap(&account)),
        "flat account remains exposure-free"
    );
    assert_eq!(
        after_withdraw.c_tot, 0,
        "only the user's collateral left c_tot"
    );
    assert_eq!(
        after_withdraw.vault,
        appended.vault - DEPOSIT,
        "accounting vault debited exactly the withdrawal"
    );
    assert_eq!(
        after_withdraw.insurance, appended.insurance,
        "permissionless create fee insurance remains untouched"
    );
    assert_domain_budget_remaining_total_consistent(&after_withdraw, "post-append flat withdraw");
}

// security.md sweep — base-unit deposit/withdraw mint routing (#5 / README L122): deposits accept ONLY
// the primary base-unit mint, but a holder may withdraw in EITHER the primary or the secondary mint.
#[test]
fn v16_attack_deposit_primary_only_withdraw_either() {
    let mut env = V16CuEnv::new();
    let market = env.market;
    let primary = env.mint;
    let vault_authority = env.vault_authority;
    let secondary = env.create_mint();
    env.update_base_unit_mints_with_cu(primary, secondary);

    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000); // PRIMARY deposit works.

    // SECONDARY deposit must reject (deposits are primary-only).
    let sec_src = env.token_account_for_mint(secondary, owner.pubkey(), 500);
    let sec_vault = canonical_vault_ata(vault_authority, secondary);
    env.svm
        .set_account(
            sec_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary, vault_authority, 0),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm.expire_blockhash();
    let r_dep = env.send(
        ProgInstruction::Deposit { amount: 500 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(sec_src, false),
            AccountMeta::new(sec_vault, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r_dep.is_err(),
        "depositing the secondary mint must reject (primary-only)"
    );
    assert_eq!(
        env.token_amount(sec_src),
        500,
        "rejected secondary deposit pulled nothing"
    );

    // Withdraw in PRIMARY works.
    let (pd, _) = env.withdraw_with_cu(&owner, p, 400);
    assert_eq!(env.token_amount(pd), 400, "primary withdrawal delivered");

    // Withdraw in SECONDARY works too (fund the secondary reserve, withdraw to a secondary dest).
    env.svm
        .set_account(
            sec_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary, vault_authority, 300),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let sec_dest = env.token_account_for_mint(secondary, owner.pubkey(), 0);
    env.svm.expire_blockhash();
    let r_wd = env.send(
        ProgInstruction::Withdraw { amount: 300 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(market, false),
            AccountMeta::new(p, false),
            AccountMeta::new(sec_dest, false),
            AccountMeta::new(sec_vault, false),
            AccountMeta::new_readonly(vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        r_wd.is_ok(),
        "withdrawing in the secondary mint must succeed: {r_wd:?}"
    );
    assert_eq!(
        env.token_amount(sec_dest),
        300,
        "secondary withdrawal delivered 1:1"
    );
}

// security.md sweep — dual-mint shared credit (#33/#44): primary and secondary withdrawals spend the
// same portfolio capital. A user must not withdraw a primary deposit once from the primary vault and
// then again from a funded secondary reserve.
#[test]
fn v16_attack_dual_mint_shared_credit_no_double_withdraw() {
    let mut env = V16CuEnv::new();
    let secondary = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary);
    let owner = Keypair::new();
    let portfolio = env.create_portfolio(&owner);
    env.deposit(&owner, portfolio, 1_000);

    let (primary_dest, _) = env.withdraw_with_cu(&owner, portfolio, 1_000);
    assert_eq!(env.token_amount(primary_dest), 1_000);
    assert_eq!(
        env.portfolio_state(portfolio).capital.get(),
        0,
        "primary withdrawal exhausted the shared credit"
    );

    let secondary_vault = canonical_vault_ata(env.vault_authority, secondary);
    env.svm
        .set_account(
            secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary, env.vault_authority, 1_000),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let secondary_dest = env.token_account_for_mint(secondary, owner.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let portfolio_before = env.svm.get_account(&portfolio).unwrap();
    let secondary_vault_before = env.svm.get_account(&secondary_vault).unwrap();
    let secondary_dest_before = env.svm.get_account(&secondary_dest).unwrap();

    env.svm.expire_blockhash();
    let double_withdraw = env.send(
        ProgInstruction::Withdraw { amount: 1 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(secondary_dest, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        double_withdraw.is_err(),
        "secondary reserve must not pay a second withdrawal after primary credit is exhausted"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&portfolio).unwrap(), portfolio_before);
    assert_eq!(
        env.svm.get_account(&secondary_vault).unwrap(),
        secondary_vault_before,
        "rejected double-withdraw leaves secondary reserve untouched"
    );
    assert_eq!(
        env.svm.get_account(&secondary_dest).unwrap(),
        secondary_dest_before,
        "rejected double-withdraw pays no secondary tokens"
    );

    env.deposit(&owner, portfolio, 1);
    env.svm.expire_blockhash();
    let legitimate_secondary = env.send(
        ProgInstruction::Withdraw { amount: 1 },
        vec![
            AccountMeta::new(owner.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(portfolio, false),
            AccountMeta::new(secondary_dest, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&owner],
    );
    assert!(
        legitimate_secondary.is_ok(),
        "fresh shared credit can still withdraw through the secondary reserve: {legitimate_secondary:?}"
    );
    assert_eq!(env.token_amount(secondary_dest), 1);
}

// security.md sweep — dual-mint insurance budget (#33/#44): the domain insurance budget is shared
// across primary and secondary payout rails. It must not pay once from the primary vault and then again
// from an independently funded secondary reserve.
#[test]
fn v16_attack_dual_mint_domain_insurance_no_double_withdraw() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let secondary = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, secondary);
    env.top_up_insurance_domain_with_authority(&admin, 0, 100);
    let (primary_dest, _) = env
        .try_withdraw_insurance_asset_with_authority(&admin, 0, 100)
        .expect("primary insurance withdrawal exhausts the budget");
    assert_eq!(env.token_amount(primary_dest), 100);
    assert_eq!(
        env.market_state().1.insurance_domain_budget[0],
        0,
        "first withdrawal exhausted the shared insurance budget"
    );

    let secondary_vault = canonical_vault_ata(env.vault_authority, secondary);
    env.svm
        .set_account(
            secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(secondary, env.vault_authority, 100),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let secondary_dest = env.token_account_for_mint(secondary, admin.pubkey(), 0);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let secondary_vault_before = env.svm.get_account(&secondary_vault).unwrap();
    let secondary_dest_before = env.svm.get_account(&secondary_dest).unwrap();

    env.svm.expire_blockhash();
    let double_withdraw = env.send(
        ProgInstruction::WithdrawInsuranceAsset {
            asset_index: 0,
            amount: 1,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(secondary_dest, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        double_withdraw.is_err(),
        "secondary reserve must not pay after the insurance budget is exhausted"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(
        env.svm.get_account(&secondary_vault).unwrap(),
        secondary_vault_before,
        "rejected double-withdraw leaves secondary reserve untouched"
    );
    assert_eq!(
        env.svm.get_account(&secondary_dest).unwrap(),
        secondary_dest_before,
        "rejected double-withdraw pays no secondary insurance"
    );

    env.top_up_insurance_domain_with_authority(&admin, 0, 1);
    env.svm.expire_blockhash();
    let legitimate_secondary = env.send(
        ProgInstruction::WithdrawInsuranceAsset {
            asset_index: 0,
            amount: 1,
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(secondary_dest, false),
            AccountMeta::new(secondary_vault, false),
            AccountMeta::new_readonly(env.vault_authority, false),
            AccountMeta::new_readonly(spl_token::ID, false),
        ],
        &[&admin],
    );
    assert!(
        legitimate_secondary.is_ok(),
        "fresh insurance budget can still pay through the secondary reserve: {legitimate_secondary:?}"
    );
    assert_eq!(env.token_amount(secondary_dest), 1);
}

// security.md sweep — base-unit mints changeable only when empty (#5 / README L127): the base-unit
// authority may (re)set the primary/secondary mints ONLY while the market holds no value; once funded,
// the change is rejected so live collateral can never be re-denominated out from under holders.
#[test]
fn v16_attack_base_unit_mints_changeable_only_when_empty() {
    let mut env = V16CuEnv::new();
    let market = env.market;
    let primary = env.mint;
    let admin = env.admin.insecure_clone();
    // EMPTY market: the base-unit authority may set the secondary mint.
    let new_secondary = env.create_mint();
    env.svm.expire_blockhash();
    let r_empty = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: primary.to_bytes(),
            secondary_mint: new_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market, false),
            AccountMeta::new_readonly(primary, false),
            AccountMeta::new_readonly(new_secondary, false),
        ],
        &[&admin],
    );
    assert!(
        r_empty.is_ok(),
        "empty market: base-unit authority may set the secondary mint: {r_empty:?}"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        new_secondary.to_bytes(),
        "secondary mint updated while empty"
    );

    // Fund the market; a further change must now reject.
    let owner = Keypair::new();
    let p = env.create_portfolio(&owner);
    env.deposit(&owner, p, 1_000);
    let other = env.create_mint();
    env.svm.expire_blockhash();
    let r_funded = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: primary.to_bytes(),
            secondary_mint: other.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(market, false),
            AccountMeta::new_readonly(primary, false),
            AccountMeta::new_readonly(other, false),
        ],
        &[&admin],
    );
    assert!(
        r_funded.is_err(),
        "funded market: secondary-mint change must reject"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        new_secondary.to_bytes(),
        "secondary mint unchanged while funded"
    );
}

// security.md sweep — base-unit reserve liveness (#44/#48): accounting-empty is not enough to
// change away from an already configured secondary mint. The old canonical PDA reserve may still
// hold secondary tokens, and CloseSlab can only recover the currently configured secondary reserve.
#[test]
fn v16_attack_base_unit_mint_reset_requires_old_secondary_reserve_empty() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let first_secondary = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, first_secondary);

    let first_secondary_vault = canonical_vault_ata(env.vault_authority, first_secondary);
    env.svm
        .set_account(
            first_secondary_vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(first_secondary, env.vault_authority, 50),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    assert_eq!(
        env.market_state().1.vault,
        0,
        "market accounting is empty despite raw secondary reserve custody"
    );

    let replacement_secondary = env.create_mint();
    let market_before = env.svm.get_account(&env.market).unwrap();
    let old_vault_before = env.svm.get_account(&first_secondary_vault).unwrap();
    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: replacement_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(replacement_secondary, false),
            AccountMeta::new_readonly(first_secondary_vault, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "must not reset secondary mint while the old canonical reserve still holds tokens"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected reset leaves configured mints unchanged"
    );
    assert_eq!(
        env.svm.get_account(&first_secondary_vault).unwrap(),
        old_vault_before,
        "rejected reset leaves the old secondary reserve recoverable"
    );

    env.set_token_account_amount(
        first_secondary_vault,
        first_secondary,
        env.vault_authority,
        0,
    );
    env.svm.expire_blockhash();
    let ok = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: replacement_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(replacement_secondary, false),
            AccountMeta::new_readonly(first_secondary_vault, false),
        ],
        &[&admin],
    );
    assert!(
        ok.is_ok(),
        "empty old secondary reserve can be rotated away: {ok:?}"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        replacement_secondary.to_bytes(),
        "replacement secondary mint stored once old reserve is empty"
    );

    env.svm
        .set_account(
            env.vault,
            Account {
                lamports: 1_000_000_000,
                data: make_token_data(env.mint, env.vault_authority, 7),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let replacement_primary = env.create_mint();
    let market_before = env.svm.get_account(&env.market).unwrap();
    let old_primary_vault_before = env.svm.get_account(&env.vault).unwrap();
    env.svm.expire_blockhash();
    let rejected_primary = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: replacement_primary.to_bytes(),
            secondary_mint: replacement_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(replacement_primary, false),
            AccountMeta::new_readonly(replacement_secondary, false),
            AccountMeta::new_readonly(env.vault, false),
        ],
        &[&admin],
    );
    assert!(
        rejected_primary.is_err(),
        "must not reset primary mint while the old canonical primary vault still holds dust"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected primary reset leaves configured mints unchanged"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        old_primary_vault_before,
        "rejected primary reset leaves old primary dust recoverable"
    );

    env.set_token_account_amount(env.vault, env.mint, env.vault_authority, 0);
    env.svm.expire_blockhash();
    let ok_primary = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: replacement_primary.to_bytes(),
            secondary_mint: replacement_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(replacement_primary, false),
            AccountMeta::new_readonly(replacement_secondary, false),
            AccountMeta::new_readonly(env.vault, false),
        ],
        &[&admin],
    );
    assert!(
        ok_primary.is_ok(),
        "empty old primary vault can be rotated away: {ok_primary:?}"
    );
    assert_eq!(
        env.market_state().0.collateral_mint,
        replacement_primary.to_bytes(),
        "replacement primary mint stored once old primary vault is empty"
    );
}

// security.md sweep — base-unit mint scale isolation (#44/#48): the primary/secondary base-unit mints
// are swapped and withdrawn 1:1. If their SPL decimals differ, the wrapper would silently re-denominate
// collateral. UpdateBaseUnitMints must reject mismatched decimals before storing the pair.
#[test]
fn v16_attack_base_unit_mints_reject_mismatched_decimals() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let mismatched_secondary = Pubkey::new_unique();
    env.svm
        .set_account(
            mismatched_secondary,
            Account {
                lamports: 1_000_000_000,
                data: make_mint_data_with_decimals(6),
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let market_before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: mismatched_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(mismatched_secondary, false),
        ],
        &[&admin],
    );
    assert!(
        rejected.is_err(),
        "base-unit mints with different decimals must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "rejected decimal mismatch must not partially update base-unit mints"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        [0u8; 32],
        "no secondary mint stored after rejected mismatch"
    );

    let matching_secondary = env.create_mint();
    env.update_base_unit_mints_with_cu(env.mint, matching_secondary);
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        matching_secondary.to_bytes(),
        "matching-decimal base-unit pair still configures"
    );
}

// LoF/DoS sweep (cron135): UpdateBaseUnitMints trusts the supplied SPL mint accounts as
// permanent custody rails. Invalid mint account state must reject before any market config write,
// while leaving the same key retryable once it becomes a real SPL mint.
#[test]
fn v16_attack_base_unit_mints_reject_malformed_new_mint_accounts() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let hostile_secondary = Pubkey::new_unique();
    env.svm
        .set_account(
            hostile_secondary,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; Mint::LEN],
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let market_before = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected_uninitialized = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: hostile_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(hostile_secondary, false),
        ],
        &[&admin],
    );
    let err =
        rejected_uninitialized.expect_err("uninitialized secondary base-unit mint must reject");
    assert!(
        err.contains("Custom(10)"),
        "uninitialized secondary base-unit mint must reject as InvalidMint, got {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "uninitialized mint rejection must not partially update base-unit config"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        [0u8; 32],
        "no secondary rail is installed after uninitialized mint rejection"
    );

    let mut hostile_account = env.svm.get_account(&hostile_secondary).unwrap();
    hostile_account.data = make_mint_data();
    hostile_account.owner = solana_sdk::system_program::ID;
    env.svm
        .set_account(hostile_secondary, hostile_account)
        .unwrap();
    let market_before_wrong_owner = env.svm.get_account(&env.market).unwrap();

    env.svm.expire_blockhash();
    let rejected_wrong_owner = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: env.mint.to_bytes(),
            secondary_mint: hostile_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(env.mint, false),
            AccountMeta::new_readonly(hostile_secondary, false),
        ],
        &[&admin],
    );
    let err = rejected_wrong_owner.expect_err("wrong-owner secondary base-unit mint must reject");
    assert!(
        err.contains("Custom(10)"),
        "wrong-owner secondary base-unit mint must reject as InvalidMint, got {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before_wrong_owner,
        "wrong-owner mint rejection must not partially update base-unit config"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        [0u8; 32],
        "no secondary rail is installed after wrong-owner mint rejection"
    );

    let mut valid_account = env.svm.get_account(&hostile_secondary).unwrap();
    valid_account.owner = spl_token::ID;
    env.svm
        .set_account(hostile_secondary, valid_account)
        .unwrap();
    env.svm.expire_blockhash();
    env.update_base_unit_mints_with_cu(env.mint, hostile_secondary);
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        hostile_secondary.to_bytes(),
        "same key can configure the secondary rail once it is a valid SPL mint"
    );
}

// LoF/DoS sweep (cron135): rotating the primary base-unit mint also requires an old-primary
// reserve proof. A malformed new primary mint must reject before that reserve-proof branch, leaving
// the old primary vault and market config byte-stable and retryable with a valid mint.
#[test]
fn v16_attack_base_unit_primary_mint_rejects_before_old_vault_proof() {
    let mut env = V16CuEnv::new();
    let admin = env.admin.insecure_clone();
    let malformed_primary = Pubkey::new_unique();
    let new_secondary = env.create_mint();
    env.svm
        .set_account(
            malformed_primary,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; Mint::LEN],
                owner: spl_token::ID,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let market_before = env.svm.get_account(&env.market).unwrap();
    let old_primary_vault_before = env.svm.get_account(&env.vault).unwrap();

    env.svm.expire_blockhash();
    let rejected = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: malformed_primary.to_bytes(),
            secondary_mint: new_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(malformed_primary, false),
            AccountMeta::new_readonly(new_secondary, false),
        ],
        &[&admin],
    );
    let err = rejected.expect_err("malformed primary base-unit mint must reject");
    assert!(
        err.contains("Custom(10)"),
        "malformed primary base-unit mint must reject as InvalidMint before old-vault proof, got {err}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "malformed primary rejection must not partially update base-unit config"
    );
    assert_eq!(
        env.svm.get_account(&env.vault).unwrap(),
        old_primary_vault_before,
        "malformed primary rejection leaves the old primary reserve untouched"
    );
    assert_eq!(
        env.market_state().0.collateral_mint,
        env.mint.to_bytes(),
        "primary rail remains pinned to the original mint after rejection"
    );
    assert_eq!(
        env.market_state().0.secondary_collateral_mint,
        [0u8; 32],
        "secondary rail is not installed by a rejected primary-mint rotation"
    );

    let mut valid_primary = env.svm.get_account(&malformed_primary).unwrap();
    valid_primary.data = make_mint_data();
    env.svm
        .set_account(malformed_primary, valid_primary)
        .unwrap();
    env.svm.expire_blockhash();
    let accepted = env.send(
        ProgInstruction::UpdateBaseUnitMints {
            primary_mint: malformed_primary.to_bytes(),
            secondary_mint: new_secondary.to_bytes(),
        },
        vec![
            AccountMeta::new(admin.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new_readonly(malformed_primary, false),
            AccountMeta::new_readonly(new_secondary, false),
            AccountMeta::new_readonly(env.vault, false),
        ],
        &[&admin],
    );
    assert!(
        accepted.is_ok(),
        "valid primary rotation remains live with the old-primary reserve proof: {accepted:?}"
    );
    let cfg = env.market_state().0;
    assert_eq!(
        cfg.collateral_mint,
        malformed_primary.to_bytes(),
        "valid retry stores the new primary mint"
    );
    assert_eq!(
        cfg.secondary_collateral_mint,
        new_secondary.to_bytes(),
        "valid retry stores the new secondary mint"
    );
}

