// CU/DoS sweep: full benign matcher tails add the worst valid account fanout to the fresh-asset
// stale-portfolio BatchTradeCpi boundary. This path must remain live for a one-leg fresh-asset batch
// and still fit below the transaction CU cap.
#[test]
fn v16_attack_stale_thirteen_leg_fresh_asset_batch_cpi_with_max_tail_stays_bounded() {
    const MAX_TAIL: usize = percolator_prog::constants::MAX_MATCHER_TAIL_ACCOUNTS;

    let mut env = V16CuEnv::new_with_market_params_and_price_move(14, 1_000, 1_000, 500);
    let long_owner = Keypair::new();
    let short_owner = Keypair::new();
    let long_account = env.create_portfolio(&long_owner);
    let short_account = env.create_portfolio(&short_owner);
    env.deposit(&long_owner, long_account, 100_000);
    env.deposit(&short_owner, short_account, 100_000);
    env.seed_n_leg_position_for_benchmark(long_account, short_account, 13);
    env.svm.warp_to_slot(16);

    let matcher_program = Pubkey::new_unique();
    let matcher_bytes = std::fs::read(auth_matcher_program_path()).expect("read auth matcher BPF");
    env.svm.add_program(matcher_program, &matcher_bytes);
    let (ctx, delegate, _) =
        env.init_auth_matcher_context(matcher_program, &short_owner, short_account);
    let tail: Vec<Pubkey> = (0..MAX_TAIL)
        .map(|_| {
            let key = Pubkey::new_unique();
            env.svm
                .set_account(
                    key,
                    Account {
                        lamports: 1_000_000_000,
                        data: vec![0u8; 8],
                        owner: Pubkey::default(),
                        executable: false,
                        rent_epoch: 0,
                    },
                )
                .unwrap();
            key
        })
        .collect();
    let mut accounts = vec![
        AccountMeta::new(long_owner.pubkey(), true),
        AccountMeta::new(env.market, false),
        AccountMeta::new(long_account, false),
        AccountMeta::new(short_account, false),
        AccountMeta::new_readonly(matcher_program, false),
        AccountMeta::new(ctx, false),
        AccountMeta::new_readonly(delegate, false),
    ];
    accounts.extend(
        tail.iter()
            .copied()
            .map(|key| AccountMeta::new_readonly(key, false)),
    );

    env.svm.expire_blockhash();
    let cu = env
        .send(
            ProgInstruction::BatchTradeCpi {
                legs: vec![BatchTradeCpiLeg {
                    asset_index: 13,
                    size_q: POS_SCALE as i128,
                    fee_bps: 0,
                    limit_price: 0,
                }],
            },
            accounts,
            &[&long_owner],
        )
        .expect("max-tail fresh-asset BatchTradeCpi from thirteen stale legs must stay live");
    println!("v16 13-stale-leg fresh-asset BatchTradeCpi max-tail CU: {cu}");
    assert!(
        cu < 1_400_000,
        "fresh-asset max-tail BatchTradeCpi CU {cu}"
    );
    let long_after = env.portfolio_state(long_account);
    let short_after = env.portfolio_state(short_account);
    assert_eq!(
        active_leg_for_asset(&long_after, 13).basis_pos_q,
        POS_SCALE as i128,
        "fresh asset opened on the taker"
    );
    assert_eq!(
        active_leg_for_asset(&short_after, 13).basis_pos_q,
        -(POS_SCALE as i128),
        "fresh asset opened on the LP"
    );
    let (_, group) = env.market_state();
    assert!(
        group.vault >= group.c_tot + group.insurance,
        "fresh-asset max-tail BatchTradeCpi preserves senior conservation"
    );
}

// CU/DoS hardening: BatchTradeCpi must reject impossible caller fee_bps before invoking a matcher.
// The single-fill CPI path checks max(caller_fee_bps, trade_fee_base_bps) before CPI; batch CPI must
// do the same. The hostile over-fill matcher is the sentinel: a valid-fee call reaches matcher-return
// validation and fails InvalidAccountData, while an over-fee call must fail InvalidInstruction first.
#[test]
fn v16_attack_batch_tradecpi_fee_bps_rejects_before_hostile_matcher_cpi() {
    let mut env = V16CuEnv::new();
    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let ta = env.create_portfolio(&taker);
    let la = env.create_portfolio(&lp);
    env.deposit(&taker, ta, 1_000_000);
    env.deposit(&lp, la, 1_000_000);

    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &la,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; MATCHER_CONTEXT_LEN],
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.set_matcher_config(hostile, &lp, la, ctx, delegate, 1);

    let send_fee = |env: &mut V16CuEnv, fee_bps: u64| {
        let mut data = vec![0u8; MATCHER_CONTEXT_LEN];
        data[0] = 0; // hostile over-fill mode: if CPI occurs, validation fails InvalidAccountData.
        env.svm
            .set_account(
                ctx,
                Account {
                    lamports: 1_000_000_000,
                    data,
                    owner: hostile,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::BatchTradeCpi {
                legs: vec![BatchTradeCpiLeg {
                    asset_index: 0,
                    size_q: (5 * POS_SCALE) as i128,
                    fee_bps,
                    limit_price: 0,
                }],
            },
            vec![
                AccountMeta::new(taker.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(ta, false),
                AccountMeta::new(la, false),
                AccountMeta::new_readonly(hostile, false),
                AccountMeta::new(ctx, false),
                AccountMeta::new_readonly(delegate, false),
            ],
            &[&taker],
        )
    };

    let valid_fee_err = send_fee(&mut env, 100)
        .expect_err("valid-fee hostile batch should reach matcher-return validation");
    assert!(
        valid_fee_err.contains("InvalidAccountData"),
        "valid-fee hostile sentinel must fail from matcher-return validation, got {valid_fee_err}"
    );
    assert!(
        !valid_fee_err.contains("Custom(9)"),
        "valid-fee sentinel must not trip the fee preflight: {valid_fee_err}"
    );

    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&ta).unwrap();
    let lp_before = env.svm.get_account(&la).unwrap();
    for bad_fee in [10_001u64, u64::MAX] {
        let rejected = send_fee(&mut env, bad_fee)
            .expect_err("over-fee BatchTradeCpi must reject before matcher CPI");
        assert!(
            rejected.contains("Custom(9)"),
            "over-fee BatchTradeCpi must fail as InvalidInstruction before hostile matcher validation, got {rejected}"
        );
        assert!(
            !rejected.contains("InvalidAccountData"),
            "over-fee BatchTradeCpi must not reach hostile matcher validation: {rejected}"
        );
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "over-fee preflight leaves market bytes unchanged"
        );
        assert_eq!(
            env.svm.get_account(&ta).unwrap(),
            taker_before,
            "over-fee preflight leaves taker bytes unchanged"
        );
        assert_eq!(
            env.svm.get_account(&la).unwrap(),
            lp_before,
            "over-fee preflight leaves LP bytes unchanged"
        );
    }
}

// CU/DoS hardening: backing-fee policy intentionally disables batch fee splitting, so BatchTradeCpi
// must reject before the external matcher CPI when any backing-fee policy is active. The no-policy
// control reaches hostile matcher validation; the policy-on path must fail at the wrapper gate first.
#[test]
fn v16_attack_batch_tradecpi_backing_fee_policy_rejects_before_hostile_matcher_cpi() {
    let mut env = V16CuEnv::new();
    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let ta = env.create_portfolio(&taker);
    let la = env.create_portfolio(&lp);
    env.deposit(&taker, ta, 1_000_000);
    env.deposit(&lp, la, 1_000_000);

    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &la,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; MATCHER_CONTEXT_LEN],
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.set_matcher_config(hostile, &lp, la, ctx, delegate, 1);

    let send = |env: &mut V16CuEnv| {
        let mut data = vec![0u8; MATCHER_CONTEXT_LEN];
        data[0] = 0; // hostile over-fill mode: if CPI occurs, validation fails InvalidAccountData.
        env.svm
            .set_account(
                ctx,
                Account {
                    lamports: 1_000_000_000,
                    data,
                    owner: hostile,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::BatchTradeCpi {
                legs: vec![BatchTradeCpiLeg {
                    asset_index: 0,
                    size_q: (5 * POS_SCALE) as i128,
                    fee_bps: 0,
                    limit_price: 0,
                }],
            },
            vec![
                AccountMeta::new(taker.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(ta, false),
                AccountMeta::new(la, false),
                AccountMeta::new_readonly(hostile, false),
                AccountMeta::new(ctx, false),
                AccountMeta::new_readonly(delegate, false),
            ],
            &[&taker],
        )
    };

    let no_policy_err = send(&mut env)
        .expect_err("without backing-fee policy, hostile batch should reach matcher validation");
    assert!(
        no_policy_err.contains("InvalidAccountData"),
        "no-policy hostile control should fail from matcher-return validation, got {no_policy_err}"
    );
    assert!(
        !no_policy_err.contains("Custom(9)"),
        "no-policy hostile control must not trip the backing-fee policy gate: {no_policy_err}"
    );

    env.update_backing_fee_policy_with_cu(0, 77, 5_000);
    assert_eq!(
        env.market_state().0.backing_trade_fee_policy_count,
        1,
        "test setup must activate the backing-fee batch gate"
    );
    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&ta).unwrap();
    let lp_before = env.svm.get_account(&la).unwrap();
    let rejected = send(&mut env)
        .expect_err("backing-fee policy BatchTradeCpi must reject before matcher CPI");
    assert!(
        rejected.contains("Custom(9)"),
        "backing-fee policy BatchTradeCpi must fail as InvalidInstruction before hostile matcher validation, got {rejected}"
    );
    assert!(
        !rejected.contains("InvalidAccountData"),
        "backing-fee policy BatchTradeCpi must not reach hostile matcher validation: {rejected}"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "policy preflight leaves market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&ta).unwrap(),
        taker_before,
        "policy preflight leaves taker bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&la).unwrap(),
        lp_before,
        "policy preflight leaves LP bytes unchanged"
    );
}

// security.md sweep - stale BatchTradeNoCpi legacy realloc rollback (#30/#44/#48): the no-CPI batch
// path grows legacy portfolios before the shared stale-market freeze check. A stale-matured batch must
// reject without leaving an attacker-triggered realloc/zero-fill DoS behind; while fresh, the same
// legacy portfolios must still grow and trade normally.
#[test]
fn v16_attack_batch_nocpi_stale_reject_rolls_back_legacy_realloc() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(1, 1_000, 1_000, 500);
    env.configure_permissionless_resolve_with_cu(5, 5);
    env.svm.warp_to_slot(1);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);

    let taker = Keypair::new();
    let lp = Keypair::new();
    let taker_portfolio = env.create_portfolio(&taker);
    let lp_portfolio = env.create_portfolio(&lp);
    env.deposit(&taker, taker_portfolio, 1_000_000);
    env.deposit(&lp, lp_portfolio, 1_000_000);

    let truncate_to_legacy = |env: &mut V16CuEnv, portfolio: Pubkey| {
        let mut account = env.svm.get_account(&portfolio).unwrap();
        account.data.truncate(PORTFOLIO_ENGINE_ACCOUNT_LEN);
        env.svm.set_account(portfolio, account).unwrap();
    };
    truncate_to_legacy(&mut env, taker_portfolio);
    truncate_to_legacy(&mut env, lp_portfolio);
    assert_eq!(
        env.svm.get_account(&taker_portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "test setup starts with a legacy taker portfolio"
    );
    assert_eq!(
        env.svm.get_account(&lp_portfolio).unwrap().data.len(),
        PORTFOLIO_ENGINE_ACCOUNT_LEN,
        "test setup starts with a legacy LP portfolio"
    );

    let batch = |env: &mut V16CuEnv, size_q: i128| {
        env.svm.expire_blockhash();
        env.send(
            ProgInstruction::BatchTradeNoCpi {
                legs: vec![BatchTradeLeg {
                    asset_index: 0,
                    size_q,
                    exec_price: 100,
                    fee_bps: 100,
                }],
            },
            vec![
                AccountMeta::new(taker.pubkey(), true),
                AccountMeta::new(lp.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(taker_portfolio, false),
                AccountMeta::new(lp_portfolio, false),
            ],
            &[&taker, &lp],
        )
    };

    env.svm.warp_to_slot(4);
    let fresh = batch(&mut env, POS_SCALE as i128);
    assert!(
        fresh.is_ok(),
        "fresh-oracle BatchTradeNoCpi must grow legacy portfolios and trade: {fresh:?}"
    );
    assert_eq!(
        env.svm.get_account(&taker_portfolio).unwrap().data.len(),
        env.portfolio_account_len,
        "fresh batch grows the legacy taker storage"
    );
    assert_eq!(
        env.svm.get_account(&lp_portfolio).unwrap().data.len(),
        env.portfolio_account_len,
        "fresh batch grows the legacy LP storage"
    );
    assert_eq!(
        active_leg_for_asset(&env.portfolio_state(taker_portfolio), 0).basis_pos_q,
        POS_SCALE as i128,
        "fresh control opened the taker leg"
    );

    truncate_to_legacy(&mut env, taker_portfolio);
    truncate_to_legacy(&mut env, lp_portfolio);
    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&taker_portfolio).unwrap();
    let lp_before = env.svm.get_account(&lp_portfolio).unwrap();

    env.svm.warp_to_slot(40);
    let rejected = batch(&mut env, POS_SCALE as i128);
    assert!(
        rejected.is_err(),
        "stale-resolve-matured BatchTradeNoCpi must reject"
    );
    assert_eq!(
        env.svm.get_account(&env.market).unwrap(),
        market_before,
        "stale legacy batch leaves market bytes unchanged"
    );
    assert_eq!(
        env.svm.get_account(&taker_portfolio).unwrap(),
        taker_before,
        "stale legacy batch rolls back taker realloc and zero-fill"
    );
    assert_eq!(
        env.svm.get_account(&lp_portfolio).unwrap(),
        lp_before,
        "stale legacy batch rolls back LP realloc and zero-fill"
    );

    env.svm.expire_blockhash();
    let resolve = env.send(
        ProgInstruction::ResolveStalePermissionless { now_slot: 0 },
        vec![AccountMeta::new(env.market, false)],
        &[],
    );
    assert!(
        resolve.is_ok(),
        "permissionless resolve remains live after the rejected stale legacy batch: {resolve:?}"
    );
}

// Anti-spoof core: validate_matcher_return is the per-leg gate that bounds a (possibly hostile)
// matcher's reply. Every CPI integration test feeds it HONEST returns; this exercises the REJECTION
// branches directly with crafted hostile replies (over-fill, reversed sign, forged echo, bad flags,
// zero price, unflagged partial). Guards the anti-spoof against regression end-to-end of the struct.
#[test]
fn v16_attack_matcher_return_antispoof_rejections() {
    use percolator_prog::matcher_abi::{
        validate_matcher_return, MatcherReturn, FLAG_PARTIAL_OK, FLAG_REJECTED, FLAG_VALID,
    };
    const LP: u64 = 7;
    const ASSET: u16 = 1;
    const ORACLE: u64 = 100;
    const REQID: u64 = 42;
    let req: i128 = (10 * POS_SCALE) as i128; // taker buy, full size 10
    let valid = MatcherReturn {
        abi_version: MATCHER_ABI_VERSION,
        flags: FLAG_VALID,
        exec_price_e6: 100,
        exec_size: req,
        req_id: REQID,
        lp_account_id: LP,
        oracle_price_e6: ORACLE,
        asset_index: ASSET as u64,
    };
    let chk = |r: &MatcherReturn| validate_matcher_return(r, LP, ASSET, ORACLE, req, REQID);
    // baseline: a faithful full fill is accepted.
    assert!(chk(&valid).is_ok(), "faithful full fill must validate");
    // a faithful partial fill (flagged) is accepted.
    let mut partial = valid;
    partial.exec_size = (5 * POS_SCALE) as i128;
    partial.flags = FLAG_VALID | FLAG_PARTIAL_OK;
    assert!(chk(&partial).is_ok(), "flagged partial fill validates");

    // --- hostile replies, each must REJECT ---
    let cases: &[(&str, fn(MatcherReturn) -> MatcherReturn)] = &[
        ("over-fill (exec>req)", |mut r| {
            r.exec_size = (20 * POS_SCALE) as i128;
            r
        }),
        ("reversed sign", |mut r| {
            r.exec_size = -((10 * POS_SCALE) as i128);
            r
        }),
        ("forged asset echo", |mut r| {
            r.asset_index = 2;
            r
        }),
        ("forged oracle echo", |mut r| {
            r.oracle_price_e6 = 99;
            r
        }),
        ("forged req_id", |mut r| {
            r.req_id = 43;
            r
        }),
        ("forged lp_account_id", |mut r| {
            r.lp_account_id = 8;
            r
        }),
        ("bad abi_version", |mut r| {
            r.abi_version = MATCHER_ABI_VERSION + 1;
            r
        }),
        ("REJECTED flag set", |mut r| {
            r.flags = FLAG_VALID | FLAG_REJECTED;
            r
        }),
        ("VALID flag missing", |mut r| {
            r.flags = 0;
            r
        }),
        ("unknown flag bit", |mut r| {
            r.flags = FLAG_VALID | 0x100;
            r
        }),
        ("zero exec_price", |mut r| {
            r.exec_price_e6 = 0;
            r
        }),
        ("unflagged partial (exec<req, no PARTIAL_OK)", |mut r| {
            r.exec_size = (5 * POS_SCALE) as i128;
            r
        }),
    ];
    for (name, mutate) in cases {
        let bad = mutate(valid);
        assert!(
            chk(&bad).is_err(),
            "hostile matcher return must be rejected: {name}"
        );
    }
}

fn hostile_matcher_program_path() -> PathBuf {
    let mut path = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    path.push("tests/fixtures/hostile_matcher/target/deploy/hostile_matcher.so");
    assert!(
        path.exists(),
        "build the hostile matcher: cargo build-sbf in {path:?}"
    );
    path
}

// End-to-end adversarial: a HOSTILE matcher .so returns crafted tag-3 replies (over-fill, reversed
// sign, forged asset/oracle/req_id/lp echo, zero price, unflagged partial, short return length). The
// wrapper's get_return_data + per-leg validate_matcher_return must REJECT every one (whole batch
// reverts, no position opened); only the faithful reply (mode 9) executes. Complements the
// validate_matcher_return UNIT test by exercising the full CPI return-data plumbing end-to-end.
#[test]
fn v16_attack_hostile_matcher_batch_returns_all_rejected() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);
    env.configure_auth_mark_for_asset_as_admin(1, 1, 100);
    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let ta = env.create_portfolio(&taker);
    let la = env.create_portfolio(&lp);
    env.deposit(&taker, ta, 1_000_000);
    env.deposit(&lp, la, 1_000_000);
    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &la,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: vec![0u8; MATCHER_CONTEXT_LEN],
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    env.set_matcher_config(hostile, &lp, la, ctx, delegate, 1);
    let sz = (5 * POS_SCALE) as i128;
    let send_mode = |env: &mut V16CuEnv,
                     mode: u8|
     -> (Result<u64, String>, Account, Account, Account, Account) {
        let mut data = vec![0u8; MATCHER_CONTEXT_LEN];
        data[0] = mode;
        env.svm
            .set_account(
                ctx,
                Account {
                    lamports: 1_000_000_000,
                    data,
                    owner: hostile,
                    executable: false,
                    rent_epoch: 0,
                },
            )
            .unwrap();
        let market_before = env.svm.get_account(&env.market).unwrap();
        let taker_before = env.svm.get_account(&ta).unwrap();
        let lp_before = env.svm.get_account(&la).unwrap();
        let ctx_before = env.svm.get_account(&ctx).unwrap();
        env.svm.expire_blockhash();
        let result = env.send(
            ProgInstruction::BatchTradeCpi {
                legs: vec![
                    BatchTradeCpiLeg {
                        asset_index: 0,
                        size_q: sz,
                        fee_bps: 100,
                        limit_price: 0,
                    },
                    BatchTradeCpiLeg {
                        asset_index: 1,
                        size_q: sz,
                        fee_bps: 100,
                        limit_price: 0,
                    },
                ],
            },
            vec![
                AccountMeta::new(taker.pubkey(), true),
                AccountMeta::new(env.market, false),
                AccountMeta::new(ta, false),
                AccountMeta::new(la, false),
                AccountMeta::new_readonly(hostile, false),
                AccountMeta::new(ctx, false),
                AccountMeta::new_readonly(delegate, false),
            ],
            &[&taker],
        );
        (result, market_before, taker_before, lp_before, ctx_before)
    };
    let labels = [
        "over-fill",
        "reversed-sign",
        "forged-asset",
        "forged-oracle",
        "forged-req_id",
        "forged-lp",
        "zero-price",
        "unflagged-partial",
        "short-length",
    ];
    for (mode, label) in labels.iter().enumerate() {
        let (r, market_before, taker_before, lp_before, ctx_before) =
            send_mode(&mut env, mode as u8);
        assert!(
            r.is_err(),
            "hostile matcher mode '{label}' must be rejected by the wrapper"
        );
        assert_eq!(
            env.svm.get_account(&env.market).unwrap(),
            market_before,
            "hostile batch mode '{label}' must not mutate market state"
        );
        assert_eq!(
            env.svm.get_account(&ta).unwrap(),
            taker_before,
            "hostile batch mode '{label}' must not mutate taker state"
        );
        assert_eq!(
            env.svm.get_account(&la).unwrap(),
            lp_before,
            "hostile batch mode '{label}' must not mutate LP state"
        );
        assert_eq!(
            env.svm.get_account(&ctx).unwrap(),
            ctx_before,
            "hostile batch mode '{label}' must roll back matcher context writes"
        );
        let t = state::read_portfolio(&env.svm.get_account(&ta).unwrap().data).unwrap();
        assert!(
            !has_active_leg_for_asset(&t, 0) && !has_active_leg_for_asset(&t, 1),
            "no position may be opened on a rejected hostile reply ({label})"
        );
    }
    // sanity: the SAME harness with a faithful reply (mode 9) executes -> rejections above are real,
    // not a broken test setup.
    let (ok, _, _, _, _) = send_mode(&mut env, 9);
    assert!(
        ok.is_ok(),
        "faithful matcher reply must execute through the same path: {ok:?}"
    );
    let t = state::read_portfolio(&env.svm.get_account(&ta).unwrap().data).unwrap();
    assert!(
        has_active_leg_for_asset(&t, 0) && has_active_leg_for_asset(&t, 1),
        "faithful reply fills both legs"
    );
}

// full-interface sweep / issue: removing the LP signer from TradeCpi is only safe if Percolator
// verifies that the LP owner explicitly authorized this matcher program/context. A hostile matcher can
// otherwise return a perfectly well-formed oracle-priced fill and force a victim LP portfolio into a
// position. This is the single-fill reproducer: no LP signature and no Percolator matcher config
// must reject before any position is opened.
#[test]
fn v16_attack_tradecpi_rejects_unapproved_unsigned_lp_matcher() {
    let mut env = V16CuEnv::new_with_market_params_and_price_move(2, 1_000, 1_000, 500);
    env.configure_auth_mark_for_asset_as_admin(0, 1, 100);
    let hostile = Pubkey::new_unique();
    env.svm.add_program(
        hostile,
        &std::fs::read(hostile_matcher_program_path()).unwrap(),
    );
    let taker = Keypair::new();
    let lp = Keypair::new();
    let ta = env.create_portfolio(&taker);
    let la = env.create_portfolio(&lp);
    env.deposit(&taker, ta, 1_000_000);
    env.deposit(&lp, la, 1_000_000);

    let ctx = Pubkey::new_unique();
    let delegate = matcher_delegate_key(
        &env.program_id,
        &env.market,
        &la,
        &lp.pubkey(),
        &hostile,
        &ctx,
    );
    env.svm
        .set_account(
            delegate,
            Account {
                lamports: 1_000_000_000,
                data: vec![],
                owner: Pubkey::default(),
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();
    let mut ctx_data = vec![0u8; MATCHER_CONTEXT_LEN];
    ctx_data[0] = 9; // hostile fixture faithful mode: returns a valid fill.
    env.svm
        .set_account(
            ctx,
            Account {
                lamports: 1_000_000_000,
                data: ctx_data,
                owner: hostile,
                executable: false,
                rent_epoch: 0,
            },
        )
        .unwrap();

    let market_before = env.svm.get_account(&env.market).unwrap();
    let taker_before = env.svm.get_account(&ta).unwrap();
    let lp_before = env.svm.get_account(&la).unwrap();
    let ctx_before = env.svm.get_account(&ctx).unwrap();

    env.svm.expire_blockhash();
    let r = env.send(
        ProgInstruction::TradeCpi {
            asset_index: 0,
            size_q: (5 * POS_SCALE) as i128,
            fee_bps: 100,
            limit_price: 0,
        },
        vec![
            AccountMeta::new(taker.pubkey(), true),
            AccountMeta::new(env.market, false),
            AccountMeta::new(ta, false),
            AccountMeta::new(la, false),
            AccountMeta::new_readonly(hostile, false),
            AccountMeta::new(ctx, false),
            AccountMeta::new_readonly(delegate, false),
        ],
        &[&taker],
    );
    assert!(
        r.is_err(),
        "unauthorized matcher must not be able to force an unsigned LP TradeCpi fill"
    );
    assert_eq!(env.svm.get_account(&env.market).unwrap(), market_before);
    assert_eq!(env.svm.get_account(&ta).unwrap(), taker_before);
    assert_eq!(env.svm.get_account(&la).unwrap(), lp_before);
    assert_eq!(env.svm.get_account(&ctx).unwrap(), ctx_before);
    assert!(!has_active_leg_for_asset(
        &state::read_portfolio(&env.svm.get_account(&la).unwrap().data).unwrap(),
        0
    ));
}

